window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-035.json"] = [{"name":"啸声掩鼻风鸟","english_name":"Growling Riflebird","scientific_name":"Ptiloris intercedens","overview":"啸声掩鼻风鸟（英文名：Growling Riflebird，学名：Ptiloris intercedens），是雀形目极乐鸟科掩鼻风鸟属的中等体型的鸟类。其名称源于黑色羽毛类似英国军队步枪团制服，且雄鸟拥有独特的啸叫声。分布在新几内亚东部低地森林，具有显著的蓝色胸盾和羽毛覆盖的喙基。","appearance":"雄鸟体长约34厘米，体重155至214克，全身大部分呈哑光黑色，带有蓝色光泽的头部和胸部，下腹部有浅色边线。雌鸟和幼鸟背部棕色，腹部淡色，带有深色条纹。雄鸟的喙略短，嘴部颜色从柠檬黄到鲜绿色，脚暗灰色至黑色。雌鸟喙稍长，背部橙红褐色，有明显的眉纹。","call":"发出响亮而粗糙的啸叫声，'hrrrak hrrrow'，首音上扬，第二音下降，有时重复多次，不同于其近亲的音乐性哨声。","habits":"栖息于低地雨林、山地森林和较低海拔的森林地带，偶尔进入红树林，偏好高大树木和森林斑块。以果实和无脊椎动物为食，常在主树冠层寻找果实，而在较低层搜寻动物性食物。","breeding":"繁殖季节未知，但在7月观察到雌鸟携带筑巢材料。在4月至9月期间，雄鸟独自在展示点吸引雌鸟。巢为由树枝构成的松散杯状，靠近树干支撑。每窝产1至2枚蛋，孵化和育雏期未详。","identification":"与丽色掩鼻风鸟相似，但通过其独特的啸叫声、较短的侧翼羽毛和喙基的羽毛化程度可以区分。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚东部，自拉穆河和阿斯特罗拉贝湾北部至普拉里河南部。","other":"虽然全球数量未量化，但其种群被认为稳定，未受威胁。但可能因伐木、森林清除和人类定居点扩张而局部减少。"},{"name":"黑镰嘴风鸟","english_name":"Black Sicklebill","scientific_name":"Epimachus fastosus","overview":"黑镰嘴风鸟（英文名：Black Sicklebill，学名：Epimachus fastosus），是雀形目极乐鸟科镰嘴风鸟属的鸟类。大型、长尾的极乐鸟科成员，广泛分布于新几内亚中西部至中南部和西北部的山地森林中，主要活跃在海拔1800至2150米的高度。其显著特征是雄鸟拥有黑色的身体、银色微弯的长喙和异常长的尾羽，而雌鸟则呈棕色，腹部有条纹。","appearance":"雄性黑镰嘴风鸟全长约63厘米（含尾羽可达110厘米），体重250至318克；雌鸟略小，长约55厘米，体重160至255克。雄鸟头部全黑，带有金属绿蓝紫色光泽的鳞状羽毛，上身黑色，翼上部有变色的蓝紫或品红色光泽。雌鸟较小，上体棕色，下体淡色带深棕色条纹，尾较短。幼鸟类似雌鸟，但羽色更柔和。","call":"雄鸟的鸣叫声独特，两组爆炸性的空洞双音节“wak-wak！wak-wak！”响亮且穿透力强。","habits":"栖息于中高海拔的山地森林，偶尔出现在林缘，偏好原始森林，较少见于次生林和花园边缘。以水果和动物为食，比例相当，常在森林中层和上层觅食，有时也会降至地面。","breeding":"繁殖期大致在11月至翌年2月（雨季），雄鸟在4月至9月期间具有增大的睾丸，雌鸟在2月初卵巢中可见大卵。雄鸟进行壮观的展示，雌鸟单独筑巢。具体繁殖细节尚不明确。","identification":"与褐镰嘴风鸟相似，但黑镰嘴风鸟通常生活在较低海拔，胸部黑色。雄鸟通过其独特的羽毛展示和声音与同类区分开来。","protection":"IUCN：LC（无危）。CITES II。物种数量估计在2500至10000只之间，由于栖息地丧失、人口规模小和部分地区的猎杀，数量正在下降。","distribution":"分布于新几内亚中西部至中南部和西北部的山地森林中，以及中北部沿海山脉。","other":"曾与黑蓝长尾风鸟杂交产生Elliot's sicklebill和astrapian sicklebill，后者现在普遍被认为是杂交种。"},{"name":"褐镰嘴风鸟","english_name":"Brown Sicklebill","scientific_name":"Epimachus meyeri","overview":"褐镰嘴风鸟（英文名：Brown Sicklebill，学名：Epimachus meyeri），是雀形目极乐鸟科镰嘴风鸟属的鸟类。大型山地森林鸟类，以独特的长曲喙和长尾著称。分布于新几内亚的中西部至东南部山区，雄鸟拥有黑色上部羽毛，带虹彩光泽，棕色下部羽毛和异常长的尾巴。雌鸟上部棕色，头部红棕色，腹部具条纹，脸部黑色。","appearance":"雄性褐镰嘴风鸟总长可达49厘米（含中央尾羽长达96厘米），体重144至310克；雌鸟则稍小，约52厘米，体重140至202克。雄鸟全身黑亮，带有金属蓝绿色虹彩，下部棕色，尾羽中央两根极为延长呈镰刀状；雌鸟暗褐色，头部偏红，腹部具条纹，脸黑色。雌雄皆有长而弯曲的喙。","call":"雄鸟发出的叫声如同短促的机关枪声，具有地域性变化，最远可在2公里外听到。雌鸟类似鸡鸣，另有‘ugh!’的吠叫声。","habits":"栖息于中高海拔的山地森林，包括苔藓森林，也会出现在受扰森林、次生林和森林边缘，高度范围1500至3200米，主要在1900至2900米之间。以果实、节肢动物和小型脊椎动物为食，觅食范围广泛，从地面到树冠层均有其踪迹。","breeding":"繁殖期至少从4月至次年1月。雄鸟在特定月份生殖腺增大，雌鸟卵泡在特定月份亦会增大。雄鸟会在特定地点进行展示求偶，雌鸟单独筑巢。巢穴由苔藓、蕨类叶片、草和细藤构成，位于4至12米高的树冠处，通常在鹤望兰或树蕨上。每次产卵一枚。","identification":"与黑镰嘴风鸟相似，但褐镰嘴风鸟通常在更高海拔出现，雄鸟有棕色下体，雌鸟腹部具条纹，且眼色淡蓝。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的中西部至东南部山区，包括澳大利亚的蒙特安纳森林。","other":"曾因传统狩猎导致部分地区数量稀少，但目前整体状态稳定，未受到立即威胁。"},{"name":"黑嘴镰嘴风鸟","english_name":"Black-billed Sicklebill","scientific_name":"Drepanornis albertisi","overview":"黑嘴镰嘴风鸟（英文名：Black-billed Sicklebill，学名：Drepanornis albertisi），是雀形目极乐鸟科短尾镰嘴风鸟属的鸟类。新几内亚中海拔山地森林中的一种大型、长喙的天堂鸟。雄鸟具有黑色喉部及眼前的角状蓝绿虹彩羽冠，雌鸟下体具深色鳞状斑纹。该物种以昆虫为主食，也取食果实，分布于新几内亚多个山脉，海拔600至2250米之间。","appearance":"雄鸟体长约35厘米，体重103–125克；雌鸟体长约33厘米，体重92–138克。雄鸟头部呈肉桂棕色，冠羽具铜紫色虹彩；眼前有角状蓝绿虹彩羽簇；面部裸露皮肤为暗褐灰色；上体及翼上覆羽为肉桂棕色，尾羽淡肉桂色；上胸为烟褐色，具紫罗兰色虹彩羽端；腹部中央、尾下覆羽白色；喙黑色，具镰刀状弯曲。雌鸟无虹彩羽，上体色较深，喉部肉桂棕色，下体具暗褐色横斑，尾较雄鸟短。亚种cervinicauda体型较小，尾更短，尾羽及尾上覆羽颜色更浅，雌鸟型个体下体为淡黄褐色，横斑更淡。","call":"雄鸟的广告鸣唱为一系列高亢、响亮的哨音“dyu dyu dyu...”，节奏逐渐加快，音调升高或偶尔下降；联系叫声为哀怨的“wrenh”；求偶展示时的叫声更为急促，常以嘶嘶声“tish-tish-tish”或“ki-ki-ki”结尾。Fakfak山脉的种群鸣声为缓慢下降的哨音，与Arfak山脉的急促颤音不同。","habits":"栖息于中海拔山地森林，偶见于轻微采伐区域及林缘，海拔范围600–2250米，主要在1100–1900米。为留鸟，活动范围较小，曾记录一只雌鸟在八天内活动于其43公顷的家域内。以昆虫为主食，也取食果实，通常在森林中层及上层觅食，利用长喙探取树皮、枯木、苔藓及落叶中的猎物，亦会加入混合种觅食群。","breeding":"繁殖期至少为9月至12月，全年2–10月间均可见到生殖器官增大的个体。雄鸟为多配偶制，占据并守卫约14公顷的展示兼觅食领地，全年在固定展示点鸣唱求偶，展示包括静态及倒悬姿势，并抖动胸羽、侧羽及头部羽毛。雌鸟单独筑巢并育雏，已知巢为薄而扁平的结构，由淡红棕色草构成，内衬黑色根须，置于细枝分叉处。每窝产1或2枚卵，孵化及育雏期未知。一只雄鸟在成鸟羽饰状态下被环志后至少存活9年，寿命超过15岁。","identification":"雌鸟与黑嘴镰嘴风鸟及淡嘴镰嘴风鸟雌鸟相似，但通常分布于较低海拔，尾较短，且无黑色喉部。亚种cervinicauda体型小于指名亚种，尾更短，尾羽颜色更浅。","protection":"IUCN: LC（无危）。列入CITES附录II。虽非全球性受胁物种，但数量普遍不丰富，可能在一些看似适宜的栖息地中缺失，建议持续监测。","distribution":"分布于新几内亚多个山脉，包括Vogelkop、Wandammen半岛、Huon半岛及Foja山脉等；亚种cervinicauda分布于新几内亚中部Cordillera山脉，从Weyland山脉向东至Lordberg及Tari地区，以及东南部山区。","other":"亚种cervinicauda曾被部分分类系统视为独立物种，但差异较小。Huon半岛的种群曾被提议为独立亚种geisleri，需进一步研究确认。"},{"name":"淡嘴镰嘴风鸟","english_name":"Pale-billed Sicklebill","scientific_name":"Drepanornis bruijnii","overview":"淡嘴镰嘴风鸟（英文名：Pale-billed Sicklebill，学名：Drepanornis bruijnii），是雀形目极乐鸟科短尾镰嘴风鸟属的鸟类。以其独特的病态色上喙和中等体型著称。体长约为35厘米，主要分布于新几内亚中北部的低地雨林，相对不起眼的鸟类，其上部呈暗橄榄色，下部灰褐色，头部深棕色，最显著特征是围绕眼睛的铅灰色裸露面部皮肤和头顶上的两簇虹彩羽毛。","appearance":"淡嘴镰嘴风鸟的雄鸟拥有独特的外观，额头、冠部及前额区颜色多变，呈暗棕色，头顶上有蓝紫或红紫色虹彩的延长羽毛，形成竖立的羽簇；下巴、喉咙和耳覆羽深黑色，带叶绿色虹彩；背部暗棕色至肉桂棕色，翅膀棕色，边缘略淡，尾羽肉桂棕色；胸部暗橄榄棕色，翼下覆羽暗灰棕色，带有铜红色或蓝紫色虹彩尖端，腹部暗暖灰色。雌鸟体型与雄鸟相似但体重较轻，缺乏虹彩羽毛，下巴至上胸为淡色，向下逐渐变暗，腹部肉桂色，全身均匀分布黑棕色条纹。","call":"雄鸟的广告鸣叫为一系列变化的、沙哑或空洞的口哨声，音调上升或下降，有时伴有低沉的音乐般的咕噜声或咳嗽声。觅食时会发出安静的询问声。","habits":"生活在新几内亚的低地雨林，包括受干扰的地区和石灰岩丘陵的原始及选择性砍伐森林，海拔高度从海平面到180米。主要以果实和节肢动物为食，更倾向于果食。在树冠层觅食，偶尔下降到较低层次加入混合物种觅食群。","breeding":"雄鸟在繁殖季节会进行展示，包括静态姿势和动作，如展开尾羽和张嘴，可能还有其他未知的展示动作。雌鸟独自筑巢和照料巢穴。雄鸟领土意识强，每天巡逻领地，对邻近雄鸟的鸣叫和展示做出反应。","identification":"与十二线鸟天堂鸟和辉煌凤头鸟相比，淡嘴镰嘴风鸟雌鸟的喙更长、更细且更弯曲。雄鸟的虹彩装饰羽毛和独特鸣叫也是辨识要点。","protection":"IUCN：LC（无危）。该物种因栖息地丧失和退化而面临威胁，尤其是在其有限范围内，低地森林受到开发压力和商业木材贸易的影响。","distribution":"分布于新几内亚东北部，从Geelvink湾东侧穿过Meervlakte（Lakeplain）并延伸至Vanimo地区及Sepik河上游西北部。","other":"尽管分布范围小，但在其地理范围内可能广泛分布且局部常见，甚至在选择性砍伐的森林中也能发现。"},{"name":"丽色极乐鸟","english_name":"Magnificent Bird-of-paradise","scientific_name":"Diphyllodes magnificus","overview":"丽色极乐鸟（英文名：Magnificent Bird-of-paradise，学名：Diphyllodes magnificus），是雀形目极乐鸟科卷尾极乐鸟属的鸟类。中等体型的热带森林鸟类，以雄鸟独特的展示行为闻名。雄鸟拥有瓶绿色胸部和黄色颈部装饰，能竖立成华丽的装饰品，尾羽呈蓝色光泽。雌鸟较小，上体褐色，具蓝喙及眼后纹。该物种广泛分布于新几内亚和周边岛屿。","appearance":"雄鸟体长19厘米（含中央尾羽可达26厘米），体重75-119克。头部短而橄榄棕色，颈部有黄绿色小斑点，背部形成半圆形的深红色羽毛，边缘黑色。下背至臀部红棕色，尾羽深橄榄棕色，尾羽尖端细长呈病镰状，上部蓝绿色，下部橄榄棕色。雌鸟体长19厘米，体重52-60克，上体橄榄至红棕色，下体暗褐色横纹，喉部脏白色，嘴灰蓝，腿脚蓝色。","call":"雄鸟发出一系列下滑的‘joo！’音符，响亮的‘jip！’或粗糙的刮擦声。","habits":"栖息于山地森林，海拔约1500米，有时高达1780米。以果实和各种昆虫为主食，偶尔取食蜘蛛。单独觅食，常见于混合物种觅食群。飞行时可能产生可听的咔哒声或嘎吱声。","breeding":"繁殖季节为7月至12月，可能全年都有繁殖活动。雄鸟建立传统地面展示场，雌鸟独建巢，巢由苔藓、干叶、杂草和兽毛构成，位于地面1-4米高处。每次产卵1-2枚，孵化期18-19天，雏鸟期17-18天。","identification":"雄鸟独特，雌鸟较同属雌鸟小，与雌性王极乐鸟和Lophorina属物种区别明显，比雌性王极乐鸟大，具蓝喙及眼后纹。亚种间辨识依据羽毛色彩和尺寸差异。","protection":"IUCN：LC（无危）","distribution":"分布于印尼、新几内亚及周边岛屿，主要栖息于热带和亚热带山地及丘陵森林。","other":"与王极乐鸟有杂交现象，杂交种曾被误认为独立物种。"},{"name":"威氏极乐鸟","english_name":"Wilson's Bird-of-paradise","scientific_name":"Diphyllodes respublica","overview":"威氏极乐鸟（英文名：Wilson's Bird-of-paradise，学名：Diphyllodes respublica），是雀形目极乐鸟科卷尾极乐鸟属的鸟类。又译: 威尔逊极乐鸟、威氏风鸟、威氏丽色风鸟，是印度尼西亚巴布亚岛的特有种，主要分布于Waigeo和Batanta岛屿的丘陵森林中。这种鸟以其独特的外观和华丽的色彩著称，雄鸟拥有蓝紫色的脚和头部裸露的淡蓝色皮肤，雌鸟则呈现暗褐色。在1996年，大卫阿滕伯勒首次拍摄到了这种鸟的镜头，为BBC制作纪录片。","appearance":"威氏极乐鸟体型较小，雄鸟体长约16厘米（含中央尾羽可达21厘米），体重53至67克；雌鸟体长同样约为16厘米，体重52至60克。雄鸟拥有瓶绿色胸部、红色背部和黄色颈部，以及奇特的扁平卷曲尾羽，能反射出蓝色光芒。头部裸露的蓝色皮肤上带有黑色细线图案，雌鸟则为上部橄榄棕色至红棕色，下部有条纹，尾羽温暖的棕色。","call":"雄鸟发出一系列响亮、音调下滑的‘piuu！’叫声，音量逐渐增大。","habits":"主要栖息于丘陵森林，偶尔也出现在低地雨林和中高山区森林，活动海拔从300米至1000至1200米。食物包括果实和节肢动物，可能参与混合物种觅食群。","breeding":"繁殖季节未知，雄鸟在5月至6月和10月期间具有增大的生殖腺，雌鸟在6月时有适度增大的卵细胞。雄鸟进行独占式多配偶制，独自清理地面的展示场，雌鸟单独筑巢和照料幼鸟。","identification":"雄鸟的鲜艳色彩和复杂的展示动作使其在分布范围内独一无二。雌鸟的暗褐色和下部条纹有助于区分。","protection":"IUCN：NT（近危）","distribution":"分布于印尼的West Papuan Is（Waigeo和Batanta），位于新几内亚西北部。","other":"尽管在某些地区因皮肤而被猎杀，威氏极乐鸟在较高海拔的森林中似乎相对安全。"},{"name":"王极乐鸟","english_name":"King Bird-of-paradise","scientific_name":"Cicinnurus regius","overview":"王极乐鸟（英文名：King Bird-of-paradise，学名：Cicinnurus regius），是雀形目极乐鸟科王极乐鸟属的唯一物种，与Diphyllodes属关系密切。小型而色彩艳丽的极乐鸟，雄鸟拥有金属红色的外观，雌鸟则呈橄榄色头部和上部，黄色腹部，紫蓝色腿部。分布于新几内亚大陆及周边岛屿的低地森林。","appearance":"雄性王极乐鸟约16厘米长，若含中央尾羽可达31厘米，体重43至65克；雌鸟长约19厘米，重38至58克。雄鸟头部、下巴、胸部及上部为深红至橙红色，具绿色金属光泽的胸带，下胸处有细白边，尾羽中央为两根长丝状，末端螺旋盘绕成绿金属色。雌鸟橄榄褐色，下部黄褐色，具暗褐色条纹，腿蓝紫色。幼鸟上头棕色，翼羽较暗，下部灰色具暗条纹。","call":"雄鸟的鸣叫多样，包括下降的\"whei-wher-wha\"声、响亮的\"wher-whei-wha\"声、\"queu-queu-queu\"声、深沉的\"kraaa\"声、喉音\"cho-chow-chaw-chaw-chaw-chaw-chai\"系列音符、鼻音\"ca\"、\"wa\"或\"wau\"的上升音阶、低音颤音\"rahn rahn rahn rahn\"、高音鼻音\"ki-kyer\"以及快速下降音阶的\"ki kyer kyer kyer\"。","habits":"王极乐鸟栖息于新几内亚的低地雨林、季风林、河岸林及林缘，包括受干扰地区和高大次生林，海拔高度从海平面至950米，主要不超过300至400米。它们以果实和节肢动物为食，常加入混合物种觅食群寻找森林底层的昆虫。","breeding":"繁殖期至少在3月至10月间，雄鸟在孤立或群体展示场进行求偶展示，雌鸟独自筑巢于树洞中，孵化期17天，雏鸟期14天，属于一夫多妻制。","identification":"雄性王极乐鸟与雌鸟形态显著不同，雌鸟类似雌鸟华丽极乐鸟，但后者喙为蓝色而非黄色。雄性王极乐鸟的特有特征在于其尾羽的螺旋盘绕结构。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚大陆及周边岛屿，包括Aru、Salawati、Missol和Yapen岛的低地森林。","other":"首次成功繁殖记录是在1958年，由瑞典的Sten Bergman实现。"},{"name":"幡羽极乐鸟","english_name":"Standardwing","scientific_name":"Semioptera wallacii","overview":"幡羽极乐鸟（英文名：Standardwing，学名：Semioptera wallacii），是雀形目极乐鸟科幡羽极乐鸟属的鸟类。中等体型，长约28厘米，以橄榄棕色为主调，雄鸟的头部呈现光泽的紫罗兰和淡紫色，胸前拥有醒目的翠绿色盾牌。其最引人注目的特征是肩部延伸出的两对长而洁白的羽毛，能够随鸟儿的意愿升降。雌鸟较小，未有装饰性羽毛，呈橄榄棕色，尾部比雄鸟更长。分布于印尼北方摩鹿加群岛的哈马黑拉岛和Bacan岛，栖息于低地热带雨林和山丘。","appearance":"雄性幡羽极乐鸟体长约26厘米，重152-174克；雌鸟略小，约23厘米，重126-143克。雄鸟具有独特的头部构造，上喙基部上方有一明显的羽毛簇，脸部颜色由淡紫色渐变为淡灰色，带有淡紫色光泽，胸部拥有大面积的绿松石色至黄绿色的金属光泽羽毛，形成显著的胸盾。肩部两侧伸出两对异常延长的白色羽毛，形似‘标准’，长度可与翅膀相当甚至更长。雌鸟全身呈土褐色，缺乏雄鸟的特征羽毛和胸盾，上鼻孔处的羽毛簇比成年雄鸟小。幼鸟类似雌鸟，但平均尾长稍长。亚成年雄鸟的羽毛介于雌鸟和成年雄鸟之间。","call":"雄鸟在展示时发出非常响亮的声音，包括刺耳的“WAA-WAA…”和“KEE-KEE…”音符。此外，还有四种不同的鸣叫：招引叫声由6-7个上扬的响亮清晰的‘wark’音符组成；空中展示时的叫声粗犷嘈杂；与高强度展示相关的音乐般的叽喳声；以及最常见的是觅食成年雄鸟或远离展示区移动个体发出的一系列上扬、鼻音的‘wark’音符，可能是一种联系叫声。","habits":"栖息于低地和山丘的热带雨林，海拔高度至少到1000米。以果实和节肢动物为食，群居于3-4个个体组成的群体中，在密集的下层树冠中觅食。偶尔加入混合物种的觅食群。通常被认为是居民鸟种，很少迁徙。","breeding":"繁殖期至少从5月持续至9月。雄鸟在4月至10月期间，生殖腺显著增大；雌鸟在9月也有类似现象。巢由雌鸟独自建造和照料，位于森林树冠的高处，距离地面25-30米。繁殖行为包括肢体跳跃、静态姿势和飞行展示，涉及翅膀、胸盾和翼标准的动作。已知的一个巢是一个开放的杯状结构，底座由干枯的叶子构成，位于大寄生兰花和棕榈树之间的10米高处。","identification":"雄性幡羽极乐鸟通过其独特的头部羽毛簇、翠绿色的胸盾和肩部的长白羽毛与同类区别。雌鸟与雄鸟相比，缺少上述特征，主要通过色彩和大小识别。亚成年雄鸟羽毛介于雌鸟和成年雄鸟之间，尾长介于两者之间。","protection":"IUCN：LC（无危）","distribution":"分布于印尼北方摩鹿加群岛的哈马黑拉岛和Bacan岛，主要栖息于低地热带雨林和山丘。","other":"在19世纪，标准翼鸟首次被欧洲人认识，源于费迪南德·麦哲伦环球航行中收到的礼物。自1858年首次发现以来，曾近60年未再见到，直到1983年再次被发现，开始对其行为进行详细观察。"},{"name":"十二线极乐鸟","english_name":"Twelve-wired Bird-of-paradise","scientific_name":"Seleucidis melanoleucus","overview":"十二线极乐鸟（英文名：Twelve-wired Bird-of-paradise，学名：Seleucidis melanoleucus），是雀形目极乐鸟科十二线极乐鸟属的唯一物种。雄鸟拥有黑色头部、上身和胸部，带有薄绿边框，黄色腹部，以及独特的十二根丝状尾羽。雌鸟呈红褐色，下体具条纹。分布于新几内亚和印尼萨拉瓦蒂岛的低地森林。","appearance":"雄性十二线极乐鸟长约33厘米，体重170至217克，具有黑色头部、上身和胸部，被绿色边缘环绕，余下腹部为鲜艳的黄色。十二根丝状物替代了尾部，从背部延伸而出。雌鸟长度约35厘米，体重160至188克，上体红褐色，下体带条纹。雄鸟头部丝绒黑，带有铜绿光泽，翅膀覆盖物黑绿油光，翼下部分紫色闪光，腹部黑色，胸下部有绿色镶边的羽毛形成领饰，两侧延伸。雌鸟头部及上背灰黑色，余下上体棕褐，下体灰白带黑色斑点和条纹。","call":"雄鸟有两种广告叫声，一种是喉音的下滑音“harnhr hahn”，另一种是一系列3到8个“hahr-haw haw haw”的叫声，首声最高，随后短暂停顿，最后连续快速发出2到7声。当雌鸟靠近时，雄鸟会发出更高、急促、鼻音的‘twang hahng-hahng-hahng’，音调下降，以及一系列类似Paradisaea的上升音。","habits":"栖息于低地森林和平坦沼泽森林，以果实、节肢动物、青蛙、昆虫和花蜜为主食。雄鸟在清晨从展示杆上发出叫声，吸引雌鸟。","breeding":"繁殖期为1月至10月底至11月初，雄鸟在特定月份有扩大的睾丸，雌鸟有增大的卵子。雄鸟在传统的展示枝上单独展示，雌鸟独自筑巢。巢由藤蔓或树花序茎构成，位于地面以上高达14米处的兰花或西谷椰子树中。每窝通常产一枚蛋，有时两枚。在圈养条件下，孵化期约为20天，雏鸟在三周大时离巢。","identification":"雄性十二线极乐鸟以其独特的十二根丝状尾羽和黄腹为显著特征，雌鸟与雌鸟Riflebird相似，但头部黑色。雄鸟在展示时会展开其胸盾。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚和印尼的萨拉瓦蒂岛（Raja Ampat Islands西北部）。","other":"十二线极乐鸟在新加坡的裕廊鸟类公园进行了首次成功的圈养繁殖。"},{"name":"大极乐鸟","english_name":"Greater Bird-of-paradise","scientific_name":"Paradisaea apoda","overview":"大极乐鸟（英文名：Greater Bird-of-paradise，学名：Paradisaea apoda），是雀形目极乐鸟科极乐鸟属的鸟类。以其华丽的羽毛和独特的求偶表演闻名。雄鸟拥有黑色胸部和醒目的白黄相间的背部羽毛，雌鸟全身呈现暗褐色。分布于新几内亚南部和阿鲁群岛，曾因羽毛贸易面临威胁。","appearance":"雄性大极乐鸟全长约43厘米（不含尾羽），雌鸟约35厘米，重170至173克。雄鸟面部虹彩绿，头部银色光泽，上体为深赤褐色，翼下覆羽边缘橙黄，尾羽细长如丝，腹面暗棕，大腿粉棕色。雌鸟全身暗褐色。幼鸟未详述。","call":"雄鸟发出典型的重复鼻音叫声，如深沉的'wauk'声，常在求偶展示中伴随翅膀拍打。","habits":"栖息于低地和丘陵森林，最高可达海拔950米。主要食物包括果实、种子和小型昆虫。展示活动通常在日出前开始，持续至黄昏。","breeding":"繁殖期主要集中在3月、5月和8月至12月。雄鸟在传统展示树上建立求偶场，雌鸟独自筑巢。巢为浅盘状，由大叶、兰花茎、藤蔓和蕨类植物组成，位于大树枝叉。每次产卵一枚，人工孵化需16至17天，雏鸟在18至20天后离巢。","identification":"雄性大极乐鸟比同类物种更大，缺乏黄色背部，雌鸟全身呈暗褐色，区别于其他物种。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚南部和印尼阿鲁群岛，主要栖息于低地和丘陵森林。","other":"曾因羽毛贸易遭受严重捕猎，目前保护状况良好，常见于其自然分布范围内。"},{"name":"新几内亚极乐鸟","english_name":"Raggiana Bird-of-paradise","scientific_name":"Paradisaea raggiana","overview":"新几内亚极乐鸟（英文名：Raggiana Bird-of-paradise，学名：Paradisaea raggiana），是雀形目极乐鸟科极乐鸟属的鸟类。又名: 红羽极乐鸟或红羽天堂鸟，是新几内亚南部及东北部广泛分布的一种大型极乐鸟。作为巴布亚新几内亚的国鸟，其鲜艳的色彩和独特的展示行为使其成为该地区的标志性物种。雄鸟拥有醒目的红橙色羽毛，雌鸟则呈现较为低调的栗红危色调。","appearance":"雄性新几内亚极乐鸟长约34厘米，具有一对细长的黑色尾丝和大型侧翼羽毛，颜色从深红到橙色不等，取决于亚种。其头部为黄色，喉咙呈暗绿色，上胸部黑色，腹部及臀部为棕色至粉棕色。雌鸟较小，约33厘米，上体及下体均为淡黄褐色，腹部颜色更浅。幼鸟全为暗褐色，四个月后逐渐展现出成鸟特征。","call":"雄鸟在展示时发出一系列响亮、远传的叫声，音调逐渐升高，有时音高亦增加，结尾音最长且最粗犷。此外，还有一种较高音调的快速、沙哑叫声。","habits":"栖息于低地森林、山地森林及较低海拔的山地森林，偶尔出现在次生林、林缘、花园及开阔地带的松树林中。以果实（尤其是蒴果和无花果）和节肢动物为食，是新几内亚某些树木的重要种子传播者。","breeding":"繁殖季节至少从四月至十二月，巢建于2至11米高的树干上，通常在森林内部或残存森林的树冠层。雌鸟独自筑巢，巢呈碗状，主要由叶子、茎、蕨类和其他植物纤维组成。每窝产1至2枚粉红色的蛋，孵化期为18至20天，仅由雌鸟负责。","identification":"雄性新几内亚极乐鸟与同属其他物种的区别在于其红橙色而非白色的侧翼羽毛。雌鸟通过黄色的眼睛和头部背面的黄色区别于其他种类。亚种间颜色有所不同，如P. r. augustavictoriae的侧翼羽毛为杏橙色。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚东北部和东南部的热带森林内，繁殖区域与非繁殖区域重合，遍及澳大利亚新几内亚的东北部和东南部。"},{"name":"小极乐鸟","english_name":"Lesser Bird-of-paradise","scientific_name":"Paradisaea minor","overview":"小极乐鸟（英文名：Lesser Bird-of-paradise，学名：Paradisaea minor），是雀形目极乐鸟科极乐鸟属的鸟类。分布于新几内亚西部和北部以及邻近的Misool和Yapen岛。其最显著的特征为黄色头部和背部，雄鸟拥有一对长尾丝和深黄色基部的装饰性侧羽，逐渐变白向外延伸。雌鸟头部呈暗棕色，腹部为淡色。","appearance":"小极乐鸟是一种中等体型的鸟类，总长可达32厘米，雄鸟体重183至300克，雌鸟141至210克。雄鸟具墨绿色喉部，黄色冠部和上背部呈棕色，拥有长尾丝和深黄色渐变为白色的侧羽。雌鸟全身暗赤栗色，头部暗棕色，腹部淡色。幼鸟特征未详，亚成体类似雌鸟，但可能部分展示雄鸟成鸟的羽毛特征。","call":"雄鸟在求偶场中的广告歌是一系列高音清脆的'wak'音符，与同类的歌曲相似，但更兴奋、音调更高，速度更快。求偶叫声通常由较柔和的初始音符开始，随后变得急促。","habits":"小极乐鸟栖息于低地和山麓森林及其边缘地带。雄鸟群聚在树上进行求偶展示，雌鸟独自筑巢。它们主要以果实和昆虫为食，雄鸟的求偶舞蹈极为精彩，包括高举双翅、伸直颈部、耸立羽毛并连续颤动。","breeding":"繁殖季节至少从7月持续到2月，雄鸟在多数月份具有增大的生殖腺，而雌鸟在特定月份有增大的卵子。雄鸟在传统树栖点进行求偶展示，雌鸟单独筑巢。巢由树枝、藤蔓和枯叶制成，位于树高处。每窝产1-2枚粉红色带暗斑的蛋，孵化期约为18天。","identification":"小极乐鸟与较大的大极乐鸟相区别，后者雄鸟胸部较深，雌鸟全身呈棕色，无淡色腹部。雄性小极乐鸟的侧羽颜色与指名亚种相同，而finshi亚种的侧羽颜色略亮。","protection":"IUCN：LC（无危）","distribution":"小极乐鸟广泛分布于新几内亚的西部和北部，以及附近的Misool和Yapen岛。","other":"小极乐鸟的皮肤可能含有从昆虫猎物中获得的毒素，这一特性需进一步研究证实。"},{"name":"戈氏极乐鸟","english_name":"Goldie's Bird-of-paradise","scientific_name":"Paradisaea decora","overview":"戈氏极乐鸟（英文名：Goldie's Bird-of-paradise，学名：Paradisaea decora），是雀形目极乐鸟科极乐鸟属的鸟类。以发现者苏格兰采集者安德鲁·戈迪命名。雄鸟拥有黄绿色至暗绿色的羽毛，黄色的眼环和灰色的胸部，雌鸟则呈现橄榄褐色，下方为肉桂棕色。仅分布于巴布亚新几内亚东部的当特尔卡斯托群岛中的Fergusson和Normanby两岛。","appearance":"雄鸟33厘米长（不含尾羽丝），体重约237克；雌鸟稍小，29厘米长。雄鸟的前额、脸颊和喉部覆盖着微闪的黄绿至暗绿色羽毛；头部和背部橙黄色，翼上覆羽淡橙黄色，翼片和次级飞羽呈粉红色，带有橄榄棕色光泽，边缘黄色；尾羽中央丝状，基部黑色带绿闪；胸部中灰色，腹部粉色，大腿和尾下覆羽粉白；腹侧的延长侧羽丝绒般深红，尖端白色，背侧锈棕色。雌鸟较小，头顶至背部黄褐色，其余上部橄榄棕色，下体肉桂色，胸部较深，全身灰条纹明显。雏鸟描述未知；未成年雄鸟类似成年雌鸟；亚成年雄鸟变异，可能带有成年雄鸟羽毛，最初头部可见，尾羽中央较长，逐渐向成年雄鸟转变。","call":"雄鸟在求偶场发出典型的‘wok-wok’或‘wark’声，通常在雌鸟不在时；还发出柔和的‘whick-whick’声，可能作为雄鸟间的接触信号，而当雌鸟在场时会发出响亮、清澈、尖锐的‘whit whit whit’叫声。展示开始时，雄鸟会发出低沉的咆哮声；两只雄鸟同时展示，尤其是在雌鸟面前，可能会交替发出响亮、金属般的‘waak’音符，速度逐渐加快，产生连续的金属颤音。","habits":"戈氏极乐鸟爱顶风飞行，因此被称为‘风鸟’。它们以果实为主食，偶尔也会捕食昆虫、蛙类和小型蜥蜴。鸣声粗厉，通常单独或成对生活。","identification":"戈氏极乐鸟与其他天堂鸟没有重叠分布区，雄鸟的灰色胸部羽毛是其独特标志。","protection":"IUCN：VU（易危）","distribution":"分布于澳新界，具体为Fergusson和Normanby（巴布亚新几内亚当特尔卡斯托群岛，东部，新几内亚东南部），即其繁殖区域。"},{"name":"红极乐鸟","english_name":"Red Bird-of-paradise","scientific_name":"Paradisaea rubra","overview":"红极乐鸟（英文名：Red Bird-of-paradise，学名：Paradisaea rubra），是雀形目极乐鸟科极乐鸟属的鸟类。这大型的热带森林鸟类，拥有黄色的喙、胸部和头部后方。雄鸟以其独特的展示而著名，具有2条细长的黑色尾羽流苏，栗色翅膀和鲜红色的羽毛簇，而雌鸟面部呈黑色，体型略小。该物种分布于印尼的瓦伊盖奥岛和巴坦塔岛等西北岛屿的低地雨林。","appearance":"雄性红极乐鸟总长可达33厘米（不含尾丝），体重158至224克；雌鸟则稍小，长度约30厘米，体重在115至208克之间。雄鸟的头部至眼后区域覆盖着精细的虹彩暗绿色羽毛，上眼部位的羽毛稍长且弯曲形成可竖立的垫状结构；头部剩余部分、颈背、上背部和类似披肩的上翼覆羽呈淡橙黄色，侧背部和下中部背部为琥珀色，泛黄并带有虹彩光泽，逐渐过渡到背部的赤褐色；臀部和上尾覆羽呈淡橙黄色，带琥珀色；上翼和包括翼尖覆羽在内的上尾为赤褐色；中央一对尾羽异常延长，形成细长、轻盈的黑色“带子”，宽约3至4毫米，质地和外观类似塑料；胸部长而略硬的浅橙黄色羽毛形成小型胸盾，下方羽毛呈深棕色，泛紫红色，腹部颜色渐淡，少紫红色，过渡至腹股沟、肛门和下尾覆羽的榛色；侧翼长而略硬、向下弯曲的羽毛为朱红色至深红色，上表面颜色变化从深棕色到中棕色，末端有白色丝线状尖端。雌鸟较雄鸟略小，中央一对尾羽较窄且更尖锐，面部至眼后区和喉部为深棕色，后冠、颈部和颈背为淡黄色，向上体部分渐变为深棕色；上胸有一条明显的宽光泽稻草黄色横杠，其余下体部分为棕色。幼鸟的野外描述尚未详述，但在圈养条件下，60天时开始出现黄色上胸，125天时已明显，类似于成年雌鸟；亚成鸟的变化范围大，可能接近成年雌鸟，仅少数成年雄鸟羽毛插入，也可能接近成年雄鸟，但仍保留少量雌鸟型羽毛，中央一对尾羽最初仅比其他尾羽长、窄、尖，逐渐变成相对短的裸露中央羽轴线，顶部有延长的扁平状末端，这一过程会随年龄增长而变长，末端逐渐变小，雄鸟需5至6年才能获得完整的成年羽毛。","call":"红极乐鸟的雄鸟在求偶场中发出的最常见广告叫声是一连串响亮、清晰的“wak”声，它们通过喉咙发出的“work - wok, wak, wak, wak, wak, wak”的声音逐渐加强至高音量的“wok-wau-wau-wau”。其他叫声包括类似但音调更高的“ca-ca-ca-ca-ca-ca”；常发的乌鸦般的粗哑、低沉“kaw, kaw, kaw”；还有一种常见的柔和、哀伤的“weep”声，以及不太常见的柔和高音“meew”和单次的喙部咔嚓声，此外还有一种可能由高音“beep”开始，以低沉的“book”结束的滴答声。","habits":"红极乐鸟栖息于低地雨林环境中，主要分布于印尼的瓦伊盖奥岛和巴坦塔岛等西北岛屿。它们的食谱主要由果实、浆果和节肢动物组成。","breeding":"红极乐鸟的繁殖季节通常在9月至10月，雌鸟在此期间会有增大的卵巢，显示处于繁殖状态。雄鸟会在传统的展示枝上进行群体求偶，雌鸟独自筑巢并照顾后代。在瓦伊盖奥岛上，雄鸟会在清晨后在森林空地中的一棵大树上展示和呼唤，每棵树上最多可有十只成年雄鸟。求偶行为包括三个基本阶段：收敛展示、静态展示和交配序列舞蹈，伴随着一些额外的姿势和动作。在圈养环境下，产卵数量为1至2枚，间隔日或隔日产出，孵化期为14至17天，雏鸟期为15至20天。","identification":"红极乐鸟与同域的威尔逊极乐鸟在形态上有明显差异，可通过其独特的红色羽毛簇和黑色尾丝加以区分。","protection":"IUCN：NT（近危）","distribution":"红极乐鸟主要分布在印尼的瓦伊盖奥岛（Waigeo）、加姆岛（Gam）、萨奥内克岛（Saonek）的南部地区和巴坦塔岛（Batanta），位于四王群岛西北部的新几内亚附近。","other":"红极乐鸟在野外与另一种极乐鸟——威尔逊极乐鸟共享栖息地，但二者间尚未有杂交记录。"},{"name":"线翎极乐鸟","english_name":"Emperor Bird-of-paradise","scientific_name":"Paradisaea guilielmi","overview":"线翎极乐鸟（英文名：Emperor Bird-of-paradise，学名：Paradisaea guilielmi），是雀形目极乐鸟科极乐鸟属的鸟类。极乐鸟科的大型鸟类，主要分布在新几内亚东北部的休恩半岛，栖息于山林之间。其最显著的特征是雄鸟拥有深绿色的头部和胸部，长长的黑色尾丝，以及在展示时会张开的白色侧翼装饰羽毛。雌鸟全身呈棕色，体型较雄鸟小，缺乏装饰性的羽毛。","appearance":"雄性线翎极乐鸟体长约33厘米（不包括尾丝），体重约250至265克。头部和上胸部为油绿色，带有光泽，颈部至背部为淡黄色，其余背部、臀部、上尾覆羽和三级飞羽为暗棕色，双翅和尾部为深棕色，中央尾羽极度延长，仅基部有羽毛，末端细长如丝。雌鸟较小，全身呈暗棕色，缺乏雄鸟的金属光泽和延长的羽毛。幼鸟特征未详细描述。","call":"雄鸟在繁殖展示时发出一系列6到8个音符的叫声，起初音调较低，随后为连续高音的“whu, whow, whow, whow, whow, whow”。同时也会发出类似金属质感的鼻音‘whai’音符。雄鸟在展示时还会发出‘pop’, ‘baupop’, 和‘bau’音节，有时伴随爆炸般的响声，如同鞭炮爆裂。","habits":"主要栖息于原生山林中，高度约450至1500米，通常在670至1350米之间。以果实为主食，辅以部分节肢动物。在树上进行攀爬搜寻昆虫，单独或成对觅食，特别是在果树林中与其他极乐鸟共同觅食。","breeding":"繁殖季节至少从9月至12月，雄鸟的生殖腺在10月开始增大，11月至12月显著增大。雄鸟在传统的展示栖木上进行群聚展示，吸引雌鸟独自筑巢。展示分为收敛展示和静态展示两个阶段，雄鸟在静态展示时会倒挂并展开侧翼的白色羽毛，形成独特的展示姿态。","identification":"与Raggiana和小极乐鸟相比，线翎极乐鸟通常出现在更高海拔，雄鸟胸部为瓶绿色，雌鸟颈背更偏黄色。雄鸟的叫声为鼻音‘caw！’或兴奋的呼啸。","protection":"IUCN：NT（近危）","distribution":"分布于新几内亚东北部的休恩半岛，具体包括芬斯特雷山脉、萨鲁瓦盖德山脉、克罗姆威尔山脉和罗林森山脉。","other":"线翎极乐鸟的命名是为了纪念德国最后一位皇帝威廉二世。"},{"name":"蓝极乐鸟","english_name":"Blue Bird-of-paradise","scientific_name":"Paradisornis rudolphi","overview":"蓝极乐鸟（英文名：Blue Bird-of-paradise，学名：Paradisornis rudolphi），是雀形目极乐鸟科 Paradisornis 属的鸟类。以雄鸟的独特羽毛和炫耀性展示闻名。其分布于新几内亚东部的中央山脉，大型森林鸟类，拥有黑色头部和背部，亮蓝色翅膀和尾巴，以及白色喙和眼环。雌雄差异显著，雄鸟具有红蓝相间的羽毛和两条长尾流苏，而雌鸟则呈褐色，有轻微的条纹。","appearance":"雄性蓝极乐鸟长约30厘米（不含尾流苏），重158至189克；雌鸟相似，但略小，重124至166克。雄鸟头部、颈部和肩部呈闪亮的墨黑色，带绿青铜光泽；后颈和颈背有暗红色；背部和臀部黑色，具蓝绿色、蓝色和靛蓝色光泽；上翼覆盖羽蓝至紫蓝色；尾羽紫色，中央两根延长为窄黑丝状，末端微白，闪烁蓝光；胸腹部黑色，大腿和下尾覆羽深棕色；侧腹有细长的丝状羽毛，基部深紫蓝，向尖端渐变为蓝至紫罗兰色；上表面锈琥珀色，内侧腹羽形成黑色和深红色线条，展示时形成双色线；虹膜深棕色；喙淡蓝白色，几乎纯白；腿紫灰色。雌鸟较小，缺乏延长的羽毛，上体类似雄鸟但较暗，下体棕褐色，喉部黑色渐变至暗肉桂色，有轻微的黑色斑点。","call":"雄鸟的广告鸣叫为‘kwank’，类似但音调更低更似钟声；还有高音调、钟声般的上升音符，随后是一系列硬下降音符‘kouwi-carr-carrr-carr-carr...’；以及缓慢节奏、哀婉的下降音符系列‘wahr, wahr, wahr, wahr, wahr, wahr’，比同类更高音和鼻音。还发出下降的‘we wah wah wah wah wah weh weh weh’音符序列，每个音符上升，重复响亮、鼻音的‘quoi’，一系列几个音调升高的高音符，以及单独的‘quaa’或‘kwaa’音符。展示时，倒挂的雄鸟会发出节奏混合的低鼻音叽叽喳喳声和‘caw’音符，有时伴有奇怪的颤动音，变成快速节奏的嗡嗡声，像电动机一样。","habits":"蓝极乐鸟栖息于海拔1100至2000米的中低山森林、森林边缘和较密的老次生林；主要分布在海拔1400至1800米之间。成年雄鸟倾向于在海拔范围内活动，年轻雄鸟在上部和下部区域。它们主要以果实为食，尤其是无花果、核果和浆果，也吃一些动物，主要是节肢动物，可能还包括蜥蜴。在寻找果实时会在高树冠觅食；当寻找节肢动物时，也会在森林较低处活动，通过刮擦树皮获取食物。雄鸟通常独自行动，但在果实丰富的树冠中可能会与其他雌鸟外观的个体和其他极乐鸟物种一起。雌鸟会保卫食物资源（果实）。","breeding":"繁殖季节在物种分布范围内全年都可能发生，主要集中在7月至2月；4月产卵，11月至12月育雏，12月中旬可以看到刚离巢的小鸟被责备的父母照顾；在西北部范围内的展示活动主要在4月至11月底。雄鸟是多配偶制，独居的雄鸟在传统高位唱歌展示，雌鸟单独筑巢和照料巢穴。雄鸟在距离地面1至3米的瘦枝、竹子、草或藤蔓茎上展示，周围有直接上方的树叶遮盖；雄鸟会清除展示枝周围的叶子；相邻的两个成年雄鸟相距约300米。求偶展示仅包括倒挂静态展示，缺乏收敛展示和仪式化的交配序列。巢由长而柔韧的绿色兰花茎、面包树叶、棕榈叶纤维、木麻黄针叶和少量其他叶子构成，内部铺有柔韧的木质细藤，可能来自藤蔓，建在4至19米高的地面，地点多样，从低灌木到高次冠层树。每窝产1枚蛋，偶尔产2枚；孵化期超过18天；亲鸟对近巢的同类和其他极乐鸟物种表现出攻击性；关于雏鸟期的持续时间没有信息。","identification":"蓝极乐鸟雄鸟与雌鸟在外形上有明显区别，雄鸟有独特的长尾流苏和色彩斑斓的羽毛，而雌鸟较为暗淡，呈褐色。与同类相比，蓝极乐鸟的体型较大，且雄鸟的炫耀性羽毛和叫声是识别的重要特征。与其他极乐鸟的区别在于其特有的羽毛颜色和展示方式。","protection":"IUCN：NT（近危）","distribution":"蓝极乐鸟主要分布于新几内亚东部的中央山脉，即澳新界新几内亚中部和东南部。"},{"name":"地丛鹟","english_name":"Ashy Robin","scientific_name":"Heteromyias albispecularis","overview":"地丛鹟（英文名：Ashy Robin，学名：Heteromyias albispecularis），是雀形目鸲鹟科异鸲鹟属的鸟类。原生于新几内亚的山地森林中。其特征包括灰白的下体、粉红色的腿、翼上的模糊白色标记和眼下的明显白色斑点。鸣唱由一系列相同音调的笛声组成，节奏变化不定。","appearance":"成年地丛鹟体长15至18厘米，体重28至37.5克。喉部至脸颊前部为白色，头部其余部分为暗灰色，后颈稍淡，上体橄榄灰色；飞羽深褐色，除最外侧三枚初级飞羽和最内侧次级飞羽外，其余飞羽边缘呈橄榄棕色，这些飞羽的外缘基部为黑色，形成翼折时的白色斑块；尾羽深褐色，腹面白色，两胁及下尾覆羽锈橄榄色；虹膜深棕色；喙橄榄棕色，尖端较浅；腿粉色至淡灰白色。雌雄相似。幼鸟头部和身体大部分为赤褐色，下体较浅；不成熟个体类似成鸟，但部分上翼大覆羽尖端为赤栗色，喙淡色基部较深。","call":"鸣唱为一系列短促、铃铛般的音符，音量稳定，音高恒定。叫声为歌曲的缩短版（2至5个音符），报警声为“kak-kaktak-kak”。另有3至4个清晰、高音的上升哨声“yo-ba-go”，和柔和的哨声“ee-ya ee-ya-weee”，以及“who-he”，首音节低于次音节。","habits":"栖息于海拔1400至2400米的山地森林，偶尔低至850米。以昆虫为主食，包括甲虫、蚂蚁、竹节虫、蜈蚣和蚯蚓。常在灌木层和地面活动，觅食方式包括拣食和低植被的快速突袭。","breeding":"繁殖季节早期为12月初，孵化期在6月第三周。已知巢穴仅两个，由藤蔓和细根构成，外表面覆盖苔藓和地衣，内部衬有藤蔓和深色细根，位于树蕨顶部约1米处，有时悬挂在巢下有多数枝条或兰花茎。每次产一枚蛋，蛋壳颜色为淡黄白色，散布着淡棕色和灰色斑点，较大的一端有棕色灰色斑点环绕的橙棕色污渍。","identification":"与黑顶丛鹟的区别在于后者冠部和耳羽为黑色而非暗灰色，眼后超眉纹为白色而非中灰色，翼上的白色斑块更为显眼，上体更呈橄榄绿色，鸣唱为一系列快速单调的中至高音哨声，节奏不均匀，而地丛鹟的鸣唱为一系列相同长度和振幅的音符，节奏稳定。","protection":"IUCN：LC（无危）。地丛鹟在当地数量较为常见，特别是在库马瓦山脉，但有时也会稀少，偶尔在看似适宜的地区缺失。种群规模未知，但相信物种目前没有立即面临风险。","distribution":"分布于新几内亚西北部的塔姆劳山脉、阿尔法克山脉和库马瓦山脉；福贾山脉的种群可能也是此物种。在澳大利亚和新西兰界，主要见于鸟头半岛山区和Neck（新几内亚西北部）。","other":"直到最近，地丛鹟被认为与黑顶丛鹟同种，但现在它们被认为是不同的物种。"},{"name":"灰头丛鹟","english_name":"Grey-headed Robin","scientific_name":"Heteromyias cinereifrons","overview":"灰头丛鹟（英文名：Grey-headed Robin，学名：Heteromyias cinereifrons），是雀形目鸲鹟科异鸲鹟属的大型鸟类，主要分布在澳大利亚东北部的昆士兰中东部地区，包括卡德尔威尔至布卢姆菲尔德河一带的远北昆士兰高山区。","appearance":"灰头丛鹟体长约18.5-20厘米，体重31-40克。头部灰色，颈背橄榄棕色，有宽阔的灰色眉纹，耳羽前部黑色，后部灰色。上体橄榄棕色，翼暗橄榄灰色，具白色翼斑。下体白色至淡灰色，腹部偏白，两胁和腹侧带橄榄色，尾基部红棕色渐变至橄榄棕色。喙和眼深褐色，腿粉灰色。雌雄相似，幼鸟体色较暗，翼羽缘红棕色。","call":"发出单调重复的哨声，音调平稳，后接2到3个较短的低音。雄鸟喂食时发出‘cheep’声，雌鸟以‘chuck’声和叽叽喳喳的声音回应。","habits":"栖息于蒙特雷雨林地带，主要在地面觅食，超过92%的时间在落叶层中寻找昆虫和其他无脊椎动物，偶尔也会从高处扑向猎物，或在树干和高枝上觅食。","breeding":"繁殖季节从8月至次年1月，每季可育一到两窝。巢为浅杯状，由树皮、草和干叶构成，外部装饰有干枯植被，内部用蕨类和棕榈条铺垫。巢通常置于律师藤上，离地高度可达10米。每次产卵1-2枚，蛋呈奶油色或暗绿色，带有淡褐色斑点，尺寸约26x19毫米。","identification":"灰头丛鹟的灰顶、橄榄色背部、白色翼斑和独特的站立姿态使其容易与其他物种区分开来。与地丛鹟相比，其体型更大，头部颜色更灰。","protection":"IUCN：NT（近危）","distribution":"澳大利亚东北部，具体分布于昆士兰中东部的高地，从Mount Amos南部至Mount Spec。","other":"曾与地丛鹟视为同一物种，现确认为独立物种，属于异鸲鹟属的两个成员之一。"},{"name":"黑顶丛鹟","english_name":"Black-capped Robin","scientific_name":"Heteromyias armiti","overview":"黑顶丛鹟（英文名：Black-capped Robin，学名：Heteromyias armiti），是雀形目鸲鹟科异鸲鹟属的鸟类。原被归类于地丛鹟，现独立为一物种。广泛分布于新几内亚的中西部、中东部及东北部山区森林。","appearance":"该鸟中等体型，背部呈褐色，腹部淡灰色，最显著的特征是黑色的头部，头顶至眼后有一条宽大的白色线条，这一特征区别于其他类似物种。雌雄及幼鸟的具体差异尚未详细描述。","call":"其鸣声由一系列相同的音符组成，但节奏不规则，类似莫尔斯电码，形成独特的声音模式。","habits":"栖息于湿润的山地森林环境中，具体的生活习性如活动范围、觅食方式及食物来源等细节需进一步研究。","breeding":"关于繁殖行为、巢穴构建、交配、产卵及育雏等生长繁殖方面的信息尚不详尽，有待更多观察记录。","identification":"与白眼丛鹟相比，黑顶丛鹟拥有暗色的眼睛和一条延伸至眼底的白色标记，这成为区分两者的重要依据。","distribution":"分布于新几内亚的山区，具体涵盖中西部、中东部及东北部地区。"},{"name":"白胸杂色鹟","english_name":"Black-chinned Robin","scientific_name":"Poecilodryas brachyura","overview":"白胸杂色鹟（英文名：Black-chinned Robin，学名：Poecilodryas brachyura），是雀形目鸲鹟科杂色鹟属的中等体型的林鸟。显著特征为黑色上身、头部及狭窄的下巴带，白色下体，突出的白色眉纹和翼斑。分布于新几内亚的低地和山麓森林内部，常见于西北部和北部，海拔高度可达650米。","appearance":"体长约14至15厘米，重约25克。具有宽大的白色眉纹，从眼睛前方延伸到颈侧。头顶和头部侧面黑色，上体深灰色，翅膀和尾巴黑色，内侧主翼羽和次级飞羽的外缘有白色斑块，形成折叠翼上的横带和飞行中的宽条纹。下巴黑色，喉咙和腹部白色。虹膜深棕色，喙黑色，腿呈淡褐色。性别相似。幼鸟描述不详，可能比成鸟更偏褐色。亚种albotae­niata颜色更深，黑色下巴斑较小；dumasi亚种与指名亚种类似，但上体黑色。","call":"鸣声高亢、响亮而尖锐，由2至3个短促的哨音组成，最后一个音符低于前几个。类似于扇尾杜鹃的鸣声。","habits":"常栖息于低地和山麓森林的下层和中层，活动范围限于热带湿润森林，可能为留鸟。以昆虫为食，通过空中捕虫的方式觅食。","breeding":"已知的繁殖信息有限，曾在一个可能的巢穴中发现一枚单个带有丰富红褐色斑点的白色蛋，位于新几内亚Cyclops山脉自然保护区。","identification":"与黑侧鹟非常相似，但黑颚莺缺乏胸部两侧的黑色，眉纹更宽，下巴黑色。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的西北部和北部，主要在西巴布亚，仅少量分布于巴布亚新几内亚的西北部，从海平面至650米的高度。","other":"关于其一般生物学和生态学的知识相对匮乏。"},{"name":"黑白杂色鹟","english_name":"Black-sided Robin","scientific_name":"Poecilodryas hypoleuca","overview":"黑白杂色鹟（英文名：Black-sided Robin，学名：Poecilodryas hypoleuca），是雀形目鸲鹟科杂色鹟属的鸟类。特征为上体、头部和胸部侧面呈黑色，下体白色至喙部，眼上有细白眉纹，眼下方有楔形白斑，翼上有白色斑块。分布广泛，主要栖息于新几内亚的低地和山脚森林，常隐匿于树荫下。","appearance":"中等体型，体长13-15厘米，体重约18克。头部、颈部、背部、翅膀和尾巴为黑色或暗褐色，翼上近基部有宽大的白色斑块，形成明显的条纹。下体白色，胸侧有黑色斑块。眼睛深棕色，喙黑色，腿灰色或粉红色。雌雄相似，幼鸟呈淡褐色，下体白色。","call":"叫声独特，通常听到‘wee-chow！’声，第二音节带有爆发性。歌声由4个短促的哨音组成，先升后降，类似‘ti-tu-tu tu’。","habits":"栖息于低地雨林和沼泽森林，偏好有莎草榈（Metroxylon）的环境，偶尔出现在次生林中。主要在低地活动，但在无竞争物种的情况下可上至海拔750-1200米的山区。以昆虫为食，常在下层林木或地面捕食，采用扫视捕捉或空中捕食的方式。","breeding":"繁殖季节报道为9月至次年1月，有记录显示雏鸟在12月末出现。雄鸟在5月进入繁殖状态，雌鸟在4月刚结束产卵，暗示繁殖也可能发生在干季后期。具体繁殖行为信息缺乏。","identification":"与白胸杂色鹟非常相似，但黑白杂色鹟胸侧有黑色斑块，白眉更窄。两物种在某些区域共存。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚，从休恩半岛向西延伸至西巴布亚及周边岛屿，但在南端的Transfly地区未见分布。","other":"在古希腊语中，属名Poecilodryas意为‘杂色的森林女神’，种名hypoleuca意为‘微白’。"},{"name":"白眉杂色鹟","english_name":"White-browed Robin","scientific_name":"Poecilodryas superciliosa","overview":"白眉杂色鹟（英文名：White-browed Robin，学名：Poecilodryas superciliosa），是雀形目鸲鹟科杂色鹟属的鸟类。以其显著的白色眉纹而得名。这种小型圆形鸣禽主要栖息于澳大利亚东北部的热带雨林和溪流旁的茂密植被中。具有灰褐色的上体，白色的下体，以及独特的黑色耳羽和翼尾上的白色标记。白眉杂色鹟的分布局限于昆士兰州北部和东北部。","appearance":"白眉杂色鹟体长约14至16厘米，体重介于15.5至22克之间。最显著的特征是其宽大的白色眉纹，从喙基延伸至颈背，配合着烟灰色条纹从眼窝至颈侧。头部和颈后橄榄棕色至灰棕色，上体呈深橄榄棕色。翅膀和尾巴也是深橄榄棕色，翼上有白色斑块和边缘，尤其在内侧初级飞羽和次级飞羽上可见，次级飞羽的覆羽有白色尖端，形成Y形翼带。尾巴除中央一对羽毛外，其余均广泛地以白色尖端结束。下体白色，胸侧带有淡灰色晕染，颈部侧面的羽毛向上卷曲在耳羽后方。虹膜深棕色，喙黑色，腿暗灰色。雌雄相似，幼鸟体色偏红，翼和尾部特征与成鸟相似。","call":"白眉杂色鹟的鸣唱包括一种哨声似的‘tit-toe-ee-toe-ee tit-toe’，以及接触时拉长的哨音和报警时的喋喋不休的音节。叫声中还包括快速三音的‘zap-zap-zap’，如同电流般急促。","habits":"白眉杂色鹟主要栖息于雨林、雨林与相邻桉树（Eucalyptus）林地的过渡地带、河流边的植被，包括扇棕榈和竹子，藤本灌木，以及茶树（Leptospermum）沼泽。它们从海岸到山脚均有分布，通常为定居状态，标记的个体回收距离不超过10米。主要以昆虫和其他小节肢动物为食，偶尔也会吃种子。觅食主要在地上，从高处的栖木上扑向猎物；也会在树叶和树干上觅食。有时会进行飞捕。","breeding":"繁殖季节从7月至次年1月，每季可能产一到两窝。独居繁殖，领域性明显。筑巢由雌鸟完成，巢为杯状，由根须、藤蔓和树皮条编织而成，外部有时装饰有苔藓，内部铺垫有根须、藤蔓、植物纤维和草，通常位于树、灌木或藤本缠结的密集植被中的薄水平或垂直叉枝上，距地面1至11米（通常约3米）。每次产1至2枚蛋，颜色为浅绿或蓝绿色，带有棕色和灰色的斑点和斑块，平均尺寸为19.7×14.4毫米。孵化由雌鸟负责，持续16天。雏鸟由双亲共同喂养，9天后离巢；若有两只雏鸟，则每只雏鸟由一位父母单独照顾。已知最长寿命为8年11个月。","identification":"与白眉杂色鹟相似的物种有棕胁杂色鹟，后者具有橙色的胁部和下尾部（注意分布范围差异）。白眉杂色鹟的白色眉纹和翼尾上的白色标记是其辨识的关键。","protection":"IUCN：LC（无危）。普遍常见，但分布零散；与河岸植被密切相关。","distribution":"主要分布在澳大利亚东北部，从昆士兰州的约克角半岛南至伯德金河区域。","other":"白眉杂色鹟曾将棕胁杂色鹟作为其亚种之一。"},{"name":"棕胁杂色鹟","english_name":"Buff-sided Robin","scientific_name":"Poecilodryas cerviniventris","appearance":"棕胁杂色鹟体长约16至18厘米，雄鸟体重20至25克，雌鸟15.5至20克。头部和颈部呈深色，具显著的白色眉纹，耳羽黑色，脸颊白色，喉部白色，翼部和尾部有白色斑点。胸部有灰色调，腹侧、两胁和下尾覆羽呈肉桂色。雄鸟和雌鸟在外表上相似，但雄鸟通常体型较大。幼鸟体羽呈锈褐色，翼部和尾部与成鸟相似，但更浅色。","call":"其鸣声包括愉快的重复柔和哨音，通常由3至5个音符组成，以及尖锐的哨鸣叫声。","habits":"栖息于密集的沿河植被，包括竹丛和季风雨林，偏好低地环境。以地面昆虫为主要食物来源，通过从观察点飞扑捕捉猎物。偶尔也会在空中捕捉飞行昆虫或从树干和树叶上觅食。","breeding":"繁殖季节为10月至次年3月，可能有1至2窝。雌鸟单独筑巢，巢为编织杯状，用根须、藤蔓和树皮条制成，内部铺有根须、藤蔓、植物纤维和草。每窝产2至3枚蛋，蛋壳黄绿色带红棕色斑点，平均尺寸为19×14.3毫米。孵化和育雏期的具体时长未知，但与白眉杂色鹟类似（分别为16天和9天）。","identification":"与白眉杂色鹟相比，棕胁杂色鹟体型更大，有更宽的白色眉纹，上背部颜色较暗，脸部有宽黑带，胸部呈灰色，翼部有更宽的白色条纹，两胁至橙色，尾羽末端全都有白色。","protection":"IUCN：LC（无危）","distribution":"分布于西澳大利亚北部至昆士兰州西北部，包括金伯利地区、北领地的顶端地区至卡奔塔利亚湾西北部。具体包括西澳大利亚州的中央金伯利、北部金伯利和奥德维多利亚平原等生物区域，北领地的维多利亚邦帕特、达尔文沿海、阿纳姆海岸等区域，以及昆士兰州的格雷戈里河、劳恩山国家公园等地。"},{"name":"黄绿杂色鹟","english_name":"Banded Yellow Robin","scientific_name":"Gennaeodryas placens","overview":"黄绿杂色鹟（英文名：Banded Yellow Robin，学名：Gennaeodryas placens），是雀形目鸲鹟科Gennaeodryas的特有种。仅见于新几内亚的特定山地森林中。其特征为橙色腿脚，灰头灰翅，橄榄色背部及胸带，腹部亮黄，喉部有不完整的环状领。此鸟以低处停歇并扫描林地而闻名。","appearance":"中等体型，长约14至15厘米，重24至28克。头部深灰色，上体橄榄绿色；翅膀暗褐色，翼羽边缘橄榄绿，尾羽暗褐；喉部及胸部上方暗灰，侧面及下体亮黄色，胸部具暗橄榄绿横带；眼睛深棕色，喙黑色，腿脚浅黄至橙色。雌雄相似，幼鸟全红棕色。","call":"鸣唱由一系列哨音组成，“pwip! pyuu-pyuu-pyuu-pyuu-pyuu”，首音上升，随后有间隔，再连续发出相同的音节。","habits":"栖息于海拔100至1450米的原始山地森林，偏好阴暗、底层相对开阔的环境。似乎为留鸟，以昆虫为食，通常在地面0.6至1.5米处捕食，偶尔低飞捕食。飞行时从栖处扑向地面或落叶堆捕食猎物。","breeding":"繁殖资料有限，巢为浅碗状，由寄生植物根和其他植物材料精细编织，外部覆有苔藓，置于低层树木或幼树侧枝0.75至2.1米高处。7月时发现有扩大的生殖腺，幼鸟出现在6月至7月。","identification":"与绿背鹟和白脸鹟相比，后者脸部有白色斑纹。叫声独特，为五声钟铃般的音符。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的零散局部地区，包括Batanta岛、Wandammen山脉、Bomberai半岛、Weyland山脉、Astrolabe湾、L Kutubu、Mt Bosavi、Karimui等地。在Batanta岛海拔850至880米，Wandammen山脉710至1450米，Weyland山脉300至1000米，Angabunga河至Goldie河区域100至350米。","other":"黄绿杂色鹟是西巴布亚低地、北巴布亚低地、南巴布亚低地和东南巴布亚低地次要区域的限制范围物种。虽然分布零星，但在某些地区较为常见，有时在其海拔范围内是最常见的鹟科鸟类。"},{"name":"黑喉杂色鹟","english_name":"Black-throated Robin","scientific_name":"Plesiodryas albonotata","overview":"黑喉杂色鹟（英文名：Black-throated Robin，学名：Plesiodryas albonotata），是雀形目鸲鹟科Plesiodryas的中型鸟类。以灰蓝色上体、黑色脸部和喉部以及独特的白色颈侧斑纹著称。广泛分布于新几内亚中部山地的湿润森林中，海拔高度约1150至2750米。","appearance":"体长约18至19厘米，体重约38至43克。成鸟具有深蓝灰色的头部和背部，脸部、喉部及上胸部黑色，颈侧有明显的白色斜向标记。腹部在中心区域呈灰色，而在鸟头半岛和新几内亚东南部地区则为白色。幼鸟全身羽毛呈淡肉桂色，仅颈部有白色标记。雄雌相似。","call":"叫声为高音的口哨声，可为单一音符或一系列模糊的相似音符组成。","habits":"常出现在较高林层，偶尔会降至较低层次，活动高度通常在离地面6至20米之间。主要通过空中捕食昆虫（约占80%）和从植被上拾取（约占20%）的方式觅食。","breeding":"未提供具体繁殖信息。","identification":"与蓝灰色杂色鹟颜色相似，但体型更大，拥有黑色喉部。与黑腹蝉鸟颜色模式相近，但体型明显更大。幼鸟和亚成鸟的肉桂色外观使其容易识别。","protection":"IUCN状态未知。","distribution":"分布于新几内亚的山地雨林，从西部的鸟头半岛到东部的休恩半岛，海拔1800至2750米。","other":"物种历史系统学未详述。"},{"name":"白翅薮鹟","english_name":"White-winged Robin","scientific_name":"Peneothello sigillata","overview":"白翅薮鹟（英文名：White-winged Robin，学名：Peneothello sigillata），是雀形目鸲鹟科薮鹟属的鸟类。体型较小的上高山森林鸟类，通体黑色，翼上具醒目的白斑，是巴布亚新几内亚中部与东北部高海拔地区的特有种。其显著特征为黑色羽毛与白色翼斑形成的强烈对比，活动于海拔2400–3900米的苔藓森林及灌丛，以昆虫为主食，繁殖期集中于干季末至湿季初。","appearance":"体长14–15厘米，体重21–28克。成鸟头、颈、体背至尾羽均呈丝绒般的黑色；飞羽褐黑，三级飞羽白色而端部黑色，形成显眼的翼上白斑；中、小覆羽亦黑；虹膜深褐，嘴与脚全黑。雌雄同色。幼鸟全身暗褐，腹面略淡，体羽及翼覆羽具淡黄褐或橄榄褐的羽干纹；亚成鸟仍保留部分幼羽。亚种quadrimaculata体型最小，三级飞羽的黑端更宽；hagenensis三级飞羽无黑端；quadrimaculata胸侧各具一白斑，为易辨识特征。","call":"鸣唱为缓慢、管笛般的颤音，音调时升时降。常见叫声包括快速的高音下滑颤音、尖锐的警戒声，以及在追逐时发出的细薄金属音。","habits":"栖息于海拔2400–3900米的苔藓森林及其毗邻灌丛，局部可下延至2150米，低海拔区域由蓝灰薮鹟取代。留鸟，无明显迁徙。主要活动于森林下层，常停栖于低处的垂直苔藓树干上，俯视地面搜寻猎物。觅食方式以空中飞捕为主（约占80%），辅以枝叶间啄取（约20%）；猎物60%取自地面，40%取自林下植被。食物以昆虫为主，偶食果实和种子。","breeding":"繁殖期至少从干季末持续到湿季初：9月末巢中见雏鸟，10月末巢中同时见卵与雏鸟，翌年1月末见具依赖性的离巢幼鸟。巢为大型松散结构，由鲜绿苔藓及细根编织，内衬薄膜蕨干茎及细枝，置于树杈间。每窝通常仅1卵，偶见2卵；卵淡橄榄色，稀疏散布棕褐斑，钝端具褐色帽斑。孵化期及育雏期尚无记录。","identification":"与低海拔分布的白腰薮鹟外观相似，但二者海拔带不重叠；与草地栖的白斑黑石䳭亦似，然白翅薮鹟栖于森林且缺少白腰。亚种间辨识：quadrimaculata胸侧具白斑；hagenensis与quadrimaculata三级飞羽均无黑端，但后者胸侧白斑明显；saruwagedi体型较小，黑端略宽。","protection":"IUCN: LC（无危）","distribution":"繁殖区：新几内亚中部与东南部山脉（Schrader山脉、俾斯麦山脉、Kubor山脉）；中央新几内亚山地（Mt Antares至Mt Hagen）；Huon半岛山地；以及西部Nassau山脉与Oranje山脉。非繁殖区：无迁徙记录，全年留居繁殖地。"},{"name":"灰薮鹟","english_name":"Smoky Robin","scientific_name":"Peneothello cryptoleuca","overview":"灰薮鹟（英文名：Smoky Robin，学名：Peneothello cryptoleuca），是雀形目鸲鹟科薮鹟属的小型山地森林鸟类。体型较小的山地林栖鸟类，整体呈板岩灰色，腹部稍淡，翅尾近黑，常低栖于斜枝或覆苔树干上，摆尾并俯视地面搜捕昆虫。其分布局限于新几内亚西北至中部海拔1400–2500米的山地森林，与蓝灰薮鹟呈垂直替代分布。","appearance":"体长约14.5厘米，体重18–20克。成鸟雌雄同色：头顶蓝灰，上体煤灰色；飞羽与尾羽黑色；下体淡板岩灰；腋羽蓝灰；初级飞羽基部内侧下表面白色，形成小翼下白斑；虹膜暗褐；喙与脚黑色。亚种albidior腹部更淡，呈灰白；亚种maxima体型更大，下体近白，腋羽灰白相间。幼鸟尚无描述。","call":"鸣声为上扬且逐渐减速的哨音颤音；叫声为单声或连续的“chip”。","habits":"栖息于山地森林、灌丛及林缘，海拔1400–2500米。与蓝灰薮鹟同域分布时呈海拔替代：本种占据较高海拔，过渡带在Gauttier山约1415米、Weyland山约2400米。推测留鸟。以昆虫为食，在林下近地面至5米高的灌丛中觅食。","breeding":"1–2月曾见成鸟携带幼鸟，其他繁殖信息缺乏。","identification":"与蓝灰薮鹟极为相似，但灰薮鹟羽色不泛蓝，腹部更淡，黑色飞羽对比度较低。亚种间差异：albidior腹色更淡；maxima体型大，下体近白。","protection":"IUCN: LC（无危）。虽为全球非受威胁的狭域种，见于西巴布亚高地及中部巴布亚山脉EBA，但资料匮乏，种群状况尚不明确。","distribution":"繁殖与居留区域一致。指名亚种分布于新几内亚西北的Vogelkop（Tamrau山、Arfak山）及北部Foja山；亚种albidior分布于中西部新几内亚的Weyland山、Gauttier山、Nassau山；亚种maxima分布于Bomberai半岛西部的Kumawa山。","other":"分类上曾被置于Pogonocichla，与蓝灰薮鹟关系密切，二者有时并入独立属Papualestes。"},{"name":"蓝灰薮鹟","english_name":"Slaty Robin","scientific_name":"Peneothello cyanus","overview":"蓝灰薮鹟（英文名：Slaty Robin，学名：Peneothello cyanus），是雀形目鸲鹟科薮鹟属的鸟类。分布于新几内亚高山区及北部稀疏地带。其自然生境为亚热带或热带湿润山地森林。","appearance":"成鸟体长约14至15厘米，体重约24至30克，全身覆盖均匀的蓝灰色羽毛，腹部略浅，面颊部稍暗。翅膀和尾巴呈深灰色至黑色，喙、脚为黑色，虹膜为深棕色。雌雄外观相似。幼鸟体羽和翼覆羽为板岩色，带有淡色轴纹和锈褐色尖端。","call":"鸣唱由12个音乐性的哨音组成，起始于相同的音调，随后逐渐升高并加速。叫声包括响亮的、无旋律的三音节短语，重复多次，前有一到两个音符，以及快速的‘teeder-teeder-teeder-teeder-teeder’系列，每对音符中的第一个音调比第二个更高。","habits":"栖息于海拔约900至2750米的山地森林及其相邻的次生植被中，主要活动于1500至2500米的高度。以昆虫为食，包括蚂蚁、象鼻虫和其他小甲虫以及Thyonnid胡蜂。在灌木层和地面觅食，偶尔上升至5米高度。","breeding":"巢为深杯状，由根须构成并衬以苔藓，通常位于树叉上，离地面约6米。产卵数为1至2枚，蛋壳呈淡绿色或橄榄色，点缀着橄榄绿或棕色斑点，尺寸约为23.5 毫米x 17–19 毫米。","identification":"与灰薮鹟非常相似，但蓝灰薮鹟的灰色带有明显的蓝色调，腹部颜色较一致，且翅膀的对比更加明显。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚山脉的高海拔地区，从海拔900至2750米，主要活动于1500至2500米的高度。"},{"name":"白腰薮鹟","english_name":"White-rumped Robin","scientific_name":"Peneothello bimaculata","overview":"白腰薮鹟（英文名：White-rumped Robin，学名：Peneothello bimaculata），是雀形目鸲鹟科薮鹟属的鸟类。尾基部上下均为白色。腹部颜色随地域而异，多数地区为白色，东北部则为黑色。","appearance":"成年雄性白腰薮鹟长13至14厘米，体重20至27克，全身黑色，除尾羽上方覆羽及下喉侧至胸侧有白色带，腹部白色；雌鸟相似，但黑色部位略带棕色；幼鸟呈烟黑色，部分上翼覆羽略显棕色，下尾覆羽尖端白色。vicaria亚种与指名亚种的区别在于腹部黑色。","call":"鸣唱由4至6个短促的哨音组成，先以一个较高的音调开始，随后是一系列中音的铃声般的音符。","habits":"栖息于新几内亚的山地森林中，海拔高度从300米至1700米。通常成对出现在雨林的林下层或地面，以昆虫为食。","breeding":"关于生长繁殖的具体信息未详述。","identification":"与白斑黑石䳭极为相似，但白腰薮鹟的白色斑点位于肩前而非肩部，且栖息于森林而非草地。","protection":"IUCN状态未知。","distribution":"主要分布在新几内亚的高海拔地区，包括南部山脉沿线以及Huon半岛和Adelbert山脉。"},{"name":"红树鸲鹟","english_name":"Mangrove Robin","scientific_name":"Peneothello pulverulenta","overview":"红树鸲鹟（英文名：Mangrove Robin，学名：Peneothello pulverulenta），是雀形目鸲鹟科薮鹟属的鸟类。体型圆润，栖息于密集的红树林区，尤其偏好大型红树林中的高跷根部。其名称来源于它独特的自然栖息环境。分布于新几内亚沿海及澳大利亚北部。","appearance":"红树鸲鹟身长14至15厘米，体重18至24克。成鸟头侧黑色，耳羽暗烟灰色；头顶至臀部呈暗烟灰色，尾上覆羽黑色；翅膀棕色偏黑，近基部有一小而不显眼的白色斑点；尾羽黑褐色，除中央尾羽外，其余尾羽基部白色；下巴、脸颊和喉咙白色，胸至胁部带灰白色调，腹部及尾下覆羽白色。虹膜深棕色，喙和腿黑色或深灰色。雌雄外观相似。幼鸟头部及背部暗棕色，具浅色轴纹，翅膀覆羽末端暗黄褐色，下体灰白色，喙角褐色；亚成鸟与成鸟相似，但翅膀覆羽和次级飞羽边缘较淡。","call":"叫声为缓慢、哀怨的哨音，通常重复，由1至3个优美而略带哀愁的低音符组成，‘pyu’或‘pupyu’；其他声音包括悦耳的颤鸣、尖锐的‘chack’声和轻柔的叽喳声。","habits":"栖息于海岸及近岸红树林，有时进入新几内亚的亚沿海纸皮树沼泽及内陆的河边芦苇丛。仅在海平面附近活动。红树鸲鹟是留鸟，以昆虫、甲壳类和其他小型无脊椎动物为食，主要在地面觅食，从高处俯冲捕捉猎物。","breeding":"在新几内亚，繁殖期跨越湿季和旱季，主要在9月至次年2月。巢由雌鸟建造，是一个紧致的杯状结构，由树皮和干草构成，用蜘蛛网固定，外部装饰有垂直悬挂的树皮条，内部铺垫细根、草和其他精细植被。巢置于红树林分叉处或树枝基部，离地面1至4.5米。每窝产2枚蛋，偶尔3枚，橄榄绿或淡黄绿色，较大端有暗红色斑点，平均尺寸20.1×15.6毫米。雌鸟孵卵，两性共同喂养和照顾幼鸟，孵化和育雏期的具体时间未知。","identification":"红树鸲鹟与其他白颏鸟类物种（如雌性辉阔嘴鹟）相比更为圆胖。头侧黑色，耳羽暗烟灰色，翼上有细微的白色斑点，尾羽基部白色，是识别的关键特征。","protection":"IUCN：LC（无危）","distribution":"广泛分布于新几内亚沿岸，局部地区常见至普通；澳大利亚北部局部地区常见。分布于澳大利亚北部地区和新几内亚沿海。"},{"name":"白脸歌鸲鹟","english_name":"White-faced Robin","scientific_name":"Tregellasia leucops","overview":"白脸歌鸲鹟（英文名：White-faced Robin，学名：Tregellasia leucops），是雀形目鸲鹟科歌鸲鹟属的鸟类。小型鸣禽，以其独特的黑头、白脸和鲜亮的黄色下体而闻名。分布于新几内亚和澳大利亚东北部的约克角半岛，偏好热带雨林环境。","appearance":"体长约11.5至14.5厘米，体重15.3至19.4克。头部黑色，脸部白色，上体橄榄色，下体黄色明亮。成年鸟具白色眼斑，黑色眼纹，耳羽暗灰色，头顶深灰，颈侧和后颈淡灰，翼上覆羽橄榄绿，飞羽橄榄棕，尾羽橄榄棕色，尾羽尖端微黄。嘴黑色，腿橙黄色。两性相似，幼鸟身体锈褐色，翼上覆羽有浅色边缘。不同亚种在头部图案和喙色上有差异。","call":"鸣声为一连串短促而尖锐的哨音，包括三连音节的哨声，中间音调最高，随后是两个逐渐升高的音符。","habits":"栖息于新几内亚的橡树和南洋杉森林，海拔300至2200米，澳大利亚则见于热带雨林和藤蔓丛生地带。主要以昆虫和其他小节肢动物为食，偶尔吃种子。觅食时在植被低层活动，通过扑击、掠取等方式捕捉猎物。","breeding":"筑巢由一对中的一个成员，可能是雌鸟，使用细植物纤维和树皮条编织成杯状巢，外部加固，内部铺垫精细材料，巢高6.4至7.6厘米，直径5.7至7厘米。每窝产2枚蛋，淡绿色带棕色和灰色斑点。繁殖季节在新几内亚主要在旱季中期，澳大利亚则在9月至次年1月，或更早，有两个高峰（8月至10月和1月）。","identification":"与黄胸船嘴鹟区别在于较长的尾巴、白色的翼条和黄色的眉纹。不同亚种在外观上有细微差别。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚和澳大利亚的约克角半岛东北部，澳大利亚分布限于热带雨林和低山区域。"},{"name":"淡黄歌鸲鹟","english_name":"Pale-yellow Robin","scientific_name":"Tregellasia capito","overview":"淡黄歌鸲鹟（英文名：Pale-yellow Robin，学名：Tregellasia capito），是雀形目鸲鹟科歌鸲鹟属的鸟类。特征为橄榄绿色背部，灰色头部，黄色下部，白色嘴基周围。分布于澳大利亚东部的热带雨林区域，特别是在律师藤丰富的地方。该鸟种分为两个亚种，北昆士兰的较小亚种nana和东南昆士兰及新南威尔士东北部的较大且较罕见的指名亚种capito。","appearance":"体长12至13.5厘米，体重14.5至16克（capito亚种），12至14.5克（nana亚种）。头部侧边和额头呈灰白色，脸部灰色，眼圈淡黄褐色，耳羽深灰；头顶、颈背暗灰，融入灰橄榄色上体；翼橄榄棕色，初级飞羽和内侧次级飞羽上有浅色条纹；尾橄榄棕色，新鲜羽毛时末端有浅色边缘；喉部白色，上喉柠檬黄，其余下体淡柠檬黄色，胸腹两侧及两胁微染橄榄色；虹膜深褐色；喙黑色；腿橙粉色。性别相似。幼鸟体羽红褐色，腹部较淡，头部有散落的浅色条纹，翼覆羽边缘红褐色；亚成鸟类似成鸟，但翼覆羽边缘红褐色。","call":"鸣唱为一系列从中音到高音的尖叫声，'see-see-see-see-see-see'，速度、音调和音量逐渐增加。接触叫声为柔和的颤音；警报声为刺耳的责骂声；还有双音节的尖叫声和柔和的'soo-soo-soo'。","habits":"栖息于雨林和相邻的茂密、湿润桉树林，海拔从海平面到1500米，低海拔更为常见。全年定居，年轻个体离巢后约分散500至600米，标记个体的全部回收均在首次环志地点10公里以内。以昆虫和其他小型无脊椎动物为主食，偶尔食用种子；主要在地面捕食，从树上扑向猎物，通常低于10米，更常低于2米；偶尔在树冠层狩猎，高达18米。有时通过扫食获取食物，较少通过空中突袭。","breeding":"繁殖季为8月至12月，有时延伸至1月北部。单对繁殖或形成由繁殖雄鸟、一至两名雌鸟和一至两名辅助雄鸟组成的群体。雄鸟在整个繁殖季节喂养雌鸟。筑巢由繁殖雌鸟负责，需7至15天，巢为草、藤蔓须、树皮条和植物纤维制成的开放杯状，用蜘蛛网固定，外部覆盖树皮、苔藓和地衣，置于距地面1至10米（通常3至3.5米）高的树苗分叉处或律师藤中，位于密集植被近溪流处；领域面积0.7至1公顷，未受干扰区域更大。每窝产卵2枚，浅绿或绿白底，斑点或斑块棕色（尤其在大端），平均尺寸20.3×15.6毫米（北部稍小）；仅繁殖雌鸟孵卵，持续14至18天；雏鸟由主雌鸟照料，群体成员共同喂养，巢期15至19天；接近巢时，成鸟会进行地面抖翅远离巢穴的引诱动作；离巢后，幼鸟移至密集植被数日，由群体成员喂养，随后各自跟随不同亲鸟，喂养7至8周，独立于10至11周。","identification":"与东黄鸲鹟区别在于后者下方更亮黄，具黑腿和眼先。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，北至昆士兰州Mount Amos至Paluma，南至阳光海岸Cooloola至新南威尔士州Barrington Tops国家公园。","other":"对栖息地破碎化和农业、畜牧业引起的生境丧失敏感。避免最近形成的空隙，巢址至少远离30米。小片森林消失。选择性砍伐和清砍森林20至30年后返回。"},{"name":"东黄鸲鹟","english_name":"Eastern Yellow Robin","scientific_name":"Eopsaltria australis","overview":"东黄鸲鹟（英文名：Eastern Yellow Robin，学名：Eopsaltria australis），是雀形目鸲鹟科黄鸲鹟属的鸟类。澳大利亚东部和东南部特有的小型鸟类。体型丰满，上体呈灰色，下体鲜黄色，脸部暗灰至黑色，与相似的Tregellasia capito有所区别。常见于澳大利亚东部森林，活跃于低枝及树干侧面，以地面猎物为食。","appearance":"体长13.5至17厘米，体重18至28克（雄鸟）和15至24克（雌鸟）。头部和颈部灰色，眼上方有一条极淡的白色眉纹，脸部黑色，耳羽有淡淡的白色条纹；背部和翅膀灰色带橄榄色，臀部和尾上覆羽橄榄色；上翼主要为灰棕色，翼覆羽灰色，内侧初级飞羽和次级飞羽基部淡色，形成飞行中的翼纹；尾巴灰棕色，最外侧尾羽有狭窄的淡色尖端。下体黄色，两胁带有橄榄色。眼睛深棕色，喙黑色，腿黑褐色。雄雌相似，幼鸟呈赤褐色，有淡色条纹。亚种chrysorrhos与指名亚种的区别在于臀部和尾上覆羽明亮的黄色，与下体颜色一致。","call":"叫声为缓慢重复的哨音，也发出响亮的双音哨声，值得学习识别。","habits":"栖息于雨林、湿性和干性桉树林、河岸灌木丛、马利灌木、金合欢-卡里特里斯灌木丛、花园、公园和外来松树种植园，偏好有高矮植被层、稀疏地面覆盖和中等到密集下层植被的环境。一般被认为是留鸟，但存在季节性局部移动，尤其在东南高地记录到向低海拔迁移的现象。以昆虫、蜘蛛和其他小型节肢动物为食，主要从地面捕捉，有时从低处的树枝或落叶中搜寻，也会空中捕食。","breeding":"繁殖季为7月至次年1月，偶尔6月开始；每窝产卵2枚，有时1或3枚，极少4枚，由雌鸟单独筑巢，每次产卵需10至15天筑新巢，巢由树皮条、细枝、草、叶和其他植被构成，外部以蜘蛛网固定，附着苔藓和树皮碎片，内部铺有根须、草和树皮，直径6至10厘米，高度5至9厘米，内部直径5至7厘米，深度3至4厘米；巢通常建于1至6米高处的树或灌木叉中，巢寄生现象由光亮铜绿鸠和霍斯菲尔德铜绿鸠引起。孵化期15至17天，由雌鸟承担，孵化成功率约60%，离巢成功率28至39%。","identification":"与淡黄鸲鹟的区别在于脸部颜色和鸣叫声的不同，亚种chrysorrhos可通过其明亮的黄色臀部和尾上覆羽与指名亚种区分。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部和东南部，从南澳大利亚州的极东南角，穿过维多利亚州的大部分地区和新南威尔士州的西部一半，北至库克镇。热带北昆士兰州的鸟类主要局限于大分水岭的温暖高地。","other":"与西部黄鸲鹟在叫声、生态和行为上的相似性曾被归类为单一物种，但后来的DNA分析证实它们是独立的物种。"},{"name":"西黄鸲鹟","english_name":"Western Yellow Robin","scientific_name":"Eopsaltria griseogularis","overview":"西黄鸲鹟（英文名：Western Yellow Robin，学名：Eopsaltria griseogularis），是雀形目鸲鹟科黄鸲鹟属的鸟类。小型鸣禽，以灰色头部、颈部和上体，明亮黄色下体，以及灰色上胸部和近白色喉咙为显著特征。分布在澳大利亚西南部及南澳大利亚的艾尔半岛。该物种在森林环境中活动，常在低枝或树干旁停留，随后飞至地面捕食。其鸣声独特，由缓慢重复的\"chew-chew-chew\"哨音组成。","appearance":"体长13.5至15.5厘米，体重18.5至21.5克。头部和颈部灰色，黑眼纹，不明显的浅灰眉线，背部至橄榄灰，臀部鲜黄或黄绿色，翼上有一淡色条纹，主要在飞行时可见。下巴和喉咙白色，胸部浅灰，腹部和尾下覆羽黄色。眼睛深棕色，喙黑色，腿黑褐色。雄雌相似，幼鸟呈赤褐色，有淡色轴纹，随成长逐渐获得成鸟特征。","call":"发出两声急促的笛音，随后是一系列拉长的哨音。接触叫声为\"tchair tchair\"的口哨声，报警声为爆发性的\"churr churr\"。","habits":"主要栖息在开放的桉树林、灌木丛和有丰富下层植被的环境。食物以昆虫为主，偶尔食用小节肢动物和种子。通常在地面捕食，也会在树干上觅食。冬季更多时间在地面活动，觅食位置更低，使用较低的栖息点。","breeding":"繁殖季节为7月至次年1月，多在9月至11月。通常尝试两次繁殖。巢由雌鸟建造，杯状，位于树叉中，由树皮、草、枯枝和树叶构成，用蜘蛛网加固，内部铺有干草和枯叶。每窝产2枚蛋，偶尔3枚，孵化期约15天，幼鸟由双亲和帮手喂养。","identification":"与东黄鸲鹟的区别在于灰色胸部和分布范围不同。幼鸟与白胸歌鸲鹟幼鸟类似，但可通过橄榄色调的边缘识别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚西南部和中南部，包括西澳州南部沿海和南澳州的艾尔半岛。","other":"已知最长寿命超过8年11个月。"},{"name":"白胸歌鸲鹟","english_name":"White-breasted Robin","scientific_name":"Quoyornis georgianus","overview":"白胸歌鸲鹟（英文名：White-breasted Robin，学名：Quoyornis georgianus），是雀形目鸲鹟科Quoyornis的鸟类。属于雀形目，分布于西澳大利亚西南部沿海地区，自杰拉尔顿以南至奥班尼一带。小型、丰满的鸣禽，上体呈灰黑色，翼部较暗，下体白色，胸部略带淡灰色。该物种为澳大利亚特有种。","appearance":"体长15-16.5厘米，雄鸟体重19-22.5克，雌鸟15-19克。头部和上体为烟灰色，眼周黑色；翅膀深黑色，内侧初级飞羽和次级飞羽基部有白色斑块，折叠时隐蔽，飞行时可见为翼条；尾巴深灰色，内缘白色，中央羽毛尖端狭窄，向外逐渐加宽，形成尾角的白色边缘；下体白色，胸部带有淡灰色调；虹膜深棕色，喙和腿黑色。雌雄相似。幼鸟上体、胸部和两胁为赤褐色，有浅色轴纹；未成年鸟类似成鸟，但保留幼鸟的翅膀覆羽，有浅色纹路。","call":"叫声包括快速上升的单音节‘ziip’声，通常重复。鸣唱为吹口哨式的双音节‘see-ow’。","habits":"栖息于浓密的灌木丛，如金合欢和茶树，以及湿润的桉树林。以昆虫和其他小型节肢动物为食，主要通过从高处俯冲到地面捕食（占攻击行为的76%），其余在低至1米（15%）和1-2米（9%）的高度捕食。捕食的基质包括地面（76%）、叶面（16%）和树干枝条（5%），另有3%的猎物在空中捕获。","breeding":"繁殖季节为6月至次年1月，每季可产2-3窝。以一对繁殖，但巢穴常有多至三只帮手（主要是雄鸟）；雄鸟和帮手喂养繁殖雌鸟。求偶展示时，雄鸟翘尾、蓬松身体羽毛，低头弯腰同时发出激动的叫声。巢由雌鸟建造，为松紧适中的草杯状巢，直径9厘米，高度6厘米，内部直径5厘米，深度2-3毫米；位于地面以上0.5-10米（通常约2.5米）的密集灌木丛中。一窝产1-3枚卵，通常2枚，颜色为淡橄榄棕色或橄榄蓝色，有微弱的红色斑点，平均尺寸21.3×15.6毫米；孵化由雌鸟负责，周期14-15天；雏鸟由雄鸟和任何在场的帮手喂养，12-14天离巢；离巢幼鸟由所有成鸟喂养；成鸟和帮手通过在地上展翅奔跑的方式分散捕食者的注意力。巢穴被淡色杜鹃寄生。孵化成功率63%-80%，73%-87%的孵化成功幼鸟能离巢，每巢平均产生0.9-1.32只幼鸟；巢穴捕食者包括猫和各种鸟类。最长寿命可达12年。","identification":"与冠鸲鹟雌鸟相比，后者在折叠翅膀上有白色条纹，尾部边缘白色，通常栖息于更开阔的地带；还与褐背小鹟相比较，后者尾部有大量白色边缘。可以通过上述特征区分。","protection":"IUCN：LC（无危）","distribution":"分布于西澳大利亚西南部沿海地区，从杰拉尔顿以南至奥班尼一带，主要栖息于金合欢和茶树的浓密灌木丛以及湿润的桉树林中。"},{"name":"冠鸲鹟","english_name":"Hooded Robin","scientific_name":"Melanodryas cucullata","overview":"冠鸲鹟（英文名：Hooded Robin，学名：Melanodryas cucullata），是雀形目鸲鹟科黑鸲鹟属的鸟类。雄鸟以醒目的黑白相间羽毛著称，头部全黑，雌鸟则呈现灰褐色。广泛分布于澳大利亚内陆干旱地区，但在塔斯马尼亚州和澳大利亚北部部分地区未见踪迹。","appearance":"雄性冠鸲鹟具有独特的黑白色调，头部、颈部黑色，肩部有白色条纹，上翼黑色，带有明亮的白色翼斑。雌鸟上身灰色，下身淡色，翅膀带有浅色翼斑。雄鸟体型约15-17.5厘米，重21-28克，头部和背部黑色，翼上有白色翼斑，尾部黑色，下身白色；雌鸟上身灰褐色，下身淡灰色至白色，翼和尾与雄鸟相似但黑色部分为深棕色。幼鸟暗灰褐色，带有淡色条纹，翼和尾与雌鸟相似。","call":"鸣唱为清晰的哨音‘whee-whew whee-whew whee-whew’（清晨）或‘wheetyer-cantyer-cantyer-wheetyer’（夜晚，尤其是在月光明亮时）。叫声包括2-3个音符作为联系声，还有单调的管笛声‘phew’，高音金属声‘squee’，尖锐的责备声。","habits":"栖息于半干旱和干旱地带的轻木林和灌木丛，偏好尤加利树和金合欢为主的环境。通常为留鸟，有轻微的局部移动，不进行大规模迁徙。主要以昆虫和其他小型节肢动物为食，偶尔食用种子。冬季更多时间在地面或接近地面处觅食。会加入冬季的混合物种觅食群。","breeding":"繁殖期从8月初到12月底，可能持续到1月中旬，可能双窝繁殖，一季最多产五窝替代卵。以单配偶制繁殖，约三分之一的配对会有1-2个帮手。雌鸟筑巢，巢为杯状，由树皮、草、枝条和根须构成，外部用蜘蛛网绑定，内部铺细草、根须、毛发和羽毛。孵化期14-16天，育雏期12-14天；幼鸟离巢后长达4周内仍被喂养。","identification":"雄性冠鸲鹟与雌鸟明显不同，雄鸟黑白色调鲜明，雌鸟灰褐色。与褐背小鹟的区别在于后者体型较小，缺乏翼斑图案，尾巴摆动。四个亚种在大小和羽毛色彩上有细微差异。","protection":"IUCN：LC（无危）。东南澳大利亚的指名亚种因农业开垦导致数量和范围显著减少，被认为‘近危’；Tiwi Island的melvillensis亚种被认为‘易危’。","distribution":"主要分布于澳大利亚内陆干旱地区，包括昆士兰东南部至南澳大利亚东南角。在塔斯马尼亚、Nullarbor平原、Cape York和Simpson沙漠周边地区未发现。Tiwi hooded robin存在于Bathurst和Melville岛屿。","other":"历史上，指名亚种在东南澳大利亚的数量和范围由于农业开垦而大幅减少。Tiwi Island上的小种群可能受到类似影响。"},{"name":"暗色鸲鹟","english_name":"Dusky Robin","scientific_name":"Melanodryas vittata","overview":"暗色鸲鹟（英文名：Dusky Robin，学名：Melanodryas vittata），是雀形目鸲鹟科黑鸲鹟属的鸟类。原生于澳大利亚的塔斯马尼亚州。也被称为Dozey、Sad、Sleepy、Stump、Tasmania/Wood Robin、Native Sparrow或Sad Bird。这种鸟以深褐色为主调，具有独特的窄线纹，从眼后延伸至耳羽后方，以及翼上的白色条纹。其学名来源于拉丁词vittatus，意为‘带状’。","appearance":"暗色鸲鹟体长约14-16.5厘米，体重约27克，整体呈深褐色，无明亮色彩。它拥有短而细的喙和适中的长尾，比塔斯马尼亚的其他Petroicidae成员体型更大。性别间外观相似，无季节性变化或性二型性。成鸟头部和颈侧为棕色，具有一条从眼后延伸至耳羽的暗棕色线条，上方有奶油色眉纹，下体颜色较浅，多为淡灰褐色。幼鸟的头部和颈侧黑色至棕色，具大量白色斑纹，下体为灰色至褐色，有斑点和条纹。成年鸟的翅膀和尾巴为深棕色，有细微的白色边缘。","call":"暗色鸲鹟的叫声被形容为低沉、单调的“Choo-wee, Choo-we-er”，没有显著特征，其曲目限于几个低音符。它们的歌唱不多，声音常在黎明时分响起，给人以哀伤的印象。","habits":"生活在干燥的桉树（Eucalyptus）林地，偏好生态交错区，如森林边缘、海岸灌木丛、草地、果园、最近烧过的地区；海拔从海平面到1200米。主要为留鸟，但在繁殖季后期会进行局部移动至较低海拔或更开阔的生境。食性以昆虫等无脊椎动物为主，偶尔食用种子。捕食时，会从高处如围栏柱上扑向地面猎物。","breeding":"繁殖季从7月持续至12月，可能双窝育雏。巢由雌鸟建造，是一个不规则的杯状结构，直径约10厘米，高度5.1-7厘米，内部直径6.4厘米，深度3.8-4.4厘米，位于地面至5米的高度，通常在1.5米左右。每窝产卵2-4枚，通常为3枚，蛋色绿蓝至橄榄绿，带有红棕色斑点或污渍，平均尺寸22.3×16.8毫米。孵化期16-18天，仅由雌鸟负责，期间雄鸟和其他帮助者提供食物。雏鸟由双亲和任何助手共同照料，离巢时间为14-16天。若巢穴受威胁，成鸟会在地面进行装死表演以分散注意。幼鸟由成鸟喂养四周，至少六至七周内与父母同行。","identification":"与相似物种相比，暗色鸲鹟整体颜色更深，没有明显的浅色翼板。其独特的窄眼纹和翼上的白色条纹有助于识别。","protection":"IUCN：VU（易危）","distribution":"暗色鸲鹟是塔斯马尼亚特有的物种，广泛分布于该地区，包括巴斯海峡岛屿。它们适应能力强，即使在森林砍伐或火灾后也能迅速占领适宜的生境。","other":"暗色鸲鹟能很好地适应生境改变，如森林砍伐，经常在经过改造的环境中被发现。"},{"name":"绿丛鹟","english_name":"Green-backed Robin","scientific_name":"Pachycephalopsis hattamensis","overview":"绿丛鹟（英文名：Green-backed Robin，学名：Pachycephalopsis hattamensis），是雀形目鸲鹟科厚嘴丛鹟属的鸟类。中等体型的森林鸟类。其橄榄绿色背部、灰头带黑边白喉、脏黄绿色腹部及红褐色翅膀是其显著特征。分布于新几内亚的山地森林，主要栖息在760至1650米的高度，偶尔可达2000米。","appearance":"成年绿丛鹟体长约15厘米，体重33至35克。头部侧面、头顶至眼下方为灰色，眉区白色，背部橄榄绿，上尾覆羽锈棕色，飞羽暗灰带红棕边缘，小翼羽和中翼羽橄榄绿；尾部暗灰，边缘红棕至橄榄棕；下颌、上喉及颊区白色；腹部黄橄榄色，腹下更黄，尾下覆羽橙色，腋下橄榄色；虹膜淡灰色；喙黑色；腿灰色。雄雌相似，幼鸟特征未详述。存在数个亚种，差异在于胸部颜色深浅、腹部颜色、喉部白色区域大小等。","call":"鸣声包括三声逐渐升高的嘶哑音，通常后跟两声同高音调；尖锐的上升哨音，以及短促重复的平音。","habits":"栖息于山地森林和较低的高山森林，偏好760至1650米的海拔，以昆虫为食，常在低矮植被层和地面觅食，特别是在蕨类植物和高草丛生的区域。","breeding":"巢由苔藓构成，距地面约0.5米，藏于藤蔓弯曲处。","identification":"与白脸丛鹟相似，但绿丛鹟体型更大，具红褐色翅膀，腹部更偏绿色。不同亚种间存在颜色深浅和分布的差异。","protection":"IUCN：LC（无危）；绿丛鹟在当地常见，但由于隐秘的生活习性而容易被忽视，其存在通常通过鸣声被发现。","distribution":"分布于新几内亚西部和中部山区。"},{"name":"白眼丛鹟","english_name":"White-eyed Robin","scientific_name":"Pachycephalopsis poliosoma","overview":"白眼丛鹟（英文名：White-eyed Robin，学名：Pachycephalopsis poliosoma），是雀形目鸲鹟科厚嘴丛鹟属的鸟类。最显著的外部特征是拥有淡色的眼睛和白色的喉咙，与黑色的眼纹形成鲜明对比。分布在新几内亚的中海拔山林地带。","appearance":"体型中等，长度约15至16.5厘米，体重35至42克。全身呈现烟灰色，腹部颜色较浅，脸部和翅膀颜色更深。成鸟头部至上背部呈深灰色，翼上覆羽略深于背部，上翼和尾部烟灰色。喉部白色，与暗色面部形成对比，下喉更白且无斑点。虹膜淡灰或米色，喙黑色，腿色从粉灰到蓝灰色。雌雄相似。幼鸟上体橄榄棕色，脸颊非常深的黑褐色，下巴白色，喉、胸及两侧棕色，腹部白色羽毛尖端棕色，尾下覆羽淡黄色。不同亚种在喉部颜色、翼和尾部色调、腹部白色程度上有所差异。","call":"叫声特征明显，包括一系列4至10个响亮的、远距离传播的嗡嗡声，前几个音节上扬，随后逐渐升高。还有一种清脆的钟声般的哨音，音调上升，发音为'periwee'。","habits":"栖息于海拔400至1700米的山地森林和较低的亚高山森林，通常在700米以上，最高可达2200米。生活方式似乎是定居的，以昆虫为主要食物来源，偶尔可能捕食较大的猎物，如鸟蛋或雏鸟。活动范围低至地面2.5米以下，大多数猎物通过从地面或低矮植被中捕获。","breeding":"繁殖期可能在旱季中期至晚期，至少在8月观察到雄鸟睾丸增大，8月中旬发现刚孵化的雏鸟，11月初见到幼鸟。巢呈杯状，由根须和绿色苔藓构成，曾在一个树苗中发现巢位于距地面1.3米处。每窝产一枚蛋，蛋壳颜色为乳白色，密布棕色和淡紫色斑点，大端形成紫灰色盖状，尺寸为27.3×19.4毫米。","identification":"与灰薮鹟和蓝灰薮鹟有有限的海拔重叠，但白眼丛鹟通常在较低的海拔高度被发现，具有白色的眼睛和喉部。不同的亚种在喉部颜色、翼和尾部色调、腹部白色程度上有所不同。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚，具体在澳大利亚新几内亚的山地森林和亚高山森林。"},{"name":"特岛鸲鹟","english_name":"Torrent Flyrobin","scientific_name":"Monachella muelleriana","overview":"特岛鸲鹟（英文名：Torrent Flyrobin，学名：Monachella muelleriana），是雀形目鸲鹟科特岛鸲鹟属的鸟类。在新几内亚和俾斯麦群岛（New Britain）特有的小型鸟类。也被称为torrent robin，是单型属Monachella的唯一成员。特岛鸲鹟偏好湍急河流旁的岩石地带，从山脚到山区都能找到它们的身影。","appearance":"成年特岛鸲鹟体长约14至15厘米，体重23至28克。头部顶部呈棕黑色，背部为浅灰色，臀部白色，两翼和尾巴棕黑色。脸部有显著的白色斑点，位于喙基部与眼睛之间，下方有一条狭窄的棕色眉纹。颈侧、喉部和下体均为白色，虹膜深褐色，喙和腿呈黑色或黑褐色。雌雄相似，幼鸟缺乏成鸟的白色面部斑点，羽端带有较淡的颜色。","call":"发出高音调的笛声或刺耳的沙哑叫声。","habits":"特岛鸲鹟栖息于植被稀少的湍急河流与溪流旁，偏好露出水面的巨石，活动范围主要在山地和低山区域，偶尔在低地靠近山丘的地方，海拔高度可达1800米，有时高达2130米。它们通常在离河床100米内的范围内活动，以昆虫为食，从暴露的栖息地如岩石、裸露的河床、倒木或附近的开阔地树枝上捕食空中飞虫。","breeding":"繁殖期未详，但观察到的巢中幼鸟出现在8月初、9月底和11月初，表明繁殖可能发生在旱季后期（河流水位较低时）。巢是一个精致的浅杯状结构，由细根须和苔藓构成，外部直径9至9.2厘米，内部直径6至6.5厘米，深度约2至2.5厘米，通常建在细枝上，曾有一次记录显示巢位于距水面约2.5米的大石块的平台上。一窝产两枚蛋，颜色为淡褐色带深色斑点。孵化和育雏期未知，但有记录显示成鸟会共同喂养幼鸟。","identification":"与同生境的山鹊鹩相比，特岛鸲鹟体型较小，没有黑色的背部和脸部。鸣叫声也有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚及俾斯麦群岛的New Britain，主要栖息于山地和低山区域的湍急河流旁，海拔高度从300至750米不等，偶尔在低地靠近山丘的地方。","other":"特岛鸲鹟的分布虽然局部且稀疏，但在适宜的生境中广泛存在。"},{"name":"巴布亚小鹟","english_name":"Canary Flyrobin","scientific_name":"Devioeca papuana","overview":"巴布亚小鹟（英文名：Canary Flyrobin，学名：Devioeca papuana），是雀形目鸲鹟科Devioeca的鸟类。此物种分布于新几内亚的山地森林，主要栖息在海拔1100至3500米之间，以橄榄绿的上体和黄色的下体为显著特征。","appearance":"巴布亚小鹟体型小巧，长度介于11.5至13厘米，体重约13至16克。其头部、面部和上体呈黄橄榄绿色，飞羽橄榄棕色，翼上的中覆羽和小覆羽同样呈现黄橄榄绿。尾巴橄榄棕色，喉咙侧面和腹部为黄色，下巴颜色较淡，腹侧和大腿处带有轻微的橄榄色。眼睛深褐色，喙黑色，腿橙黄色。雌雄相似，幼鸟则有大量淡色斑点。","call":"其鸣唱被描述为高音清脆下降的颤音，或一系列高音的啾啾声和颤音混杂。此外，还会发出尖锐的‘tsee’声，微弱的嘶嘶声，以及连续的单音责骂声。","habits":"巴布亚小鹟主要栖息在新几内亚山脉的山地森林、森林边缘和小片开阔地带，活动范围在海拔1800至2500米，局部地区可低至1100米，高至3500米。以昆虫为食，包括象鼻虫和其他甲虫、膜翅目昆虫等，通过空中捕捉猎物，偶尔也会从栖息地出击捕食。生活方式似乎为定居。","breeding":"关于繁殖的数据较少，已知在12月有成鸟处于繁殖状态，4月初观察到有鸟坐在巢中，2月初至2月中旬见到幼鸟，表明繁殖可能主要或仅发生在雨季。巢为小型、整洁的杯状，离地面约10米，位于无遮挡的树苗水平枝上，通常观察到两只或更多的幼鸟跟随成鸟。","identification":"巴布亚小鹟与Yellow-legged Flycatcher和白脸歌鸲鹟有相似之处，但其出现在更高海拔，脸部和喉咙缺乏白色标记，有助于区分。","protection":"IUCN：LC（无危）","distribution":"巴布亚小鹟分布在新几内亚的山区，主要栖息在1100至3500米的海拔高度，常见于山地森林、森林边缘和小片开阔地带。","other":"巴布亚小鹟在1875年由德国鸟类学家Adolf Bernhard Meyer首次描述，原属Microeca属，后根据分子系统发育研究结果，于2011年被归入由澳大利亚鸟类学家Gregory Mathews于1925年提出的Devioeca属。"},{"name":"黄脚小鹟","english_name":"Yellow-legged Flyrobin","scientific_name":"Kempiella griseoceps","overview":"黄脚小鹟（英文名：Yellow-legged Flyrobin，学名：Kempiella griseoceps），是雀形目鸲鹟科Kempiella的小型鸟类。其最显著的特征是橙黄色的腿和奶油黄色的下颚，以及橄榄棕色的背部和灰白色的喉部。分布于新几内亚和澳大利亚远东北部的约克角半岛，偏好雨林生境。","appearance":"成年黄脚小鹟长约12至13厘米，体重介于10至12克之间。头部顶部、侧面和颈背呈灰色，眼圈和眼前斑点为灰白色。上体橄榄绿色，翅膀和尾巴深棕色，尾羽边缘橄榄棕色。下巴到上胸灰白色，其余下体部分为稻草黄色，上胸带有淡棕色晕染。眼睛深褐色，上喙黑色，下喙奶油黄色，腿亮橙色。雄雌相似。幼鸟上体羽毛尖端呈淡黄色，翼羽覆羽有浅色尖端，下体羽毛尖端较暗；亚成鸟类似成鸟，仅翼次级飞羽覆羽尖端淡色。西部亚种冠部比指名亚种更暗更棕，上体颜色更深；kempi亚种则颜色更浅。","call":"鸣唱为响亮清晰的哨音，重复5至10次，部分音符带有颤音。觅食时发出低沉的管状或嘶嘶声'zzt zzt zzt'，还有低调的'tew joei joei joei'声和喋喋声。","habits":"栖息于新几内亚的原始森林、高大次生林、森林边缘和部分清理地带，主要在山丘和低山区域，海拔高度550至1400米，偶尔可达2300米。在低海拔地区通常被绿小鹟取代，在较高海拔由占据，有时存在广泛的重叠区域。在澳大利亚（kempi亚种）居住在雨林及其边缘，可延伸至相邻的桉树和纸皮树森林，季风雨林；避开森林密集区域。在Aru岛有迷鸟记录出现在红树林。","breeding":"在新几内亚，已知的繁殖季节为10月至翌年1月，覆盖晚干季和早湿季，可能还包括湿季末期（五月巢穴报道可能有误）。在澳大利亚可能在10/11月至1/2月，湿季期间繁殖。巢为小巧整洁的杯状，由根须构成，用蜘蛛网绑定并装饰以树皮碎片和苔藓，外部直径3.8厘米，高度4厘米，内部深度2厘米；放置在离地面6至30米的水平树枝上。每窝产2枚卵，浅蓝色，遍布深棕色和灰色斑点（主要在较大端），尺寸15×12毫米；观察到成鸟轮流孵卵，每次持续4至7分钟，然后离开巢约相同时间。无更多信息。","identification":"与Lemon-bellied Flycatcher区别在于后者具有深色的喙和腿。各亚种间主要通过颜色深浅区分。","protection":"IUCN：LC（无危）","distribution":"在新几内亚和约克角半岛北部（澳大利亚远东北部）分布。在澳大利亚，从昆士兰州Coen和阿瑟顿高原附近向南的报告需要证实。","other":"曾归类于Microeca属，基于2011年分子系统发育研究结果，现归于Kempiella属。"},{"name":"绿小鹟","english_name":"Olive Flyrobin","scientific_name":"Kempiella flavovirescens","overview":"绿小鹟（英文名：Olive Flyrobin，学名：Kempiella flavovirescens），是雀形目鸲鹟科Kempiella的鸟类。生活在新几内亚低地和丘陵森林中的小型鸟类。其上体橄榄绿色，腹部黄橄榄色，喉部鲜黄色，具有独特的黄色眼环和双色喙，上喙黑，下喙橙色。曾被归入Microeca属，现基于分子系统学研究归入Kempiella属。","appearance":"绿小鹟长约13至14厘米，重14至17克。头部冠羽、头部两侧和上体呈暗橄榄绿色，翼上和尾部深橄榄棕色，腹部浅橄榄黄色，两胁带橄榄色晕染。虹膜深褐色，上喙暗灰褐色，下喙淡黄或橙黄色，腿淡黄或淡褐色。雌雄相似，幼鸟羽毛末端苍白，成鸟特征保留自幼鸟状态。亚种cuicui的上体颜色更鲜亮，下体黄色更深。","call":"鸣唱为快速连串的下降再上升的二音节音乐哨音，单调重复的\"uliuliuliuliuli...\"。还有较安静的口哨音，重复3至5次或更多，以及严厉的鼻音责骂声和类似生锈铰链发出的不悦耳的\"swee\"声。","habits":"栖息于雨林、季风林，有时在柚木（Tectona）种植园，偶尔会飞到附近开阔地带觅食。主要在低地和低山地区活动，最高可达海拔1200米，罕见至1500米。通常与黄脚小鹟在同一海拔范围内共同出现。以昆虫为食，主要在中层林冠（50%）、下层林冠（35%）和林下层（15%）觅食，通过突然出击（约50%）、空中捕食（约30%）、拾取和悬停等方式捕食。","breeding":"繁殖季节在新几内亚东南部（波蒙特低地）为6月至8月，筑巢于树苗或小树的水平枝上，距地面1.5至12米处，用苔藓和蛛网编织的小杯状巢，内部铺有毛发，一窝产2枚蛋。具体繁殖细节尚不清楚。","identification":"与黄腿鹟（Yellow-legged Flycatcher）的区别在于绿小鹟的喉部为黄色而非白色。与柠檬腹鹟（Lemon-bellied Flycatcher）的区别在于绿小鹟有明显的眼环，且栖息于森林而非草原。","protection":"IUCN：LC（无危）","distribution":"分布于西巴布亚群岛（瓦伊盖奥岛、巴坦塔岛、米苏尔岛）、亚彭岛、阿鲁群岛和新几内亚主岛。在澳大利亚和新西兰地区，可见于四王群岛（新几内亚西北部）、印尼阿鲁群岛（新几内亚西南部）、印尼亚彭岛（鸟头湾，新几内亚西北部）和新几内亚。","other":"绿小鹟在新几内亚东南部雨林研究点附近的R. Brown地区，估计密度约为20只/10公顷，表明其在该地区数量相当普遍。"},{"name":"黄胸小鹟","english_name":"Lemon-bellied Flyrobin","scientific_name":"Microeca flavigaster","overview":"黄胸小鹟（英文名：Lemon-bellied Flyrobin，学名：Microeca flavigaster），是雀形目鸲鹟科小鹟属的小型鸟类。其特征为上体橄榄褐色，下体柠檬黄色，喉部白色。广泛分布于澳大利亚北部、新几内亚及印尼部分地区。","appearance":"成年黄胸小鹟长约11.5厘米，两性羽色相似。头部灰色，具狭窄的白眉纹，上体橄榄褐色，下体柠檬黄色，喉部白色。喙黑色，基部淡色，腿暗灰色。亚成鸟和成鸟相似，但翼覆羽末端具淡色斑点，下体羽毛尖端橄榄褐色。有四个亚种，其中laetissima亚种比指名亚种片种稍大，flavissima亚种上体和喉部带明显黄色调。","call":"发出一系列丰富而多变的清脆哨音，如‘pa-treeter’或‘peter peter’的重复叫声，有时在类似百灵鸟的歌唱飞行中发出。还有‘chauncey chauncey chew’的弹跳声和短促单调的哨音，后面跟着较高的音节和快速下降的音符序列。","habits":"栖息于各种生境类型，包括桉树（Eucalyptus）稀树草原、开阔林地、红树林、橡胶种植园，低地至海拔约670米的上山山谷。以昆虫和其他小型节肢动物为食，如蚂蚁、膜翅目昆虫、甲虫和毛虫。在红树林中，从地面到树冠的各个高度都有觅食行为。在桉树林地和季风林中，主要在4米以上高度觅食。","breeding":"繁殖季节在澳大利亚全年均有记录，主要在9月（次要峰值在12月至1月），昆士兰州，北领地则在2月至10月（峰值在3月至4月和8月至10月）。筑巢于离地面0.6至20米的水平枝叉或枯枝末端，巢由草和树皮纤维构成，用蛛网固定，外表装饰有树皮和苔藓。每窝产1-2枚蛋，平均尺寸18.8×13.8毫米，蛋壳蓝白色，带棕色和紫色斑点。","identification":"与褐背小鹟的区别在于后者尾部外侧有白色羽毛，且无柠檬黄色腹部。Golden Whistler体型更大，黄色仅限于下腹部。四个亚种之间在大小、颜色深浅和黄色分布上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚北部（从奥德河西部至昆士兰沿海）、新几内亚及印尼部分岛屿。在澳大利亚，常见于红树林、纸皮树沼泽森林和林地。","other":"曾被认为与Microeca tormenti同种，后因发现杂交区而被重新分类。"},{"name":"金腹小鹟","english_name":"Golden-bellied Flyrobin","scientific_name":"Microeca hemixantha","overview":"金腹小鹟（英文名：Golden-bellied Flyrobin，学名：Microeca hemixantha），是雀形目鸲鹟科小鹟属的鸟类。以其橄榄绿的上体和鲜明的柠檬黄色下体著称，分布于印尼摩鹿加群岛南部的塔宁巴尔群岛。","appearance":"体长约12厘米，头部至背部呈现暗橄榄色，翅膀和尾巴颜色一致，腹部鲜艳的黄色，喉咙部分颜色略淡。嘴基至眼后有一模糊的黄色眉纹，耳羽灰暗，虹膜深棕色，上喙黑色，下喙浅粉橙色，腿黑色。雌雄外观相似，幼鸟特征未知，推测其羽尖可能带有浅色。","call":"鸣唱为一系列甜美婉转的音符，约12至14个，偶尔发出更高音的版本。叫声包含高亢而细薄的“seeE”音，尾音加重。","habits":"栖息于低地的红树林、森林边缘和开阔的林地，常单独或成对活动。主要以昆虫为食，活动于树木中层，很少低于10米高度。通过短暂飞行从暴露的栖木捕食猎物，有时加入混合物种的觅食群。","breeding":"关于繁殖的信息非常有限。已知在11月，发现其巢穴为树上水平枝条上的小杯状巢，成鸟可能正在孵卵。","identification":"在塔宁巴尔群岛没有其他类似的小型、鲜黄色鸣禽。黄色眉纹和暗色眼线为其显著特征。","protection":"IUCN：NT（近危）。限制范围物种，仅存在于班达海岛屿特有鸟类区。在其极小范围内常见，但部分地区存在大量砍伐，可能对生境丧失和退化敏感。","distribution":"分布于澳新界的塔宁巴尔群岛（印尼摩鹿加群岛南部）。"},{"name":"褐背小鹟","english_name":"Jacky Winter","scientific_name":"Microeca fascinans","overview":"褐背小鹟（英文名：Jacky Winter，学名：Microeca fascinans），是雀形目鸲鹟科小鹟属的鸟类。小型灰褐色澳大利亚鸲鹟，常见于澳大利亚和巴布亚新几内亚的开阔林地和农田。其独特的‘peter-peter-peter’叫声使其易于识别。","appearance":"体长约12.5至14厘米，体重14至20克。成鸟头顶至背部灰褐色，下体偏白，具淡白色眉纹，翼暗棕色，尾部深棕黑色，外侧尾羽白色显著。雌雄相似，幼鸟上体灰褐色，下体偏白，羽尖棕色。不同亚种在体型、颜色上有细微差异。","call":"叫声生动，常重复‘peter-peter’，另有一连串三次以上无停顿的‘pretty-pretty-pretty’清脆哨音，擅长模仿其他声音。","habits":"偏好桉树（Eucalyptus）林地、灌木丛生的干旱地带，常出现在开放的灌木层和空旷地带。以昆虫、蜘蛛、蠕虫等小型无脊椎动物为食，通过地面扑食或空中捕食的方式获取猎物。有时加入混合物种群，与大阔嘴鹟和黑白扇尾鹟共处。","breeding":"繁殖期在澳大利亚为8月至1月，雨后或有两窝雏鸟；在巴布亚新几内亚，幼鸟从10月中旬到1月末离巢，表明在旱季末繁殖。通常以一对繁殖，偶尔有帮手，最多观察到三只帮手。雌鸟筑巢，巢呈浅杯状，由草、树皮条和根须构成，内衬毛发、树皮、羽毛和苔藓，巢置于离地1至18米的树枝分叉处，多为枯枝。每窝产卵1至3枚，通常2枚，孵化期16至18天，雏鸟在17至20天后离巢。","identification":"与Lemon-bellied Flycatcher的Kimberley亚种相比，后者外侧尾羽无白色；冠鸲鹟雌鸟翅膀较暗，有明显淡色斑块；Golden Whistler雌鸟体型更大，喙厚实，腹部黄色。不同亚种在颜色和分布上有所区别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚大部分地区（除塔斯马尼亚州）和巴布亚新几内亚南部。在澳大利亚东部、中部和南部常见，在北部较少见；在巴布亚新几内亚，分布稀疏且局部。","other":"三个亚种分布于澳大利亚不同区域：M. f. fascinans分布在昆士兰中部至东部、新南威尔士、维多利亚和南澳大利亚东南部；M. f. assimilis在南澳大利亚和西澳大利亚南部；M. f. pallida在昆士兰北部和西部、北领地及西澳大利亚的金伯利地区。"},{"name":"黄腹鸲鹟","english_name":"Yellow-bellied Flyrobin","scientific_name":"Cryptomicroeca flaviventris","overview":"黄腹鸲鹟（英文名：Yellow-bellied Flyrobin，学名：Cryptomicroeca flaviventris），是雀形目鸲鹟科Cryptomicroeca的鸟类。中等体型，分布于新喀里多尼亚的Grande Terre和Ile des Pins。其特征为暗橄榄灰的背部、尾巴和翅膀，头部和胸部呈灰色，喉部颜色略浅，腹部和臀部为鲜亮的柠檬黄色。","appearance":"体长约14至15厘米，体重约10.5至14.5克。脸部、耳羽和颈侧呈淡灰色，头顶至背部为暗褐色橄榄色，臀部稍淡。飞行羽和尾羽深棕色，翼羽边缘带有橄榄色。喉咙中央和上胸非常淡灰，胸部中间偏灰，下胸和上腹部灰色，其余下体部分为明亮的柠檬黄色。虹膜深棕色，上喙暗色，下喙带黄色，脚为淡粉棕色。雌雄外观相似。幼鸟呈棕色，尤其在头顶有不明显的较浅色条纹。","call":"歌声为连续的短颤音，结合快速短促的吱吱声和许多清脆的音符。有时在短语间发出高音的“tsip-tsip”。也有规律的“chip-chip-chip-”系列音符和尖锐的警报叫声。","habits":"栖息于干燥低地森林、松树-龙舌兰林（Pinus-Pandanus）和湿润森林，海拔从海平面至约1050米，最高峰可达1525米。以昆虫为食，通常在3米以下捕食，常在地面或偶尔在低矮灌木中捕捉猎物。在落叶层中捕捉猎物。","breeding":"繁殖季节为9月至3月，可能为双窝产。巢由草和其他细小植被制成的杯状结构，外部用蜘蛛网绑定并装饰有树皮碎片和苔藓，直径约4.5厘米，置于离地面1至5米高的细枝上。每窝产2枚蛋，蛋壳呈淡蓝灰色，带有深棕色斑点；双方父母共同孵卵和抚育幼鸟，孵化期和育雏期未知；会进行假伤分散注意力的表演。","identification":"与同属其他物种相比，黄腹鸲鹟具有独特的柠檬黄色腹部和臀部，以及暗橄榄灰的上体和淡灰色的下体。叫声和栖息地选择也是重要的辨识特征。","protection":"IUCN：LC（无危）","distribution":"主要分布于新喀里多尼亚的Grande Terre和Ile des Pins。在Rivière Bleue保护区有其存在。","other":"黄腹鸲鹟是Cryptomicroeca属的唯一物种，曾长期被归类于Eopsaltria属，后遗传学研究将其移至Microeca属，最终单独置于Cryptomicroeca属中。"},{"name":"红背刺莺","english_name":"Garnet Robin","scientific_name":"Eugerygone rubra","overview":"红背刺莺（英文名：Garnet Robin，学名：Eugerygone rubra），是雀形目鸲鹟科红背刺莺属的鸟类。而雌鸟背部呈橄榄绿色。主要栖息于新几内亚的山地森林中。","appearance":"红背刺莺体长10至11.5厘米，体重9至11克。雄鸟成鸟额部有小白点，脸部和耳羽深灰色，翼上有一小块白色斑纹，形成斜杠状，尾羽外侧有白色尖端，腹部灰白，胸和侧部较暗，腹白，尾下覆羽和大腿处有暗红色晕染。雌鸟与雄鸟相似，但色泽较淡，额部无白色，上体呈黄橄榄绿。幼鸟全身巧克力棕色，翅膀灰色，亚成鸟上体暗肉桂棕色，下体浅肉桂棕色。","call":"其歌声极高音，微弱而清脆，音调忽高忽低。叫声为细腻的上升滑音，类似‘uwee’、‘uweeo’或‘deeyu’。","habits":"栖息于海拔1400至3680米的山地森林边缘和杂草丛生的花园，主要在1700至2500米之间。它们展现出独特的水平姿势，常摆动翅膀和尾巴。","breeding":"关于繁殖行为的具体信息未详述。","identification":"雄鸟的暗红色背部和雌鸟的橄榄绿色背部是辨别性别的重要特征。它们的白色翼斑在同类中独一无二。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的山地森林，主要在1700至2500米之间。","other":"红背刺莺由Richard Bowdler Sharpe首次描述，后被归入Eugerygone属。"},{"name":"瑰色鸲鹟","english_name":"Rose Robin","scientific_name":"Petroica rosea","overview":"瑰色鸲鹟（英文名：Rose Robin，学名：Petroica rosea），是雀形目鸲鹟科岩鸲鹟属的鸟类。雄性瑰色鸲鹟上体呈暗灰色，胸部粉红，腹部白色，翼下白色，尾羽黑色带白色尖端，外观独特。雌鸟为灰褐色，腹部颜色较淡，胸部有时带有粉红色调。主要分布于澳大利亚东南海岸地区，从昆士兰东南部至维多利亚州，以及南澳大利亚东南部。","appearance":"雄性瑰色鸲鹟体长约11-12厘米，体重7-10克。头部、背部暗灰色，胸至腹部玫瑰红色，腹部中间至尾下覆羽白色，尾羽黑色带白色尖端。雌鸟上体灰褐色，下体较浅，胸部可能带有粉色。幼鸟上体灰褐色有较淡的条纹，下体斑驳，翅膀和尾巴特征类似雌鸟。成年雄鸟有明显的粉色胸部，成年雌鸟和幼鸟较为素朴。","call":"鸣唱为柔和悦耳的颤音，‘dick dick diddit deer deer’，像铃声，最后两个音节较高。联系叫声为鼻音‘neep’，也有类似干枝折断声的‘tick’，以及尖锐的警戒音和各种啾啾声。","habits":"栖息于澳大利亚东南海岸的温带森林沟谷和热带湿润低地森林。以昆虫和其他小节肢动物为食，多在距地面2米以上的地方觅食，有时高达20米。捕食技巧多样，包括空中捕食、突袭打击、从栖木俯冲等。加入多种鸟类混合觅食群。","breeding":"繁殖季节为9月至次年1月，通常产一到两窝。巢为深杯状，由苔藓、蕨类碎片构成，内部填充蜘蛛网、羽毛和毛发，外部装饰有地衣。巢位于大树的分叉处，高度约10-20米。每次产2-3枚蛋，蛋壳为淡白色带蓝、灰或棕色色调，有深灰色斑点。","identification":"雄性瑰色鸲鹟的粉红胸部和暗灰色上体，以及白色翼下和尾羽尖端是辨识关键。雌鸟与雄鸟的颜色差异显著，主要通过颜色和分布区辨识。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东南部，从昆士兰东南部至维多利亚州，以及南澳大利亚东南部，繁殖季以外也可能向北延伸至昆士兰东南部和南澳大利亚东南部。","other":"瑰色鸲鹟在澳大利亚本土被称为‘红知更鸟’，以区别于‘黄知更鸟’。"},{"name":"粉红鸲鹟","english_name":"Pink Robin","scientific_name":"Petroica rodinogaster","overview":"粉红鸲鹟（英文名：Pink Robin，学名：Petroica rodinogaster），是雀形目鸲鹟科岩鸲鹟属的鸟类。主要分布在澳大利亚东南部和塔斯马尼亚岛的凉温带森林中。雄鸟拥有独特的白色额斑和粉红色胸腹，上体呈灰黑色，而雌鸟则呈现灰褐色羽毛。该物种属于岩鸲鹟属，与欧洲或美洲的知更鸟无亲缘关系，而是早期的Passerida鸣禽分支。","appearance":"粉红鸲鹟长约13.5厘米，体重9-11克。雄鸟成鸟头、背、翼和尾深灰黑色，胸部和腹部粉红，腹部下方和尾羽下覆羽白色，两胁及大腿深灰黑色；雌鸟成鸟上体暖橄榄褐色，额斑淡黄白色至灰白色，眼圈灰白色，翼深褐色，具暗黄褐色斑点，下体浅棕色，胸侧和胁部灰褐色。幼鸟上体橄榄褐色，有淡色条纹，下体杂以灰黄褐色。","call":"其鸣唱为快速颤音‘chr t- tr-tr-t-r-r’，低沉但穿透力强。接触叫声为‘tick’，类似小树枝折断的声音；警戒声为训斥般的‘chur-r-r’。","habits":"栖息于雨林和湿润的桉树（Eucalyptus）林，常有茂密的下层植被；非繁殖季节会出现在较干燥、开阔的生境。主要食物为昆虫和其他小型节肢动物，觅食方式多样，包括空中捕食、飞扑捕食和从地面及低矮灌木中觅食。","breeding":"繁殖季节为9月至次年3月，通常产一窝或两窝。巢由雌鸟建造，呈深杯状，由苔藓和植物纤维构成，用蜘蛛网固定，外覆地衣，内部铺垫草或毛发，置于距地面0.5至7.9米的水平枝叉处。每窝产2至4枚蛋，平均尺寸18.7×14.2毫米，孵化期约16天，由雌鸟承担。雏鸟由双亲喂养，具体离巢时间未知。巢穴可能被扇尾杜鹃和霍氏金鹃寄生。","identification":"雄性粉红鸲鹟的头部和上体颜色深灰黑色，胸部粉红色，与雌鸟的灰褐色形成鲜明对比。与瑰色鸲鹟相比，尾部全黑，无瑰色鸲鹟那样的白色端斑。雌性粉红鸲鹟的上体颜色较暖，与雄鸟明显不同。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚东南部的维多利亚州、南澳大利亚州和新南威尔士州，以及塔斯马尼亚岛。繁殖季节在上述地区，非繁殖季节可能会出现在较为干燥、开阔的生境。","other":"无"},{"name":"岩鸲鹟","english_name":"Snow Mountain Robin","scientific_name":"Petroica archboldi","overview":"岩鸲鹟（英文名：Snow Mountain Robin，学名：Petroica archboldi），是雀形目鸲鹟科岩鸲鹟属的鸟类。主要分布在奥新界山区中西部高海拔的New Guinea。其特征是通体呈炭灰色，腹部颜色较浅，前额有一窄白带，胸部显著的红色斑块，使其在特定的高山环境中极为显眼。","appearance":"雄性岩鸲鹟头部和颈背暗灰石板色，略带红粉色调，头部侧面为石板灰色，喙基部和眼周黑色，具一小白色前额斑。上体暗灰石板色，臀部略浅；翅膀黑色，次级飞羽外缘灰白色，内侧主翼羽和外侧次级飞羽内缘约三分之一处有白色斑点，形成翼下条纹；尾巴黑色，尾羽外缘基部和内缘末端白色，最外侧尾羽有大白色尖端，相邻两对尾羽尖端窄白色。喉部和胸部石板色，带红粉调，胸中心有明亮的红色斑点，逐渐变为两侧灰色，腹部灰白色，下尾覆羽白色，大腿部石板色；虹膜深棕色，喙和腿黑色。雌鸟类似雄鸟但体型稍小，颜色更淡，胸部红色斑点较淡。幼鸟带褐色调，缺乏红色胸部斑块。","call":"发出一系列宽泛的音符，如同水滴声，类似某些鹦鹉的声音。此外，也会发出响亮的“chip”叫声和粗糙的斥责声。","habits":"栖息于裸露岩石斜坡边缘、悬崖和碎石坡上的巨石之间，以及岩石苔原或高山灌丛中的山谷地带。通常出现在林线以上，大约3850米以上的高度。基本定居，以昆虫为主食，主要在地面觅食，常在岩石上停留并扫描周围环境，然后扑向猎物，之后返回栖息处。","breeding":"已知在9月观察到成鸟喂养离巢幼鸟，且在12月至次年2月间广泛歌唱，暗示繁殖活动。具体繁殖细节尚不清楚。","identification":"在其栖息环境中，岩鸲鹟的特征鲜明，难以混淆，尤其是其独特的红胸斑块和叫声。","protection":"IUCN：NT（近危）。目前认为是数据缺乏物种，受限于中央巴布亚山脉EBA。最初报告在其极小范围内普遍，但近期报道有限，可能反映了访问这一偏远地区的困难。全球种群数量无估计，趋势数据缺失。当地采矿作业可能对物种产生不利影响，全球变暖导致Mt Trikora冰盖在过去几十年融化，也可能构成威胁。然而，关于其分布范围、种群数量和威胁的信息不足，无法进行稳健的灭绝风险评估，因此被列为数据缺乏状态。急需针对性的调查。","distribution":"分布于New Guinea的中西部山区，具体地点为Mt Wilhelmina和Mt Carstensz（位于Oranje山脉），均为C New Guinea的高海拔地区。","other":"无"},{"name":"林鸲鹟","english_name":"Mountain Robin","scientific_name":"Petroica bivittata","overview":"林鸲鹟（英文名：Mountain Robin，学名：Petroica bivittata），是雀形目鸲鹟科岩鸲鹟属的鸟类。广泛但稀疏分布于新几内亚高地的亚高山森林中。","appearance":"雄鸟成鸟头部、颈部和上体黑色，具小白额斑；飞羽和大覆羽棕黑，小覆羽和中覆羽黑色；尾部黑色，最外侧尾羽末端白色（某些个体的白色部分超过羽毛长度的一半），次外侧两对尾羽具小白尖。颏、喉至胸部黑色，其余下体白色或灰白色，大腿部烟灰色。雌鸟相似，但色泽较暗淡，黑色部位呈灰黑色，与灰白腹部界限不明显。幼鸟描述不明。亚种caudata体型较小，尾部白色显著减少。","call":"鸣唱为响亮而刻意的“dad dad dad dad”重复音节。","habits":"栖息于高海拔山林、亚高山灌木丛及亚高山森林与高山草地生态交错带，最高记录海拔可达3900米。推测为留鸟。以昆虫为主食，几乎全部通过空中捕食获取猎物，主要在树冠层（约75%的观察记录）和中间层（约25%）活动。","breeding":"卵呈灰褐色，布满灰褐色斑点，尺寸约为22–24 x 15.8–17.8毫米。关于繁殖行为的其他信息未知。","identification":"与白翼鸲相比较，本种具有白色而非黑色的腹部，雄鸟头部和上体黑色，雌鸟颜色较为暗淡。","protection":"IUCN：LC（无危）；限制分布物种，仅见于中央巴布亚山脉特有种分布区。数量稀少，研究资料较少。","distribution":"新几内亚山区，包括Carstensz Massif（Nassau Range）、Central Highlands以及Wharton和Owen Stanley Ranges，分布海拔介于2750至3700米之间。"},{"name":"火红鸲鹟","english_name":"Flame Robin","scientific_name":"Petroica phoenicea","overview":"火红鸲鹟（英文名：Flame Robin，学名：Petroica phoenicea），是雀形目鸲鹟科岩鸲鹟属的鸟类。体型较小的澳大利亚鸲鹟，雄鸟头背石板灰色，胸腹亮橙红色；雌鸟褐色。主要分布于澳大利亚东南部和塔斯马尼亚的森林、草地及农田等开阔生境。","appearance":"体长12–14厘米，体重11–14.5克。雄鸟头至上背深灰色，前额具白色小点；翼黑灰色，次级飞羽及覆羽形成宽阔白色翼斑；尾羽深灰色，白色量个体差异大；颏喉黑色，胸至上腹橙红色，下腹及尾下覆羽白色。雌鸟头背褐色，前额淡褐色小斑，眼圈细白；翼暗褐色，具淡褐色翼斑；尾似雄但褐色；颏喉灰褐，胸略深，向下渐淡，个别胸部带淡橙色。幼鸟褐色具淡色纵纹，翼尾似雌，下体具灰褐与乳白相间斑纹；亚成鸟似雌。","call":"鸣唱为略下降的笛音三句三音节序列，持续重复，可拟作“you-may-come, if-you-will, to-the-sea”。联络叫声为短促“tlip”；雄鸟在巢位附近示爱时发出喘息声。","habits":"繁殖期栖息于海拔至1800米的湿润至潮湿桉树林及疏林，非繁殖期降至低海拔，活动于干燥桉树林、草地、农田和公园。具迁徙性，3月离巢，8月返回高地。迁徙时成小群，通常12–15只，偶达30只。食物为节肢动物，多在地面捕食，亦从低栖木飞扑。觅食策略随季节变化：春季以扑击为主，夏季和秋季空中飞捕比例升高，冬季以地面拾取为主。","breeding":"繁殖期8月至次年2月，可育3窝。每年重新配对，雄鸟在求偶及整个繁殖期持续喂雌。巢由雌鸟独自筑造，杯状，用草、树皮、根须、蕨绒外覆蛛网，常贴树皮地衣，内衬细草、羽毛、毛发等，外径6.9–12.7厘米，高5.7–8.9厘米，内径4.4–5.1厘米，深3.2–3.8厘米，通常离地4–8.5米，最高35米。每窝3枚（偶4枚）淡暖蓝色卵，具棕色斑点，平均18.3×14.2毫米。雌鸟孵卵15–17天；雏鸟裸出，第2天头出绒；雌鸟育雏前3天，之后双亲共同喂养，巢期约17天，离巢后继续喂养21–37天。巢常被淡色杜鹃及扇尾杜鹃寄生。孵化成功率约40%，出飞成功率约25%，天敌包括灰鵙鹟、斑噪钟鹊及蛇类。最长寿命记录9年2个月。","identification":"雌鸟在塔斯马尼亚与雌暗色鸲鹟相似，但后者翼无淡色斑块。与同属其他种相比，雄鸟橙红胸腹及白色翼斑显著；雌鸟褐色体羽和淡色翼斑亦可区分。","protection":"IUCN: LC（无危）。虽全球评估为无危，但当前在澳大利亚被视为近危。20世纪80年代以来数量明显下降，原因未完全明确，可能与气温升高及西部非繁殖地退化有关。","distribution":"繁殖于澳大利亚东南部，自新南威尔士州东北部向南至维多利亚州南端，并见于巴斯海峡岛屿（金岛、弗林德斯岛）及塔斯马尼亚。非繁殖期北迁，可达昆士兰州极东南角，向西至南澳大利亚州东南端（约克半岛以东）。","other":"本种为单型种，无亚种分化。"},{"name":"太平洋鸲鹟","english_name":"Pacific Robin","scientific_name":"Petroica pusilla","overview":"太平洋鸲鹟（英文名：Pacific Robin，学名：Petroica pusilla），是雀形目鸲鹟科岩鸲鹟属的鸟类。在梅拉尼西亚和波利尼西亚的岛屿上被发现，与澳大利亚的红胸鸲相类似，直到1999年才由Schodde和Mason将其区分为不同物种。太平洋鸲鹟有十三个亚种，在外表、觅食偏好和栖息环境上表现出显著差异。此前，诺福克鸲曾被认为是太平洋鸲鹟的一个亚种，但现在被视为一个独立的物种。","appearance":"太平洋鸲鹟是一种小型雀形目鸟类，体长11.5至13.5厘米，体重约9至11克。在其大部分分布范围内，它是体型最小的鸟类之一。雄鸟和雌鸟的羽毛颜色有明显差异，这种差异在不同的亚种间有所变化。雄鸟指名亚种为黑头、白前额、黑背、黑尾和黑色翅膀，翅膀上有白色条纹，胸部和腹部为红色，下腹和臀部为白色。雌鸟缺乏白前额和翼上的白色条纹，其黑色羽毛被深棕色羽毛取代，胸部的颜色比雄鸟更暗淡，带有更多的棕色，臀部的白色区域也较小。","habits":"太平洋鸲鹟生活在西南太平洋的岛屿上，从巴布亚新几内亚的布干维尔岛到所罗门群岛、瓦努阿图，向东延伸至斐济和萨摩亚。它们是留鸟，但在非繁殖季节可能会有小规模的局部移动。它们以昆虫、蜘蛛和伪蝎为食，主要在森林较低层觅食，偶尔也会到达森林冠层。它们会加入混合物种觅食群，通过空中捕食、摘取、飞扑等方式获取猎物。","breeding":"太平洋鸲鹟是季节性繁殖者，繁殖季节的时间因分布区域而异。在瓦努阿图，繁殖季从十月持续到一月。它们建造紧凑的巢穴，通常位于树叉或树干上，外面装饰着苔藓和地衣，使其难以被发现。每窝产卵两到四枚，多为两或三枚。雌鸟负责孵化蛋，巢穴可能受到扇尾杜鹃的寄生。","identification":"太平洋鸲鹟与澳大利亚的红胸鸲在外观上相似，但可通过分布区域和一些细微的外表差异进行区分。此外，不同亚种间的羽毛颜色和图案也有助于辨识。","protection":"IUCN：LC（无危）","distribution":"太平洋鸲鹟分布于澳新界，主要在瓦努阿图、斐济（波利尼西亚西南部）和萨摩亚（波利尼西亚中部）。根据IOC 10.2版本，polymorpha亚种已独立为所罗门鸲鹟。","other":"太平洋鸲鹟的分类历史上曾与澳大利亚的红胸鸲和新西兰的雀鸲鹟归为同一物种，后经研究确认为独立物种。"},{"name":"诺岛鸲鹟","english_name":"Norfolk Robin","scientific_name":"Petroica multicolor","appearance":"雄鸟头部大部分黑色，额部有大白色斑点，上体黑色，翼部具白色条纹，尾羽尖端微白，胸部和上腹部鲜红色，下腹白色。雌鸟颜色较暗淡，主要为褐色，胸部带粉色。幼鸟类似雌鸟，但色泽更为灰褐。诺岛鸲鹟体型在太平洋鸲鹟群中最大，但仍稍小于绯红鸲鹟。","call":"鸣声由几声‘tut’音节开始，随后是一连串快速的颤音，先降调再升调，常重复。报警叫声为短暂哨音后接快速叽喳声。","habits":"栖息于成熟的雨林，偶尔出现在棕榈树和橄榄树（Olea）林中，极少在异域桉树（Eucalyptus）森林。偏好不超过10米高的森林，地面层开阔，有深湿落叶层。以昆虫和其他无脊椎动物为主食，如蜘蛛、伪蝎子，经常加入混种觅食群。","breeding":"繁殖期为9月至12月末。筑巢于小枝丫中，距地1至15米，巢为细植物纤维构成的小杯状，内衬植物纤维或羽毛，巢外覆有苔藓或地衣。每窝产2至4枚卵，通常两枚，卵色为灰白色至浅绿色，带有灰色和棕色斑点，孵化期和雏鸟期长度未知。","identification":"与绯红鸲鹟相比，诺岛鸲鹟雄鸟的额部斑更大，体型更大，鸣声更低沉且结构不同。与太平洋鸲鹟群相比，其体型最大。","protection":"IUCN：EN（濒危）","distribution":"仅分布于诺福克岛（澳大利亚东部）。","other":"历史上曾与绯红鸲鹟视为同一物种，2015年确定为独立物种。"},{"name":"绯红鸲鹟","english_name":"Scarlet Robin","scientific_name":"Petroica boodang","overview":"绯红鸲鹟（英文名：Scarlet Robin，学名：Petroica boodang），是雀形目鸲鹟科岩鸲鹟属的鸟类。分布于澳大利亚东南部、西南部、塔斯马尼亚岛及一些近岸岛屿，包括大陆澳大利亚和其离岸岛屿。1999年，Schodde和Mason将其从原本的物种中分离出来，原种保留了multicolor的名称，现今被称为诺福克鸲鹟。","appearance":"绯红鸲鹟体型结实，头部较大，长度约为12至13.5厘米，体重介于12至14克之间。性别二色性明显，雄鸟上身、头、颈和尾巴呈黑色，翼展有大面积白色斑块，胸部和腹部呈现鲜艳的绯红色，其余部分白色；雌鸟上半身为褐色，下半身较淡，胸部有淡红色斑块，腹面为浅黄色，翅膀和尾巴的图案与雄鸟相似，但色彩较暗淡。幼鸟外观似雌鸟，但胸部缺乏红色调。","call":"其鸣唱为清脆的口哨式颤音，常被描述为“wee-cheedalee-dalee”。联系叫声为“chip”，其他叫声包括低沉的颤音、短促的“tick”声以及类似手指摩擦玻璃发出的“wheez”声。","habits":"栖息于桉树（Eucalyptus）森林和林地，尤其偏好开阔的灌木或草地环境，秋季至冬季也会迁移到更为开放的生境，甚至城市环境中。活动范围从海平面到海拔1000米。以捕食节肢动物为主，如昆虫和蜘蛛。觅食高度和技巧随季节变化，冬季主要在地面觅食，夏季和春季则倾向于从树皮和树叶上捕食。通常单独活动，偶尔会加入冬季的混合物种觅食群。","breeding":"繁殖季节为7月至次年2月，一对繁殖，每年产两至三窝，有时可达五窝。雄鸟会对雌鸟进行求偶喂食。巢由雌鸟建造，耗时4至10天，巢形紧凑，主要材料为树皮条、根须和草，外部用蛛网固定，装饰有苔藓和地衣，内部衬以植物绒毛、兽毛和羽毛。巢位一般位于水平或倾斜的树叉中，有时也在空心树桩或小洞穴中，高度从地面到24米不等，平均约6米。每窝产卵1至4枚，平均3枚，卵壳颜色为淡蓝色、灰色或绿色，布满深棕色和橄榄棕色的斑点或斑块，平均尺寸为18.7×14.2毫米。孵化期14至18天，主要由雌鸟承担，偶尔雄鸟也会协助。幼鸟由双亲共同喂养，约在16至18天后离巢。巢寄生现象常见，寄生者包括扇尾杜鹃、灌丛杜鹃、淡色杜鹃和金鹃。成功孵化率48%至56%，成功育雏率8%至40%。","identification":"与塔斯马尼亚的暗色鸲鹟相比，绯红鸲鹟在翼展上有明显的白色斑块。亚种leggii在塔斯马尼亚和巴斯海峡的弗林德斯岛上发现，而campbelli则出现在西澳大利亚西南部。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东南部、西南部和塔斯马尼亚岛，以及澳大利亚西南部的部分地区。在大陆澳大利亚及塔斯马尼亚均有稳定分布。","other":"绯红鸲鹟的寿命记录最长为10年零1个月。"},{"name":"红头鸲鹟","english_name":"Red-capped Robin","scientific_name":"Petroica goodenovii","overview":"红头鸲鹟（英文名：Red-capped Robin，学名：Petroica goodenovii），是雀形目鸲鹟科岩鸲鹟属的小型鸟类，主要分布在澳大利亚内陆，偏好干燥环境中的灌木和开阔林地。雄鸟拥有醒目的红色头顶和胸部，黑色上体，白色翼斑；雌鸟颜色较淡，呈灰褐色，有微弱的红色前额。这种鸟以昆虫为食，善于地面捕食。","appearance":"红头鸲鹟体型小巧，长度约10.5至12.5厘米，重量在7至9克之间。雄鸟头部、颈部和上体黑色，具鲜亮的红色前额和胸部，肩部和下体白色，翼上有显著的白色斑块。雌鸟上体灰色至棕褐色，下体偏白，翼部和尾部有淡色斑纹，前额可能带有淡红色。幼鸟外观类似雌鸟，但羽色更显斑驳。","call":"红头鸲鹟发出金属质感的‘drit-drit-drrr-it’的鸣唱声，以及短促的‘tick’叫声，有时会发出尖锐的连续音。","habits":"红头鸲鹟栖息于澳大利亚内陆的干燥地带，偏好灌木丛和开阔的林地。它们主要以昆虫和其他小型节肢动物为食，通过从低矮的栖木俯冲捕食地面猎物。它们的活动范围广泛，通常在地面或低枝上寻找食物。","breeding":"繁殖期从六月底持续到一月中旬，每季可育雏2至3窝，偶尔可达4窝。雄鸟和雌鸟共同维护领地，雌鸟负责筑巢，巢为紧凑的杯状结构，位于树叉或灌木丛中，离地高度从0.3米到9米不等。雌鸟独自孵化，雄鸟辅助喂养雏鸟。雏鸟孵化后，父母双方共同喂养，直至幼鸟离巢。","identification":"雄性红头鸲鹟与同属的其他物种如火焰鸲鹟和红胸鸲鹟相比，可通过其红色的头顶和较小的体型来区分。雌鸟和幼鸟与这些近缘物种的区别在于前额的红色调和更白的下体。","protection":"IUCN：LC（无危）","distribution":"红头鸲鹟遍布澳大利亚内陆大部分地区，但在塔斯马尼亚、开普约克半岛、北部顶端和金伯利地区的大部分地区较为罕见。在澳大利亚大陆的内陆区域广泛分布，但在东海岸和南部沿海地区较少见。","other":"红头鸲鹟的社会行为研究尚少，但已知它们在繁殖季节中表现出强烈的领土性。"},{"name":"雀鸲鹟","english_name":"Tomtit","scientific_name":"Petroica macrocephala","overview":"雀鸲鹟（英文名：Tomtit，学名：Petroica macrocephala），是雀形目鸲鹟科岩鸲鹟属的鸟类。小型森林鸟，以其大头小尾的独特外观著称，仅见于新西兰的北岛、南岛、斯纳尔斯群岛、奥克兰群岛和查塔姆群岛。雄鸟通常呈黑白色，而雌鸟为棕白色，头部和喙基部有白色斑点，用于威胁展示。偏好成熟的本土森林，但也可见于灌木丛和异域森林。","appearance":"雀鸲鹟体长约13厘米，体重11-13克。雄鸟具有黑色的头部、颈部和上身，白色额头斑点，上翼黑色，翼根有白色横条纹，尾羽中央三对黑色，T4黑色尖端白色，T5白色基部黑色，T6白色基部黑色，尖端宽黑色；下身颜色由黑色渐变为黄色或橙色边缘。雌鸟暗橄榄褐色，上身有细白条纹，翅膀和尾巴黑色变为黑褐色，下巴和喉咙暗灰色，下身黄白色，胸腹部常有橄榄褐色晕染。幼鸟较成鸟暗淡且更棕色，有斑驳和细条纹。","call":"雄鸟的歌声清脆悦耳，类似于‘ti-oly-oly-oly-ho’，常被比作吱吱作响的门轴声。此外，还有1-5个‘zet’音符在单独觅食时发出，可能作为联系叫声，以及2-7个‘seet’音符在受干扰时发出，伴随软绵绵的紧密哨音。","habits":"雀鸲鹟栖息于成熟和再生的本土森林，从低地到高山地带，包括松树种植园、农田、公园和花园。它们在所有高度觅食，偏好森林底层，偶尔在开阔地带活动。主要以昆虫和其他无脊椎动物为食，偶尔食用果实。","breeding":"繁殖季节在8月至3月（北岛），9月至2月（南岛），10月至12月（离岸岛屿）。一季通常育两至三窝，每窝2-6枚蛋，孵化期14-18天。雌鸟为主孵化，雄鸟偶尔协助。幼鸟裸体孵化，约3天后开始长毛，5天后全身覆盖绒毛。巢由雌鸟建造，由苔藓、树叶、树根、草和树皮构成，外部以蜘蛛网固定，内部铺以细草、羽毛、毛发和树蕨鳞片。","identification":"与其他岩鸲鹟属物种相比，雀鸲鹟的特征在于其头部较大，尾部较短，以及独特的黑白或棕白色羽毛。不同亚种间存在体型和羽毛颜色上的差异。","protection":"IUCN：LC（无危）。雀鸲鹟在当地常见，但由于栖息地破坏和外来捕食者的引入，种群数量曾一度下降，但近年来似乎已稳定，部分地区甚至有所增加。然而，查塔姆群岛亚种chathamensis被列为Endangered（濒危），而marrineri亚种则列为Naturally Uncommon（自然稀少）。","distribution":"分布于新西兰的北岛、南岛、斯图尔特岛北部、查塔姆群岛、斯纳尔斯群岛和奥克兰群岛。在斯纳尔斯群岛，种群密度估计为250-999成熟个体，面临潜在的灭绝风险。","other":"雀鸲鹟已适应了新西兰生物多样性的变化，但仍然受到家猫、黑鼠和普通刷尾负鼠等外来捕食者的威胁。"},{"name":"北岛鸲鹟","english_name":"North Island Robin","scientific_name":"Petroica longipes","overview":"北岛鸲鹟（英文名：North Island Robin，学名：Petroica longipes），是雀形目鸲鹟科岩鸲鹟属的鸟类。为新西兰特有种。主要分布在新西兰北岛中部以及几个离岸的无掠食者岛屿上。雄鸟几乎全黑，喙基部上方有一小白斑点，雌鸟和幼鸟则呈现较浅的灰色，胸部和喉部有较淡的斑块。其好奇心强，对人类并不避讳。","appearance":"体长约18厘米，体重介于25.9至35克之间。雄鸟具有一圈窄白眼环，喙基部上方有小而分离的白色斑点，头部、颈部、背部及大部分腹部为深烟灰色，腹部至尾下覆羽为纯白色；雌鸟与雄鸟相似，但总体颜色略浅，腹部白色区域较小且有轻微的灰色条纹；幼鸟更接近雌鸟，但色调更棕色，前额斑点更小。翼部深褐色，次级飞羽和内侧初级飞羽的内缘有隐蔽的白色斑点。","call":"雄鸟的鸣唱由一系列相同音符组成，例如“tink, tink, tink, tink, tink, tonk, tonk, tonk, tonk, tonk”，与岩鸲鹟的歌曲非常相似。叫声为“chuk”，并有多种变体。","habits":"栖息于成熟的本土森林和一些老的外来森林，包括松树（Pinus）种植园，以及小岛上的次生灌木丛。以各种昆虫为食，从大型蝉到蜘蛛，偶尔也会食用浆果。在地面2米以内觅食，常在落叶中寻找食物，通过颤动脚部和抖动翅膀尾巴来惊扰猎物，偶尔会将食物储藏在原木顶部、苔藓覆盖的树枝间或其它地方。","breeding":"繁殖期通常在9月至1月，好的年份可能会有两到三窝。一夫一妻制，有时终身伴侣。雄鸟在整个繁殖季节喂养雌鸟。雌鸟筑巢，巢通常位于树干或大枝的分叉处，高0.9至13.6米，每窝产1至3枚蛋，主要是2至3枚，孵化期18至20天。雏鸟由双亲共同喂养，离巢后约30至50天仍被喂食。长尾角鸮会寄生在它们的巢中，导致繁殖成功率较低。","identification":"与其他岩鸲鹟属物种相比，北岛鸲鹟的羽毛颜色稍暗，腹部的白色部分仅限于中央腹部，而非从中胸延伸至肛门。体型较小。","protection":"IUCN：LC（无危）","distribution":"分布于新西兰北岛及其周边卫星岛屿。","other":"曾与南岛鸲鹟被视为同种，但因羽毛颜色、条纹差异及体型大小被确认为独立物种。"},{"name":"新西兰鸲鹟","english_name":"South Island Robin","scientific_name":"Petroica australis","appearance":"南岛鸲鹟长约18厘米，体重33至47克。雄鸟指名亚种为头、颈及上部呈炭灰色，具黑色带分离喙基与小白色额斑；雌鸟与雄鸟相似，但上体、喉及侧腹略显苍白。幼鸟似雌鸟，但略带棕色，前额斑点减小；幼鸟与成鸟难以区分，但保留幼鸟的初级飞羽和初级覆羽（这些羽毛磨损）。","call":"雄鸟的鸣唱是一系列短促音符组成的乐句，音调起伏，‘叮叮叮叮叮咚咚咚咚咚’，已识别出114种音符类型，平均个体曲目含23.6种音符。叫声为下降的非常响亮的音符串，用于宣示领地、间距或联络。","habits":"南岛鸲鹟栖息于多种森林环境，包括Manuka和kanuka灌木丛，Nothofagus-podocarp森林，以及成熟的Douglas fir森林。以昆虫为主食，包括大型蝉、毛虫、大蛾、wetas、stick-insects、蚯蚓、甲虫、蜘蛛等，偶尔吃浆果。大多数觅食活动发生在地面以上2米范围内。","breeding":"繁殖季节从5月初到3月底，多数在7月至12月。雌雄配对，通常终生相伴。巢由雌鸟建造，位于树干分叉处或空洞中，高离地0.8至8.7米。每窝产卵2至4枚，孵化期17至19天，雏鸟由双亲喂养，离巢期19至22天。父母双方会在雏鸟离巢后继续喂养33至48天。","identification":"雄鸟与雌鸟的主要区别在于胸部颜色的对比度，雄鸟的对比更鲜明。幼鸟与雌鸟相似，但颜色较暗淡。与其他物种的区别主要通过声音和行为模式来辨识。","protection":"IUCN：LC（无危）。局部常见或相当常见，但在某些地区稀少。总体数量似乎在下降，主要是由于栖息地丧失和入侵捕食者的威胁。","distribution":"主要分布在新西兰的南岛和斯图尔特岛，包括Green、Motonui、Jacky Lee、Poutama和Tamaitemioka等小岛屿。","other":"南岛鸲鹟在被毒杀计划清除捕食者后，繁殖成功率显著提高。"},{"name":"查岛鸲鹟","english_name":"Black Robin","scientific_name":"Petroica traversi","overview":"查岛鸲鹟（英文名：Black Robin，学名：Petroica traversi），是雀形目鸲鹟科岩鸲鹟属的鸟类。罕见的小型鸟类，仅分布于新西兰东海岸的查塔姆群岛。与南岛鸲鹟亲缘关系密切。查岛鸲鹟的全身几乎呈深褐色至黑色，飞行能力较弱，适应了没有哺乳类捕食者的环境，这使它在引入物种如猫和鼠后变得脆弱。","appearance":"查岛鸲鹟体长约10-15厘米，全身呈现暗褐色至黑色，脚部黄色底色，眼睛深棕色。雌雄体型相似，但雌鸟略小。雄鸟的鸣唱由5到7个简单的音符组成，叫声为高音单音。","call":"雄鸟鸣唱简单，由4-5个清澈的音符构成；雌鸟偶尔发出短暂的叫声。","habits":"查岛鸲鹟栖息于低海拔的灌木林和森林残片中，以昆虫为食，常在地面或低矮枝条上觅食，偏好在树洞或树桩中筑巢。它们在强风和恶劣海况下，会藏身于森林较低层或有深厚落叶层的平地。它们主要在白天和夜间寻找食物，具有良好的夜视能力。","breeding":"繁殖季节通常在10月至12月，一对知更鸟每年可能产下一至三枚蛋，通常为两枚。蛋的颜色为乳白色，带有紫色斑点。雌鸟负责孵化，孵化期约18天。幼鸟在出生后约23天离巢，但父母会继续喂养幼鸟直至约65天大。平均寿命约为四年，部分个体可达6至13年。","identification":"查岛鸲鹟与本地的雀鸲鹟相比，后者腹部颜色较浅，不会混淆。其独特的生活习性和分布区域也是辨识的重要依据。","protection":"IUCN：VU（易危）","distribution":"查岛鸲鹟仅分布于新西兰查塔姆群岛的Mangere和Rangatira岛屿。曾经在查塔姆群岛主岛上生存，但在人类活动影响下，现仅限于Mangere和Rangatira岛屿。","other":"查岛鸲鹟经历了严重的人口瓶颈，几乎所有现存个体都源自1980年的唯一繁殖雌鸟“Old Blue”。尽管遗传多样性极低，但似乎并未引发严重的近亲繁殖问题。"},{"name":"所罗门鸲鹟","english_name":"Solomons Robin","scientific_name":"Petroica polymorpha","overview":"所罗门鸲鹟（英文名：Solomons Robin，学名：Petroica polymorpha），是雀形目鸲鹟科岩鸲鹟属的鸟类。原本是太平洋鸲鹟的一个亚种，但在最新的国际鸟盟（IOC）分类系统中，已经将其分拆为独立物种。","appearance":"关于所罗门鸲鹟的具体外观特征，文献中并未提供详尽描述，一般而言，属于鸲鹟科的鸟类通常具有鲜艳的羽毛颜色，以及较为紧凑的身体结构。","habits":"所罗门鸲鹟生活在所罗门群岛的山区，偏好居住在亚热带或热带的湿润山林和亚高山灌木丛中。","identification":"所罗门鸲鹟与同属的其他物种的区别在于其分布区域的独特性，即仅限于所罗门群岛的山区。","protection":"IUCN：LC（无危）","distribution":"所罗门鸲鹟的分布范围局限于太平洋中的所罗门群岛山区，特别是在亚高山森林和湿润的山地环境中。","other":"所罗门鸲鹟在最近的国际鸟盟（IOC）分类更新中，从太平洋鸲鹟中分离出来成为独立物种。"},{"name":"巴布亚薮鸲","english_name":"Papuan Scrub Robin","scientific_name":"Drymodes beccarii","overview":"巴布亚薮鸲（英文名：Papuan Scrub Robin，学名：Drymodes beccarii），是雀形目鸲鹟科薮鸲属的鸟类。中等体型的薮鸲，具有明显的长尾。曾被误认为与北方薮鸲同种，后经遗传学研究确认为独立物种。分布于新几内亚及阿鲁群岛，共三个亚种。","appearance":"成年巴布亚薮鸲长约20厘米，体重36至58克。头部眼上方至颈部侧面有垂直黑色条纹，耳羽和颈侧呈灰色，额头及头冠至背部暗褐色带微红棕色调。翼上部黑褐，有两道显著白边形成翼条，尾羽亮红棕，末端四对尾羽宽幅白尖。下部灰白色，腹部两侧泛红棕色。眼睛深褐色，喙黑色，腿粉色。性别间外观相似，幼鸟细节未知，但报告称其上部较暗淡，喉部和胸部具斑点。","call":"鸣唱为缓慢、哀婉、拉长的上升哨音，重复五次以上，音调逐渐下降，常从密林深处连续数分钟发出。警戒声为短促的“skusssh”。","habits":"栖息于山脚及低海拔森林地面，以小无脊椎动物为食。通常单独觅食，善于隐蔽，利用喙翻动落叶和地表杂物寻食。","breeding":"关于繁殖信息尚无具体记载，推测与近缘种纹眉薮鸲的繁殖习性类似。","identification":"独特的垂直黑色眼纹及白色翼条，长而白尖的尾羽使其在良好观察条件下易于识别。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚西部、北部、南部和东南部，包括阿法克山脉、万达曼山脉、福贾山脉、西克洛普斯山脉、贝瓦尼山脉、托里塞利山脉和阿德尔伯特山脉；以及阿鲁群岛。","other":"在新几内亚东南部的瓦里拉塔国家公园有其栖息地记录。"},{"name":"纹眉薮鸲","english_name":"Northern Scrub Robin","scientific_name":"Drymodes superciliaris","overview":"纹眉薮鸲（英文名：Northern Scrub Robin，学名：Drymodes superciliaris），是雀形目鸲鹟科薮鸲属的鸟类。长腿的鸣禽，以其独特的黑色眼纹和斑驳的羽色而著称。主要分布在澳大利亚约克角半岛东北部的雨林地带，这里是其专属的栖息地。","appearance":"成年纹眉薮鸲体型约为21至22厘米，体重42至46克。上体呈肉桂棕色，臀部和尾上覆羽亮红褐色，翅膀黑色带白色边缘，形成明显的翼斑。尾巴红褐，外侧四对尾羽宽幅白尖。下体淡黄色，腹部侧面和胁部带有红褐色。眼先和眼后有一块白色，从眼睛上方到喉咙两侧有一条黑色垂直条纹，这是识别该物种的关键特征。两性相似，幼鸟信息较少，但通常更暗淡且偏红褐色，翅膀覆羽有红褐色边缘。","call":"纹眉薮鸲的声音包括一系列清晰、细长的哨声，还有粗糙的责备音符。","habits":"这种鸟类偏好有丰富落叶层的雨林环境，常在低矮处或地面活动。它们是留鸟，很少有环志个体的回收记录，所有记录都在距离原环志地点10公里以内。主要以昆虫和其他小型无脊椎动物为食，通过翻动落叶和地表碎片觅食。","breeding":"繁殖季节为11月至翌年1月晚期。雌鸟会建造一个开放碗状的巢，由枯枝、细根、藤蔓和其他植物纤维构成，内部铺有死叶，放置于地面的凹槽中，通常位于树基、灌木或倒木旁。每窝产两枚灰底蓝灰和红褐色斑点的蛋，尺寸约22至25.4 x 17.8毫米。孵化由雌鸟或双亲共同承担，但关于孵化期和雏鸟成长期的具体时间未知。已知最长寿命为五年零11个月。","identification":"纹眉薮鸲最显著的辨识特征是其通过眼睛的黑色垂直条纹，以及翅膀上的白色条纹。它与巴布亚薮鸲有遗传差异，曾被认为属于同一物种。","protection":"IUCN：LC（无危）","distribution":"纹眉薮鸲分布于澳大利亚东北部，特别是在约克角半岛北部的雨林中。它们是当地的特有种，虽然分布范围相对较小，但种群稳定，没有显著的下降趋势或严重威胁。","other":"曾有一争议性的亚种D. s. colcloughi，即Roper River scrub robin，但因标本来源存疑，至今无后续记录，其分类地位尚不明朗。"},{"name":"栗腰薮鸲","english_name":"Southern Scrub Robin","scientific_name":"Drymodes brunneopygia","overview":"栗腰薮鸲（英文名：Southern Scrub Robin，学名：Drymodes brunneopygia），是雀形目鸲鹟科薮鸲属的鸟类。包括西澳大利亚西南部至新南威尔士州中部和维多利亚州西部。以灰褐色上体、红褐色尾巴和黑白相间的翅膀为显著特征，拥有异常长的腿。","appearance":"成年栗腰薮鸲约22厘米长，其中约三分之一是尾羽长度。上体呈灰色，尾巴红褐色，翅膀有黑色和白色的图案。脸部侧面和颈部为棕色，有淡淡的眉纹，白色眼圈，眼睛上有短的垂直黑色条纹。头部和颈背至背部为暗灰棕色，臀部深棕色，上尾覆羽红棕色。翼部灰棕色，中等和大翼覆羽有淡色尖端形成双翼斑。尾巴深锈色，除中央一对尾羽外，其余尾羽尖端白色。下巴白色，逐渐变为棕色喉咙和下体，腹部较浅，肛门区域棕色。虹膜深棕色，喙和腿黑色。两性相似。幼鸟为灰棕色，有淡色条纹和更深的斑点，翼覆羽有条纹。亚成鸟与成鸟类似，但保留了幼鸟的条纹翼覆羽。","call":"鸣唱为悦耳的“chip chip par-ee”。可能的联系叫声为尖锐的高音“pee-pee”；报警声为连续的咔嚓声，“charr-rrr-tuk-ertuk-ertuk”。","habits":"生活在密集的灌木丛和半干旱的植被中，特别偏好扫帚灌木，同时出现在海岸茶树厚林和桉树林带浓密下层的地方。几乎完全在地上觅食（至少98%的时间），主要在密集覆盖下活动，用喙拨开枯叶寻找昆虫和其他小无脊椎动物。","breeding":"繁殖季节在7月至12月之间。巢由树枝构成，建于地面，内衬树枝、草和树皮。南方薮鸲异常地只产一枚蛋，蛋为灰绿色，用于伪装在硬叶植被中。孵化期约为16天。幼鸟在10-13天后离开巢穴，但会继续由双亲喂养一段时间。","identification":"通过其独特的红褐色尾巴、黑白相间的翅膀和长腿与同类区分开。","protection":"IUCN：LC（无危）。在新南威尔士州，根据《2016年生物多样性保护法》列为易危物种。","distribution":"分布在澳大利亚南部，包括西澳大利亚的零星地点，南澳大利亚东南部（从艾尔半岛向东，弗林德斯山脉以南），新南威尔士州中部和维多利亚州西北部。"},{"name":"大地鸲","english_name":"Greater Ground Robin","scientific_name":"Amalocichla sclateriana","overview":"大地鸲（英文名：Greater Ground Robin，学名：Amalocichla sclateriana），是雀形目鸲鹟科地鸲属的中型鸟类，体长约20厘米。其最显著的外部特征是棕色头部和上体延伸至胸部两侧，腹部呈淡灰色，喉部和腹部中央为白色，有时胸部可见一些斑点。分布于新几内亚山区的亚高山森林地带，约2800至3720米之间。","appearance":"成年大地鸲的冠部和上体为深橄榄棕色，头部侧面呈暖棕色，眼周为浅灰黄色；翅膀深棕色，飞羽和翼覆羽边缘带锈色，次级飞羽尤为明显；尾巴深橄榄棕色；下巴和上喉部分为淡灰色，带有棕色细斑；下喉至颈部侧面为近白色；胸部有灰色棕色斑点，腹侧和两胁为灰色，腹部中心至淡黄白色；翼下有淡色条纹跨过飞羽基部；虹膜深棕色；喙为暗棕色，下颌较浅；腿为稻草棕色。雌雄相似。幼鸟头部和背部呈淡锈色，带有黑色斑点，翼覆羽具锈黑相间的横斑，胸部羽毛红棕色，尖端狭窄呈黑色。","call":"具有独特而短促的哨声，听起来像‘What do you think？’，最后一个音节上扬。同时也发出尖锐的责骂式警报叫声。","habits":"栖息于海拔2500至3900米的高山森林，以昆虫为食，如甲虫。","identification":"与小地鸲相比，大地鸲体型更大，出现在更高海拔，叫声更为独特。","protection":"IUCN状态未知。","distribution":"分布于新几内亚的中部和东南部山区。"},{"name":"小地鸲","english_name":"Lesser Ground Robin","scientific_name":"Amalocichla incerta","overview":"小地鸲（英文名：Lesser Ground Robin，学名：Amalocichla incerta），是雀形目鸲鹟科地鸲属的鸟类。体型较小，山地森林地面活动鸟。以其独特的外观和习性著称。分布于新几内亚山区。","appearance":"小地鸲长约15厘米，重约30至31克。头顶和上体深棕色至赤褐色，前额侧面有白色斑点，翼部暗棕色，飞羽外缘赤褐色，近基部有赤色斑点（除最外侧四枚初级飞羽）。尾部暗棕色，尾羽外缘微带赤褐色。喉部和颈侧白色，胸部和两胁中等赤褐色，腹部白色，尾下覆羽淡赤色。下翼有浅色条纹跨过飞羽基部。虹膜棕色，喙黑色，腿灰色或灰褐色。雄雌相似。幼鸟头部和侧面有赤褐色斑点，背部和上翼覆羽有丰富的赤褐色斑点，下体有深棕色斑驳，胸部最为明显；最初缺乏白色眉斑。","call":"鸣声被描述为轻快的哨音，由数个音符组成；单一个体能发出两种不同的八音符歌曲，第一首大体下降，第二首几乎在同一音高持续，交替歌唱，仿佛不在同一地点重复（以前认为涉及两只个体的对唱）。叫声为短暂的高音鼻音嗡嗡声，后接刺耳的‘ch-ch-ch-ch-ch’连续颤音。","habits":"生活在新几内亚的山地森林地面，偏好较低海拔区域。比同类物种大地鸲体型更小，常听到其声音而难见其身影。其习性与大地鸲相似。","breeding":"筑巢于十月中期，孵化期在一月初；幼鸟出现在十二月。巢为开放式的杯状，主要由苔藓构成，辅以草叶和细根，内衬干草，直径约4厘米，深约3厘米，通常位于地面靠近覆盖苔藓的树根旁，周围散落树叶和枝条；也曾发现筑巢于树洞中，离地面1.2米，树洞深30厘米，开口两边，树干直径20厘米。一窝仅一枚蛋，白色，有少量深褐色或黑色小斑点集中在较大端，或遍布细小巧克力色斑点，尺寸约为28×19.5毫米；关于孵化和雏鸟期的信息未知。","identification":"与大地鸲相比，小地鸲体型更小，出现于更低海拔，通过其特定的鸣声和外观细节加以区分。","protection":"IUCN状态未知。","distribution":"分布于新几内亚的山地区域。"},{"name":"白颈岩鹛","english_name":"White-necked Rockfowl","scientific_name":"Picathartes gymnocephalus","overview":"白颈岩鹛（英文名：White-necked Rockfowl，学名：Picathartes gymnocephalus），是雀形目岩鹛科岩鹛属的鸟类。又名: 秃头岩鹛，又称秃头岩鹛，中等体型的岩鹛科鸟类，主要分布在西非的几内亚南部到加纳的高海拔岩石森林地带。其独特的外观特征包括裸露的黄色头部和两侧的黑色斑块，上身呈现灰黑色，下体白色。","appearance":"白颈岩鹛拥有33至38厘米的体长，体重介于192至254克之间。其头部大部分裸露，呈黄色，与黑色的后侧形成鲜明对比；上体颜色偏暗，略带褐色，尤其是肩部和尾巴；下体白色，带有淡柠檬黄色的色调，逐渐过渡到喉咙和腹部的浅黄色。眼睛棕色，瞳孔蓝黑色；喙和腿分别为黑色和银灰色。性别相似，幼鸟类似成鸟，但头部的黄色皮肤上有深色斑点。","call":"通常保持沉默，但在特定情境下会发出低沉的咕咕声和其他柔和的接触叫声。","habits":"居住在低地森林、丘陵森林以及次生灌木丛中，偏好有大石头和洞穴的环境用于筑巢和栖息。在森林地面成对或成群觅食，夜晚返回岩石集体栖息。主要在湿润的季节繁殖，筑巢于岩石表面、悬崖或洞穴顶部的泥杯状巢穴。","breeding":"繁殖期与雨季同步，通常在6月至12月间产卵，巢中通常有2枚蛋。孵化由双亲交替进行，平均孵化期约20天。幼鸟由双方喂养，离巢期一般为25至26天。繁殖成功率较低，受到捕食、同类相残、竞争和不育蛋的影响。","identification":"其独特的裸露头部、黄色皮肤和黑色斑块，以及特殊的栖息地选择，使其易于与其他物种区分开来。与其他岩鹛科成员相比，白颈岩鹛的头部特征尤为显著。","protection":"IUCN：VU（易危）","distribution":"分布于几内亚南部至加纳的西非森林带，包括塞拉利昂、利比里亚、象牙海岸等地。在几内亚、塞拉利昂和象牙海岸的部分地区较为常见，但在利比里亚和加纳则相对较少。","other":"该物种在1990年代成为生态旅游和雨林保护的象征，且在某些地区的土著文化中被视为守护者。"},{"name":"灰颈岩鹛","english_name":"Grey-necked Rockfowl","scientific_name":"Picathartes oreas","overview":"灰颈岩鹛（英文名：Grey-necked Rockfowl，学名：Picathartes oreas），是雀形目岩鹛科岩鹛属的鸟类。中等体型的岩鹛科鸟类，主要分布在非洲喀麦隆南部、尼日利亚北部以及中非地区的加蓬和刚果西北部。以独特的灰颈和长尾著称，常在雨林中岩石地带活动，尤其偏好靠近水源的地方。该物种的分布呈斑块状，各族群间可能相互隔离。","appearance":"灰颈岩鹛的体长约为33到38厘米，尾部占约14厘米，体重介于200至250克。头部几乎无羽，前额和上喙基部皮肤呈粉蓝色，后冠和颈背皮肤为深红色，两颊和眼周覆盖黑色裸皮。上体和尾部呈暗蓝灰色，翼羽黑，形成明显的色带。颈部、喉部至上胸为淡灰色，其余下体为柔和的柠檬黄色至淡黄褐色。虹膜深棕色，喙黑色，腿脚银灰色，肌肉发达。雌雄相似，幼鸟头部颜色不明显，尾部较短。","call":"灰颈岩鹛通常较为安静，已知发出的叫声包括短暂的嘶嘶声‘wheet’，以及喂食时的‘peep’声和巢边的低沉‘ga-a-a’声。","habits":"偏好位于雨林中的崎岖地形，常与大石块、洞穴和溪流相伴。主要生活在低地，但在喀麦隆的山地可达海拔1800米。活动范围局限，非迁徙种，可耐受一定程度的人类干扰。","breeding":"在雨季繁殖，每年筑巢两次，通常在洞穴、大石下或路桥下集体繁殖。巢由泥巴、根须和纤维构成，形状似杯，平均含2枚蛋，孵化期21至24天，雏鸟期约24天。存在巢穴破坏现象，主要因同类相食和捕食导致。","identification":"与白颈岩鹛相比，灰颈岩鹛的颈部呈灰色，头侧和颊部有黑色裸皮，而白颈岩鹛的颈部为白色，头侧和颊部为黑色。","protection":"IUCN：NT（近危）","distribution":"分布于尼日利亚东南部、喀麦隆西南部至加蓬西南部和刚果共和国西南部，包括比奥科岛。","other":"灰颈岩鹛在当地文化中受到尊重甚至敬畏，是生态旅游和鸟类观察的重要对象，但由于栖息地丧失和非法捕捉，其数量受到威胁。"},{"name":"棕岩鸫","english_name":"Cape Rockjumper","scientific_name":"Chaetops frenatus","overview":"棕岩鸫（英文名：Cape Rockjumper，学名：Chaetops frenatus），是雀形目岩鸫科岩鸫属的鸟类。独特的山地鸟类，广泛分布于南非西部至东南部的Fynbos山区。雄鸟拥有深红褐色的腹部和臀部，黑色喉咙，白色髭纹；雌鸟色调较淡，具条纹胸部。本物种偏好风大、高降雨量的高山斜坡和山脊地带。","appearance":"棕岩鸫长约23-25厘米，体重54-60克。雄鸟头部为银灰色，具密集黑纹，胸至腹部为鲜艳的红褐色，尾羽黑色而尖端白色。雌鸟颜色更暗淡，上部橄榄褐色，腹部和臀部浅红色，翅膀呈褐色。幼鸟类似雌鸟，但斑纹较弱。","call":"鸣唱为一系列穿透力强的管状音符，如“psuwee-psuwee-psuwee-”或“sip-sip-psu, sip-sip-psu”。遭遇领地争执时发出短促尖锐的哨声。还有单音节的接触和警报叫声。","habits":"栖息于岩石Fynbos环境，从山脉延伸至海平面，尤其偏好强风和高降雨的高地。以昆虫为主食，偶尔捕食小型蜥蜴和两栖动物。成对或家族群居，地面觅食，常在岩石和灌木基部沙地探食。","breeding":"在岩石遮蔽处筑巢，通常由繁殖对和一至两个前季幼鸟组成家庭领域，后者参与领域防御、报警和喂养巢中幼鸟。每年尝试建巢1-5次，巢由红岩兔毛或旧的Protea种子荚衬里。","identification":"与橙胸岩鸫的区别在于后者具有淡橙色腹部，且偏好高山草原。雌雄两性差异明显，雄鸟具有鲜明的黑白头部图案。","protection":"IUCN：NT（近危）。全球数量估计在32,551至59,289只之间，面临栖息地丧失和气候变化威胁。","distribution":"分布于南非西部和西南东部开普省，具体从西开普到西南东开普省，主要在S南非。","other":"全球变暖被认为是导致其数量下降的主要因素。核心栖息地在省级自然保护区得到良好保护。"},{"name":"橙胸岩鸫","english_name":"Drakensberg Rockjumper","scientific_name":"Chaetops aurantius","overview":"橙胸岩鸫（英文名：Drakensberg Rockjumper，学名：Chaetops aurantius），是雀形目岩鸫科岩鸫属的中型鸟类。特有于南非东南部德拉肯斯伯格山脉和莱索托的高山草甸与岩石露头。与它近缘的棕岩鸫同为现存唯一的岩鸫科成员。","appearance":"体长21-22厘米，体重48-53克。雄鸟具有黑色头部，细白眉纹，宽白髭纹，背部与翅膀深灰色，橙色腹部，红棕色臀部。雌鸟与幼鸟上身较淡灰，翼部暗淡，红臀，腹部呈淡黄色。尾羽长而圆，黑色带白色尖端。","call":"发出一系列尖锐的笛状叫声，包括响亮的断音‘pree-pree-pree’，重复的‘teep-teep-téép’和‘pee-téé-teep’，有时组合在一起，与棕岩鸫的叫声在音调和类型上相似但结构不同。","habits":"栖息于陡峭的高山与亚高山草地，偏好岩石露头、碎石坡和岩石沟壑，海拔主要高于2250米。以昆虫为食，包括毛虫、蛾类和蚱蜢。在地面觅食，啄食和挖掘土壤，跳跃于岩石间。","breeding":"巢筑于地面，繁殖时可能得到前一季后代的帮助，协助父母保卫领地、示警和喂养雏鸟及离巢幼鸟。","identification":"与棕岩鸫相比，橙胸岩鸫体型较小，喙较小，下体为沙橙色而非栗色，喉咙的黑色在上胸部结束得更高，眉纹更明显，耳羽较平实。雌鸟喉部斑驳淡黄白色。","protection":"IUCN：NT（近危）","distribution":"分布于莱索托高地和相邻的南非自由州、夸祖鲁-纳塔尔省及东开普省的高山地带。","other":"全球数量估计在10万至50万只之间，部分地区冬季密度低至每平方公里1.6只。"},{"name":"白眉长颈鸫","english_name":"Rail-babbler","scientific_name":"Eupetes macrocerus","overview":"白眉长颈鸫（英文名：Rail-babbler，学名：Eupetes macrocerus），是雀形目长颈鸫科长颈鸫属的鸟类。栖息于马来半岛、苏门答腊和婆罗洲的低地和山脚森林，拥有独特的长颈、长腿和细长喙部，其外观让人联想到鹭鸟。该鸟种以棕色为底色，面部色彩斑斓，包括黑、白、黄、橙和锈红。最显眼的是白色眉纹和黑色面颊线，以及颈部的蓝色裸露皮肤。雄雌相似，幼鸟色彩较为暗淡。物种分布受限，因低地原始森林的砍伐而数量减少。","appearance":"白眉长颈鸫体长约28至30厘米，体重约66至72克。具长颈、长尾和长腿，全身主色调为暖棕色。头部特征明显，有宽白眉纹，从眼睛前方延伸至颈侧，下方由黑色条纹环绕，连接鼻基至眼眶下方，颈侧有蓝色裸露斑块。头顶至后颈为栗红色，逐渐变为上体的红褐色，上覆羽稍显深色；翅膀和尾巴为红褐色，边缘略带金色；腹部为灰褐色。雌雄羽毛相似，幼鸟较暗，喉部白色，腹部深灰褐色。","call":"白眉长颈鸫发出长而单调的哨音，音量先渐增后渐弱，伴有类似蛙鸣的‘goink’声，可能作为警报信号。","habits":"栖息于密闭树冠下的高大原始森林和被砍伐的森林，偏好底层植被丰富和较为开放的地面。也见于沼泽森林和灌木林。活动于低地至海拔1300米的山区，以昆虫为主食，包括蝉和甲虫，偶尔捕食蜘蛛。通常在地面行走，追逐猎物，受扰时更倾向于奔跑而非飞行。","breeding":"繁殖期大约在1月或2月初，幼鸟出现在6月。巢为浅杯状，由植物纤维构成，置于离地面约30厘米的落叶堆中。每窝产2枚无斑点的白色蛋。","identification":"白眉长颈鸫与其他森林地面栖鸟显著不同，具有长颈、长腿和细长喙部，面部色彩斑斓。与同属的差异在于头色更深，上体更红，下体更偏赤褐色。","protection":"IUCN：NT（近危）。在部分区域稀少至常见，但在塔曼纳加拉国家公园极为罕见。尽管在被砍伐的森林中可以生存，但低地森林的持续砍伐对其构成了威胁。","distribution":"分布于马来半岛南部泰国和马来西亚，苏门答腊，婆罗洲，以及纳土纳群岛。在马来半岛可上至海拔约1060米，苏门答腊和婆罗洲则可达900米。","other":"关于分类地位存在争议，目前认为与非洲的岩鸡有远亲关系，属于单型科Eupetidae。"},{"name":"太平鸟","english_name":"Bohemian Waxwing","scientific_name":"Bombycilla garrulus","overview":"太平鸟（英文名：Bohemian Waxwing，学名：Bombycilla garrulus），是雀形目太平鸟科太平鸟属的鸟类。又称: 十二黄，以其独特的羽毛特征和游牧式的迁徙模式闻名。体长约19-23厘米，羽毛主要呈灰褐色，脸部带有明显的黑色面罩和红褐色下腹部，头部有簇状羽冠。分布于欧亚大陆和北美北部的针叶林中，冬季迁徙路径受果实丰度影响，有时会向南迁移至非典型越冬区。","appearance":"太平鸟体态圆胖，羽毛丝滑，具有白色和黄色翼斑，头顶簇状羽冠。全身及背部灰褐色，下腹羽色稍浅，颊部和尾下覆羽为红褐色。雌雄相似，但雌鸟黑色面罩较窄，红色翼尖较少，尾部黄色带较窄。幼鸟灰度更深，腹部具斑纹，缺少成鸟的红色翼尖和面部红褐色。","call":"鸣声为高频率的颤音，结构类似雪松太平鸟，但声音粗糙且音调更低。","habits":"栖息于开阔的针叶林，主要以含糖果实为食，夏季则大量摄取昆虫。迁徙模式随果实丰度而变，冬季集群于城市公园和果园，偏好浆果和苹果等水果。","breeding":"繁殖期为6月至7月，营巢于成熟针叶树中，雌鸟单独孵化3-7枚淡蓝色带黑斑的蛋，孵化期13-14天。幼鸟由双亲喂养，初期以昆虫为主，之后转为水果。繁殖密度较低。","identification":"与雪松太平鸟相比，太平鸟体型更大，羽毛更灰，翅膀图案不同，腹部无黄色。尾端颜色和头部黑色过眼纹是辨识太平鸟的关键。","protection":"IUCN：LC（无危）；在中国，太平鸟受非法贸易威胁，被列为国家林业局《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","distribution":"繁殖于欧亚大陆和北美北部的针叶林，冬季迁徙至欧洲、亚洲和北美南部，分布范围广泛。","other":"太平鸟依赖果实，能代谢发酵果实中的酒精，但有时会因此中毒。"},{"name":"小太平鸟","english_name":"Japanese Waxwing","scientific_name":"Bombycilla japonica","overview":"小太平鸟（英文名：Japanese Waxwing，学名：Bombycilla japonica），是雀形目太平鸟科太平鸟属的鸟类。别名: 十二红、绯连雀、朱连雀。体长15-18厘米，尾端绯红色显著，与太平鸟的区别在于黑色的过眼纹绕过冠羽延伸至头后，臀部红色，次级飞羽端部无蜡样附着但羽尖绯红，缺少黄色翼带。分布于西伯利亚东部及中国东北部，越冬至日本及琉球群岛。","appearance":"小太平鸟体长约18厘米，羽毛主要呈粉红褐色。具有突出的向后指的中等长度羽冠，独特的翼纹。雄鸟有黑色面罩，从喙基延伸至眼睛上方并绕至头部后方，下颚下方有一白弧，嘴角有短白条纹，黑喉。其余羽毛多为灰褐，头部（尤其是冠部和颊区）带有温暖的赤褐色调，臀部灰。次级飞羽末端有亮栗色红边，主飞羽蓝灰至黑色，主飞羽两端有白色尖端，有时外侧有粉色斑点，二级飞羽外缘通常有小红点，尾部深灰至黑色，尾端有明亮的粉红红色带，腹部下方颜色较浅，下体常泛黄色，肛周红色；虹膜深红至暗棕；喙黑色；腿深棕色。雌鸟与雄鸟非常相似，但颜色稍淡，二级飞羽末端的小红点缺失或减少，肛周较暗，更偏赭色。幼鸟主要呈灰色，冠部较暗，腹部白色，两胁有深灰色重条纹；第一年冬季羽毛仅在外侧主飞羽有白色线。","call":"最常见叫声为高音颤鸣，与同类相似，但较短（150-380毫秒）且略高（5.5-6.4千赫兹），比太平鸟的颤音短。同时，频繁发出高音（5千赫兹）的哨声，从短（约205毫秒）到长（约540毫秒），可能代表两种不同的叫声类型。","habits":"小太平鸟主要栖息于森林区域，偏好针叶树，如落叶松（Larix）、云杉（Picea）和冷杉（Abies）。越冬时出现在落叶和混交林，以及有零星树木的开阔地带，包括公园和花园，只要存在结果实的树木。迁徙模式相对短距离，几乎完全离开繁殖区，部分个体可能在俄罗斯东南部越冬，但数量受果实产量影响。主要越冬区域为中国东部（主要是河北和山东）、韩国和日本；偶尔南至中国中部和东南部（南至云南北部和福建），琉球群岛和台湾；有记录漂泊至菲律宾。在日本，通常11月底抵达，最早10月初，4月初离开，直到5月中旬仍有迷鸟；5月返回繁殖地。在中国南方的滨海边疆地区，主要在春季迁徙时可见，秋季罕见，暗示该物种可能采取不同的南迁路线。","breeding":"繁殖信息有限，推测为较晚繁殖者；6月初开始繁殖，雌鸟标本显示6月末正处于产卵中期；8月末在玛雅河观察到幼鸟群。推测为单对繁殖。已知巢穴数量不多；巢由落叶松枝条和地衣构建，位于8-10米高的落叶松上。一窝产5枚卵，偶尔4或6枚；孵化由雌鸟承担。在圈养环境下：孵化期15-16天；离巢期16天。","identification":"小太平鸟与太平鸟的主要区别在于：小太平鸟的黑色过眼纹绕过冠羽延伸至头后；小太平鸟臀部绯红，而太平鸟臀部黄色；小太平鸟次级飞羽端部羽尖红色，翼缺黄色翼带，而太平鸟有黄色翼带，羽尖黄色；小太平鸟翅膀上不像太平鸟那样具有大面积白色。","protection":"IUCN：NT（近危物种）","distribution":"小太平鸟繁殖于俄罗斯远东地区（雅库特东部、哈巴罗夫斯克和阿穆尔）、中国东北部（黑龙江北部）；越冬主要在中国东部、韩国和日本。偶尔南至中国中部和东南部（南至云南北部和福建）、琉球群岛和台湾。"},{"name":"雪松太平鸟","english_name":"Cedar Waxwing","scientific_name":"Bombycilla cedrorum","overview":"雪松太平鸟（英文名：Cedar Waxwing，学名：Bombycilla cedrorum），是雀形目太平鸟科太平鸟属的鸟类。以红蜡状翼尖命名。这种中等体型的鸟主要呈现棕色、灰色和黄色，广泛分布于北美洲，自加拿大南部至美国南部，延伸至中美洲乃至南美的西北部。其饮食以雪松球果、水果、冬青浆果和昆虫为主。","appearance":"雪松太平鸟体长约为15至18厘米，体重约30克。它们比近亲太平鸟小且颜色更偏棕。头部和胸部为淡棕色，渐变为翅膀上的柔和灰色，腹部为淡黄色，尾巴为灰色并带有明亮的黄色尖端。脸部有窄黑面具，边缘清晰的白色线条勾勒。翅膀上的红蜡状尖端是显著特征，但在野外观察时可能不易察觉。幼鸟的喉咙和侧腹有条纹，面具不如成鸟明显。雄雌外观相似。","call":"雪松太平鸟发出非常尖锐的哨声和嗡嗡的颤音，叫声持续约半秒，常被描述为‘see’或‘sree’。在飞行时它们频繁鸣叫。","habits":"雪松太平鸟偏好树木边缘的栖息地，如林地或森林，尤其是能提供浆果和水源的地方。它们通常在城市公园、高尔夫球场、墓地和其他有间隔树木的环境中被发现。在非繁殖季节，它们会组成数百只的大群觅食。这种鸟具有迁徙习性，冬季分布范围变化不定，多数群体迁往美国南部甚至更远。","breeding":"繁殖期从春末开始至夏末，雄鸟通过跳跃舞蹈吸引雌鸟。求偶期间，双方会传递花萼或昆虫。巢由草和树枝构成，内部铺垫柔软材料，位于平均2至6米高的树干上。雌鸟筑巢需5至6天，有时会从其他鸟巢偷取材料。每窝产卵5至6枚，孵化期为11至13天。幼鸟在14至18天后离巢。","identification":"雪松太平鸟比太平鸟小，颜色更偏棕色，面具为白色而非肉桂色，且下腹为黄色。叫声也有所不同，雪松太平鸟的叫声更高亢。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大至多米尼克，冬季迁徙至美国南部、中美洲直至南美的委内瑞拉和哥伦比亚。","other":"最老记录的雪松太平鸟年龄为8岁零2个月。"},{"name":"黑黄丝鹟","english_name":"Black-and-yellow Phainoptila","scientific_name":"Phainoptila melanoxantha","overview":"黑黄丝鹟（英文名：Black-and-yellow Phainoptila，学名：Phainoptila melanoxantha），是雀形目丝鹟科黑黄丝鹟属的鸟类。几乎仅见于哥斯达黎加的特有鸟类，其分类位置尚不确定。黑黄丝鹟属唯一成员，分布于中美洲，主要在哥斯达黎加和西部巴拿马的山区森林。","appearance":"雄性黑黄丝鹟上体、尾部、头部和喉部主要为黑色，胸部呈橄榄绿色，臀部和整个腹部、侧面、腹侧及下尾覆羽明亮黄色，腹部中央灰色。雌鸟上体和头部为黑色，后颈、面部、喉部渐变为烟灰色，胸部暗橄榄绿色。幼鸟类似雌鸟，但色泽较暗淡，后颈无灰色，头顶烟黑色，胸部有淡淡的尘色条纹，两侧少有黄色。","call":"鸣叫声为尖锐、高音的‘tsit’或‘tseep’，声音清脆，给人一种小型鸟的错觉。似乎不唱歌。","habits":"黑黄丝鹟栖息于海拔1000至3400米的常绿山地森林中，主要以果实为食。它们通常单独或成对活动，行动缓慢，常长时间静坐。偶尔加入灰顶丛莺群，但很快落后。有时从树叶上抓取昆虫或空中捕捉，但并不常见。繁殖季节后，会形成松散的群体。","breeding":"巢由绿色苔藓、细茎和蕨类叶片构成的紧实杯状结构，位于密集灌木或小树的1.5至4米高度处。每窝产2枚斑点灰白色蛋。繁殖期从4月持续到5月。","identification":"沿其分布范围内，没有其他物种拥有相同的黑色和黄色羽毛模式。黑黄丝鹟属是家族中的异类，与Ptiliogonatidae家族的其他两个属相比，其外观和行为更为独特。与黑丝鹟和Ptiliogonys属不同，黑黄丝鹟没有冠羽，尾巴也不长。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加和巴拿马西部山区，具体在1800米至林线的高度，繁殖季节后可能下移至较低海拔。","other":"黑黄丝鹟是Phainoptila属的唯一成员，该属在外部形态和行为上与其他两个Ptiliogonatidae家族的属形成鲜明对比。"},{"name":"灰丝鹟","english_name":"Grey Silky-flycatcher","scientific_name":"Ptiliogonys cinereus","overview":"灰丝鹟（英文名：Grey Silky-flycatcher，学名：Ptiliogonys cinereus），是雀形目丝鹟科丝鹟属的优雅鸟类，常见于中美洲的山地森林中，包括墨西哥西北部至危地马拉。其最显著的外部特征是长尾和羽冠，以及蓝灰色到暗灰色的羽毛，腹部和尾下覆羽带有变化的黄色。","appearance":"灰丝鹟体型纤细，长度介于18.5至21厘米之间，头部有突出的羽冠，尾部长而优美。雄鸟标本种具有蓝灰色的头部（包括羽冠）和上身，暗色眼后纹；翅膀和尾巴黑色，尾基有白色横带；下巴和眼上区为淡白色或棕白色，喉咙和胸部灰色，腹部白色，两胁金橄榄色或黄色，尾下覆羽鲜黄；虹膜深色，有窄白色眼环；喙和腿黑色。雌鸟头部和羽冠灰色，上身灰褐色，两侧和两胁棕色，腹部白色。幼鸟外观似雌鸟，但下方颜色更淡。亚种molybdophanes比标本种更深色，雄鸟上方更深的蓝灰色，两胁的橄榄色更局限且呈橄榄绿色；雌鸟也更深色，除了尾下覆羽的黄色。otofuscus与前者相似，但上身颜色更浅，耳侧更暗，下身的灰色在腹部延伸不那么远，雌鸟的背部更灰，臀部和尾上覆羽更亮，胸更暗。pallescens与标本种相似但更淡更灰，雄鸟的下巴、喉咙和眼上区灰白（而非棕白），耳侧更灰少棕色，雌鸟也更淡更少棕色，有灰帽和喉咙与背部和胸部形成更鲜明对比。","call":"发出响亮的“tu whip, tu whip”叫声，第二声调更高且更强调；干燥的“chi-che-rup che-chep”和鼻音的“k-lik”；飞行中的咔哒声。安静的歌声是一系列颤音的“chuck”音符，高音的“seep”音符和轻柔的口哨。","habits":"栖息于海拔1000至3500米的松树（Pinus）、橡树（Quercus）和杜松（Juniperus）的山地森林，冬季会下降至较低海拔。主要以昆虫和浆果为食，尤其是槲寄生（Loranthaceae）的浆果对其数量至关重要；捕食空中昆虫时会从栖木飞扑。一般居民鸟，但在冬季会向低处移动，偶尔进入邻近的栖息地；在云林附近，如墨西哥的Xalapa，11月至3月间，常在1300米高度以双或三至六只的小群体出现。","breeding":"在墨西哥，5月底在塔毛利帕斯州有两只正在建造的巢，6月在莫雷洛斯州发现有雏鸟的巢。开放的杯状巢由橡树猫须、粗黑毛发和植被构成，内部垫有硬挺的Usnea苔藓，大的片状苔藓通过蜘蛛网附着在外壳上，放置在9米高的橡树上。一窝产2枚蛋；孵化和离巢期未知。","identification":"与其他丝鹟科成员相比，灰丝鹟的长尾和羽冠以及独特的色彩模式是主要的区别特征。不同亚种之间在颜色深浅和部分细节上有细微差异。","protection":"IUCN：LC（无危）。在大部分分布区内普遍到相当普遍；在墨西哥西北部（索诺拉州）较为罕见。在全球32个重要鸟类区域中被发现，包括墨西哥的七个保护区。尽管目前没有明显风险，但由于其全球分布范围有限，长期关注是必要的。被列入‘Partners in Flight Watchlist’，被视为中等保护关注。每年合法收获用于笼鸟贸易的数量超过4000只。在墨西哥Xalapa附近的云林残余地带，它是槲寄生的重要传播者。","distribution":"主要分布在中美洲，包括墨西哥西北部至危地马拉。偶尔有迷鸟记录出现在美国南部。","other":"灰丝鹟是丝鹟科中的独特物种，与黑丝鹟有亲缘关系，而非真正的鵙。"},{"name":"长尾丝鹟","english_name":"Long-tailed Silky-flycatcher","scientific_name":"Ptiliogonys caudatus","overview":"长尾丝鹟（英文名：Long-tailed Silky-flycatcher，学名：Ptiliogonys caudatus），是雀形目丝鹟科丝鹟属的鸟类。主要分布在中美洲的哥斯达黎加和巴拿马的山区，以其醒目的外观和分布区域而著称。","appearance":"雄性长尾丝鹟长约24厘米，雌鸟略小，约21厘米；体重约为37克。其最显著的特征是细长的身体，突出的冠羽和极长的尾巴，尤其是中央一对尾羽远超其余。雄鸟的额头和冠部呈灰色，头部、颈部、喉部和下腹部为黄绿色；背部、臀部、上尾覆羽和上翼覆羽为蓝灰色；飞行羽和长尾黑色，尾羽内侧有大块白色斑点。雌鸟颜色较暗淡，头部、颈部和冠部为较淡的橄榄绿黄色，背部、臀部、上尾覆羽、翼覆羽、下胸和上腹为橄榄灰，两侧、下腹为黄绿色，下尾覆羽为黄白色，尾巴更短且颜色更暗。幼鸟为浅灰褐色，喙和脚为棕色，眼圈白色；上尾覆羽深棕色，下体色更淡，下尾覆羽为淡黄色，基部灰色。","call":"发出尖锐干燥的“che chip, che chip”声，如同一群鸟发出的松散石子声；飞行时会发出颤音“che-e-e-e-e”或类似铃铛的叮当声。受到威胁时，可能模仿其他鸟类的声音，如美洲山鸫。","habits":"长尾丝鹟生活在海拔1800至3000米的开放山区生境，如次生林和牧场上分散的树木旁有树林的峡谷；非繁殖季节时，它们会组成广泛散开的小群，穿越森林和牧场；偶尔会迁移到较低海拔。以昆虫和小果实为食，包括fiddlewood、Fuchsia arborescens和Eurya theoides的浆果；喂养雏鸟时，同时提供昆虫和浆果。它们在树上摘取浆果并整颗吞下，空中捕食昆虫，通常从高处的栖木上进行长时间的出击；收集食物喂养雏鸟时，会在空中翻腾旋转，捕捉大量昆虫后再返回巢穴。","breeding":"繁殖期为4月至6月。一夫一妻制；单独或松散的群体繁殖，有时2到5对在一起筑巢，保卫巢周围的较小领地。雄鸟开始筑巢，后期两性共同参与；巢由浅灰色苔藓（Usnea）构成的宽大的开放式杯状巢，用毛虫丝或蜘蛛网绑定，内部光滑坚硬，直径11.4至12.7厘米，高度5至6.4厘米，内杯直径5.7至6.4厘米，深度4.1厘米；巢置于树叉或粗横枝上，高度2至18米（平均7米），有时位置暴露。每窝产2枚蛋；孵化由雌鸟承担，雄鸟在附近或巢上喂食；孵化期16至17天；雏鸟由雌鸟照料，两性共同喂食昆虫，随着年龄增长逐渐增加果实比例；小鸟在孵化后24至25天离巢，通过侧身滑出树枝，但可能返回巢穴一两天。15个巢中成功离巢率为27%；捕食者包括褐鸦。","identification":"雄鸟与雌鸟在颜色上有明显差异，雄鸟头部、颈部、喉部和下腹部为黄绿色，雌鸟颜色更暗淡，尾部更短且颜色更暗。幼鸟与成鸟相似，但中央尾羽较短，外尾的白色斑点不明显。","protection":"IUCN：LC（无危）；常见于哥斯达黎加和巴拿马的火山山脉和塔拉曼卡山脉的适宜生境中。虽然在其大部分范围内没有直接威胁，但由于分布受限和全球数量较少，长期而言存在担忧。","distribution":"繁殖区域：中美洲哥斯达黎加（Central Cordillera, Talamanca Cordillera）和巴拿马西部。","other":"长尾丝鹟是寄生虱Brueelia ptilogonis的宿主。"},{"name":"黑丝鹟","english_name":"Phainopepla","scientific_name":"Phainopepla nitens","overview":"黑丝鹟（英文名：Phainopepla，学名：Phainopepla nitens），是雀形目丝鹟科黑丝鹟属的鸟类。属于丝鹟科，主要栖息于北美西南部至墨西哥中北部的干旱灌木丛生地带。其名字来源于希腊语，意为\"闪耀的长袍\"，这恰如其分地描述了雄性黑丝鹟那闪亮的黑色羽毛。雌鸟和幼鸟呈灰褐色，而雄性黑丝鹟的黑色羽毛在阳光下泛着蓝绿色光泽，翅膀上有着显眼的白色斑块。","appearance":"黑丝鹟体型中等，长约16至20厘米，拥有细长的身体、竖立的羽冠和长长的尾巴。雄鸟的羽毛光亮如漆，带有蓝绿色光泽，翅膀上有明显的白色斑块，雌鸟和幼鸟则呈现灰褐色，翅膀上的斑块颜色较淡。两者都有一双红色的眼睛，但在雌鸟身上更为显眼。","call":"黑丝鹟能模仿至少十二种其他鸟类的叫声，包括红尾鵟和北扑翅䴕。","habits":"黑丝鹟主要栖息在沙漠绿洲、果园、灌木丛、约书亚树森林、橡树林和梧桐树林中。它们在冬季以沙漠槲寄生为主要食物来源，春季到秋季则以其他浆果和小型昆虫为食。黑丝鹟通常具有领域性，会长时间守卫果实、巢穴和领地边界，有时会在小群体中筑巢，繁殖后常集结成大群。","breeding":"黑丝鹟在春季繁殖，筑巢由树枝、苔藓和植物纤维构成，位于树干下方20英尺以内，通常在靠近水源的密林或开阔树林中。卵呈灰色或粉色带斑点，孵化期大约为15天，由双亲共同承担。幼鸟将在父母的照料下成长19天左右。","identification":"黑丝鹟与近似物种的区别在于其独特的羽冠、长尾和明显的白色翼斑。雌雄成鸟的差异在于颜色，雄鸟全身光亮黑色，雌鸟则为灰褐色。","protection":"IUCN：LC（无危）","distribution":"黑丝鹟分布于北美西南部，包括美国西南部至墨西哥中北部，主要在加利福尼亚州南部、犹他州南部以及墨西哥内陆高原区域。","other":"黑丝鹟有两个亚种，较小的lepida和较大的nitens，它们仅通过翅膀和尾巴的测量才能区分开来。"},{"name":"灰连雀","english_name":"Grey Hypocolius","scientific_name":"Hypocolius ampelinus","overview":"灰连雀（英文名：Grey Hypocolius，学名：Hypocolius ampelinus），是雀形目连雀科连雀属的鸟类。体长约18厘米，淡灰色，具黑色面罩和微小羽冠。主要栖息于伊拉克及其邻近地区的半干旱地带，非繁殖季节会迁徙至印度、阿富汗南部及可能到达非洲。以果实为主食，偶尔摄取昆虫。","appearance":"灰连雀是一种细长、浅灰色的鸟类，体长约18-21厘米，体重48-57克。雄鸟具有黑色面罩，延伸至颈背；上体淡蓝色灰色，翼羽黑色，有广泛的白色尖端，尾部黑色，末端宽黑带。下体较淡，呈淡黄色或白色。雌鸟缺乏黑色面罩，上体颜色较暗，呈淡灰色棕色，翼羽尖端狭窄的白色，尾部有模糊的暗色终端带。幼鸟为淡沙棕色，尾羽有淡化的黑色尖端，下颚基部粉红色。","call":"鸣叫包括柔和的‘tre-tur-tur’声，最后两个音节音调较低；从栖木发出下降的‘whee-oo’声，偶尔在飞行中也会发出；在求偶展示期间连续发出响亮的‘kirrr’声。","habits":"灰连雀主要栖息于低地排水盆地和河流谷地的树木区，尤其偏爱枣椰树和白杨树林，以及有灌木（如刺槐）和荆棘树的地区。非繁殖季节栖息地类似，但范围更广，包括沙漠灌木丛、灌溉种植园和果园。果实树（尤其是Salvadora persica和枣椰树）的存在对其至关重要，饮用水供应同样重要。它们是短途迁徙者，主要在伊朗南部、巴基斯坦、印度西部、沙特阿拉伯西部和中部以及阿拉伯海湾国家过冬。","breeding":"繁殖季节从最晚的五月开始，持续至七月中期，通常会有两窝幼鸟。半群居繁殖，每对仅保卫巢穴周围的直接区域。杯状巢由双亲共同建造，深度约30毫米，位于离地面1-4米的荆棘树、刺槐或其他灌木中。每窝产卵3-5枚，双亲共同孵卵和育雏。孵化期14天，雏鸟期13-14天。","identification":"灰连雀具有独特的外形，如长尾和黑色面罩（雄鸟），使其容易与其他鸟类区分开来。雌雄之间可以通过面罩的有无来辨别，而幼鸟则呈现出与成鸟不同的沙棕色。","protection":"IUCN：LC（无危）。在中东地区分布，虽确切范围和趋势未知，但总体上不面临全球威胁。","distribution":"繁殖于伊拉克、伊朗南部、土库曼斯坦南部和阿富汗南部，以及阿拉伯半岛；非繁殖期主要分布在伊朗南部、巴基斯坦南部、印度西部、沙特阿拉伯西部和中部以及阿拉伯海湾国家，包括巴林。","other":"灰连雀是鸟类观察者追寻的目标之一，因其家族的独特性和稀有性。"},{"name":"棕榈䳭","english_name":"Palmchat","scientific_name":"Dulus dominicus","overview":"棕榈䳭（英文名：Palmchat，学名：Dulus dominicus），是雀形目棕榈䳭科棕榈䳭属的鸟类。单型科棕榈䳭科和单型属棕榈䳭属的唯一成员。广泛而显眼地分布在大安的列斯群岛的希斯帕尼奥拉岛（多米尼加共和国和海地），作为当地最常见的居民之一，尤其以黄色的喙、黄褐色的腹部、橄榄色的背部和醒目的红眼睛而容易识别。该物种在城市环境和皇家棕榈树主导的草原上最为常见，而在密林和高海拔地区较为罕见。","appearance":"棕榈䳭是一种中等大小的雀形目鸟，尾部较长。它的上体呈橄榄棕色，翅膀和臀部带有绿色调。下体为淡黄色，布满深棕色粗条纹。喙呈淡黄色，虹膜为独特的红褐色。两性相似，无明显性别差异。幼鸟与成鸟相似，但喉部和前颈几乎全黑，仅边缘稍淡，臀部更偏黄棕色。","call":"棕榈䳭的鸣声多样，包括嗡嗡声、吱吱声和哨音，它们的叫声丰富而嘈杂，常在社交互动中发出。","habits":"棕榈䳭偏好在各种开放和受干扰的生境中活动，尤其是含有棕榈树的环境。它们在城市公园、花园和草原中适应良好，通常在小群中活动，栖息在高大的棕榈树上。","breeding":"棕榈䳭是社群性繁殖者，会在高达2米宽的大型共用巢穴中筑巢，巢穴位于棕榈树冠中，有时可达十对或多至五十对鸟儿共用。每对鸟儿有自己的独立空间。繁殖期主要在3月至6月，雌鸟产2-4枚带有斑点的灰紫色蛋。","identification":"棕榈䳭在其分布范围内具有独特性，与珠眼嘲鸫相比，后者体型更大、尾巴更长，腹部条纹更细密，整体颜色更深，且有白色的眼环，尾端白色，喙较长。珠眼嘲鸫不在希斯帕尼奥拉岛上出现。","protection":"IUCN：LC（无危）","distribution":"棕榈䳭的分布限于希斯帕尼奥拉岛，包括多米尼加共和国和海地，以及附近的萨奥纳岛和戈纳韦岛。在有适宜食物树的环境中，它们广泛存在于从海平面到海拔1500米的棕榈草原和其他散树开放区域。","other":"作为多米尼加共和国的国鸟，棕榈䳭在城市公园和花园中也能很好地适应生存。"},{"name":"鬓吸蜜鸟","english_name":"Kioea","scientific_name":"Chaetoptila angustipluma","overview":"鬓吸蜜鸟（英文名：Kioea，学名：Chaetoptila angustipluma），是雀形目夏威夷吸蜜鸟科鬓吸蜜鸟属的鸟类。大型夏威夷吸蜜鸟，约13英寸（33厘米）长，喙长且略弯。其显著特征为面部的宽黑条纹和头部与胸部的鬃毛状羽毛。这种鸟在夏威夷群岛中独有，其名称\"鬓吸蜜鸟\"字面意思为\"站得高\"，与鸟类行为的具体关联尚不清楚。","appearance":"鬓吸蜜鸟拥有长且略微弯曲的喙，与头部长度大致相等。羽毛柔软且长，除头部短而鳞片状。背部呈深橄榄棕色，带有黄色的羽轴斑点，类似长矛形状。下背和臀部橄榄棕色，带有赭色调。上覆尾羽橄榄棕色，带有绿色光泽。下巴灰黄色或白色，带有细纹。前额、头顶和颈背羽毛灰白，边缘黑色，颈背强烈泛黄。脸部有矩形暗黑色面具，覆盖眼上方至下方，包括眉线和耳羽，眼下方几根羽毛斑驳灰白色。喙基部两侧头部和喉部有向外曲的黑色毛状羽毛。喉咙、胸部和上腹部暗白色，大胆地带有深棕色条纹；每根羽毛有灰色中心和棕色边缘。下腹部、侧腹和肛周强烈赭色。大腿条纹灰白色和棕色，带有赭色调。初级飞羽、次级飞羽和上翼覆羽深棕色；次级飞羽带有绿色边缘和痕迹般的浅色尖端。下翼覆羽淡棕色。尾羽深橄榄棕色，外网广泛边缘黄绿色，带有痕迹般的浅色尖端；羽轴近端背面和腹面浅棕色。","habits":"生活习性信息缺失。","breeding":"生长繁殖信息缺失。","identification":"区别于其他吸蜜鸟，鬓吸蜜鸟具有面部的宽黑条纹和头部与胸部的鬃毛状羽毛。","protection":"IUCN：EX（已灭绝）","distribution":"太平洋：夏威夷岛（Hawaiian Is.）","other":"该物种在19世纪中期已经灭绝，其灭绝原因主要是由于森林砍伐、狩猎和外来掠食者的引入，如野猫、狗和猪。"},{"name":"考岛吸蜜鸟","english_name":"Kauai Oo","scientific_name":"Moho braccatus","overview":"考岛吸蜜鸟（英文名：Kauai Oo，学名：Moho braccatus），是雀形目夏威夷吸蜜鸟科夏威夷吸蜜鸟属的鸟类。仅存于可爱岛（Kauai），身长约20厘米。头部、翅膀与尾巴黑色，上体呈蓝灰色，臀部和侧翼红棕色，喉部与胸部具白色横纹。腿羽金黄色，眼虹膜黄色，喙与腿黑色，以花蜜为主食，亦吃小型无脊椎动物和果实。","appearance":"体型小巧，总长度雄鸟为206-242毫米，雌鸟为179-225毫米。喙与头等长，尖锐而略弯，鼻孔长且窄，被小肉质盖覆盖。尾巴短，呈阶梯状，常向上翘起。腿长，脚大。头部、翅膀和尾巴黑色，背部蓝灰色，臀部和上尾覆羽淡棕色。翼弯和下翼覆羽白色，腋下淡灰黄色，喉部和上胸黑色，有横向白色亚端条纹，下胸和腹部蓝灰色，下尾覆羽赤褐色。","call":"发出空洞、不规则的笛音般的叫声，声音独特且响亮。","habits":"栖息于夏威夷可爱岛的亚热带森林，偏好在树洞中筑巢。以Lobelia物种和‘ohi‘a lehua树的花蜜为食，也捕食小型无脊椎动物和食用果实。","breeding":"关于其繁殖细节信息有限，已知的是它在树洞中筑巢。","identification":"与同属的其他吸蜜鸟相比，体型最小，尾巴最短，黄色羽毛最少。眼虹膜黄色，是唯一具有这一特征的吸蜜鸟。","protection":"IUCN：EX（已灭绝）","distribution":"分布于太平洋夏威夷群岛的可爱岛。","other":"因病媒蚊传播疾病、哺乳动物捕食者引入和森林破坏而逐渐消失，最后一次记录在1987年，2000年正式宣布灭绝。"},{"name":"欧胡吸蜜鸟","english_name":"Oahu Oo","scientific_name":"Moho apicalis","appearance":"瓦岛吸蜜鸟的头部、翅膀与尾巴羽毛为黑色，冠羽刚硬而呈矛状，前额与头顶比其余部位更黑且略带光泽。背部呈板岩灰色，臀部与尾上覆羽较淡。翼弯与下翼覆羽为白色，腋羽浅灰黄色，羽簇不发达。下巴、喉咙与上胸黑色，横跨近末端的白色条纹赋予鳞片状外观。下胸与腹部板岩灰色，尾下覆羽赤褐色。成鸟腿部羽毛亮黄色，幼鸟黑色。羽毛色泽较其他三种吸蜜鸟更偏棕色。","habits":"关于其生态习性的信息有限，栖息于欧胡岛的山地森林中，具体的生活习性与迁徙模式尚未详细记录。","identification":"与其他三种黑色羽毛的吸蜜鸟相比，瓦岛吸蜜鸟体型最小，尾羽无斑纹，黄色羽毛仅限腿部基部，眼色较淡，喉部与胸部有精细的点斑。","protection":"IUCN：EX（已灭绝）","distribution":"该物种的分布范围仅限于太平洋中的瓦胡岛（夏威夷群岛的一部分）。","other":"最后一次可靠的观测记录是在1837年由德国自然学家费迪南德·德佩在檀香山收集到的三个标本。"},{"name":"毕氏吸蜜鸟","english_name":"Bishop's Oo","scientific_name":"Moho bishopi","overview":"毕氏吸蜜鸟（英文名：Bishop's Oo，学名：Moho bishopi），是雀形目夏威夷吸蜜鸟科夏威夷吸蜜鸟属的鸟类。曾属于夏威夷吸蜜鸟科，现已灭绝。以查尔斯·里德·毕晓普命名，曾在夏威夷群岛的茂宜岛、摩洛凯岛和拉奈岛的高山森林中繁衍生息。","appearance":"毕氏吸蜜鸟是夏威夷吸蜜鸟中最小型的物种之一，具有短尾和最少黄色羽毛的黑色羽毛。雄鸟体长206-242毫米，雌鸟179-225毫米，喙长与头部相当，细长而微弯。鼻孔狭长，上覆小肉质盖，位于喙基部羽毛前方的浅沟中。背部呈石板棕色，臀部和尾上覆羽颜色较浅，翼弯和下翼覆羽白色，腋下淡灰黄色，胸腹黑褐色，下腹部和腹部石板棕色，尾下覆羽红棕色，腿羽毛部分成年个体亮黄色，幼鸟黑色。羽毛色彩较同属其他三种更偏棕色。","call":"其鸣叫声简单，两声节的“took-took”，在数里之外仍可听到。","habits":"关于其生态习性的了解甚少，已知以夏威夷龙胆花的花蜜为食。","identification":"其独特之处在于体型小巧、短黑尾、腿基部仅黄色、淡色眼和喉部及胸部的精细斑点。","protection":"IUCN：EX（已灭绝）","distribution":"原生于夏威夷群岛的茂宜岛和摩洛凯岛。","other":"最后一次被目击是在1981年，最后一次确认的目击发生在1904年。"},{"name":"夏威夷吸蜜鸟","english_name":"Hawaii Oo","scientific_name":"Moho nobilis","overview":"夏威夷吸蜜鸟（英文名：Hawaii Oo，学名：Moho nobilis），是雀形目夏威夷吸蜜鸟科夏威夷吸蜜鸟属的鸟类。已灭绝的鸟类，以光泽黑色的羽毛和腹部的褐色色调为显著特征。拥有独特的黄色腋下羽丛，且翼上的黄色羽毛最为发达。夏威夷吸蜜鸟曾在夏威夷群岛广泛分布，但因人类猎杀其羽毛制作装饰品，最终于1934年宣告灭绝。","appearance":"夏威夷吸蜜鸟的总体长度约32厘米，翅膀长度在11至11.5厘米之间，尾长可达19厘米。全身羽毛呈光泽黑色，腹部带有棕色调。头部、翅膀和尾部均为黑色，冠羽硬挺且呈长矛状，额部和头顶比其余部位更黑，略带光泽，间杂白色细纹。背部为板岩褐色，臀部和尾上覆羽颜色较淡。翼弯和下翼覆羽为白色，腋羽淡灰色，且发育不良。下巴、喉咙和上胸黑色，有横向亚端白色条纹，形成鳞片状外观。下胸和腹部为板岩褐色，下尾覆羽为赤褐色。成鸟腿部羽毛鲜黄，幼鸟则为黑色。与其他三种‘ö‘ö相比，羽毛更偏棕色。","identification":"与其他‘ö‘ö种类区分，夏威夷吸蜜鸟具有最发达的翼上黄色羽毛，缺乏黄色大腿羽毛，尾羽没有白色边缘，且拥有最大的翼上黄色羽丛。雄雌外观相似，但雌鸟体型较小。","protection":"IUCN：EX（已灭绝）","distribution":"夏威夷吸蜜鸟的分布限于太平洋中的夏威夷群岛，特别是在夏威夷岛。"},{"name":"林啸鹟","english_name":"Hylocitrea","scientific_name":"Hylocitrea bonensis","overview":"林啸鹟（英文名：Hylocitrea，学名：Hylocitrea bonensis），是雀形目林啸鹟科林啸鹟属的鸟类。为一种特有于印度尼西亚苏拉威西岛山区的鸟类，隶属于林啸鹟科的唯一物种。传统上，被归入霸鹟科（Pachycephalidae），但最新的遗传研究推荐将其置于林啸鹟科（Hylocitreidae）下的单型亚科或独立成科。","appearance":"成年雄鸟头部呈橄榄绿色，背部暗橄榄褐色，耳羽和眉纹略亮，脸颊较暗；颈部、肩部和上背为蓝灰色，中部和下背、臀部与尾上覆羽为黄橄榄色；翅膀和尾巴为蓝灰色，翼羽微泛橄榄色；下体颜色较背部稍浅，下巴、喉咙和胸部带有橄榄色，腹部淡色，两胁鲜亮黄橄榄色，尾下覆羽微染棕色肉桂色；眼睛鲜红或深棕色，喙黑色，腿脚深灰色。雌鸟喉部为肉桂色并有灰色条纹。幼鸟头部和颈部橄榄棕色，上体橄榄色，下体条纹状淡棕黄色。","call":"鸣唱主要由一系列高音的上下颤音组成，每组4-5个音符，持续0.5-1秒，整首歌曲包含1-6组短语，持续2-10秒。另有低音的下降哨音后跟连续的尖锐咔哒声，最终以略微上升的哨音结束，整个序列持续约5-7秒。叫声包括清脆的‘tsip’声。","habits":"栖息于海拔1200-3500米的山地森林，尤其是苔藓森林，主要活动于树冠下层，加入混合物种觅食群。食物包括浆果和一些节肢动物。","breeding":"繁殖信息未知。","identification":"与栗背啸鹟的区别在于黄胁歌鸲具有黄色胁部、红色眼睛、细长的喙以及喜欢在树顶停留的习性。","protection":"IUCN：LC（无危）；然而，在苏拉威西南部的种群处于EN（濒危）状态，因生境高度碎片化和退化。","distribution":"分布于苏拉威西岛北部、中部及东南部的山区，包括Lompobattang山。","other":"此物种被认为是较为安静的，其鸣唱和叫声主要在清晨和日间中间时段发出。"},{"name":"黄腹扇尾鹟","english_name":"Yellow-bellied Fantail","scientific_name":"Chelidorhynx hypoxanthus","overview":"黄腹扇尾鹟（英文名：Yellow-bellied Fantail，学名：Chelidorhynx hypoxanthus），是雀形目仙莺科黄腹扇尾鹟属的小型鸟类。体长约12厘米，下体鲜亮黄色，上体橄榄色，具有宽眼罩，雄鸟黑色，雌鸟呈深绿色。在中国西南部较为罕见。","appearance":"雄鸟的上体为暗灰橄榄色，额头和眉纹黄色，耳羽上方有明显的黑斑；翼上覆羽尖端略带白色；下体明亮黄色；尾羽棕色，尾羽末端和羽轴有显著的白色。雌鸟相似，但耳羽至眼后的黑斑为深橄榄色。幼鸟似雌鸟，但额部缺乏黄色，背部更偏灰色，眉纹和下体为淡黄色。","call":"鸣唱为一系列细薄的“sewit sweeit”和“tit”或“tsit”音符，随后是高音颤音；叫声为细高的“tseep”声，重复发出。","habits":"偏好湿润的常绿阔叶林，主要在树冠下层和较高的灌木丛中活动，尤其在森林边缘。夏季可达林线附近，一般高度约3600米（尼泊尔北部最高可达4000米），冬季下降至喜马拉雅山麓和平原，偶尔高达2560米，低至760米。主要以小型飞虫为食，如苍蝇（Diptera），通过在叶片间翻飞驱赶猎物并进行空中捕食，有时也会悬停觅食。","breeding":"信息缺失。","identification":"外形与扇尾类相似，但体型较小，更接近于鶲类。其独特的黄腹和黑色眼罩（雄鸟）或深橄榄色眼罩（雌鸟）是辨识的关键特征。","protection":"IUCN状态未知。","distribution":"分布于喜马拉雅山脉东部至东南亚，包括印度东北部（阿萨姆）、中国西南（四川西部、云南西北部）、缅甸北部、泰国西部和北部、老挝北部、越南北部（东京西部、安南北部）。","other":"曾被归类于扇尾科（Rhipiduridae），但DNA分析显示其与仙鹟科（Stenostiridae）的仙鹟关系更近，因此现被归入仙莺科中的单型属Chelidorhynx。"},{"name":"仙玉鹟","english_name":"Fairy Flycatcher","scientific_name":"Stenostira scita","overview":"仙玉鹟（英文名：Fairy Flycatcher，学名：Stenostira scita），是雀形目仙莺科仙莺属的鸟类。拥有深色面具、尾巴和翅膀，显眼的白色翼纹，以及略带玫瑰色的浅色腹部。这种鸟常见于南非卡鲁地区的荆棘树、灌木丛、密林和树木沟壑之间。通常以昆虫为食，有时会加入混合物种的鸟群，其特征之一是展开尾巴并垂下翅膀。仙玉鹟在其南部范围内为留鸟，但在更北的地方主要作为非繁殖的冬季访客。存在常常被其特有的高音调短促口哨声所揭示，通常被描述为“tseee-tseeeit-zee-tzee-tzweeet”或类似的声音。","appearance":"仙玉鹟体长约11至12厘米，体重4至8克。其显著特征为长而渐尖的尾巴。雄鸟头部到臀部均匀呈现暗蓝灰色，稍微带有橄榄色调；眼窝、耳羽和脸颊黑色，形成面罩，上方由狭窄的白色眉纹相连，下方则有长长的白色颊纹；下眼睑有一条细白线；上尾覆羽蓝黑色，尾巴光泽黑，最外侧的一对羽毛和T4至T6的羽毛逐渐加宽的白色尖端；飞羽黑色，主翼羽和次级飞羽边缘光泽灰，三级飞羽外缘白色（在最长的三级飞羽上最为明显）；初级飞羽覆盖和小翼羽黑色，大和中上翼覆羽广泛地尖端白色（与白色边缘的三级飞羽一起形成明显的长翼纹），下巴白色；上喉部白色，带有粉红色（鲑鱼粉红的羽毛基部），下喉部、颈部侧面和胸部柔软的蓝灰色；后侧腹白色，羽毛长而丝滑，覆盖着臀部一侧（常使臀部看起来白色），腹部白色，带有粉红色（羽毛带有粉色基部），下尾覆羽白色；腋下和下翼覆羽白色；虹膜深赤褐色；喙和腿黑色。雌鸟外观与雄鸟相似，但上体颜色较不清晰，蓝灰色较淡，胸部颜色较浅。幼鸟比成鸟更棕色，下巴缺乏粉红色调，胸部灰色，略带淡黄色，灰色未延伸到侧腹，腹部白色或灰白色，略带淡黄色；幼鸟描述不详。emrudebecki/em亚种略暗灰色，翼长和尾长稍长；emsaturatior/em亚种定义不明确，略暗于指名亚种。","call":"仙玉鹟大多保持沉默。其歌声多变且尖锐，一系列细薄的“tsee-tsi-zee-tseepy-tsweeu”或“tseepy-zzzz”短语，有许多变化，有点像太阳鸟（Nectariniidae）的叫声，通常以特征性的“cheep cheep”结尾。叫声包括快速的“kisskisskisskiss”颤音，以及下降的“cher cher”或“zrrt zrrt zrrt”音符。","habits":"仙玉鹟在干燥的卡鲁灌木丛和灌木、fynbos（灌木丛）、灌木丛和树木覆盖的山丘、荆棘灌木丛、多树的山谷和河岸林中繁殖。在非繁殖季节，它们会移动到金合欢（Acacia）草原、山区灌木丛、种植园和花园。它们避免封闭的森林，但需要树木和灌木用于觅食和筑巢。仙玉鹟通常是单独、成对或小群出现，以小型昆虫和其他无脊椎动物为食，如同莺鸟般在树叶中觅食。","breeding":"仙玉鹟是单配制的，除非配偶死亡，否则不会寻找新的伴侣。它用细茎和其他植物材料建造一个开放式的杯状巢，并用植物绒毛衬里。巢安置在树枝中，但藏得很好。雌鸟会产下两到三个绿色的蛋。","identification":"仙玉鹟与其他种类的区别在于其明显的头部图案、大胆的白色翼纹和略带粉红色的下体部分；体型也较小。雌鸟与雄鸟相似，但上体颜色较为模糊，胸部颜色较淡。","protection":"IUCN：LC（无危）","distribution":"仙玉鹟是非洲南部的特有种，分布于博茨瓦纳、南非、莱索托和纳米比亚，偶尔也会出现在津巴布韦和斯威士兰。它在南部高原的卡鲁灌木丛和fynbos中繁殖，然后向北迁移到较低海拔的荆棘灌木丛中度过南半球的冬季。"},{"name":"方尾鹟","english_name":"Grey-headed Canary-flycatcher","scientific_name":"Culicicapa ceylonensis","appearance":"方尾鹟体长约12-13厘米，体重6-9克。小巧玲珑，头顶稍具羽冠，头部至颈背、颈侧及上胸呈烟灰色，额部和眉纹可能带有深色条纹，环绕着窄白眼圈。上体橄榄绿至黄橄榄绿，臀部和尾上覆羽色彩更鲜艳。翅膀覆羽边缘黄色，飞羽和尾羽内翈黑色，胸部至尾下覆羽明亮黄色，侧腹和胁部橄榄色。虹膜深棕色，喙黑色，下颌基部粉红色，腿脚浅棕至淡黄色。雌雄羽色相似，雌鸟体型较小。幼鸟类似成鸟，但翼羽端部泛淡黄色，眉纹灰，胸部微带绿色，下体色泽较暗。各亚种差异不大，主要表现在色彩深浅和某些部位颜色的变化。","call":"方尾鹟全年发出响亮尖锐的五音节鸣唱，典型为‘wi-tu-wi-tu-wee！’或‘wi-wuh-wuh-wee！！’。还会发出一系列快速高亢的弹跳音符，音调先迅速上升再渐弱。其它叫声包括尖锐的‘chilup’、‘kitwik’或‘chit’，重复数次。","habits":"方尾鹟栖息于成熟和次生干阔叶林及林地，偏好有溪流的林木峡谷。分布于低地至高山地带，繁殖高度在北巴基斯坦1200-1800米，中国中部和南部100-2000米，中央喜马拉雅山脉1500-3100米。在印度西南部一般高于900米，在斯里兰卡湿区山丘550米以上。在东南亚繁殖高度1280-3050米，马来半岛低至650米，苏门答腊至巴厘岛600-2200米。在繁殖季节外，栖息于类似生境的较低海拔，如西喜马拉雅山脉低于1000米，东部山脉低于1800米。也见于较小的林地、竹林、灌木丛、红树林、果园和大花园。","breeding":"繁殖季为2月至7月，常育两窝。一夫一妻制，配偶关系持久。求偶期间，雄鸟进行短距离盘旋飞行，向雌鸟展示臀部，两者相互呼唤，此行为可重复多次。巢由雄鸟在南印度和斯里兰卡建造，由苔藓、植物纤维、地衣和蛛丝构成，通常位于离地面9米内的树干侧面或岩石上，巧妙伪装以融入环境。每窝产3-4枚卵，雄鸟协助喂养雏鸟，孵化和离巢时间未知。","identification":"方尾鹟以其独特的头部形状、灰色头部、窄白眼圈、橄榄绿色上体和明亮的黄色下体易于识别。与其他同属物种的区别在于头部颜色、下体亮度及栖息地选择。亚种间主要在色彩深浅和某些部位的颜色上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于印度至中国南方、东南亚、马来半岛及巽他群岛，包括北巴基斯坦、中国中部和南部、中央喜马拉雅山脉、印度西南部、斯里兰卡湿区山丘、东南亚、马来半岛、苏门答腊至巴厘岛等地。","other":"方尾鹟曾被认为是旧世界鹟科的一员，但研究发现它们属于新分类的Stenostiridae科，与非洲的Stenostira和Elminia属亲缘关系密切。"},{"name":"柠黄仙鹟","english_name":"Citrine Canary-flycatcher","scientific_name":"Culicicapa helianthea","overview":"柠黄仙鹟（英文名：Citrine Canary-flycatcher，学名：Culicicapa helianthea），是雀形目仙莺科方尾鹟属的小型鸟类。以其鲜明的黄色色彩命名，广泛分布于远东地区的菲律宾和印尼苏拉威西岛，栖息于低山至高山的湿润森林地带。","appearance":"柠黄仙鹟体型小巧，面部特征明显，拥有深邃的眼睛和浅色眼圈，上体呈橄榄绿色，下体为均匀的黄色。其独特的外观使其在森林环境中容易识别，常单独或成对出现在林下层。","call":"柠黄仙鹟的叫声包括一种简单的高音哨声，音调起伏，形成“swit-soo-swit-soo”的旋律，此外还会发出短促的‘ti-rip’颤音。","habits":"柠黄仙鹟偏好森林、林地和种植园的低海拔至山区环境，常见于混合物种群中，活跃于树冠下层。它们的饮食以昆虫为主，善于捕捉空中飞虫。","breeding":"关于柠黄仙鹟的繁殖信息较为有限，但通常在适宜季节内进行繁殖，营巢于树洞或隐蔽处，具体细节需进一步研究。","identification":"柠黄仙鹟与灰头仙鹟的主要区别在于前者具有黄色的颏部，缺乏灰色头部和胸部特征。与黄腹啸鹟相比，柠黄仙鹟的眼圈更明显，无白色喉部，喙型更为细长。","protection":"IUCN：LC（无危）","distribution":"柠黄仙鹟主要分布在菲律宾和苏拉威西地区，栖息于亚热带和热带的湿润山地森林。","other":"柠黄仙鹟在分类学上属于Stenostiridae科，其系统发育历史反映了其独特的生态位和地理隔离特性。"},{"name":"蓝凤头鹟","english_name":"African Blue Flycatcher","scientific_name":"Elminia longicauda","overview":"蓝凤头鹟（英文名：African Blue Flycatcher，学名：Elminia longicauda），是雀形目仙莺科凤头鹟属的小型鸟类。其特征为全身几乎亮蓝色，尾羽长且扇形，头部具小冠。分布于非洲中西部，包括雨林、河岸森林、茂密花园及红树林地带。","appearance":"蓝凤头鹟体型纤细，长约15至18厘米，体重介于7至12克之间。成年雄鸟头部至背部呈鲜艳的钴蓝色，腹部偏灰白色，翼上覆羽黑色边缘带蓝，尾羽黑边蓝或绿蓝相间。雌鸟颜色较淡，尾部较短。幼鸟上体偏灰色，翼端和尾羽尖端为乳白色。","call":"其鸣声为一系列缓慢、杂乱而略显单调的高音节，由清脆的‘tsip’和‘chip’组成，有时带有更急促的‘tsee-tsu-tsee-tsai’音调，类似太阳鸟的声音，但更为丰富多样。","habits":"生活在山地森林、河岸森林、沿海森林及次生灌木丛，偏好树荫下的密集枝叶中活动。以小型昆虫为主食，包括蜜蜂、蚂蚁、飞蛾、蜘蛛等。常成对或小家族群活动，会进行飞扑捕食昆虫。","breeding":"繁殖季节在不同地区有所不同，通常在雨季。一夫一妻制，偶尔多配偶制。巢由精细材料构成，置于树叉或树枝上，离地面高度可达5米。每窝产卵1至2枚，孵化期未知，雏鸟至少需14天的巢内期，离巢后还需至少21天的喂养。","identification":"与白尾蓝凤头鹟的区别在于整体更深的蓝色，尤其是头部，以及全蓝的尾羽。雌雄差异主要体现在色彩的饱和度和尾部长度。","protection":"IUCN：LC（无危）","distribution":"分布于西非至中非，包括毛里塔尼亚、塞内加尔、冈比亚东至肯尼亚，南至刚果民主共和国北部和安哥拉北部。","other":"该物种在当地可能常见，出现在多个保护区，如象牙海岸的Comoé国家公园和喀麦隆的Bénoué国家公园。"},{"name":"白尾蓝凤头鹟","english_name":"White-tailed Blue Flycatcher","scientific_name":"Elminia albicauda","overview":"白尾蓝凤头鹟（英文名：White-tailed Blue Flycatcher，学名：Elminia albicauda），是雀形目仙莺科凤头鹟属的鸟类。小型、优雅，主要分布于非洲的安哥拉西部、刚果民主共和国南部至乌干达南部、坦桑尼亚和马拉维等地。其显著特征为蓝色背部、浅灰色下部，以及白色外侧尾羽。","appearance":"成年雄鸟几乎全身蓝色，头顶有模糊的白色条纹，胸部淡灰色；雌鸟与雄鸟相似，但色彩略显暗淡。幼鸟像雌鸟，但脸颊呈石板灰色，翅膀覆羽泛蓝，飞羽、三级飞羽和尾巴尖端白色。体型小，长约14厘米，体重约6至9克，拥有钝圆的冠羽和长长的渐变尾羽。","call":"鸣唱为一段短促、悦耳但略显杂乱的颤音系列，以‘tip-tip’音符开头和结尾。接触音为低沉、尖锐的‘tip-tip’或‘chit-chit’声，也有口哨般的‘teereet’或‘chiri’声。","habits":"栖息于低地和亚山地常绿森林、河岸林木，常见于溪谷、高地溪流旁、森林道路边缘、灌木丛中的树木和稀树草原，海拔可达2500米。以小昆虫为主食，如蚂蚁、白蚁、甲虫、苍蝇、蛾和蜘蛛。通常成对或小群活动，加入混合物种觅食群。在开阔的树冠中间层觅食，追逐昆虫时快速翻飞。","breeding":"繁殖季节在乌干达为1月和8月至9月，在马拉维为10月至12月，在赞比亚为9月和11月，在刚果民主共和国为10月至12月，在安哥拉为8月至12月。巢由苔藓、植物纤维、木纤维和羽毛制成的小杯状结构，高至9米，位于细枝分叉处。每窝产2枚蛋，颜色为光泽的白色或黄褐色，表面云雾状橄榄色或密集的灰绿色或棕色斑点。","identification":"与非常相似的蓝凤头鹟相比，上部颜色较暗或呈灰蓝色，下部更白，胸部灰色较少，且冠羽较小，尾巴稍短。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部安哥拉和刚果民主共和国南部至乌干达南部、坦桑尼亚、马拉维，以及东非的肯尼亚、卢旺达、布隆迪和莫桑比克。在乌干达和北安哥拉较为常见，出现在多个保护区，如马拉维的Dzalanyama森林保护区。","other":"在全球范围内并不受到威胁，但在一些地区可能数量不多。"},{"name":"暗色凤头鹟","english_name":"Dusky Crested Flycatcher","scientific_name":"Elminia nigromitrata","overview":"暗色凤头鹟（英文名：Dusky Crested Flycatcher，学名：Elminia nigromitrata），是雀形目仙莺科凤头鹟属的小型鸟类。其头部呈黑色，具轻微的凤头状冠羽，腹部为石板灰色。活跃于低地和中海拔雨林的下层，常参与混合物种群落，与白腹凤头鹟和白尾凤头鹟相似，但体型更小，腹部颜色更深。","appearance":"体长约11至13厘米，体重8.5至12克。雄鸟头部、上翼和尾巴呈黑色，背部至胸部为石板灰色，略带蓝色调，腹部至两胁及下尾覆羽颜色较淡。雌鸟与雄鸟相似，但上部缺少蓝色调，下部更接近石板灰色。幼鸟全身均匀的烟灰色。colstoni亚种比指名亚种稍淡，上部有更明亮的蓝色（而非灰色）色调，翅膀和尾巴为棕色。","call":"其鸣唱为一系列延长的、变化多端的口哨声和液滴般的颤音，间断并穿插着叽叽喳喳和更高音的音符，类似欧红额金翅雀的歌曲质量和长度。接触叫声为频繁发出的‘pick’或‘chip’，有时表现为‘tsep’、‘tsiep’或‘tsip’。在加蓬，巢边问候声为‘tlee-dyew-tee’或更快的‘teedyewtew’。","habits":"暗色凤头鹟栖息于非洲热带雨林的低地和中海拔地带，偏好湿润的森林环境。它们活泼好动，经常加入混合物种的鸟类群落。","identification":"与白腹凤头鹟和白尾凤头鹟的区别在于，暗色凤头鹟缺乏明显的白色腹部和尾端。与蓝头凤头鹟相比，体型较小，下体无明显的深胸与浅腹分界。","protection":"IUCN状态未知。","distribution":"广泛分布于非洲西部和中部的热带雨林地区，包括低地和山地的湿润森林。"},{"name":"白腹凤头鹟","english_name":"White-bellied Crested Flycatcher","scientific_name":"Elminia albiventris","overview":"白腹凤头鹟（英文名：White-bellied Crested Flycatcher，学名：Elminia albiventris），是雀形目仙莺科凤头鹟属的小型鸟类，主要分布于非洲中部的喀麦隆线（含Bioko岛）及阿尔伯丁裂谷山地森林。","appearance":"该鸟体长约11厘米，体重7至10克，身形细长，头部略呈黑色，具微小的钝顶冠。背部为暗灰蓝石板色，翼上覆羽和尾部呈棕黑色，腹部中央至尾下覆羽为白色，腋羽及下翼覆羽亦为白色。虹膜深棕色，喙黑色，下颚基部带白色，腿黑色。雌雄相似，雌鸟较雄鸟稍显暗淡，幼鸟比雌鸟更暗淡，翼和尾部更呈烟熏褐色。toroensis亚种背部呈蓝灰色，喉部黑色较少。","call":"其歌声柔和悦耳，间歇地发出一系列‘psip…psip…psip… psip-trr…plee-plee-plee…tsee…tsee-tsi…tlee-lee-lee’的旋律，有时会接续短暂的轻柔啾啾声或偶尔更圆润的音符。在卢旺达，其歌声更像是高音的啾啾声，几乎与白尾凤头鹟的歌声相同。在西非，接触叫声为尖锐的‘pink’或‘slip’以及干燥的‘frrit, frrit’。","habits":"白腹凤头鹟常见于山地森林的下层和中层，常成对出现，频繁加入混种群。这是一种活泼好动的鸟类，似乎永不停歇。","identification":"与暗色凤头鹟相似，但通常出现在更高海拔，且腹部有白色。与白尾凤头鹟相似，但体型较小，腹部白色较少，尾部无白色。与E.nigromitrata的区别在于腹部至尾下的白色，与E.albonotata的区别在于全尾均为石板灰色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部，包括喀麦隆线（含Bioko岛）及阿尔伯丁裂谷山地森林。"},{"name":"白尾凤头鹟","english_name":"White-tailed Crested Flycatcher","scientific_name":"Elminia albonotata","overview":"白尾凤头鹟（英文名：White-tailed Crested Flycatcher，学名：Elminia albonotata），是雀形目仙莺科凤头鹟属的小型鸟类，身长约13厘米，体重5至10克。其最显著的特征为黑色头部、略显的凤头、白色腹部以及宽阔的白色尾端。分布于非洲东部山区森林，常见于肯尼亚、乌干达至坦桑尼亚西南部，南部延伸至莫桑比克。","appearance":"雄鸟成鸟具有蓝黑色的头部、下颏、喉咙和颈背，上体呈灰色或微带蓝色，臀部至尾羽基部为棕色，尾羽外侧具宽白边。雌鸟上体较均匀的灰蓝色。幼鸟头部和翅膀呈烟灰色，有明显的黄色口角。尾羽长而渐尖。","call":"鸣唱为一系列甜美与嗡鸣声交织的弱音，穿插着尖锐的颤音或偶尔模仿其他鸟类的声音，联系叫声为尖锐的‘zitt’声。","habits":"栖息于亚热带或热带的常绿山地森林及其周边的灌木丛和竹林，海拔高度在600米至2700米之间。以昆虫为主食，包括苍蝇、蚂蚁、飞蛾和蜘蛛。","breeding":"繁殖季节从五月持续到十二月，一夫一妻制，领域性明显。雄鸟通过展示尾羽和喂食行为向雌鸟求偶。巢为小巧精致的杯状，由绿色苔藓、地衣和蛛丝编织，位于离地面2至6.5米高的树叉中。每窝产2枚卵，卵壳光滑，白色或淡奶油色，带有褐色、橄榄色或灰紫色斑点，仅由雌鸟孵化，孵化期约15至16天。","identification":"与近缘物种白腹凤头鹟相比，白尾凤头鹟在海拔较高的地区生活，通常不低于2250米。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中南部，具体包括肯尼亚、乌干达、坦桑尼亚、马拉维、赞比亚、津巴布韦和莫桑比克。"},{"name":"火冠雀","english_name":"Fire-capped Tit","scientific_name":"Cephalopyrus flammiceps","overview":"火冠雀（英文名：Fire-capped Tit，学名：Cephalopyrus flammiceps），是雀形目山雀科火冠雀属的小型鸟类。其最显著的特征为雄鸟的前额及喉部呈现出独特的火红色，分布于喜马拉雅山脉至老挝北部，冬季可见于印度中部平原。该鸟种在分类上曾被认为是王鹟，现归类于山雀科，自成一属。","appearance":"非繁殖季节，火冠雀的头部顶部为暗橄榄棕色，边缘带有黄绿橄榄色，背部呈黄绿色至橄榄绿色，臀部则为黄绿色至橄榄金色。尾羽最长部分为深灰色，翅膀颜色与尾羽相似，边缘为橄榄黄色。喉咙白色，胸腹部和两侧呈现柠檬黄色，与大腿、肛周区域及尾下侧的灰色形成鲜明对比。繁殖季节，雄鸟的头顶略显橙红至深红色，眼眉和眼周带有金黄色，脸颊、耳羽和颈侧橄榄黄色，喉部和上喉部橙铬色，逐渐过渡到金黄色胸部。雌鸟在非繁殖季节与雄鸟相似，但上体（包括脸颊、眉线和颈侧）为橄榄灰绿色，下巴和喉咙为灰白色，胸腹橄榄黄，上腹和下腹淡黄。无论季节，虹膜为棕色至深棕色，喙为蓝灰色，尖端更暗，腿脚也是蓝灰色。","call":"火冠雀发出高音但响亮且断断续续的“tsit-tsit-tsit-tsit”叫声，以及柔和低沉的“whitoo-whitoo”接触叫声。在歌唱时，雄鸟会飞到高处显眼的位置，如树顶，连续几分钟发出一系列快速、高音符，形成结构完整的旋律。","habits":"火冠雀栖息于高山针叶林或混交林，偏好温带雨林和混合落叶林环境，接近针叶林带下方。它在不同海拔高度活动，冬季会下移到平原地区。它通常以群体形式活动，迁徙和冬季时会组成小至中等规模的群落。它觅食时主要在大树的较高部位，有时也会在接近地面的灌木丛中寻找食物。食物主要包括昆虫，但也食用树叶、花、芽，可能还有花粉和树液。","breeding":"繁殖季节从4月初持续至6月中旬。巢筑于树干或大枝的空洞内，通常选择有树枝或疤痕遮挡的洞口。巢由干草、细根和偶尔的羽毛构成，内衬更细的草和羽毛，由雌鸟建造，而雄鸟则负责保卫领地。每巢通常产四枚暗蓝绿色的卵，孵化期未知，雏鸟由双亲共同喂养，雌鸟独自维护和清洁巢穴。","identification":"火冠雀与同属的其他鸟类相比，最明显的区别在于雄鸟的火红色头部和喉部，以及雌鸟的特定色彩模式。其体型较小，喙尖锐，翼上有浅色条纹。","protection":"IUCN：LC（无危）","distribution":"火冠雀的繁殖区域位于东洋界，从喜马拉雅山脉延伸至老挝北部。非繁殖期间，它们会在印度中部平原过冬。在中国大陆，分布于陕西、四川、云南、西藏等地，冬季时可见于平原地区。","other":"火冠雀的巢穴常位于6至12米的高度，隐蔽性极强，不易被发现。"},{"name":"黄眉林雀","english_name":"Yellow-browed Tit","scientific_name":"Sylviparus modestus","overview":"黄眉林雀（英文名：Yellow-browed Tit，学名：Sylviparus modestus），是雀形目山雀科黄眉林雀属的鸟类。外观独特，羽冠短，眼圈黄色狭窄，浅黄色眉纹有时被覆盖，腿粗壮。分布于喜马拉雅山脉至越南中南部，主要栖息于亚热带或热带湿润的低地森林和山地森林。","appearance":"黄眉林雀体长约9-10厘米，体重5-9克，是最小的山雀科成员之一，拥有小喙、短尾和粗壮的腿。成鸟的羽冠和上体为橄榄绿色，前额略带灰色，臀部和上尾覆羽呈较亮的黄绿色，翼羽和尾羽边缘橄榄绿，尾基部微黄，大覆羽尖端淡色形成不明显翼斑，虹膜深褐色，喙色暗角至蓝灰色，腿蓝色。幼鸟与成鸟相似，但尾羽尖端可见。不同亚种间差异不大，simlaensis亚种上体更鲜亮或黄橄榄色，klossi亚种头顶稍暗，背部和翼羽边缘更绿，下体颜色稍亮。","call":"叫声包括细薄或尖锐的“tsit”、“psit”或“pit”，以及更刺耳的“chip”或“tchup”，有时交替出现如“psit, chup, psit psit, tchup, psit”。也会发出快速的颤音“si-si-si-si-si-si-si-si-si”或更长且响亮的“tszizizizi tszizizizizi”。受惊时会连续发出高音“tee”或“tzee-tzee”。鸣唱发生在3月初至5月底，一系列尖锐的哨声，如“piu-piu-piu-piu”或“tiu-tiu-tiu”，类似Nutcracker（Sitta）的叫声，或更双音节的“zee-zi zee-zi zee-zi”，常重复一段时间。","habits":"黄眉林雀活跃，行动似山雀，遇警或兴奋时冠羽耸立，浅色眉纹显出。栖息于蒙松的亚热带或热带森林中，偏好中上层植被。常见于混合种类的小群中。","identification":"与火冠雀区别在于具有冠羽且腰部无浅色反差。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉至越南中南部，主要在亚热带或热带湿润的低地森林和山地森林中。"},{"name":"冕雀","english_name":"Sultan Tit","scientific_name":"Melanochlora sultanea","overview":"冕雀（英文名：Sultan Tit，学名：Melanochlora sultanea），是雀形目山雀科冕雀属的鸟类。体型较大、色彩鲜明的亚洲森林鸟，以其独特的黑色与黄色相间的羽毛著称。分布于低地和亚山地森林，常见于中国南方、喜马拉雅山脉东部至越南等地。","appearance":"冕雀体长20-21厘米，体重35-49克，是其家族中体型最大的成员。雄鸟头部前额、顶冠及冠羽呈鲜艳的硫磺黄色，其余部分包括翅膀、尾巴以及胸部的羽毛呈光亮的绿色黑色，腹部及翼下覆羽为鲜黄色。雌鸟与雄鸟相似，但颜色略显暗淡。幼鸟颜色更淡，冠羽较短且圆，上体缺乏光泽。四个亚种间差异不大，主要体现在羽毛色泽的细微差别。","call":"冕雀非常善于发声，常发出清脆、尖锐的鸣叫，包括类似金属声的‘tji-jup’、刺耳的‘krssh-krssh’以及快速、尖锐的‘tria-tria-tria’等叫声。其歌声由一连串响亮、清晰的‘chew’或‘kree’哨音组成，通常会反复多次。","habits":"冕雀主要栖息于低地和亚山地的落叶、混交及常绿森林，偏好竹林、灌木丛和农田边的树林。它们以小昆虫和虫卵为主食，也会食用果实和种子。通常成对或以家庭群体出现，有时加入混合物种的觅食群。活动于树冠层，偶尔在开阔地带快速飞行。","breeding":"冕雀在印度的繁殖季节为4月至7月，会在树洞中筑巢，每次产卵5至7枚。它们主要以毛虫为食，偶尔也吃小型浆果。","identification":"冕雀以其独特的体型和色彩与其他山雀区分开来，特别是其显著的黑色和黄色羽毛以及长而柔软的冠羽。与近似种相比，冕雀的体型更大，颜色更为鲜明。","protection":"IUCN：LC（无危）","distribution":"冕雀广泛分布于喜马拉雅山脉东部至中国南部、泰国北部和越南中部，以及缅甸大部分地区。在中国，主要分布于南方的原始森林和次生林。","other":"冕雀被列入国家林业局2000年发布的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。"},{"name":"棕枕山雀","english_name":"Rufous-naped Tit","scientific_name":"Periparus rufonuchalis","overview":"棕枕山雀（英文名：Rufous-naped Tit，学名：Periparus rufonuchalis），是雀形目山雀科黑冠山雀属的山雀科鸟类。广泛分布于喜马拉雅山脉西部至西北部，包括印度、中国部分地区、巴基斯坦、图尔克斯坦、吉尔吉斯斯坦和阿富汗。该物种具有黑色的胸部围兜和醒目的白色脸颊，常见于高海拔地区的针叶林中，使用石块开裂坚果。","appearance":"棕枕山雀是一种中到大型的山雀，身长约为13厘米，体重介于11.4至14.7克之间。其特征为短而尖的冠羽和明亮的白色脸颊。雄鸟头部至冠羽为黑色或略带蓝黑色光泽，颈背有小块白色斑点，边缘呈暖褐色。上体呈深灰色，轻微橄榄色（东阿富汗和北巴基斯坦地区更浅）。尾羽颜色与背部相似，翼覆羽深灰色，边缘泛蓝灰。黑色的胸部延伸至腹部上方，下胸侧、上腹侧和腋窝处为棕红色或淡肉桂色，下腹和下腹侧为灰色，尾下覆羽淡棕至肉桂色。虹膜棕色，喙黑色，腿呈铅灰色至黑色。雌鸟与雄鸟非常相似，但平均而言，冠羽光泽较弱，胸部和腹部上方的黑色较暗淡且范围较小。幼鸟外观类似成鸟，但冠羽和顶冠较暗，上体更多橄榄棕色，下体淡灰棕色。","call":"棕枕山雀的叫声多样，包括哀怨的‘cheep’或‘peep’和短促的‘sip’，常组合发出如‘sip-sip-sip, pee-sip, sih-pee, puu-sih-pu, tu-si-si’，还有低沉尖锐的‘chut’或‘chut-chut’以及快速的‘trrrr’，类似大山雀已删除的叫声。有两种歌曲：一种用于领地标记，由最多6个吹哨音后跟快速颤音或嗡嗡声组成；另一种用于领地防御，是一系列变化的吹哨音后跟下滑音。","habits":"棕枕山雀栖息于高海拔的针叶林，如云杉、冷杉、雪松和松树为主的森林。在喜马拉雅山脉西部，它常见于杜松林，中央喜马拉雅山脉扩展到云杉-橡树林、白桦林和杜鹃花丛。也出现在开阔地带的灌木和树木山坡上。繁殖季节外，少量个体会降至较低海拔。食物以小型无脊椎动物、种子和浆果为主，巢中幼鸟完全喂食昆虫和幼虫。利用树皮裂缝或树枝作为敲打种子和坚果的‘砧板’。","breeding":"繁殖季节为4月至7月，实行一夫一妻制。雄鸟求偶时会展翅半开，抖动翅膀，围绕雌鸟跳跃并发出柔和的啾啾声。巢由两性共同建造，主要由苔藓、动物毛发、羊毛和羽毛构成，位于树干或树桩低处的洞穴或壁龛中，有时也会在地面的陡峭河岸孔洞中。每窝产4至6枚蛋，孵化由雌鸟承担，双亲共同喂养雏鸟。","identification":"棕枕山雀与黑冠山雀极为相似，区别在于前者胸部黑色围兜更大，飞羽接近黑色，后者下腹部为灰色而非棕红色。","protection":"IUCN：LC（无危）","distribution":"棕枕山雀分布于乌兹别克斯坦南部、塔吉克斯坦、吉尔吉斯斯坦、中国西北部新疆西部、阿富汗西北部和东部、巴基斯坦西部和北部、尼泊尔西部至中部（卡利甘达基峡谷）。在中亚和阿富汗繁殖高度为1800至3000米，在巴基斯坦北部和印度北部为2200至3700米，在尼泊尔西部为2400至4000米，在中国西北部为2900至3500米。非繁殖季节会降至更低海拔。","other":"在印度北部常见，在尼泊尔分布较广且数量较多；在分布范围内局部常见，但在西中国较为少见。"},{"name":"黑冠山雀","english_name":"Rufous-vented Tit","scientific_name":"Periparus rubidiventris","overview":"黑冠山雀（英文名：Rufous-vented Tit，学名：Periparus rubidiventris），是雀形目山雀科黑冠山雀属的鸟类。直译为棕臀山雀，分布广泛，主要栖息于喜马拉雅山脉至缅甸的高山森林地带，包括中国西部的部分地区。其显著特征为黑色头部和鲜明的红棕色腹部。","appearance":"黑冠山雀体型小至中等，约12至13厘米长，体重介于7至13.1克之间。具有黑色的帽子和尖锐的冠羽，雄鸟标本头部黑色，额头至冠部有时带蓝绿色光泽，脸颊和耳羽白色，上体暗灰，翼覆羽深灰，边缘蓝灰。下体红棕色，腹部颜色较深。雌鸟与雄鸟类似，但头部颜色略淡，下体色彩更暗淡。幼鸟的冠羽和尾端钝，上体泛黄，下体呈淡灰色。","call":"发出细高音调的叫声，如‘seet’或‘seep’，还有清晰或嘶哑的‘pseet’、‘pee’或‘piu’，以及柔和的‘pwit’或‘whit’，有时会组合成长系列的叫声，例如‘seep-seep, seep-seep sip-ti, pseet-seep, tip-pee, tip-piu-sweep, tip-piu-chip’。","habits":"常在成对或小群体中活动，特别是在繁殖季节，非繁殖季时也会加入混合种类的觅食群。栖息于阔叶林、混交林及高山松林，偏好橡树为主的森林。在非繁殖季节，它们会下降到较低海拔的温带橡树林。","breeding":"繁殖期从3月中旬至6月中旬，具体习性资料尚不充分。","identification":"与棕枕山雀相比，黑冠山雀的黑色胸部面积较小，飞羽呈灰色，而非黑色。两者在外观上有细微差别，主要通过下体颜色和飞羽颜色进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉至缅甸，包括中国陕西、甘肃、青海、新疆、四川、云南、西藏等地，海拔2000米以上，主要在高山针叶林、竹林或杜鹃灌丛间。","other":"历史上，部分亚种曾被归类于西方近亲棕枕山雀，或两物种被认为完全同种。"},{"name":"煤山雀","english_name":"Coal Tit","scientific_name":"Periparus ater","overview":"煤山雀（英文名：Coal Tit，学名：Periparus ater），是雀形目山雀科黑冠山雀属的鸟类。广泛分布于亚洲、欧洲和北非的褐头山雀。以针叶林为其主要栖息地，耐寒并善于储藏食物以备冬需。体长约为11厘米，其特征为两道白色翼斑和颈背部的白斑，或有时可见尖状的黑色冠羽。该物种被列入国家林业局2000年8月1日发布的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","appearance":"体长约10至12厘米，体重约7.2至12克。头部黑色并带有光泽，喉颈部有大面积黑色条带，翼上有两条白色翼斑，枕部有一条宽白纹。上体灰色或蓝灰色，两翼有明显翼斑。下体白色，两胁至腹部呈灰至肉桂色。雌雄相似，但雌鸟冠部光泽较弱，肩部和覆羽颜色略偏绿色，翼羽稍暗或边缘色更灰。幼鸟头部和颈背烟灰色，白色颈斑较小且偏黄，上体偏暗灰，翼羽边缘深灰，下体黄色，脸颊和耳羽泛淡黄色，胸腹深棕或更灰。","call":"发出连续的短促‘dee’或‘see-see’叫声，用于群体间的联系。歌曲似尖锐的‘if-he, if-he, if-he’，频率高且节奏快，尤其在1月至6月间常见，秋季亦可听到。北非种群还有一种‘currr’的叫声。","habits":"主要栖息于温带湿润的针叶林，但在不同地区适应性强，可见于多种森林类型。冬季形成小群，与其他褐头山雀混群。食物多样，包括种子、昆虫、小型无脊椎动物，偏好从锥果中取出种子。在冬季，红血细胞含更多线粒体，以产生更多热量。会访问花园觅食。","breeding":"筑巢于腐朽树干的洞穴中，低至地面，巢由苔藓、毛发和草紧密编织而成，内部衬以兔毛或羽毛。每窝产卵7至11枚，通常在5月繁殖，每年繁殖一次。","identification":"与欧亚大山雀及褐冠山雀区别在于胸中部无黑色纵纹，与褐冠山雀一样具有两条白色翼斑，而欧亚大山雀仅有一条。种内不同亚种间存在颜色深浅和色调的差异。","protection":"IUCN：LC（无危）","distribution":"在欧亚大陆广泛分布，包括北非。在中国大陆，主要见于针叶林地带，具体分布高度随地区而异，从海平面至海拔1800米，部分地区可达2050米。在喜马拉雅山区，冬季活动于1800至3810米之间。","other":"在实验室研究中，煤山雀在能量负平衡时倾向于在变化的觅食地点觅食。它们在听到猫头鹰叫声后会增加晚间体重。在食物获取率低的情况下，早晨会尽快增加体重，直到达到一个拐点，之后体重增加速度放缓。"},{"name":"黄腹山雀","english_name":"Yellow-bellied Tit","scientific_name":"Pardaliparus venustulus","overview":"黄腹山雀（英文名：Yellow-bellied Tit，学名：Pardaliparus venustulus），是雀形目山雀科黄腹山雀属的鸟类。俗名: 采花鸟、黄豆崽、黄点儿，这种羽色鲜亮的小鸟长约10厘米，以其发金属光泽的黑色头部和亮黄色腹部而著称。在中国东部、中部和南部广泛分布，是当地特有的珍稀鸟种。","appearance":"成年雄鸟拥有光泽的黑色头部，脸颊和枕部白色，双翼灰黑，腹部亮黄色；雌鸟则顶冠灰色，喉部白色，腹部黄而稍淡。幼鸟类似雌鸟，但头部至背部橄榄绿色，脸颊和耳羽黄色，颊部和耳羽边缘灰暗，下颈有淡黄色斑点。雄鸟幼鸟早期即可分辨，其头部、枕部和背部橄榄绿色，眼上有一非常短且往往不明显的眉纹，脸颊和耳羽黄色，下颈有淡黄色斑点。","call":"鸣唱包括尖细柔和的“sit-oo”，快速高音的“si-si-si-si-si”，以及频繁发出的鼻音三音节“dzee dzee dzee”，有时会延伸成更多变化的音调，如“sip-eeh, sip, zee-zee-zee”。其歌声主要是重复短语的一系列单音或双音，带有金属质感，偶尔穿插更复杂的旋律。","habits":"栖息于阔叶温带森林及常绿森林，包括混合松树和落叶树的林区，竹林、落叶松（Larix）、柳树（Salix）林地及农田边缘的零散树木。夏季活动高度在1200-1500米左右，冬季则通常在1000米以下，包括平原和沿海地带。它们以小昆虫、幼虫和种子为食，有储存食物的行为，但具体细节未知。通常成对或小群活动，非繁殖季节则可能形成多达30只的大群。","breeding":"4月开始繁殖，选择天然树洞筑巢，巢呈杯状，由苔藓、细软草叶、草茎等构成，内衬兽毛。每窝产卵5-7枚，卵白色，带红色或褐色点斑。雄鸟非常领土性，但与邻居保持尊重，体现了“亲爱的敌人”效应。","identification":"黄腹山雀体型较小，胸腹部无黑色纵纹，与大山雀已删除和绿背山雀明显不同，野外容易识别。","protection":"IUCN：LC（无危）。2012年评估。被列入中国林业局2000年8月1日发布的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。黄腹山雀种群数量局部丰富，但由于森林砍伐和捕捉笼养，数量有所下降，需加强保护。","distribution":"分布于中国东部、中部和南部，包括河北东北部至甘肃南部、四川中部和东部、云南东北部、湖北西部至广西西北部和安徽南部、湖南中部、江西北部和广东北部。非繁殖季节时，分布至江苏南部至广东南部的沿海地区。","other":"黄腹山雀具有间歇性的繁殖爆发，是山雀家族中少见的‘夫妻’双栖双飞鸟种，被誉为山雀中的爱情鸟。"},{"name":"丽色山雀","english_name":"Elegant Tit","scientific_name":"Pardaliparus elegans","overview":"丽色山雀（英文名：Elegant Tit，学名：Pardaliparus elegans），是雀形目山雀科黄腹山雀属的鸟类。为菲律宾特有种，广泛分布于该国除巴拉望岛以外的多数岛屿。","appearance":"这是一种小型鸟类，两性相似，共有9个亚种，主要差异在于头部及翅膀上的白色或黄色斑点的分布和数量。雄鸟具有光泽的蓝黑色头顶、喉部和上胸部，颈背黑色带有一抹黄色，披肩黑色点缀着白色斑点，下背部呈淡灰色；尾巴黑色，基部半边边缘白色；初级飞羽边缘白色；脸部、下胸和腹部为黄色。雌鸟颜色较为暗淡，雏鸟与成鸟相似，但喉咙呈淡黄色，具黑色髭纹。","call":"鸣唱由中音哨声开始，随后是两个高音符，反复：“chuu chit-chit！chuu chit-chit！chuu。”此外，还会发出鼻音的沙哑叫声，这是山雀典型的叫声。","habits":"栖息于森林和较为开阔的林地，从山脚至山区均有分布。其自然栖息地为亚热带或热带湿润的低地森林和山地森林。","identification":"黄色脸颊和下体，黑色领圈、帽状纹和翅膀，翼上有白色的斑点，黑色尾羽带有白色尖端和边缘标记，特征明显，在其分布范围内无可混淆。","distribution":"分布于菲律宾群岛，遍布大部分岛屿，但不包括巴拉望岛。"},{"name":"巴拉望山雀","english_name":"Palawan Tit","scientific_name":"Pardaliparus amabilis","overview":"巴拉望山雀（英文名：Palawan Tit，学名：Pardaliparus amabilis），是雀形目山雀科黄腹山雀属的小型鸟类。主要分布于菲律宾西南部的巴拉望岛以及邻近的小型岛屿，如Calauit和Balabac。其最显著的外部特征是黑色的头部、喉咙和颈部，黄色的背部、腹部和胸部，以及黑白相间的翅膀和尾巴。","appearance":"雄性巴拉望山雀拥有黑色的头、喉和颈，黄色的背、腹和胸，翅膀和尾巴为黑白色块状。雌鸟的背部呈橄榄色，其余部分与雄鸟相似，展现出有限的性别二态性。整体上，这种山雀体型小巧，羽毛色彩鲜明。","call":"其声音包括上下起伏的哨声歌曲，高音调的金属般清脆颤音，以及鼻音的嘶哑声。","habits":"栖息于低地森林环境，包括次生林、林缘、沼泽和亚山区森林。它们以小昆虫、昆虫幼虫、种子和果实为食。通常单独或成对出现，有时会加入混种觅食群。","breeding":"关于其繁殖行为的具体信息在现有资料中未详尽描述。","identification":"与雄性黑翅雀鹎（未提供中文名）相似，但巴拉望山雀具有黑色而非黄色的喉咙。","protection":"IUCN：NT（近危）","distribution":"主要分布在菲律宾的巴拉望岛及周边的Calauit和Balabac等岛屿。","other":"面临的主要威胁是栖息地丧失，尤其是岛上近期开始的森林砍伐活动。"},{"name":"凤头山雀","english_name":"Crested Tit","scientific_name":"Lophophanes cristatus","overview":"凤头山雀（英文名：Crested Tit，学名：Lophophanes cristatus），是雀形目山雀科冠山雀属的鸟类。最显著的特征是独特的羽冠，分布于欧洲的针叶林区，特别是在法国、伊比利亚半岛的落叶林中广泛可见。英国的分布局限于苏格兰古老松树林，鲜少离开其栖息地。","appearance":"小型至中型山雀，体长11.5-12厘米，体重9.7-15.8克，具有黑色与白色相间的面部图案。雄鸟有黑色前额至冠部，短而尖锐的羽冠边缘为白色，形成鳞片状外观。雌鸟类似雄鸟，但平均而言，羽冠较短，头部侧面条纹较窄，两胁偏黄褐色。幼鸟与成鸟相似，但羽冠更圆钝，侧脸呈黄褐色，眼纹和耳羽后缘颜色较淡。","call":"发出清脆上升的‘zee-zee-zee-cheera-cheera’声，随后是低沉颤抖的‘brrrrrr, t-brrrrrr…’声，有时以‘zizizi’或轻快的‘si-si-si-sisisisisi’结尾。","habits":"栖息于松树、云杉为主的森林，夏季多在树冠层活动，其他季节会下降至较低层次甚至地面觅食。食物主要包括小昆虫及其幼虫，冬季则转向种子和果实。常与混种山雀群一起觅食。","breeding":"繁殖季为3月至6月，单窝产卵5-11枚，由雌鸟孵化，孵化期13-18天。雏鸟由双亲喂养，离巢期16-22天，之后依赖父母23-25天。平均每窝成功抚育4.7至5.9只幼鸟。","identification":"与其他山雀相比，凤头山雀拥有明显的羽冠，以及独特的黑白面部图案。与近似物种的区别在于其更长的羽冠和特有的头部标记。","protection":"IUCN：LC（无危）","distribution":"广泛分布于欧洲中部和北部的针叶林，法国和伊比利亚半岛的落叶林，以及英国苏格兰的古老松树林。","other":"凤头山雀在第一年即可繁殖，最长记录寿命为7年零7个月。"},{"name":"褐冠山雀","english_name":"Grey-crested Tit","scientific_name":"Lophophanes dichrous","overview":"褐冠山雀（英文名：Grey-crested Tit，学名：Lophophanes dichrous），是雀形目山雀科冠山雀属的小型鸟类。其特征在于拥有一顶显眼的向上翘起的大型灰色羽冠。分布于喜马拉雅山脉至缅甸，中国的陕西、甘肃、青海、四川、云南、西藏等地，常见于海拔3000米左右的高山针叶林或灌木丛。","appearance":"褐冠山雀体长约11.5-12.5厘米，体重约11.2-14克。整体呈灰褐色，腹部橙黄色，颈部有狭窄的白色条纹，耳后有一黑色新月状斑纹。头部具有独特的长而直立的灰色羽冠，上额浅色，头顶和羽冠颜色较深。上体主要是均匀的灰褐色，边缘微带黄褐色；尾部暗淡的棕灰色，翼羽黑色，边缘稍淡；脸颊、耳羽和喉部淡黄褐色，尖端略带灰色，形成斑驳的效果；胸前有一条白色的半环形条纹，下巴和喉咙灰黄或灰棕色；下体橙黄色，有时带有温暖的棕色调，腹部和臀部更白。幼鸟类似成鸟，但羽冠较短，上体颜色略深，臀部微带黄褐色，脸颊、耳羽和喉咙更淡，少有黄褐色。性别相似，种族间差异不大。","call":"褐冠山雀叫声较为柔和，包括尖细的‘zee’或‘zai’声，快速而断断续续的‘ti-ti-ti-ti-ti’或‘tirrit tzit tizit’声，还有更柔和的‘sip-sip-sip’或‘sip-pi-pi’声，以及一系列‘whee-whee-tz-tz-tz’的歌曲，其中融入了各种呼叫音和颤音。","habits":"褐冠山雀通常成对或小群体活动，偶尔加入混合物种的觅食队伍，与煤山雀和其他莺类一同觅食。它们主要在森林的中下层觅食，冬季时也会在地面寻找食物，尤其是在矮杜鹃和桦树灌木下收集食物。食物以昆虫和幼虫为主。","identification":"与其他山雀科鸟类相比，褐冠山雀的显著特征是其独特的灰色羽冠和橙黄色的腹部。种族间的辨识要点主要在于羽色的细微差别。","protection":"IUCN状态未提供。","distribution":"褐冠山雀分布在喜马拉雅山脉至缅甸，中国境内主要分布于陕西、甘肃、青海、四川、云南、西藏等地，尤其在海拔3000米左右的高山针叶林或灌木丛中。"},{"name":"白眉冠山雀","english_name":"Bridled Titmouse","scientific_name":"Baeolophus wollweberi","overview":"白眉冠山雀（英文名：Bridled Titmouse，学名：Baeolophus wollweberi），是雀形目山雀科凤头山雀属的小型鸟类，以其独特的黑白相间头部和冠羽著称，分布于北美地区的墨西哥以及美国西南部的山区，偏好橡树林及混合林带。该物种为永久居民，冬季常加入混群。","appearance":"白眉冠山雀体长约10厘米，体重约10克，头顶黑色，两侧头部白色，具醒目的黑白相间面部图案。背部和尾巴灰色，腹部灰白色。性别相似，但在繁殖季节可通过泄殖腔突起和抱窝斑辨别。无年龄相关羽毛差异。与北美其他山雀相比，体型较小，更似䴓鴲。","call":"鸣叫声多样，主要为哨音“pidi-pidi-pidi-pidi”，还有多种音质相似的声音。","habits":"栖息于海拔较高的橡木或松橡混交林地带，以昆虫、坚果和浆果为主食，尤其喜食毛虫。它们活跃于枝干上，有时也会在地面觅食，有储藏食物的习惯。冬季会与其他食虫鸟种形成小规模混群。","breeding":"繁殖期在洞穴中筑巢，通常选择自然树洞或旧啄木鸟巢，离地面4至28英尺。巢由棉花木绒、茎、叶和草构成。每窝产卵5至9枚，卵色白，可能带有红褐色斑点。","identification":"与北美其他山雀区别明显，头部黑白相间的复杂图案和黑领为其独特标识。与䴓鴲相比，具有冠羽，但下方视角容易误认。","protection":"IUCN：LC（无危）","distribution":"主要分布于美国西南部（亚利桑那州和新墨西哥州南部）和墨西哥，偏好高山橡木林和松橡混交林。","other":"白眉冠山雀在非繁殖季节常与食虫鸟类混群，如䴓鴲、王鹟、莺鸟等，扮演着吸引其他鸟类的核心角色。"},{"name":"纯色冠山雀","english_name":"Oak Titmouse","scientific_name":"Baeolophus inornatus","overview":"纯色冠山雀（英文名：Oak Titmouse，学名：Baeolophus inornatus），是雀形目山雀科凤头山雀属的鸟类。小型灰褐色鸟类，头部有小而圆的羽冠，脸部素净，下体颜色较浅。主要栖息于北美西部的温暖干燥的橡树林及橡松混合林中，分布范围从南部俄勒冈南至加州，西至内华达山脉以西，至下加利福尼亚北部。","appearance":"纯色冠山雀为小型鸟类，体色呈灰褐色调，上体略深，下体稍淡，具有一抹淡黄褐色的侧面。其头部有明显的短羽冠，眼睛周围有黑色眼斑，使眼睛显得突出。两性外观相似，仅在尺寸上有细微差异，雄鸟略大于雌鸟。成鸟与幼鸟的羽色基本一致，但幼鸟的尾下覆羽更细长。不同的亚种在体型、色彩和喙部大小上有微小差异。","call":"纯色冠山雀的叫声为急促而粗糙的‘tsicka-dee-dee’，歌声由一系列重复的音节组成，通常包含二至三个音符，最后一个音符音调较低，通常三到七个短语组合在一起。","habits":"纯色冠山雀全年居住于太平洋沿岸的橡木或橡松混交林中，偏好低至中海拔的干燥地带。它们在树洞、密集枝叶或人工鸟屋中过夜，形成小家庭群体，而非大群。它们以昆虫、蜘蛛、浆果、橡子和种子为食，善于在空中捕捉昆虫，也常在树叶、树枝和树干上觅食，偶尔倒挂觅食，会用枝条敲开种子。","breeding":"繁殖期从3月持续至7月，高峰期在4月至5月。巢筑于啄木鸟留下的洞穴、自然空腔或巢箱中，使用草、苔藓、泥、毛发、羽毛和兽毛建造。每窝产卵3-9枚，平均6-8枚，由雌鸟为主孵化，孵化期14-16天。幼鸟为晚成鸟，由双亲共同照料，巢中停留16-21天，离巢后父母继续照顾3-4周。","identification":"与林山雀极为相似，但可通过背色(纯色冠山雀背部偏棕色)和叫声(纯色冠山雀发出一系列3-7个音节，每个音节一低一高；林山雀的歌声是一系列快速的同音节)加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于北美西部，从南部俄勒冈至加州，西至内华达山脉以西，至下加利福尼亚北部。在繁殖季节，集中于橡木或橡松混交林，非繁殖季节可能在更广阔的森林区域活动。","other":"纯色冠山雀和林山雀曾被认为是单一物种，直到1996年因显著的歌曲、生境偏好和遗传差异被划分为两个独立物种。"},{"name":"林山雀","english_name":"Juniper Titmouse","scientific_name":"Baeolophus ridgwayi","overview":"林山雀（英文名：Juniper Titmouse，学名：Baeolophus ridgwayi），是雀形目山雀科凤头山雀属的鸟类。以独特的短羽冠和圆润的喙著称，雄雌外观相似。该物种主要栖息于北美西部干燥的松果松和杜松林中，分布范围从美国东南部俄勒冈州和中部科罗拉多州，南至加利福尼亚东部莫哈韦沙漠、亚利桑那州中部，以及西得克萨斯和墨西哥东北部的马德兰天空岛。偏好温暖干燥的环境。","appearance":"林山雀体型较小，全身覆盖着均匀的灰色羽毛，腹部略显苍白。头部有一撮明显的黑色眼睛和一个黑色的小羽冠，使得其头部轮廓显得尖锐。雄鸟和雌鸟的外观几乎相同，仅在大小上略有差异，雄鸟略大于雌鸟。它们的喙短而厚实，呈圆形。","call":"林山雀的叫声如同一系列连贯的音节，音调相同，给人一种仿佛游戏机音效的感觉。其叫声则像沙哑的‘tschick-adee’。","habits":"林山雀全年居住在大盆地，偶尔会在适宜的生境中造访鸟食器。它们在树洞、浓密的树叶或鸟舍中过夜，有时会模仿洞穴栖息，选择被密集树叶或死松针包围的枝条。它们通常形成一对或小群体，不组成大群。在繁殖季节后，它们可能会加入混合种类的觅食群。林山雀主要以昆虫和蜘蛛为食，有时在空中捕捉昆虫，也吃浆果、橡子和一些种子，有时会用喙敲打树枝打开种子。","breeding":"林山雀在啄木鸟洞、自然空洞或鸟舍中筑巢，用草、苔藓、泥、毛发、羽毛和皮毛做窝。繁殖期从三月持续到七月，高峰期在四月和五月，每窝产卵3-9枚，通常为4-7枚。雌鸟为主要孵卵者，孵化期约为14-16天。雏鸟为晚熟型，由双亲共同照顾约16-21天，直到离巢。离巢后，父母继续照料幼鸟3-4周。","identification":"林山雀与橡树山雀外表几乎相同，但可通过叫声和分布范围进行区分。橡树山雀背部颜色偏棕色，叫声为重复的三到七个音节，每个音节由一个低音和一个高音组成，而林山雀的叫声则是一系列快速的同音音节。两者的分布范围在加州一小部分地区重叠。","protection":"IUCN：LC（无危）","distribution":"林山雀主要分布于北美西部，包括美国中西部和墨西哥北部。","other":"直到1996年，林山雀和橡树山雀曾被认为是单一物种，归类于Parus属下的普通山雀（Parus inornatus）。"},{"name":"美洲凤头山雀","english_name":"Tufted Titmouse","scientific_name":"Baeolophus bicolor","overview":"美洲凤头山雀（英文名：Tufted Titmouse，学名：Baeolophus bicolor），是雀形目山雀科凤头山雀属的鸟类。小型鸣禽，特征包括灰色头部上的羽冠，橙色侧身，黑色前额，以及大眼睛，分布于北美东部至东南部，常在落叶林和混合林中发现，也是城市和郊区成熟树木地带的常见居民。这种鸟经常光顾喂鸟器，以太阳花种子和脂肪为食。","appearance":"美洲凤头山雀的羽毛总体呈灰色，腹部颜色较淡，侧身带有橙色。性别相似，具有一顶可升降的灰色羽冠，黑色前额，蓝色至灰色的腿脚。幼鸟的前额较暗淡，眼圈呈浅色，尾下覆羽质地较松散，嘴内颜色从黄色到粉灰色。成年鸟有黑色的额头，翅膀和尾巴略显深色，被橄榄灰色遮盖，次级飞羽带绿，翼羽微带棕色。两侧腹部和侧身有类似冬季枯叶的锈色。","call":"美洲凤头山雀会发出清晰的哨音“peter-peter-peter”，是其显著的鸣叫特征。","habits":"栖息于落叶和混合林区，也常见于有人居住的地区。它们通常在秋季和冬季访问喂鸟器，偏好太阳花籽和脂肪。这种鸟非常活跃，会在树枝上移动，偶尔在枝下搜寻节肢动物。它们是群居的，常常与其他鸣鸟如山雀和山雀莺一起活动，影响着群鸟的行进路线。","breeding":"美洲凤头山雀在树洞中筑巢，通常是木啄鸟留下的洞穴，也会利用人工巢箱。配对关系可能持续多个繁殖季节，不同于大多数山雀和山雀莺，幼鸟常在冬季与父母同住，直到第二年晚些时候才离开。有时，一年生的幼鸟会留在出生地帮助父母养育更小的兄弟姐妹。","identification":"与黑冠凤头山雀区分，后者具有黑色的羽冠和白色的前额。在西南俄克拉荷马州、得克萨斯州和墨西哥的混合区，两个物种会发生杂交。此外，与纯色冠山雀和林山雀相比，美洲凤头山雀体型更大，色彩更鲜艳，侧身有锈色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于北美东部至东南部，包括美国的俄亥俄河和密西西比河流域。非繁殖区域包括加拿大安大略省和魁北克省的部分地区。近年来，由于气候变暖和喂鸟器的影响，其分布范围向北扩展。","other":"在过去70年里，该物种的分布范围已向北扩展至新英格兰和加拿大南部，气候变化可能是最主要的因素。历史上，黑冠凤头山雀曾被认为是美洲凤头山雀的一个亚种，但在2002年被认定为独立物种。"},{"name":"黑冠凤头山雀","english_name":"Black-crested Titmouse","scientific_name":"Baeolophus atricristatus","overview":"黑冠凤头山雀（英文名：Black-crested Titmouse，学名：Baeolophus atricristatus），是雀形目山雀科凤头山雀属的鸟类。原被视作与美洲凤头山雀同一物种，2002年确认为独立种。分布于美国南部德克萨斯州、俄克拉荷马州及墨西哥东中部，偶见于圣路易斯，密苏里州等地。常见于树木茂盛之地，无论是落叶林、浓密森林还是城市树荫。","appearance":"体长约14至15厘米，上身呈灰色，腹部白色，两胁锈色。雄鸟具长而深黑色的竖立冠羽，雌鸟的冠羽颜色较淡。喙短而圆，脚力强健，能灵活悬挂在树枝上。","call":"发出类似‘彼得，彼得，彼得’的叫声，与美洲凤头山雀相似，但更短促。","habits":"栖息于各种树林环境，包括落叶林、重木林及城市树荫区。以浆果、坚果、蜘蛛、昆虫及虫卵为食。","breeding":"在树洞、电线杆、篱笆柱或鸟箱中筑巢。每年三月至四月产卵，每窝产四至七枚，卵壳白底带红褐色斑点。","identification":"与美洲凤头山雀相比，体型略小，背部和臀部绿色调更明显，冠羽相对更长。雌雄差异在于冠羽颜色，雄鸟黑色，雌鸟暗灰色。","protection":"IUCN：LC（无危）","distribution":"主要分布于北美，具体包括美国德克萨斯州、俄克拉荷马州以及墨西哥东北部。"},{"name":"杂色山雀","english_name":"Varied Tit","scientific_name":"Sittiparus varius","overview":"杂色山雀（英文名：Varied Tit，学名：Sittiparus varius），是雀形目山雀科白额山雀属的鸟类。体长约13厘米，头顶至后颈黑色，后头中央有一白斑，上背栗色，上体余部及翼蓝灰色，颏、喉黑色，下体栗红色。台湾亚种形体较小且胸、腹纯为栗色。活跃于温带低海拔地区和丘陵森林，其独特的亮橙色腹部、蓝灰色翅膀和白色脸颊组合使其在分布区内易于识别。分布于欧亚大陆的东部，包括日本、朝鲜半岛、中国东北部及俄罗斯南部库页岛。","appearance":"杂色山雀体长12-15厘米，体重14.4-20.8克。雄鸟头部黑色，前额淡黄色，后颈有窄黄色斑点，背部栗色形成窄带，其余上体深灰蓝色，下体橙色，腹部淡黄褐色，两胁红栗色。雌鸟相似，但体型略小，胸部和两胁颜色更淡。幼鸟较暗淡，头部至后颈颜色较浅，上体泛灰棕色，初级飞羽尖端淡黄色至红黄色，覆羽顶端淡黄色，侧胸和两胁红栗色不如成鸟广泛。","call":"发出微弱的‘tsuu tsuu tsuu’作为联系声，薄而尖锐的‘pit’或‘chit’，更长更高音的‘spit-see-see-see’和责骂般的‘chi-chi-chi’或结巴的‘stit-ti-ti-ti…’。在日本，春季至夏季间重复单调或变化的哨音，通常包含响亮的‘peee’。","habits":"杂色山雀主要栖息于开放的混合森林，偏好有日本栲树和日本扁柏的环境。饮食多样，以小型无脊椎动物为主，包括蜘蛛，也吃种子、坚果和浆果。它们在秋季储存食物以度过冬季，同时作为繁殖季节雏鸟的食物。活动隐蔽，常单独或成对出现，秋冬季节可能组成小群或混入多种鸟类群中。主要在树冠层觅食，偶尔也会在较低的层次和灌木丛中取食。","breeding":"繁殖期在日本主要在3月至6月，繁殖行为包括求偶、筑巢、交配、产卵、孵化和育雏，具体细节需参照研究文献。","identification":"与台湾杂色山雀的区别在于后者仅分布于台湾，且体形较小，胸腹纯为栗色。与其他山雀属物种的区别在于其独特的色彩组合。","protection":"IUCN：LC（无危）。在南日本和库页岛常见或局部非常常见，但在北日本（北海道和本州北部）、中国大陆东北部和台湾较为罕见。Daito-jima岛上的ori亚种现被认为已灭绝。","distribution":"分布于欧亚大陆东部的南部库页岛、日本、朝鲜半岛和中国东北部。在南中国，曾有记录于广东八宝山，但可能为逃逸的笼鸟。","other":"杂色山雀是日本三种最受欢迎的笼鸟之一，传统上用于占卜游戏中。笼鸟贸易对野生种群的影响未知。"},{"name":"伊豆杂色山雀","english_name":"Owston's Tit","scientific_name":"Sittiparus owstoni","overview":"伊豆杂色山雀（英文名：Owston's Tit，学名：Sittiparus owstoni），是雀形目山雀科白额山雀属的鸟类。仅在日本伊豆群岛南部的常绿阔叶林中发现，分布于Miyakejima、Mikurajima和Hachijojima三岛。以其深锈色的身体、暗灰色的翅膀和尾巴以及黑色的喉咙和头顶斑块著称。","appearance":"体型约13-15厘米，具有显著的大喙。成年个体额头至脸颊、颈侧呈赤褐色，下颈橙赤色，背部橄榄灰，腹部全为肉桂赤色，胸部和两侧最深。雌雄相似，但雌鸟略小，喙较细弱。幼鸟比成鸟色彩淡。","call":"通常发出1-2个重复的高音节音符，如“tsuu tsuu”。鸣唱是一系列稍低于杂色山雀的哨声，以及“chip-chip-tuwee”，但其歌声的地理变异尚未充分研究。","habits":"生活在常绿阔叶林中，食物主要包括Castanopsis sieboldii的橡子，它们会在秋季储存坚果，用于求偶喂食和喂养幼鸟。已知会捕食蚂蚁。","breeding":"具体繁殖信息未详尽报道，但类似杂色山雀，可能涉及求偶喂食和幼鸟养育。","identification":"与杂色山雀相比，伊豆杂色山雀脸更暗，锈色更深，叫声更高，鸣唱略有不同。","protection":"IUCN：EN（濒危）。此物种受威胁，估计全球成熟个体数量在2900-3600之间，因栖息地丧失和可能的外来物种威胁而被提升至濒危等级。","distribution":"分布于日本伊豆群岛南部的三个岛屿：Miyakejima、Mikurajima和Hachijojima。","other":"2014年的系统发育研究表明，伊豆杂色山雀应从杂色山雀中分离出来，提升为独立物种。"},{"name":"琉球杂色山雀","english_name":"Iriomote Tit","scientific_name":"Sittiparus olivaceus","overview":"琉球杂色山雀（英文名：Iriomote Tit，学名：Sittiparus olivaceus），是雀形目山雀科白额山雀属的小型鸟类。分布局限于日本南部的八重山群岛（琉球群岛南部），尤其以Iriomote岛为主。具有红褐色体羽，黑色头冠和喉部，翅膀呈橄榄灰色。此鸟种于1923年由日本鸟类学家Nagamichi Kuroda首次描述，最初被认为是杂色山雀的亚种，但在2014年的一项系统发育研究后被提升为独立物种。","appearance":"成年琉球杂色山雀长约11至13厘米，全身呈现淡黄褐色，头部有显著的黑色项圈和窄窄的中央冠纹，背部和翅膀为深灰色。雌雄外观相似，但幼鸟比成鸟颜色更暗淡。","call":"鸣叫特征了解不多，已知会发出高低音交替的快速短音节叫声，类似杂色山雀。","habits":"栖息于常绿阔叶林，尤其偏好高海拔地带。其饮食和觅食行为可能与杂色山雀复杂群中的其他成员相似，但具体数据尚未发表。","breeding":"关于生长繁殖的信息尚不明确。","identification":"与杂色山雀相比，琉球杂色山雀背部有橄榄绿色调，这是两者之间的重要区别点。","protection":"IUCN：LC（无危）。此物种虽分布范围有限，但尚未达到易危标准。","distribution":"主要分布于日本南部的八重山群岛，特别是在Iriomote岛。","other":"2014年的研究确认了琉球杂色山雀的独立物种地位，此前曾被认为是杂色山雀的一个亚种。"},{"name":"台湾杂色山雀","english_name":"Chestnut-bellied Tit","scientific_name":"Sittiparus castaneoventris","overview":"台湾杂色山雀（英文名：Chestnut-bellied Tit，学名：Sittiparus castaneoventris），是雀形目山雀科白额山雀属的鸟类。为台湾特有的小型山雀科鸟类。拥有独特的黑白头冠和灰翅，以及鲜明的深锈红色胸腹部，与杂色山雀相似但分布范围不重叠，腹部无白色。群居，活跃于森林、公园及花园，常见于山麓与山区。","appearance":"体长约11至13厘米，成鸟具有黑色喉部和头冠，白色脸颊，钢灰色上体，以及鲜艳的深栗色下体。雌雄相似，幼鸟特征未详述。比标准杂色山雀小，翼展60至64毫米，脸部和颈背呈纯白色，上体暗蓝灰色无橄榄色调，下体统一深栗色。","call":"鸣叫声包括尖细的啾啾声和鼻音，与之前认为同种的杂色山雀相比，叫声更高亢，发出欢快的“chay chikyechay cherr”声和快速的“tsititititititititi”声，后者可能为物种的鸣唱。","habits":"栖息于台湾的森林、公园和花园，主要在山脚和山区地带，以群居形式觅食，有时与其他物种混群。饮食和觅食行为与杂色山雀类似。","identification":"在台湾没有类似物种，与杂色山雀的区别在于深色的胸腹部，分布范围不同，且腹部无白色。幼鸟特征未知。","protection":"IUCN：LC（无危）。台湾特有种，分布受限，数量从常见到罕见不等，目前未发现对其生存构成威胁的因素。估计种群可能不足1万对，但缺乏官方数据和专项调查。","distribution":"欧亚：仅限台湾。"},{"name":"白额山雀","english_name":"White-fronted Tit","scientific_name":"Sittiparus semilarvatus","overview":"白额山雀（英文名：White-fronted Tit，学名：Sittiparus semilarvatus），是雀形目山雀科白额山雀属的鸟类。主要分布在菲律宾的吕宋岛和棉兰老岛。其最显著的特征是头部前方有一明显的白色标记，延伸至眼和喙之间。雄鸟全身黑色，雌鸟则为深棕色腹部。鸣声为一系列下降的高音调‘piu-piu piu’，同时发出快速的断奏颤音。","appearance":"体长约13厘米，中等体型，喙大而尾长，羽毛主要为黑色。雄鸟额头至上颊白色或淡黄褐色，其余部分黑褐，上部光泽深靛蓝，胸部略带蓝色光泽，背部羽毛基部有隐蔽的白色颈斑。雌鸟与雄鸟相似，但额头至脸颊呈扩散状黄白色，下体颜色较淡或偏赭褐色，最长的尾下覆羽尖端白色。幼鸟类似雌鸟，年轻雄鸟下体更暗或近黑色，大覆羽尖端稍淡。","call":"鸣声包括短促尖锐的‘psit’，更高音的滚动‘tsuit’或金属质‘zeeeeet’，有时组合成长串的‘sit-tsuit-suit-suit’；亦发出连续的‘tsi-tsi-tsi-tsi-tsi’或‘zit-zit-zit-zit-zit’，有时以‘tsre’或‘tsree’开头或结尾，伴随较长的‘tsee-tsi-tsi’。","habits":"栖息于低地和丘陵森林，包括森林边缘、次生林和林地，偶尔出现在灌木丛地带。通常独居、成对或形成多达十只的小群，也可见于混种觅食群。害羞且难以察觉，觅食于树冠中上层，移动迅速，偶尔在下层植被中活动。","breeding":"繁殖信息知之甚少。二月初观察到成对寻找巢穴，三月中旬成鸟喂养离巢幼鸟，五月发现处于繁殖状态的成鸟。具体繁殖细节不明。","identification":"与其他山雀属物种区分明显，特别是通过头部的白色标记。不同亚种间的差异在于翼部的额外白色标记以及羽毛颜色的细微变化。","protection":"IUCN：NT（近危）","distribution":"分布于菲律宾北部的吕宋岛和南部的棉兰老岛。在吕宋岛的北侧Sierra Madre山脉和北吕宋岛局部常见，但在棉兰老岛（nehrkorni亚种）的观察记录极少。","other":"近年来菲律宾大规模的森林破坏严重缩减了这一羞涩且隐秘物种的适宜栖息地，导致其数量急剧减少。"},{"name":"白眉山雀","english_name":"White-browed Tit","scientific_name":"Poecile superciliosus","overview":"白眉山雀（英文名：White-browed Tit，学名：Poecile superciliosus），是雀形目山雀科高山山雀属的鸟类。广泛分布于中国中部和西藏的高山森林。其显著特征为细长的白色眉纹、黑色的冠顶和喉部，以及带有锈色的脸颊。体长13.5至14厘米，体重介于10.1到12.4克之间。","appearance":"白眉山雀体型较大，尾巴较长，头部呈黑色，具有醒目的白色眉纹。雄鸟的冠顶至颈背为暗黑色，眉纹自额部向后延伸，渐细于颈侧；面颊至颈侧呈淡灰肉桂色，下巴和喉部为烟黑色，形成大块暗色领圈，下体颜色从淡粉红至粉肉桂色。雌鸟与雄鸟相似，但冠顶和领圈较暗淡，眉纹更窄，上体颜色略带淡黄褐色。幼鸟与成鸟类似，但尾羽边缘和尖端常更白。","call":"白眉山雀频繁发出细薄的‘si-si’声或更高音的‘see-see’声，通常成系列，还有‘stip’或‘tip’声，以及干燥昆虫般的‘trrrrrrr’或‘tsirrrr’声。警报时会发出一系列‘si’、‘sip’或‘tchip’音，节奏感强。","habits":"栖息于高山矮树丛中，如Berberis、Rhamnus、Rhododendron和Salix，海拔高度3200至4235米，冬季下降至较低的针叶林区，主要为云杉林。以小昆虫、幼虫和部分种子为食。繁殖季节成对出现，非繁殖季则结成小群，多达十二只，常与花彩雀莺一同活动。","breeding":"繁殖信息了解不多，至少在五月和六月繁殖。巢筑于植物根部的洞穴或废弃的鼠洞中，由动物毛发、少量鸟羽和苔藓构成。雌鸟孵化，雄鸟在巢附近喂养。","identification":"与David's Tit（Poecile davidianus）相比，白眉山雀的白色眉纹更宽，脸颊颜色更深，下体颜色更浅。","protection":"IUCN：LC（无危）；国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"分布于中国中部，包括青海东部至甘肃南部和四川北部，以及西藏东北部和东南部（昌都地区、拉萨地区）。","other":"分子系统发育研究显示，白眉山雀与暗山雀亲缘关系最近。"},{"name":"暗山雀","english_name":"Sombre Tit","scientific_name":"Poecile lugubris","overview":"暗山雀（英文名：Sombre Tit，学名：Poecile lugubris），是雀形目山雀科高山山雀属的鸟类。单色的山雀，以黑色、白色和灰褐色为主色调，缺乏鲜艳色彩。体型和结构与欧亚大山雀相似，常见于干燥的灌木林区、地中海灌丛和岩石山丘。在东南欧洲和西南亚洲分布，常栖息于海拔1000至1600米的稀疏林地。","appearance":"体长12.4-15厘米，体重15-19克。雄鸟具较大喙，灰褐色的山雀，头冠至颈背呈黑褐色至深烟灰色，耳羽和脸颊白色，颈侧转为浅黄色；上体大部分为暗淡的灰棕色，尾羽灰棕色带橄榄灰色边缘，翼覆羽与上体相似，但大覆羽有淡黄色或更淡的边缘；下体白色，胸部和两胁泛黄；雄鸟指名亚种的头部特征更为明显，雌鸟头部颜色变异从黑褐到深巧克力色，下体较暗或泛灰。幼鸟似雌鸟，但头部颜色更接近上体，脸颊泛白，大覆羽尖端明显白色。","call":"叫声为尖细或鼻音的‘si’或‘zee’作为联系声，可延长成下降的‘si-si-si-si-si-si-si’声调，有时以短促的‘trrrr’颤音结束；也会发出刺耳的‘chit’声，连续的‘chit-cht-cht-cht-cht-cht’颤音；报警时发出急促响亮的‘trrrrrrrr’颤音，类似麻雀的叫声。","habits":"栖息于散落树木和灌木的干燥马基斯地区，如橄榄树、野李子果园和其他果树地带，以及开阔的橡树林和灌木林，包括山毛榉、柳树和杨树；也见于针叶林，尤其是云杉和雪松。从地中海海平面到土耳其的2200米高度都有分布，冬季会下移至较低海拔。","breeding":"繁殖期从4月初持续到7月底或8月初，通常产4到9枚卵，每年产两窝。它们在树洞中筑巢，如杜松、柳树、杨树等，有时也在铁管或人工巢箱中筑巢。繁殖密度每公里约5-10对。","identification":"与沼泽山雀的主要区别在于体型更大，喙更粗壮，头冠暗黑而非光泽黑色，上体带有灰色调的棕色，喉咙和胸脯的黑色更深。","protection":"IUCN：LC（无危）。在保加利亚和土耳其数量稳定，但克罗地亚的数量正在减少。","distribution":"分布于斯洛文尼亚山区南部至罗马尼亚，南至希腊和土耳其，向东至格鲁吉亚西南部、亚美尼亚南部、阿塞拜疆西南部和伊朗西北部，南至以色列北部和伊朗中南部。","other":"分子系统发育研究表明，暗山雀与白眉山雀亲缘关系最近。"},{"name":"红腹山雀","english_name":"Pere David's Tit","scientific_name":"Poecile davidi","overview":"红腹山雀（英文名：Pere David's Tit，学名：Poecile davidi），是雀形目山雀科高山山雀属的鸟类。为中国特有种，主要分布在甘肃南部至四川南部、陕西南部及湖北西部的中海拔混合森林中。这中等体型的山雀，拥有黑色的头冠，白色的面颊，以及醒目的橙红色腹部。在中国中部的特定区域内相对罕见。","appearance":"红腹山雀体长约12至13厘米，体重约10至12.5克。头部顶部至颈背呈黑色，侧颈为锈红色形成半环状领。上体为棕色至橄榄棕色，翅膀的覆羽深棕色边缘为橄榄棕色，飞羽棕色边缘淡黄褐色。尾巴颜色为棕色至橄榄棕色。脸颊至颈侧白色，毛发蓬松。下巴和喉咙为烟灰色黑色，形成大的暗色领结。下体为肉桂色，腹部中心略浅。幼鸟的面颊和耳羽带有黄色调，下体颜色更淡或微带黄色，尾羽尖端呈尖锐状。","call":"其鸣叫包括多种高音调的“sip”、“tsip”、“tis”、“psit”和较硬的“chit”、“sit”或“ssit”声，还有拉长的“chi-it-it”和“tsip-tzee”声。此外，也会发出类似“chic-a-dee”的叫声作为歌曲。","habits":"红腹山雀常在成熟混交林中活动，林中包含云杉、冷杉、松树、白桦、杨树、柳树、桤木和橡树，常伴有竹子灌木层。它们在繁殖季节通常以对出现，而非繁殖季节则形成最多十只的小群体。在树冠层活跃觅食，也偶尔在灌木中寻找食物，主要食物为小型无脊椎动物、幼虫和种子。","breeding":"繁殖季节至少在五月开始，具体细节未知。巢穴建于腐朽或腐烂的树干或树桩中的洞或空腔中，高度从地面4至10米，由苔藓和可能的苔藓构成。孵化期间，雌鸟由雄鸟喂食。","identification":"红腹山雀最显著的特点是其橙红色的腹部，与沼泽山雀相似但腹部色彩更加鲜明。它在中等海拔的中国中部森林中活动，与其他山雀的区别在于其独特的鸣叫和颜色模式。","protection":"IUCN：LC（无危）。国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"主要分布在中国中部，包括甘肃南部至四川南部、陕西南部和湖北西部，活动于海拔2135米至3400米之间，冬季则在略低的海拔，如四川的2200米至3050米。"},{"name":"沼泽山雀","english_name":"Marsh Tit","scientific_name":"Poecile palustris","overview":"沼泽山雀（英文名：Marsh Tit，学名：Poecile palustris），是雀形目山雀科高山山雀属的鸟类。又名: 小仔伯、仔仔红、红子、小豆雀、唧唧鬼子、泥泽山雀，体长约12厘米，体重约12克，具黑冠与黑颈，脸颊白皙，背羽灰褐，翼及尾羽灰褐。全球分布广泛，尤其在欧洲和亚洲北部。繁殖季节为3月至5月，营巢于树洞中，巢精致，呈杯状，内垫柔软材料。","appearance":"体长11至12厘米，体重8.9至15克。具有光泽的黑色帽状头部和灰褐色背部，下颚至颈部有小而黑色的喉斑。雌雄外观相似，幼鸟与成鸟类似，但色泽较暗，光泽度较低。各亚种差异不大，主要体现在体型和羽毛色调上。","call":"鸣叫声多样，最典型的是尖锐的\"pitchuu\"声，常连续发出\"pitchuu-bee-bee-bee\"，可与褐头山雀的声音混淆。鸣唱丰富，包括响亮的重复单音符声，如\"schip-schip-schip-schip-ship\"，更柔和的\"tu-tu-tu-tu-tu\"，甚至甜美的\"tyeu-tyeu-tyeu-tyeu-tyeu\"。","habits":"栖息于低地至亚高山的成熟落叶林，偏好有较高比例枯木和开阔下层植被的环境。主要食物为昆虫，春季和夏季以蜘蛛和昆虫为主，秋季和冬季转向种子、坚果和浆果。常在落叶林、果园和花园中觅食。","breeding":"繁殖季节从3月底持续至6月，一窝产5至11枚蛋，通常为6至9枚，孵化期13至17天。幼鸟由双亲共同喂养，巢期16至21天。幼鸟离巢后仍被喂养七天，之后15天内独立。","identification":"与褐头山雀难以区分，主要通过声音、头部标记和行为特征。沼泽山雀头部的黑白分界线较为水平，脸颊和耳羽的对比更为明显。鸣叫声尖锐，有别于褐头山雀。","protection":"IUCN：LC（无危）。在中国被列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","distribution":"分布于欧洲大部分地区，从西班牙北部至苏格兰东南部，东至俄罗斯西部，亚洲东部从阿尔泰山脉向东至日本北部和中国北部及西部。","other":"在英国，自1960年代以来，数量减少了近75%，可能与生存率下降和栖息地连接性丧失有关。"},{"name":"伊朗山雀","english_name":"Caspian Tit","scientific_name":"Poecile hyrcanus","overview":"伊朗山雀（英文名：Caspian Tit，学名：Poecile hyrcanus），是雀形目山雀科高山山雀属的鸟类。其特征为具有诊断性的棕色头冠，界限模糊的黑色胸带，以及深棕色的上体。分布于阿塞拜疆山区东南部和伊朗北部的塔里什山脉及厄尔布尔士山脉。","appearance":"春季成鸟的头部呈温暖的栗褐色，背部和肩部灰色略带黄褐色调，臀部色彩更鲜明，含红棕色元素；黑色的胸带，胸部和腹部白色，侧面较暗，带有淡红褐色调；下尾羽白色或带棕色尖端；飞羽边缘白色，部分内侧二级飞羽及其覆羽边缘灰色；2-3枚外侧尾羽外网白色，其余尾羽较窄，灰白相间。秋季成鸟头冠暗淡，背部有更多黄锈色元素，胸带颜色暗淡，下体有更广泛的红棕色元素，下尾羽淡棕色，飞羽边缘有更宽的淡色边缘。雌雄相似，幼鸟外观类似秋季成鸟，但体型更短小，松散，头冠暗淡，背部灰色带少量红棕色，胸带颜色偏棕，下体白色带淡红褐色调，尾羽尖端更锐利。伊朗山雀比近缘种暗山雀稍小且颜色更深，尾巴较短，喙相对较大。","call":"通常较为沉默，即使在繁殖季节，歌声也很少被听到。其歌声为清晰而略带减弱的‘tiu’声，重复3至5次，与欧亚山雀相似，但音符更为柔和。报警叫声为短促鼻音的‘chev’或‘tshef’，可连续发出多次，与暗山雀的一声歌唱中的音符相呼应。","habits":"栖息于混合阔叶山地林区，以山毛榉(Fagus orientalis)、榛树(Carpinus betulus)为主，辅以橡树(Quercus castaneifolia)和枫树(Acer hyrcanum)，林下层丰富，以山楂(Crataegus monogyna)、野苹果(Mespilus caucasica)、榅桲(Cydonia oblonga)和蔷薇(Rosa spp.)为主，包括部分砍伐和强烈放牧区域，海拔400-2100米。夏季饮食包含毛虫、甲虫、陆生软体动物和豆科植物种子，幼鸟还被喂食长脚蚊(Tipulidae)。","breeding":"繁殖季节因海拔高度略有差异，低海拔地区首枚卵产于4月14日至17日，高海拔地区则在4月22日至5月初。一夫一妻制，领地意识强，很少离巢树超过120-150米。巢穴由双亲共同挖掘于死树或活树的洞穴中，筑巢材料包括树皮条、动物毛发、星状毛和羽毛，巢直径68-82毫米，高度48-63毫米，杯径46-60毫米，深30-43毫米。每窝产卵4-7枚，颜色与暗山雀相似，卵长16-18.1毫米×宽12.2-13.3毫米，重量1.2-1.5克，孵化期最多13-14天，由雌鸟承担。雏鸟喂养频率高达约每小时21次。","identification":"与暗山雀相比，伊朗山雀的头部和颈背的暗栗褐色更广泛，上体颜色更深（肩部可能带粉红色调），三级飞羽缺乏宽大的淡色边缘，大覆羽尖端更呈淡棕色而非白色，胸带颜色更深，向下延伸至上胸部，但不至两侧，下体在新羽时呈现锈色或粉红米色，旧羽时更苍白。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于阿塞拜疆的塔里什山脉和伊朗北部的厄尔布尔士山脉，海拔550-1250米，特别是在1000米以上。在阿塞拜疆，主要分布在550-1250米的海拔范围内。","other":"分子系统发育研究表明，伊朗山雀与褐头山雀关系最为密切。"},{"name":"黑喉山雀","english_name":"Black-bibbed Tit","scientific_name":"Poecile hypermelaenus","overview":"黑喉山雀（英文名：Black-bibbed Tit，学名：Poecile hypermelaenus），是雀形目山雀科高山山雀属的鸟类。在中国中部、西部和西南部以及缅甸西部有分布。其与沼泽山雀亲缘关系密切，曾被《中国鸟类野外手册》作为沼泽山雀的一个亚种。","appearance":"黑喉山雀是一种中等大小的山雀，体长11-12厘米，体重9-11.5克。头顶黑色，有黑色的喉咙斑块，成鸟的前额、头顶至颈背均为黑色，有时可见短而粗糙的冠羽；脸颊和耳羽白色，有时耳羽后方略带褐色。上体橄榄色带灰棕色调，飞羽暗褐色，边缘为褐色橄榄色，尾羽灰棕色，边缘更灰色。下巴到喉咙两侧和下喉中心至胸上部黑色或深棕色；下体白色，除了下胸部和胁部呈灰橄榄色，通常延伸到腹部。虹膜深棕色或黑色，喙黑色，上颚切割边缘较淡灰色，腿蓝至板岩灰色。幼鸟与成鸟相似，但头顶至颈背为烟黑色或棕色，缺乏光泽，上体颜色更温暖或更灰，飞羽和尾羽边缘更棕色，脸颊和耳羽更白，喉咙斑块部分被白色尖端遮挡，下体更白，胁部和臀部带有黄色色调。","call":"鸣唱由一系列尖锐的单音节'schip'音符或更短的'chi chi chi chi'组成，有时以'swi-sweet weet weet'或类似的声音结尾。叫声包括清澈的'psit'或'stip'，最常见的为尖锐或爆破的'pitchuu, pitchuu'变体，还有细高的'tip'声，嘶嘶声'see'常重复多次，报警叫声包括'chay'的叽喳声或'char-tchar-tchar-tchar'的尖厉鼻音。","habits":"黑喉山雀偏好中至高海拔的森林，常与中国松林或缅甸的混合林相伴。在中国的分布海拔从1525米到4270米不等，而在缅甸的维多利亚山，则居住在海拔2200米至约3000米的高山地带。","breeding":"繁殖季节从3月至6月。在缅甸维多利亚山的一处巢穴发现于4月19日，几乎已孵化的小鸟位于一棵断裂的大约8米高的树洞中，洞的上部形成了巢室。在贵州发现的巢穴位于墙内，由根须和毛发构成，含六枚紫点白色的蛋，尺寸约为17.9×13.1毫米。","identification":"与沼泽山雀相比，黑喉山雀具有更广泛的黑色喉咙斑块，到达胸上部，下体颜色更暗淡，广泛覆盖深灰色橄榄棕色，而非浅灰色或黄褐色；帽更大，延伸至披肩更远；脸颊斑块在后方更宽；上体颜色更暗，绿色橄榄色而非温暖的灰褐色或沙棕色；翅膀和尾巴较为朴素，无亮白色边缘；尾巴较短。","protection":"IUCN：LC（无危）","distribution":"在中国中部、西部、西南部以及缅甸西部有分布。具体在中国的甘肃南部、陕西南部、四川、湖北西部、云南北部至贵州西北部以及缅甸北部和西部有记录。","other":"关于黑喉山雀的分类地位存在争议，一些学者认为它可能是沼泽山雀的亚种，而另一些则支持其物种地位。分子证据支持其与褐头山雀的关系更为紧密。"},{"name":"褐头山雀","english_name":"Willow Tit","scientific_name":"Poecile montanus","overview":"褐头山雀（英文名：Willow Tit，学名：Poecile montanus），是雀形目山雀科高山山雀属的鸟类。俗名: 唧唧鬼子，常见的小型山雀科鸟类，广泛分布于欧亚大陆，自英国至日本皆有其踪迹。其头部顶部和颏部呈褐黑色，上体为褐灰色调，下体接近白色，缺乏明显的翼斑和项纹。在针叶林或针阔混交林中生活，活跃于低地到高山森林地带。","appearance":"体长约11.5厘米，翼展17-20.5厘米，体重约11克。拥有较大的头和细长的喙，顶冠和颈背呈现暗黑色，脸部两侧为白色，背部呈灰褐色，腹部则为淡黄色。雌雄外观相似，但随着地理位置的不同，颜色可能会有所差异。幼鸟的冠羽较成鸟更为暗淡，上体颜色更偏冷灰色。","call":"发出尖锐的鼻音‘zee-zee-zee’，偶尔会重复双音节‘ipsee-ipsee’四到五次。","habits":"栖息于各种类型的森林，包括松树林、落叶松林和云杉林，尤其偏好湿润的环境，如泥炭沼泽和柳树丛。在欧洲，也可见于柳树、桤木和灌木丛生地带。大部分时间居留于原地，但在食物短缺时，北方种群会进行短距离迁移。以昆虫、虫卵、种子和浆果为食，冬季植物性食物占比增加。","breeding":"繁殖期通常在4月至8月，雌雄共同挖掘巢穴，多位于腐朽的树干或旧树桩中，巢由苔藓、毛发和木屑构成。每窝产卵数为6-9枚，卵壳为白色，带有红褐色斑点，由雌鸟单独孵化，孵化期13-15天。幼鸟由双亲喂养，离巢时间为17-20天。","identification":"与沼泽山雀相似，但前者冠羽呈烟灰色而非光泽蓝黑色，整体色彩更淡，腹部更偏黄褐色，两胁明显更红棕色。闭合翅膀时，次级飞羽的淡色边缘形成明显的光斑。","protection":"IUCN：LC（无危）。虽然全球数量庞大，但英国种群自1995至2017年下降了83%，归因于栖息地丧失、巢穴竞争和巢穴掠食。","distribution":"分布于欧洲自英国、法国、意大利、罗马尼亚、保加利亚向东至俄罗斯、蒙古、日本、朝鲜及中国多个省份，包括河北、山西、内蒙古、黑龙江、吉林、辽宁、宁夏、甘肃、青海、新疆、四川、云南、西藏。在欧洲，分布密度最高的是西伯利亚，尤其是在黑暗的针叶林带。","other":"在北芬兰的研究显示，幼鸟首年的存活率为0.58，成年后年生存率约为0.64，平均寿命仅三年。最长记录年龄为11年。"},{"name":"川褐头山雀","english_name":"Sichuan Tit","scientific_name":"Poecile weigoldicus","overview":"川褐头山雀（英文名：Sichuan Tit，学名：Poecile weigoldicus），是雀形目山雀科高山山雀属的鸟类。是中国特有种，原作为褐头山雀的亚种，现已提升为独立物种。分布于中国中西部，包括四川、青海东南部及云南西北部的森林地带。","appearance":"川褐头山雀体长11至12厘米，体重8至15克。头部宽大，翼上有明显的淡色斑块。头顶至眼下方边缘、颈背及上背部呈暗黑色，其余上体部分为淡灰棕色，飞羽深灰色，边缘浅色，次级飞羽有白色或淡黄褐色边，形成闭合翼上的显著条纹。尾羽黑灰，外缘有宽淡黄褐色边。脸颊、耳羽白色，颈侧奶油色。下颏和喉部暗黑，形成不规则的围兜，喉咙边缘及下缘有白色尖端。下体呈淡灰白色，新鲜羽毛时带粉红黄褐色侧面和两胁，磨损羽毛时上体更淡或更灰色，翼斑有时不那么突出，围兜略大，下体更白，除温暖的黄褐色两胁和尾下覆羽。虹膜棕色至深棕色，喙深蓝黑色或黑色，腿深灰蓝色。雌雄相似，幼鸟冠部较暗棕黑色，上体较冷灰棕色，脸颊和耳羽淡奶油色，围兜稍淡棕色，边缘白色，下体更白，两胁和尾下覆羽带黄褐色。不同亚种在体型、尾长和体色上有所差异。","call":"发出一系列不同的叫声，包括鼻音和咔哒声的呼叫，歌曲包含鼻音和重复的高音“tseep”。","habits":"栖息于低地到高山的森林和林地，主要在松树、落叶松和云杉等针叶林，也见于西伯利亚石松的草原森林。在欧洲，也出现在柳树、桤木和灌木丛中，包括接骨木树丛、树林边缘、小树林和树篱，尤其沿河和湖边。活动海拔从海平面到林线，欧洲可达约2000米，中国天山1830至2745米，四川2200至4275米，夏季在青海3350至4000米，西藏3840米（三月）和3960米（七月）。主要以昆虫和幼虫为食，非繁殖季节也吃谷物和种子。","breeding":"繁殖季为4月至7月，一窝产5至9枚卵。雌雄配对终身。巢由雌鸟建造，通常位于腐朽树干或旧树桩的洞或裂缝中，离地面高度0.3至3米。孵化期13至15天，由雌鸟承担，有时在巢未建完前就开始孵化。幼鸟由双亲喂养，巢期17至20天。幼鸟依赖父母12至15天后分散。","identification":"与黑围兜山雀相比，川褐头山雀头部更宽，帽顶延伸至上背部，翼上斑点明显，且尾羽和飞羽中心更暗或接近黑色，围兜略大，下体更广泛地带有深黄褐色。","protection":"IUCN：LC（无危）","distribution":"分布于中国中西部，包括四川、青海东南部及云南西北部。在繁殖区域内，海拔范围广泛，从海平面至4275米。","other":"自20世纪60年代起，该物种在英国的数量开始下降，至1995年至2010年间，其数量减少了79%，分布范围收缩了50%。"},{"name":"卡罗山雀","english_name":"Carolina Chickadee","scientific_name":"Poecile carolinensis","overview":"卡罗山雀（英文名：Carolina Chickadee，学名：Poecile carolinensis），是雀形目山雀科高山山雀属的鸟类。以其灰色的外表、鲜明的黑白头纹以及活泼好动的性格而闻名。这种山雀体型圆胖，头部较大，拥有黑色的顶冠和喉咙，白色的面颊，背部和翅膀呈灰绿色。在冬季能够形成混合种群，与多种小型鸣禽共同活动，同时也能适应城市环境。","appearance":"成年卡罗山雀的体长介于11.5至13厘米之间，体重在9至12克左右。其特征为黑色的顶冠和围嘴，白色的脸颊，背部和翅膀为灰色，下体白色，两翼侧带锈褐色。喙短而黑，尾羽适中，翼展较短。雌雄外观相似，但雄鸟平均比雌鸟大。","call":"卡罗山雀的叫声包括快速而高音的“chick-a-dee”声，以及四音节的“fee-bee-fee-bay”歌声，与黑顶山雀的声音有细微差别。","habits":"卡罗山雀栖息于美国东南部的混合林或落叶林中，是永久居民，即使在严冬也不迁徙。它们以昆虫为主要食物，夏天更甚，冬天则转向种子和浆果。卡罗山雀会利用树洞或巢箱筑巢，也会在树枝上啄开种子。","breeding":"繁殖期通常在春季，卡罗山雀会在树洞中筑巢，有时使用自然形成的空洞或旧啄木鸟巢。雌鸟负责用苔藓和树皮条建造巢穴，再以毛发或植物纤维做内衬。每窝产卵数为3至10枚，孵化期约为12至16天，雏鸟期大约持续16至19天。","identification":"与黑顶山雀相比，卡罗山雀的翼上有略微棕色的色彩，大覆羽边缘为棕色而非白色，尾羽略短且末端较平。视觉识别较为困难，需依赖叫声。","protection":"IUCN：LC（无危）","distribution":"卡罗山雀的繁殖区位于美国东南部，从新泽西和宾夕法尼亚向西至堪萨斯南部，南至佛罗里达和得克萨斯。在阿巴拉契亚山脉的高海拔地区，其分布被黑顶山雀取代。","other":"卡罗山雀和黑顶山雀在接触区可以杂交，但杂交后代的孵化成功率较低，性别比例偏向雄鸟，这符合哈尔丹规则。"},{"name":"黑顶山雀","english_name":"Black-capped Chickadee","scientific_name":"Poecile atricapillus","overview":"黑顶山雀（英文名：Black-capped Chickadee，学名：Poecile atricapillus），是雀形目山雀科高山山雀属的鸟类。北美广泛分布的小型鸣禽，长约13厘米。头顶与下颚为深黑色，双颊洁白，腹部淡黄色至黄褐色，背部和翅膀灰绿色，尾羽呈暗灰色。活跃于北美的森林与居住区，偏好树木与灌木丛生的环境。","appearance":"黑顶山雀拥有明显的黑色顶冠与下颚，双颊雪白，背部与翅膀呈现柔和的灰绿色，腹部及两肋带黄褐色，尾羽瓦灰色。成年鸟的体型紧凑，翼展适中，尾部相对较长。雄鸟较雌鸟略大，且具有较大的黑色喉部。幼鸟外观类似成鸟，但羽毛质地更柔软，色泽稍显暗淡。","call":"黑顶山雀以其复杂且多变的鸣叫声著称，最具标志性的‘费比’两音节鸣唱，第二个音节略低于第一个，以及‘叽叽啾啾啾啾’的报警声，后者用于警示同伴危险的存在。","habits":"栖息于北美的森林地带，包括混交林与针叶林，常见于城市公园与郊区。夏季以昆虫为主食，冬季转向浆果和种子。具有悬停捕食的能力，常倒挂于枝头。冬季形成混合物种群落，与其他鸣禽共同活动。","breeding":"繁殖期从晚春持续到初夏，筑巢于天然树洞或啄木鸟弃巢中。雌鸟负责筑巢，巢由粗材料铺底，细软材料做衬。每窝产卵六至八枚，孵化期约为11至14天，由雌鸟独自孵卵，期间雄鸟负责喂食。","identification":"与卡罗山雀极为相似，主要通过声音、翼羽的白色边缘和黑色喉部的边界区分。黑顶山雀的叫声更为低沉，翼羽的白色边缘更宽，喉部边界较模糊。","protection":"IUCN：LC（无危）","distribution":"遍布加拿大南部至美国北部三分之二的地区，西至阿拉斯加与育空，东至大西洋省份与纽芬兰，南至加州北部、内华达州北部与新墨西哥州，东部至阿巴拉契亚山脉。","other":"黑顶山雀是美国缅因州和马萨诸塞州的州鸟，加拿大的新不伦瑞克省的省鸟。"},{"name":"北美白眉山雀","english_name":"Mountain Chickadee","scientific_name":"Poecile gambeli","overview":"北美白眉山雀（英文名：Mountain Chickadee，学名：Poecile gambeli），是雀形目山雀科高山山雀属的鸟类。小型的山地森林鸟类。其最显著的特征是眼睛上方有一条白色条纹，将黑色的顶冠和眼罩分开。分布于北美的西部地区，包括美国西部及加拿大南部，直至墨西哥西北部的山地。常栖息于高海拔的针叶林地带。","appearance":"北美白眉山雀体型小巧，平均长度约为128.4毫米（雄鸟）至122.8毫米（雌鸟），体重约11.2克。头部顶部至眼睛下方为黑色，形成独特的黑色帽状图案。额头和眉线为白色，中断了黑色的帽状区域。脸颊呈灰白色，背部、翅膀和尾巴为灰橄榄色至淡褐色，腹部和胸部为灰白色。两性外观相似，但在繁殖季节，雄鸟的泄殖腔凸起较大，雌鸟则有孵卵斑。幼鸟与成鸟外观类似，但成鸟体型更大。","call":"其叫声为沙哑的“chick-adee-dee-dee”，而歌声为3到4个音符的下降哨音，类似“fee-bee-bay”或“fee-bee-fee-bee”，有时听起来像是在吹口哨说“Cheeseburger”。","habits":"北美白眉山雀栖息于西部山地的干燥针叶林区，高度活跃且敏捷，常在小枝和细枝上跳跃，甚至倒挂在松果上。冬季时，它们会与金雀鸟和旋木雀混群活动。全年访问鸟食台，食用牛油果、黑油葵花籽和尼杰尔种子。以昆虫为主食，夏季和繁殖季节尤为明显，同时也摄取松果种子和其他植物种子。","breeding":"它们实行一夫一妻制，每年繁殖1到2窝，每窝平均产5至9枚蛋，蛋壳白色带赤陶色斑点。孵化由雌鸟承担，为期14天。雏鸟为晚成雏，需在巢中停留21天，期间双亲共同喂养。","identification":"与北美其他山雀的区别在于其头部黑色部分被一条白色眉线分割。与黑顶山雀相比，其翼羽和次级飞羽边缘较淡，翼展较大，尾部相对更短，喙部更大，上体有橄榄绿至淡褐色调，侧翼颜色介于烟灰色和浅橄榄色之间。","protection":"IUCN：LC（无危）","distribution":"北美白眉山雀广泛分布于美国西部、加拿大南部直至墨西哥西北部的山地，常见于高海拔的针叶林地区。","other":"该物种在繁殖季节结束时，会形成由几只成鸟和一些幼鸟组成的群体。幼鸟通常独自度过夏天，但在冬天会与成年鸟群汇合。"},{"name":"墨西哥山雀","english_name":"Mexican Chickadee","scientific_name":"Poecile sclateri","overview":"墨西哥山雀（英文名：Mexican Chickadee，学名：Poecile sclateri），是雀形目山雀科高山山雀属的鸟类。显著特征是黑色的头部，白色的颊部，以及延伸至胸部的黑色喉部。主要分布在墨西哥西部、中部和东北部的高海拔森林地带，极少数个体在美国西南部的山区被发现。该物种是永久居民，但在冬季可能会向较低海拔迁移。","appearance":"成年墨西哥山雀体长12.5-13.5厘米，翼展18-21厘米，体重介于7.5-11克之间。两性皆具黑色的顶冠、白色脸颊和短小的黑色喙。背部和侧身呈现灰色，腹部颜色较浅。与黑顶山雀和北美白眉山雀相似，但可通过更长的黑色胸带和腹中延伸的白色条纹来区分。","call":"墨西哥山雀的鸣唱复杂而多变，包括‘chischu-wur’的颤音和‘cheelee’的丰富声音，与其它山雀种类的鸣声截然不同。","habits":"墨西哥山雀居住在高海拔的松林中，通常与多种小型鸣禽混群活动。它们主要以昆虫为食，偶尔也会迁徙到较低的海拔以应对寒冷的冬季。","breeding":"筑巢由雌鸟负责，巢建在树洞或枯木中，距地面高达18米，巢材包括草、苔藓、树皮碎片和兽毛。每次产卵5-8枚，卵呈白色，带有细小的红棕色斑点。孵化期大约为11-14天，由雌鸟承担，雏鸟在18-21天后离巢。","identification":"墨西哥山雀与黑顶山雀和北美白眉山雀相似，但其更长的黑色胸带和腹中延伸的白色条纹是重要的辨识特征。此外，其复杂的鸣声也是区分的关键。","protection":"IUCN：LC（无危）","distribution":"主要分布于墨西哥西部、中部和东北部的高海拔森林，以及美国西南部的亚利桑那州和新墨西哥州的部分山区。","other":"墨西哥山雀的自然历史数据较少，对其生物学的多个方面仍需更多研究。"},{"name":"西伯利亚山雀","english_name":"Grey-headed Chickadee","scientific_name":"Poecile cinctus","overview":"西伯利亚山雀（英文名：Grey-headed Chickadee，学名：Poecile cinctus），是雀形目山雀科高山山雀属的鸟类。广泛分布于欧亚大陆北部及北美西北部的亚北极地带，包括挪威、阿拉斯加和加拿大极北地区。其显著特征为头部拥有黑色、白色与棕色的独特组合，而非其名所暗示的灰色头部。","appearance":"西伯利亚山雀体长约13.5至14厘米，体重介于11至14.3克之间。头部呈饱满的绒毛状，冠部暗巧克力色，脸颊白色，具有黑色的下巴斑块，两胁锈色。在北美，背部呈灰棕色，与颈背和冠部形成轻微对比，胸部和腹部白色，两胁淡黄色。幼鸟与成鸟相似，但冠部更偏暗棕色，背部更灰暗，脸颊和耳羽为淡奶油色或略带黄色，下巴斑块较大，颜色较浅的棕色，边缘有白色尖端，腹部更白，两胁和腹下部有淡黄色的洗染。雄雌外观相同。","call":"西伯利亚山雀发出多变的chik-chik-chik叫声，鸣声为重复的psiup声及类似昆虫的振翅声。","habits":"夜幕降临时，西伯利亚山雀可能会进入半冬眠状态，停栖于树洞中，利用其特殊的羽干使体羽长时间保持蓬松，以保持体温。偏好生活在保存良好的苔藓覆盖的松林和高海拔的白桦林中。它们以昆虫和种子为食，会访问喂食器。","breeding":"在繁殖季节，西伯利亚山雀会展示复杂的繁殖行为，包括求偶、筑巢、交配、产卵、孵化和育雏等过程。具体细节需参考详细的研究资料。","identification":"与北美其他山雀相比，西伯利亚山雀体型更健壮，尾巴较长，外表更蓬松。最接近的是北山雀，但后者冠部更棕色，脸颊较为暗淡，两胁棕色，翅膀灰色，而西伯利亚山雀在新鲜羽毛状态下翅膀上的大覆羽边缘呈白色。幼年北山雀常被误认为西伯利亚山雀，因它们的冠部更灰，两胁更淡。在明亮的颊部和大覆羽边缘的白色上，西伯利亚山雀更像黑顶山雀。","protection":"IUCN：LC（无危）","distribution":"西伯利亚山雀广泛分布于欧亚大陆北部，包括挪威至东欧，以及北美的阿拉斯加和加拿大极北地区。","other":"自1940年代以来，西伯利亚山雀似乎对人类活动（尤其是伐木）更为敏感，其种群数量呈现下降趋势。"},{"name":"北山雀","english_name":"Boreal Chickadee","scientific_name":"Poecile hudsonicus","appearance":"北山雀的体型约为12.5至14厘米，体重在7到12.4克之间。其上体呈灰褐色，头部有醒目的棕色帽状斑，翅膀和尾巴呈现灰色调，脸部主要为灰色，两侧有白色斑块。下体颜色为白色，两侧带棕色，喉部为黑色。喙短而暗色，翅膀短小，尾巴较长且末端呈锯齿状。飞行时表现出短暂滑翔后快速拍打翅膀的特征。","call":"北山雀发出响亮的‘tsee-day-day’声和高音颤音，后者是它们得名的来源。这种叫声由五种不同的音符组成，起始和结束音都具有高频率，用于与其他鸟沟通和传递信息。","habits":"北山雀主要栖息在加拿大、阿拉斯加和美国北部的针叶林中，全年留在繁殖范围内。它们在黑云杉、白云杉和冷杉树上觅食昆虫和松果种子，冬季会储存食物。通常以小群活动，尤其是在冬季，与其他小鸟混群。","breeding":"繁殖季节从五月持续到八月，它们会在树洞中筑巢，有时利用自然形成的空洞或旧啄木鸟的巢穴。每窝产5到7枚蛋，孵化期为13到16天。雏鸟在16到18天后能离巢飞行。","identification":"北山雀与黑顶山雀和北美白眉山雀在大小和形状上相似，但独特的棕色帽状斑、黑色喉部和橙黄色两翼侧使其易于识别。与栗背山雀相比，北山雀缺乏鲜艳的红色背部。","protection":"IUCN：LC（无危）","distribution":"北山雀主要分布在北美北部，包括加拿大、阿拉斯加和美国最北部的地区，栖息于成熟的云杉和冷杉森林。","other":"北山雀的近亲包括灰头山雀和栗背山雀，它们属于‘棕色帽状’山雀群。"},{"name":"栗背山雀","english_name":"Chestnut-backed Chickadee","scientific_name":"Poecile rufescens","appearance":"成年栗背山雀体长105.0-120.5毫米(雄鸟)，100.0-114.0毫米(雌鸟)，体重8.5-12.6克。头部呈深棕色至黑色，两侧有白色颊斑。背部至臀部为深红褐色。黑色的颈围延伸至喉部和上胸，与白色的胸部形成鲜明对比。侧面和侧翼为明亮的红褐色，与白色腹部形成对比。翅膀为棕色，内侧次级飞羽和大覆羽有白色边缘，尖端为白色。尾巴棕色，边缘较淡。喙黑色，腿脚暗灰色，眼睛深棕色。雌雄羽毛相似，但在繁殖季节可通过雌鸟的产卵斑和雄鸟的肛门突起进行区分。幼鸟与成鸟极为相似。","call":"栗背山雀的鸣叫声高亢而带嗡嗡声，不同于其他山雀的口哨音调。其特有的Chick-a-dee叫声复杂且响亮。","habits":"栖息于湿润森林，偏好密集的针叶树和橡树林，也会出现在郊区灌木丛中。冬季常结群活动，与黑顶山雀、北美白眉山雀、金冠鸟(Regulus spp.)和啄木鸟(Sitta spp.)等小型鸟类混群。飞行短促起伏，活动范围广泛。","breeding":"在树洞中筑巢，偏好利用啄木鸟遗弃的洞穴，有时自行挖掘。雌鸟独自建巢约一周，使用苔藓、树皮和动物毛发(如鹿、兔、郊狼的毛)构建巢穴。每窝产卵5-8枚，孵化期约两周，幼鸟孵化后三周离巢。","identification":"与其他山雀相比，栗背山雀的红褐色背部和侧翼是最明显的辨识特征。南加州中部海岸的个体侧翼颜色更偏向灰色，仅尾部附近有少量红褐色。","protection":"IUCN：LC(无危)","distribution":"分布于北美太平洋西北部，包括从阿拉斯加东南部至加州南部。在中央Sierra Nevada和旧金山湾区东部郊区也有发现。","other":"在华盛顿州和加州有对其繁殖生态和觅食行为的研究。"},{"name":"非洲青山雀","english_name":"African Blue Tit","scientific_name":"Cyanistes teneriffae","overview":"非洲青山雀（英文名：African Blue Tit，学名：Cyanistes teneriffae），是雀形目山雀科蓝山雀属的鸟类。显著特征为背部深蓝色，比青山雀更鲜艳，无绿色调，眼纹较窄。分布于北非和加那利群岛，常见于温带森林。","appearance":"体长约11至12厘米，重约10克。头部特征明显，前额、眉线至颈背中央白色，冠部深蓝色有光泽，逐渐变为黑色，眼纹和颊部黑色。上体灰蓝色，尾羽深石板蓝，翼覆羽灰带深蓝边缘，飞羽暗灰色带亮蓝边，下体深黄色，腹侧有暗色线。幼鸟头部黄色，冠部和上体绿蓝，尾羽和翼覆羽边缘蓝，脸和下体黄色，随年龄增长变白。不同亚种在羽毛色彩和标记上有差异。","call":"鸣声多样，包括一系列重复的音符，如有力而悦耳的“chi-chi-chirichi-chichiri”、不太旋律的“chi-iss-chi-chi”、“iss-chichichiuu”、活泼的“chivichi-chivichi”和音乐般的“chillu-chillu-chi”。警报声为响亮、振颤的“cher-er-er-er-er-g”。La Palma岛上的亚种声音独特，类似欧亚大山雀的鸣叫。","habits":"栖息于从低地混合灌木林到高山松林的各种木质环境，高度可达1800米。常成对或小群活动，善于在树冠和灌木丛中觅食，主要以小型蝴蝶、蚜虫和甲虫为食。全年居民，幼鸟不离巢区。","breeding":"繁殖季节为2月至7月，可能也在10月至1月。筑巢材料包括苔藓、松针、树叶和羽毛，通常建在距地面3米内的树洞、岩隙或地面。每窝产卵3至6枚，具体繁殖细节未知。","identification":"与青山雀相比，背部颜色更鲜艳，无绿色调，眼纹较窄。不同亚种在羽毛颜色和标记的显着性上有差异。","protection":"IUCN：LC（无危）。在特内里费岛和大加那利岛普遍常见，但在富埃特文图拉岛和兰萨罗特岛稀少或局部分布。","distribution":"主要分布于北非、加那利群岛（西班牙）、意大利的潘泰莱里亚岛。在特内里费岛和大加那利岛广泛分布，但在富埃特文图拉岛和兰萨罗特岛仅局部存在。","other":"曾被认为是蓝山雀的一个亚种，后被提升为独立物种。"},{"name":"青山雀","english_name":"Eurasian Blue Tit","scientific_name":"Cyanistes caeruleus","overview":"青山雀（英文名：Eurasian Blue Tit，学名：Cyanistes caeruleus），是雀形目山雀科蓝山雀属的鸟类。又名: 蓝冠山雀、青山雀，小型山雀科鸟类，以其鲜艳的蓝色和黄色羽毛著称，常见于欧洲的森林、公园、花园和农田中的树篱。体长约12厘米，重7.5至14.7克，头部圆润，拥有蓝色帽顶，白色面颊带有穿过眼周的黑线，黄色腹部。与欧亚大山雀相比，体型更小，活动更为敏捷，两者常一同出现，但头部图案截然不同。幼鸟夏季至早秋可见，面部略显黄色，羽毛较暗淡。常见于鸟食器旁，善于利用巢箱。","appearance":"雄鸟指名亚种为例，额头和上眉区白色，与白色眉纹相连，颈背中央白色，前额蓝色渐深至后颈，眼纹和耳羽黑色，下颈侧至颈背深蓝色，上体浅灰蓝，翼覆羽深蓝，尾羽蓝黑边缘亮蓝，外侧尾羽边缘微白；翼覆羽灰蓝，边缘深蓝，初级飞羽暗灰，边缘亮蓝，次级飞羽尖端微白；脸颊和耳羽白色；下喉至颈侧黑色，与深蓝色颈侧相接；下体黄色，胸带橄榄绿，腹中部可能有黑色细纹，腹部中心可能泛白；下体覆羽乳白；腋羽和下翼覆羽黄色；换羽时冠部、飞羽和尾部略显蓝色，上体灰色或绿色减弱，翼覆羽和飞羽的白色尖端磨损或消失，胸前黑色斑点稍深，胸中央黑色细纹更加明显。雌鸟平均比雄鸟略淡，但相似。幼鸟额头、眉纹和颈背中心淡黄，冠部和颈侧颜色更深，上体灰，尾羽蓝淡，翼覆羽边缘蓝绿，次级飞羽尖端黄白，飞羽边缘灰蓝，面部和下体淡黄，随年龄增长变白，下喉和上喉灰色，胸中央无黑色细线。不同亚种在色彩上有差异。","call":"频繁发出高音调的‘tsee’声作为伴侣或群体间的联系信号，遇险或面对捕食者时发出急促的‘churrrrit’声，有时伴随或随后单个或多个尖锐的‘tsee’或高音的‘seeee’或‘pit’音，激昂时反复。冬季也有金属质感的‘pichoo’声，以及类似‘tsee-tsi-brree tsee-tsi-brree’或‘chi-chichiwee’的尖锐叫声。","habits":"栖息于低地和亚高山带的落叶林，如橡树林和桦树林，以及常绿阔叶林，灌木丛，树篱，耕作边缘，果园，公园和城市花园，包括市区和市中心。避免大面积针叶林，但在非繁殖季节，会在混合群中出现在成熟的针叶林中。在地中海东部，见于约旦的松树林和橡树林，叙利亚西北部的雪松林，伊朗的高山橡树林；在更干旱的范围内，主要出现在河流林地，公园和花园。在北非，见于软木橡树林，阿特拉斯橡树林和常绿橡树林，摩洛哥和利比亚北部的雪松和高山杜松林；在撒哈拉绿洲的棕榈园中居住。在非繁殖季节，广泛存在于含树木和灌木的各类生境，甚至芦苇床。海拔高度从海平面至山区，繁殖季节可达奥地利阿尔卑斯山的1540米，瑞士1700米（多数低于1250米），比利牛斯山脉1800米，希腊、土耳其和伊朗西北部1525米，伊朗西南部至少2040米；在高加索山脉，繁殖高度可达林线附近的3500米左右；在摩洛哥可达1800米以上。","breeding":"繁殖季节一般为4月至6月末，产卵量和繁殖成功率与毛虫（尤其是卷蛾科）的出现时间和数量紧密相关。在欧洲部分地区，两窝繁殖常见，但在英国、德国、科西嘉岛和摩洛哥罕见。一夫一妻制，但高密度繁殖区存在一雄多雌现象；配对关系通常终身。领域性强，单独繁殖；领域在2月初已明确界定，防御入侵者，但有时巢距极近，包括同巢箱的两对。所有与一雄多雌相关的雌鸟在同一领域内筑巢，雄鸟喂养所有巢内的幼鸟。雄鸟展示包括缓慢的飞蛾般飞行和向停歇雌鸟的滑翔，期间头冠部分抬起，尾巴展开；雄鸟也可能做垂直上升至至少6米，然后垂直俯冲至低枝；雄鸟还会在身体水平，尾巴扇开并稍微抬起，枕部羽毛抬起（显示深蓝色项圈），翅膀展开但尖端下垂的状态下跳舞，沿着树枝旋转跳跃长达5米，然后飞回重复表演；雌鸟的求偶涉及雄鸟通过产卵和孵化期提供高蛋白食物。巢由雌鸟建造，主要由苔藓、干草、细树皮条、植物纤维、树叶、动物毛发和羽毛构成，置于树洞、树裂隙、柱子（包括金属路标）或其他人造地点，偶尔在其他鸟类旧巢中（或大型废弃巢的基础），很少在地面洞穴中；广泛使用巢箱；领域大小通常在1公顷内，经常更小，低至0.16公顷。产卵数因地理位置、海拔、巢腔大小和周围生境质量而异，在欧洲7至13枚（超过18枚的通常是两只雌鸟所产），在范围东端通常6至8枚；孵化仅由雌鸟承担，由雄鸟喂食，周期12至16天；雏鸟由双亲喂养，抚养期16至23天。繁殖成功率受天气和捕食影响，数据基于巢箱研究：英格兰南部（牛津郡）最初三年90-95%的小鸟能离巢，但随后几年因鼬鼠捕食而大幅下降；在英格兰南部的第二个研究地点，不同年份的33-77%的巢产生离巢小鸟，主要受灰松鼠、鼬鼠、啮齿动物和大斑啄木鸟的影响，有时繁殖对被麻雀驱逐；在英国，花园中成功率最高（86%），苏格兰松（Pinus sylvestris）种植园（71%）和无捕食威胁的地方（如苏格兰西部的Rhum岛，88%）；雏鸟死亡率受降雨量、温度骤降和食物可用性影响，晚孵出的雏鸟发育不良，死亡率更高。幼鸟前三个月的死亡率高，约为70%，从离巢到11月之间。第一年繁殖。估计约75%的繁殖对能存活至下一季（有的连续四年在一起）；郊区对通常生产力较低，这归因于可获得食物的营养价值较低。最长记录寿命为12年4个月。","identification":"与欧亚大山雀的区别在于较小的体型，活跃性更强，以及独特的头部图案，包括蓝色帽顶、白色面颊和穿过眼周的黑线。此外，叫声和鸣唱也有显著差异。不同亚种之间的辨识主要依据色彩色调的细微差别。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括欧洲温带和亚北极地带的林地，从西欧延伸至中欧。在北欧边缘和范围东南部较为罕见。偶尔在正常分布范围以外繁殖，例如在叙利亚东北部（在该地区为迷鸟）。欧洲繁殖种群估计为1650万至2300万对，西班牙、英伦群岛和德国数量最多。繁殖密度因生境、巢箱供应和与欧亚大山雀的竞争程度而异；在橡树林中密度最高，可达约250对/平方公里，而在纯针叶林种植园中最低。20世纪，分布范围逐渐向北扩展，至南芬兰自1900年左右开始，尤其自1950年代中期以来（荷兰也同期增加），1970年代进入挪威和苏格兰北部。1893年首次在约旦北部发现，直到1984年再次出现，1990年证实繁殖。能够成功抵御严寒天气，仅遭受局部或短期数量波动；在恶劣天气中，人工喂食器的食物供给被认为是大量个体生存的重要因素。","other":"在英国，蓝山雀平均寿命约为1.5岁。全年都会鸣唱，最频繁的时期为2月至6月。"},{"name":"灰蓝山雀","english_name":"Azure Tit","scientific_name":"Cyanistes cyanus","overview":"灰蓝山雀（英文名：Azure Tit，学名：Cyanistes cyanus），是雀形目山雀科蓝山雀属的鸟类。特征为头和下体几乎全白，体纹呈现淡灰色与亮丽的紫蓝色，拥有8个亚种。常见于俄罗斯、中亚、中国西北部等地的阔叶林、混合林及灌木丛中。","appearance":"灰蓝山雀体长约12-13厘米，体重介于10.6-16克之间。头部几乎纯白，眼线黑色，翼展蓝白条纹，胸部在中亚和中国中部的个体带有鲜黄斑块。尾部中央羽毛深蓝，边缘宽阔的白色尖端，外侧三对尾羽大部白色；上翅深蓝，次级飞羽和初级飞羽深灰，边缘深蓝，广泛地白尖。雌雄相似，幼鸟冠部淡灰，腹部常带奶油色或黄色调。","call":"发出各种高音调叫声，包括清脆的‘tirr’声、颤音、颤鸣和连续的‘tsi-tsi-tsi t-t-t-t-t-t’声，以及变化丰富的歌曲，包含高音笛声后跟断断续续的颤音。","habits":"偏好开阔的森林地带，包括轻度的落叶林、混合林，以及河岸柳树林。在非繁殖季节，倾向于沿森林边缘、灌木丛、半沙漠区和水边芦苇丛活动。饮食以小型无脊椎动物为主，也吃种子和水果。","breeding":"繁殖季节为4月至6月，一夫一妻制，领域性强。巢由干草、苔藓、动物毛发等构成，通常位于树洞中，离地面2-4米。每窝产卵7-11枚，孵化期13-14天，雏鸟由双亲喂养，离巢时间约16天。","identification":"与蓝山雀相比，灰蓝山雀的头顶至颈背呈淡灰色，上体略深灰色，下体更少白色，侧腹灰色。叫声和歌声具有独特性，尤其是快速的‘chink-chit-it chink’声和严厉的‘trrrrit’声。","protection":"IUCN：LC（无危）","distribution":"分布于欧亚中部和东部，包括俄罗斯、中亚、中国西北部如新疆、青海、内蒙古、黑龙江等地。在中国大陆，主要分布在新疆。","other":"已知在某些年份会与蓝山雀杂交，产生Pleske's tit。"},{"name":"地山雀","english_name":"Ground Tit","scientific_name":"Pseudopodoces humilis","appearance":"体型较大，站立时羽毛蓬松，长约19-20厘米，重42.5-48.5克。头顶淡黄褐色，背部灰棕色带沙色，下颈有宽的白色半环。尾羽中央深棕色，外侧两对白色。翅膀比背部略暗，翼尖白色。脸颊沙黄色，喉部及下体呈偏白的暖黄色调。黑眼，黑喙和腿脚。雌雄相似，幼鸟上体更黄，脸面斑驳，喉咙有条纹，喙直且短。","call":"通常沉默。叫声有微弱的‘cheep’声，清晰下降的‘cheer’声，以及响亮的‘veet’声和尖锐的‘scree-sich-ich’声。歌声以‘chip’音开始，随后是快速吹口哨式的‘cheep-cheep-cheep-cheep’，音调先升后降。","habits":"栖息于无树的草原，包括草地平原和岩石山丘，海拔3100-5500米，接近人类聚居区，如村庄、城镇和寺院。食物以小昆虫和幼虫为主，善于在软土、牦牛粪便和腐尸中探食。飞行弱，常贴近地面跳跃。与鼠兔（Ochotona）关系密切，利用其洞穴避难。","breeding":"繁殖季节为4月至7月。合作繁殖模式，26%的繁殖对有额外帮助者，多为雄鸟。巢由苔藓、干纤维和动物毛发构成，置于软土、河岸或石墙下的深洞中，深度可达2米。每窝产卵4-9枚，平均6.6枚，孵化期14-16天，雏鸟期18-20天，成功孵化率高达92%。","identification":"地山雀与地面鸦（Podoces）在外形上有一定相似性，但体型较小，缺乏明显标记。其头部颜色与下体类似，有深色帽状顶冠和浅色颈圈，与某些山雀和䴓鸟相似，但喙部强壮且略向下弯曲。","protection":"IUCN：LC（无危）","distribution":"分布于中国西南部和中部（新疆南部和青藏高原东至宁夏和甘肃，南至西藏南部和东南部，东北云南和四川西部），拉达克东南部，尼泊尔北部和锡金。","other":"地山雀在冬季会挖掘休憩洞穴，有时会下降到较低海拔的山谷过冬。"},{"name":"欧亚大山雀","english_name":"Great Tit","scientific_name":"Parus major","overview":"欧亚大山雀（英文名：Great Tit，学名：Parus major），是雀形目山雀科山雀属的鸟类。以其独特的黑白相间头部和鲜明的白色脸颊为标志，雄鸟具有比雌鸟更宽的腹部黑纹。在繁殖季节，大山雀已删除会使用巢箱，且经常光顾鸟食器。比欧亚蓝山雀更大胆，图案更明显。","appearance":"欧亚大山雀拥有显著的外观特征，包括白色的脸颊被黑色的头冠和颈围所环绕。雄鸟的黑色腹部条纹比雌鸟更宽，幼鸟（夏季至早秋可见）脸部泛黄，整体羽毛较暗淡。下体颜色在大部分范围内为亮黄色，但在中亚的“土库曼山雀”中腹部为白色。与欧亚蓝山雀相比，欧亚大山雀体积更大，图案更为鲜明。","call":"其特有的高音上下起伏的鸣唱：“tsee-dee-tsee-dee-tsee-dee”和嘈杂的责骂声，有助于识别。","habits":"欧亚大山雀栖息于开放的落叶林、混合林、林缘和农田边缘的灌木丛，包括北欧的松树林和泰加林。在欧洲偏好橡树（Quercus），而在西伯利亚、中国西部和蒙古，则主要栖息于河岸柳树（Betula）或柳树（Salix）的灌木丛中。它们适应了城市和郊区的公园和花园环境，甚至在人类定居点附近的孤立树丛中也能找到它们。在冬季，它们可能会迁移到低海拔地区。","breeding":"繁殖期从一月末至九月，筑巢于树洞中，通常由雌鸟建造，主要由植物纤维、草、苔藓、动物毛发和羽毛构成。每窝产卵5至12枚，孵化期为12至15天，幼鸟由双亲共同喂养，直到它们离巢后大约8天，有时父母会继续喂养长达25天。","identification":"欧亚大山雀、大山雀已删除和大山雀三者之间可通过上体和下体的颜色差异以及腹部中央黑纹的宽度来区分。欧亚大山雀的上背、翼覆羽和腰部为黄绿色，下体淡黄色，雄鸟中央黑纹较宽；远东山雀上背部黄绿色较少，下体灰白色或浅黄色；大山雀肩、背部及背覆羽中灰色，下体呈单调的中灰色，中央黑纹较窄且略微暗淡。","protection":"IUCN：LC（无危）","distribution":"欧亚大山雀广泛分布在欧洲、中东、亚洲中部直至东亚，包括北非的部分地区。在中国大陆，它主要分布在西部、中部以及北部地区。","other":"欧亚大山雀是世界上研究最为广泛的鸟类之一，适应了人类改变的环境，常见于城市公园和花园。"},{"name":"大山雀","english_name":"Japanese Tit","scientific_name":"Parus minor","appearance":"大山雀体型较大，成年个体头部为黑色，脸颊具有醒目的白色斑块，胸腹部呈白色，中央有一条黑色纵纹贯穿。翅膀为灰色，靠近肩羽处略带绿色光泽。幼鸟的整体颜色较暗淡，成鸟的黑色部分被灰色取代。雌雄个体在外观上差异不大。","call":"大山雀非常善于鸣叫，其鸣唱声为明亮的“tzi-hei tzi-hei”。此外，它们还会发出响亮的短促叫声、尖锐的“seep”声以及粗哑的“tzi-tzi-tzshhhhhh”声。","habits":"大山雀栖息于多种生境中，包括林地、农田、花园以及城市绿地。它们常见于东亚地区，活动范围广泛，觅食时主要以昆虫为主，也会取食种子和果实。","breeding":"繁殖季节一般从1月持续至9月，筑巢于树洞、墙洞、岩壁或建筑物中，有时利用旧松鼠巢穴或废弃的鸟巢。每窝产卵5-12枚，孵化期12-15天，幼鸟孵化后由双亲共同喂养，离巢前需喂养16-22天。","identification":"大山雀与欧亚大山雀在外形上相似，但颜色更为暗淡。与同属其他物种相比，大山雀的头部黑色区域和白色脸颊是其显著特征。","protection":"IUCN: LC（无危）","distribution":"大山雀广泛分布于东亚地区，包括日本、中国东部及韩国等地。在中国大陆，它们常见于北方及中部地区。","other":"大山雀曾被视为欧亚大山雀的一个亚种，后被划分为独立物种。现为大山雀亚种。"},{"name":"苍背山雀","english_name":"Cinereous Tit","scientific_name":"Parus cinereus","overview":"大山雀（英文名：Cinereous Tit，学名：Parus cinereus），是雀形目山雀科山雀属的鸟类。曾用名：苍背山雀。为东亚至南亚广泛分布的小型山雀科鸟类，曾被视作欧亚大山雀的亚种。体色以黑、灰、白为主，具醒目的白色颊斑与黑色胸腹纵纹，体型较同域山雀粗壮，喙略厚重。栖息于海拔0–4 400 m的阔叶林、针阔混交林、林缘、公园及庭园，常成小群活动，冬季加入混群觅食。","appearance":"体长12.5–15厘米，体重11–22克。喙短厚黑色，尾较长。雄鸟头顶及颈背亮蓝黑色，背部灰蓝，翼上覆羽形成一条显著白色翅带，飞羽黑褐具白缘；尾羽中央灰黑，外侧白色明显。面侧具大块楔形白斑，喉至上胸形成宽阔黑色胸兜，胸腹中央黑色纵纹最宽处位于喉部，向下渐细；腹部侧缘乳白或灰白。雌鸟类似但色泽稍暗，黑色纵纹较窄。幼鸟整体偏褐，头顶带褐晕，胸兜及纵纹为暗褐色。亚种差异体现在背部灰或带橄榄绿、尾端白色范围及腹部底色。","call":"繁殖期雄鸟发出响亮、略带金属质感的重复三音节“tea-cher tea-cher”或“swee-che-ti”，亦可连续发出“weeter-weeter-weeter”。日常叫声包括上扬的“twee”、尖锐的“pink”及急促的“tcha-tcha-tcha”。受惊时发出粗糙的“tchrr’rr’rrt”。鸣声与近缘的欧亚大山雀明显不同，同域种间存在方言差异。","habits":"留鸟或部分迁徙。活动于林冠中上层，也见于灌丛、地面。以敏捷跳跃、悬停方式觅食昆虫、蜘蛛及植物种子、果实，冬季频繁光顾人工饲喂器。常单独或成对活动，非繁殖季与红头长尾山雀、煤山雀等混群。在开阔林缘、公园、农田树篱、城市绿地皆可见，避开密闭原始林。","breeding":"繁殖期因地而异：东南亚2–7月，日本3–8月，爪哇几乎全年。一夫一妻制，雄鸟以喂食、鸣唱求偶。巢筑于天然树洞、墙缝、巢箱或旧鸟巢，内垫苔藓、草茎、毛发。每窝5–12(–14)枚白色带红褐斑点的卵，雌鸟单独孵卵12–15 d，双亲育雏，雏鸟15–22 d离巢。多数地区一年可育2–3窝，繁殖成功率受食物及蛇类捕食影响显著。","identification":"与欧亚大山雀相比，本种背灰而非绿，腹白而非黄，体型更大。与绿背山雀区别在于后者背呈黄绿，腹黄。与煤山雀、褐头山雀等区别在于具单一宽阔白色翅带而非两道细带。黑胸兜和中央黑纵纹亦为辨识要点。亚种间差异主要在于背部灰度、尾端白色范围及腹部底色。","protection":"IUCN: LC（无危）。未列入CITES附录及中国国家重点保护名录。分布广、数量大，在多数区域常见。","distribution":"繁殖区：阿富汗、巴基斯坦沿喜马拉雅山脉向东至中国西南、华中、华东及东北，俄罗斯远东、朝鲜半岛、日本（含琉球群岛）、缅甸、泰国、中南半岛、马来半岛、苏门答腊、爪哇、婆罗洲及小巽他群岛。非繁殖区：中国台湾、新加坡等地有迷鸟记录；南堪察加有引入种群。中国大陆见于各省海拔0–4 400 m的适宜林地。","other":"分类史上长期被视为欧亚大山雀的亚种，分子研究显示二者早在更新世中期即已分化。与欧亚大山雀在俄远东存在约250 km宽的杂交带，杂交率随区域变化。部分学者将东亚绿色亚种群独立为“日本山雀”大山雀已删除。AviList 中作为本种亚种。"},{"name":"绿背山雀","english_name":"Green-backed Tit","scientific_name":"Parus monticolus","overview":"绿背山雀（英文名：Green-backed Tit，学名：Parus monticolus），是雀形目山雀科山雀属的鸟类。又名: 青背山雀，色彩斑斓的小型山雀，分布于中国西南及台湾等地区，与白腹的欧亚大山雀亚种分布有所重叠。其最显著的特征是肩部绿色区域与颈部黑色区域交界处有一条细的亮黄色环带，以及一条纵贯整个下体的粗的黑色条带。","appearance":"绿背山雀体型小巧，拥有亮黄色的腹部，背部呈现绿色，双翼上有两条狭窄的白色翼纹，与大山雀已删除相似但特征更为鲜明。雄雌同形同色，无明显性别差异。","call":"鸣叫声为一系列3-4个哨音，叫声较为罕见，表现为粗哑的‘deedeedee’声。","habits":"绿背山雀偏好于海拔1000～4000米的中高山区，常见于山地针叶林、针阔叶混交林和阔叶林中。它们活跃于森林的中上层，成对或混群活动，以昆虫为主要食物，偶尔也食用少量植物性食物。","breeding":"繁殖季节集中在4-7月，雌鸟在天然树洞或岩石缝隙中筑巢，巢呈杯状，主要由羊毛构成，有时混合苔藓和草茎。每窝产卵4-6枚，孵化和育雏主要由雌鸟承担。","identification":"绿背山雀与欧亚大山雀绿背亚种的区别在于前者背部绿色，具两道白色翼纹，而后者仅具一道翼斑；在中国，绿背山雀仅与白腹的欧亚大山雀亚种分布有重叠。","protection":"IUCN：LC（无危）。绿背山雀虽未被列入保护动物目录，但在中国分布虽广却非优势种，属于稀有种。此外，它们还面临非法鸟类贸易的威胁，已列入国家林业局的三有保护鸟类名录。","distribution":"分布于喜马拉雅山脉西部至越南中南部和台湾，主要栖息于欧亚大陆远东地区的山地森林。","other":"绿背山雀在中国的分布虽然广泛，但在市场上的出现频率较低，由于非法贸易的影响，对野生种群构成一定威胁。"},{"name":"白枕山雀","english_name":"White-naped Tit","scientific_name":"Machlolophus nuchalis","overview":"白枕山雀（英文名：White-naped Tit，学名：Machlolophus nuchalis），是雀形目山雀科黄山雀属的鸟类。其显著特征为头部至尾部上半部分的光泽黑色，以及白色颈背斑和翼覆羽。下体白色，中央黑色带贯穿喉部至腹下部。分布于印度中部和南部的干刺森林，数量稀少。","appearance":"中等体型，约12-13厘米长，体重13-14.5克。雄鸟头部至尾部上半部分为光泽的蓝黑色，具显著白色颈背斑和上翼覆羽。中央尾羽黑色，尖端白色；外侧尾羽及次级飞羽基部白色。颊部、耳羽和颈部侧面白色或乳白色。颏部、喉部和胸部黑色，腹部具宽黑线延伸至下腹部，其余下体淡色或下侧更白。雌鸟与雄鸟相似，但色彩较暗淡，颈背斑较小，白翼覆羽和飞羽基部白色减少，下体偏黄。幼鸟头部和上体烟灰色，缺乏光泽，颈背斑乳黄色。","call":"最频繁的联系叫声为一系列尖锐的哨声，常以较高音调开始，如‘ti, pee-pee-pee, ti-pee-pee-pee-pee’或‘teep, whee-whee-whee-whee’。还有柔和的‘tip-it’声和单个温和音符，包括‘pit’或‘chit’，以及类似Common Chaffinch的尖锐‘tink’声。歌声为高音的‘tiu-sut-sut-sut’和短暂的颤音。","habits":"栖息于低地干燥的金合欢（Acacia）刺灌丛，通常位于石质或丘陵地带。也见于干燥落叶林中的灌木丛，偶尔进入相邻果园和花园。全年留居，但在非繁殖季节可能远离繁殖区。以小型无脊椎动物为主食，包括蜘蛛和幼虫，亦食果实，尤其是浆果，及花蜜。成对或小家庭群活动，有时加入混合物种觅食群。在树冠层觅食，也会在灌木和稀疏下层植被中活动。","breeding":"繁殖季节为5月至8月。巢为植物纤维和绒毛垫，辅以动物毛发和羊毛，置于树洞中，常见于啄木鸟旧巢。已知巢穴位于Salvadora persica树和Boswellia serrata树中，高度约为2.5-5米。一窝最多记录到三只雏鸟，由双亲共同喂养。","identification":"在分布范围内唯一具有强烈黑白对比的山雀。与大山雀的区别在于后者翼覆羽和背部灰色，而白枕山雀翼覆羽全白，上体黑色。南印度种群与西部种群在分布上分离。","protection":"IUCN：VU（易危）。在过去一个世纪里，其分布范围和数量大幅下降。分布零散，总体数量非常低。在印度西北部稀少，南部印度更为罕见。主要威胁为栖息地破坏和丧失。","distribution":"分布于印度中部和南部的干刺森林，主要在西部印度的Kutch和Rajasthan，以及南部印度的Karnataka和Tamil Nadu。在Rajasthan的Sajjangarh Wildlife Sanctuary有健康种群。在Anshi National Park（Karnataka）和Mudumalai National Park（Tamil Nadu）边境也有记录。","other":"曾被认为可能从西部印度迁移到南部印度，但这一假设未得到支持。"},{"name":"台湾黄山雀","english_name":"Yellow Tit","scientific_name":"Machlolophus holsti","overview":"台湾黄山雀（英文名：Yellow Tit，学名：Machlolophus holsti），是雀形目山雀科黄山雀属的鸟类。台湾特有种。其显著特征为背部黑色，腹部黄色，三角形冠羽后缘镶白色。仅分布于台湾中高海拔的阔叶林区，约800至3000米的高度。","appearance":"台湾黄山雀体型小，长约12.5至13厘米，雄鸟头部、冠羽及颈侧黑色，冠羽尖端有白色，上体蓝绿带黑，翼部及尾部黑色，尾羽边缘蓝色，翼上有灰或蓝灰色覆羽，腹部深黄色，眼前方有小黑斑，下腹部及臀部暗黑色，下体淡黄至灰白色。雌鸟相似，但颜色较暗，缺乏雄鸟的鲜艳色彩。幼鸟头部至冠羽蓝灰色，上体橄榄绿色，面部淡奶油色，下体白色或微黄。","call":"鸣叫包括连续的‘si-si-si’或更长的‘tzee-tzee-tzee’声，常与其它音节组合，如‘si-si-si dza-dza-dza’，还有‘tsut, tsut’和细长的‘dzi-dzi-dzi’声。报警时发出延长的责骂声‘dz-za-za-za’。繁殖季节的鸣唱为一系列3或4个响亮的音符，主题多变，如‘tu-wich-chi’或‘pipi-chu’。","habits":"常单独或成对活动，偶尔加入混种觅食群。主要栖息于中高海拔的阔叶林，以昆虫为主食，偶尔吃小型果实。活动于森林上层和树冠层，有时在低矮灌木顶部觅食。","breeding":"繁殖期为4月至7月，巢筑于大树的天然洞穴中，用枯叶和兽毛搭建碗状巢，每窝产3至4枚蛋。","identification":"独特的黑背黄腹外观，加上三角形冠羽后缘的白色，使其在山雀科中容易辨认。","protection":"IUCN：LC（无危）。台湾黄山雀因非法捕捉出口导致数量下降，被列为近危物种。","distribution":"分布于台湾本岛的中高海拔阔叶林区。","other":"曾属于Parus属，后经分子系统发育分析，归入Machlolophus属。"},{"name":"眼纹黄山雀","english_name":"Himalayan Black-lored Tit","scientific_name":"Machlolophus xanthogenys","overview":"眼纹黄山雀（英文名：Himalayan Black-lored Tit，学名：Machlolophus xanthogenys），是雀形目山雀科黄山雀属的鸟类。具有鲜明黑黄脸谱的山雀科黄山雀属鸟类。脸部图案显著，拥有黑色的眼纹和颊部，顶冠及喉部亦为黑色。在中国西藏的发现使其成为中国鸟类新纪录之一。","appearance":"眼纹黄山雀体长约13-14厘米，体重约12.9-19.7克。它是一种中等体型的山雀，头顶有羽冠，脸部呈黑黄相间，黄色的颈背向上延伸至最长的羽冠尖端；上体为橄榄绿至黄绿色，肩羽具黑色中心，尾羽基部白色，边缘灰色；翼羽黑色，中央和大型覆羽末端黄色；下体黑色，胸部中心和腹部中间为黑色，两侧柠檬黄色，两胁橄榄色或带有橄榄色晕染，下尾覆羽暗灰色，腋下和下翼覆羽白色。幼鸟颜色较暗淡，冠羽更短，上体颜色更灰，尾羽白色尖端模糊。","call":"其鸣声为一系列高音哨音和长而嗡嗡的音符，叫声通常为高音的杂乱音符，也会发出刺耳的责骂声。","habits":"居住在亚热带山地森林，如橡树林（Quercus）和松树林（Pinus），也在混合竹林、次生林、灌木丛和散落的树木中活动。繁殖季节在海拔850-2400米处，可能在尼泊尔达到2950米，印度半岛则在600-1830米。非繁殖季节会下降到约915米，偶尔低至75米。以小型无脊椎动物、昆虫幼虫为主食，包括蜘蛛、蚂蚁和蟑螂，也吃果实如桑葚和覆盆子，花蕾和花蜜。通常成对或小家族群活动，非繁殖季节加入混群觅食，与多种鸟类共同活动。","breeding":"使用啄木鸟或拟啄木鸟的洞穴筑巢，也会自己挖掘或利用人造巢址。","identification":"与黄颊山雀的区别在于黑纹更厚的眼纹和黑色的面颊。与印度黄山雀（Indian Yellow Tit）相似，但无地理重叠。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉，从巴基斯坦北部至尼泊尔东部，向南延伸至印度半岛。在中国西藏的发现是其分布的新纪录。","other":"在1930年代前，繁殖范围曾西至巴基斯坦的Murree Hills，但现在仅在冬季罕见地出现于此。"},{"name":"印度眼纹黄山雀","english_name":"Indian Black-lored Tit","scientific_name":"Machlolophus aplonotus","overview":"印度眼纹黄山雀（英文名：Indian Black-lored Tit，学名：Machlolophus aplonotus），是雀形目山雀科黄山雀属的鸟类。在印度次大陆广泛分布。显著特征是头部的黑色条纹和黄色脸颊，上体橄榄绿色，下体呈黑黄相间。在海拔500至1800米的山区常见，偶尔下降至更低高度。印度南部为其主要分布区域。","appearance":"中等体型（约13-14厘米），头顶具尖锐的黑色羽冠，脸部前额、眼先至冠部黑色，黄色颊斑延伸至上最长羽冠尖端；黄色眉纹从眼前延至脑后，与黄色颈背融合，宽大的黑色眼纹与黑色颈侧相连；上体橄榄绿，肩羽中央黑色，尾上覆羽灰白；尾羽黑色，边缘灰白，最外侧尾羽外缘白色；翼上覆羽黑色，中大覆羽宽边淡黄色，飞羽灰黑，三级飞羽边缘黄色，次级飞羽和内侧初级飞羽边缘灰色，外侧初级飞羽基部宽白；雌鸟和幼鸟较雄鸟暗淡，羽冠稍短，中线更细且不完整，黄色部分转为淡白色。","call":"发出“si-si”、“tsi-tsi-pit-tui”、“tzee-tzee-wheep-wheep-wheep”等叫声，类似啄木鸟的“ch-chi-chi-chi-chi”声，以及尖锐的“tst-reet”警报音。歌曲由不同音高的短双音节或三音节旋律哨声组成，快速重复，偶尔增强音量。","habits":"栖息于开阔的亚热带山地森林，以橡树和松树为主的林区，也会出现在混合竹林、次生林、灌丛、散落树木、咖啡园、豆蔻林及花园。海拔分布范围850-2400米，喜群居，成对或家族小群活动，非繁殖季节加入混种觅食群，活跃于树冠层，捕食昆虫和蜘蛛，偶尔取食果实。","breeding":"利用啄木鸟或拟啄木鸟的旧洞筑巢，有时自行挖掘或使用人造洞穴。一窝通常产3-5枚红斑白蛋，孵化期间警惕性强，遇干扰会发出嘶嘶声。","identification":"与黄颊山雀相比，前额和眼先黑色，眼纹更长，上体颜色更均匀。雌鸟和幼鸟的羽色较淡，羽冠略短。","protection":"IUCN：LC（无危）","distribution":"主要分布在印度半岛，尤其在南部地区，海拔范围从600至1830米，非繁殖季节可能下降至约915米。","other":"在历史上，其分布范围曾更广泛，但在巴基斯坦北部的Murree Hills已从繁殖地变为稀有的越冬地。"},{"name":"黄颊山雀","english_name":"Yellow-cheeked Tit","scientific_name":"Machlolophus spilonotus","overview":"黄颊山雀（英文名：Yellow-cheeked Tit，学名：Machlolophus spilonotus），是雀形目山雀科黄山雀属的鸟类。俗名: 花奇公、催耕鸟，这种中型山雀以醒目的鲜黄色脸颊和高耸的黑色冠羽著称，广泛分布于喜马拉雅山脉至越南中南部的广阔区域，包括巴基斯坦、尼泊尔、不丹、印度、孟加拉、缅甸、泰国、越南以及中国的西藏、四川、云南、贵州、湖南、广西直至福建等地。","appearance":"黄颊山雀体长13.5至15.5厘米，体重18至23克。拥有中等到大型体型，最显著的特征是其竖立的黑色冠羽和黄色脸颊。雄鸟的前额、眉纹和颈背呈黄色，与黑色的冠羽和颈侧形成鲜明对比。上体橄榄绿色，翼部灰黑相间，饰有白色斑点和条纹。腹部黑色，两侧和下腹橄榄色，带黄色调，两胁灰色橄榄色。雌鸟与雄鸟相似，但翼斑黄色偏白，飞羽边缘橄榄色，胸斑略显暗淡。幼鸟冠羽较暗，黄色脸颊和颈斑较淡，上体更灰，尾尖白色模糊，飞羽边缘更暗。","call":"黄颊山雀的叫声包括连续的‘si-si-si’或延长的‘si-si-pudi-pudi’，还有‘tsee-tsee-tsee, si-si’或‘ki-ki beer, ki-ki beer’，以及‘witch-a witch-a witch-a’，经常与持续的‘churrr-r-r-r-r-r’音符结合。其歌声是快速重复的三音节响亮短语。","habits":"黄颊山雀偏好温带和亚热带落叶或混合森林，包括橡树、松树和杜鹃树，也可见于次生林、竹林、林缘和种植区，包括种植园和散落树木的区域。在非繁殖季节，它们会降至更低海拔，最低可达450米。它们通常成对或小家庭群体活动，非繁殖季节则加入多种混杂觅食群，与其它山雀和小型噪鹛一同觅食。它们的饮食包括小无脊椎动物、幼虫、蜘蛛、芽和一些果实。黄颊山雀活跃于森林中层和下层，也会在灌木和地表活动。","breeding":"繁殖期从2月晚期至8月中旬。巢筑于树洞中，也可在岩石、墙壁缝隙中，主要由苔藓、草茎、草叶、松针、纤维等构成，内垫以兽毛、花、棉花等。每窝产卵4至6枚，卵白色或灰白色，带有暗褐色或红褐色斑点，大小约为18mm×14.5mm至18.5mm×15mm。双亲轮流孵卵约两周，雏鸟即孵化。","identification":"黄颊山雀与其他山雀的主要区别在于其独特的黄色脸颊和黑色冠羽，以及橄榄绿的上体与黑色飞羽的组合。雌鸟与雄鸟相比，翼斑颜色更浅，飞羽边缘颜色不同，胸斑颜色稍暗。","protection":"IUCN：LC（无危）；黄颊山雀在中国某些地区被捕捉作为宠物，这对其野外种群数量构成了威胁。","distribution":"黄颊山雀的分布区域覆盖了喜马拉雅山脉至越南中南部，具体包括中国（西藏、四川、云南、贵州、湖南、广西、福建）、尼泊尔、不丹、印度、孟加拉国、缅甸、泰国、越南。在中国，黄颊山雀的分布范围自1988年以来向南扩展至香港，目前小规模种群已在此地定居。","other":"黄颊山雀曾归于Parus属，但在2013年分子系统发育分析后，被移至Machlolophus属，显示其形成一个独立的支系。"},{"name":"白肩黑山雀","english_name":"White-shouldered Black Tit","scientific_name":"Melaniparus guineensis","overview":"白肩黑山雀（英文名：White-shouldered Black Tit，学名：Melaniparus guineensis），是雀形目山雀科黑山雀属的鸟类。也被称为淡眼黑山雀，是山雀科黑山雀属的一种小型鸟类。在非洲大陆上分布广泛，自西部的塞内加尔到东部的肯尼亚和埃塞俄比亚均有其踪迹。白肩黑山雀以黑色为主调，翼部具有一块显著的白色斑块，最独特的特征是它的眼睛呈淡黄色。","appearance":"这种山雀体型较大，约14厘米长，体重介于12.9至21克之间。整体羽毛呈现亮丽的黑色，头部有时可见短而略显杂乱的冠羽。尾部略带烟熏般的黑色，边缘可能泛着蓝黑色光泽，尾羽外缘或尖端有极细的白色线纹。翼覆羽上有一大块白色斑点，初级覆羽和飞羽边缘亦有白色点缀，而次级飞羽边缘宽幅的白色形成闭合翅膀时明显的白色面板。虹膜颜色从白色至黄白色不等，有时呈浅棕色。喙黑色，腿色为深棕色至蓝灰色或黑色。雌雄相似，但雌鸟的翼部白色斑块略小。幼鸟上体呈棕黑色，翅膀和尾巴为烟熏黑色，翼覆羽上的白色部分被黄白色替代，且常带有更宽的暗棕色中心条纹。","call":"白肩黑山雀的叫声典型而独特，常发出连续的‘chee-chi-chi-chi-chi’声，声音沙哑且重复。歌曲通常由3-4个音节的吹口哨式短语组成，连续重复2-3次；有些歌曲更长，不重复，或包含一些粗糙的音符。","habits":"栖息于较为湿润的灌木草原地带，包括阔叶林和荆棘丛，通常成对或以小型群体（最多8只）活动，也可能参与西非某些地区的混合物种觅食群。它们活跃而好动，一般较为害羞，偏好在树冠中部搜寻食物，倾向于在树干和树枝上寻找而非在树叶中。饮食以小型无脊椎动物、幼虫、种子和少量水果为主。","breeding":"白肩黑山雀在全年居住的松树林中繁殖，会在树洞中筑巢。一窝产4-6枚粉红色带有红褐色斑点的蛋。","identification":"与白翅黑山雀非常相似，主要通过淡黄色而非深色的眼睛来区分。幼鸟可能有深色眼睛，但通常与成鸟相伴，可以通过这些特征加以识别。","protection":"IUCN：LC（无危）","distribution":"分布于毛里塔尼亚南部和塞内加尔向东至苏丹南部和埃塞俄比亚，南至喀麦隆和刚果民主共和国北部。","other":"2013年的一份分子系统发育分析显示，白肩黑山雀曾属于Parus属，后因其构成独立的分支被重新分类至Melaniparus属。"},{"name":"白翅黑山雀","english_name":"White-winged Black Tit","scientific_name":"Melaniparus leucomelas","overview":"白翅黑山雀（英文名：White-winged Black Tit，学名：Melaniparus leucomelas），是雀形目山雀科黑山雀属的鸟类。体型较大的山雀科黑山雀属鸟类。其特征显著，全身黑色，翼部有白色斑块，眼睛深色。分布于非洲中部，自安哥拉至埃塞俄比亚一带。","appearance":"白翅黑山雀身长约15-16厘米，体重约21-24克。雄鸟成鸟全身黑色，翼覆羽有大块白色，眼色深暗。雌鸟较雄鸟略显暗淡，光泽稍逊，下体呈烟灰色黑。幼鸟上体黑褐色，翅膀和尾巴烟黑色，翼覆羽上的白色被黄白色替代。","call":"其叫声包括尖锐而突然的‘chut’或‘chit’，常作为前奏，随后是嗡嗡的‘chit-zzzzz-r’或‘chut-drrrrrrrr-du’，还有更低沉的‘chik-zworrrrr, chik-zworrrrr’，以及更悦耳的‘tszee-tuwu, tszee-tuwu’。","habits":"栖息于干燥的豆科森林、河岸森林、荆棘灌木丛及草原，常见于海拔915米以上。以小昆虫、幼虫、种子和水果为食，通常成对或小群体活动，有时加入混合物种觅食群。在高树内部活跃觅食，偏好搜寻树干而非树叶。","breeding":"繁殖季节为3月至12月，可能全年繁殖。一夫一妻制，单独筑巢。巢由草和苔藓制成的小平台构成，置于树洞或树桩中，离地面可达4米。每窝产3-5枚蛋，双亲共同孵化，幼鸟约26天后离巢。","identification":"与白肩黑山雀相似，但可通过其暗色的眼睛来区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部，从西部的安哥拉到东部的埃塞俄比亚，常见于海拔较高的地区。","other":"曾被视为Parus属的一员，但分子系统发育分析显示其属于独立的Melaniparus属。"},{"name":"南黑山雀","english_name":"Southern Black Tit","scientific_name":"Melaniparus niger","overview":"南黑山雀（英文名：Southern Black Tit，学名：Melaniparus niger），是雀形目山雀科黑山雀属的鸟类。这体型较大的黑色山雀，具有白色的肩部和翼羽边缘，尾巴下方有条纹状的灰白相间。常见于南部非洲的阔叶林木地带和荆棘灌丛中，常以活跃的群体形式出现在混合物种觅食群中。其鸣叫声嘈杂，包括一系列清脆而略带粗糙的“diddy-dzee”声。","appearance":"成年南黑山雀体长约15至16厘米，体重17.2至26克。雄鸟全身呈现黑色，新鲜羽毛下头部至尾上覆羽泛蓝光泽，尾羽黑色，边缘蓝白色，尖端白色。雌鸟外观与雄鸟相似，但光泽较弱，腹部呈灰褐色。幼鸟暗棕色，尾羽边缘浅棕色，翼羽边缘淡黄白色，下体灰色，逐渐变淡至下腹。种族间差异轻微。","call":"南黑山雀发出的鸣叫声嘈杂，包括鼻音、嗡嗡声的接触音，如“jee-jee-jee-jee”、“tsi-tsi-chacha”或“tit-si-chachacha”。还有尖锐的“chew-ri”声和柔和的“peeoo-pu-peeoo”声，以及音乐般的“phee-cher, phee-cher”。其歌声由各种叫声组成，重复播放。","habits":"南黑山雀主要以鳞翅目幼虫为食，非繁殖季节还摄食其他小型无脊椎动物、种子和水果。它们成对或小群体活动，冬季则加入混合物种群，每日移动可达10公里寻找食物。在树冠和中间层觅食，检查叶片寻找毛虫，搜寻树皮下的猎物。","breeding":"繁殖期主要在夏季湿季，但受降雨量影响较大。南黑山雀的繁殖策略适应了热带不可预测的降雨模式，通常一对亲鸟仅能喂养少量幼鸟，因此多数雄鸟需留在父母领地多年帮助抚养幼鸟。雌鸟在孵卵期间被雄鸟和帮手喂养，面对威胁时会模仿毒蛇声音。","identification":"与卡氏山雀相比，南黑山雀的尾巴下方无白色边框，且分布范围仅部分重叠。雌雄两性在颜色上有细微差异，雄鸟更显蓝黑色。","protection":"IUCN：LC（无危）","distribution":"南黑山雀分布于非洲东南部，形成半圆形分布，从安哥拉到南非的东开普省。偏好阔叶树为主的森林环境，如莫桑比克、Combretum物种和Burkea africana。在津巴布韦西部的森林中尤为常见，密度可达每平方公里五十只。","other":"南黑山雀的平均寿命数据缺乏，但推测成鸟死亡率远低于欧洲和北美的近缘物种。2013年的分子系统发育分析将其从Parus属移至Melaniparus属。"},{"name":"卡氏山雀","english_name":"Carp's Tit","scientific_name":"Melaniparus carpi","overview":"卡氏山雀（英文名：Carp's Tit，学名：Melaniparus carpi），是雀形目山雀科黑山雀属的鸟类。分布于纳米比亚中部的萨瓦纳林地及安哥拉南部的莫潘林地。","appearance":"体型较大，全长约15厘米，体重17.2-20.3克，通体黑色，翼部与尾部边缘有显著白色。雄鸟整体黑色，冠羽至尾上覆羽光泽蓝黑色，尾羽黑色，最外三根尾羽尖端白色；翅膀覆羽黑色，小翼羽和中翼羽尖端白色，形成明显白色斑块，大翼羽边缘白色，次级飞羽宽幅白色，初级飞羽边缘白色。雌鸟相似，但面部至喉部略显褐色，大翼羽和飞羽边缘稍窄。幼鸟上体黑褐，冠羽、披肩、胸部光泽蓝黑色较淡，翼和尾偏棕色，飞羽上的白色被黄褐色替代，尾羽尖端无白色。","call":"发出刺耳的‘jer-jer-jer-jer...’声作为接触叫声（有时为‘tsi-tsi-tsi-jer-jer-jer...’），亦会发出较为悦耳的‘churia-churia-churia’声和哨音‘piu-piu-piu-piu-piu...’，以及更粗糙的‘tsi-ysi, tsi-cha-cha-cha-cha’声，与南黑山雀的叫声极为相似。","habits":"常在成对或小群体中出现，栖息于干燥的萨瓦纳林地和莫潘木林，活跃且显眼。其迁徙模式和飞行特性未详述。","breeding":"关于卡氏山雀的繁殖习性，目前缺乏具体信息。","identification":"与南黑山雀相比，卡氏山雀体型略小，尾部更短，喙较小，颜色更为深黑，尤其是下体部分，尾羽尖端白色较少，大翼羽和中翼羽边缘白色更宽。与白翅黑山雀的区别在于翼部白色斑块不那么密集，外侧大翼羽中心为黑色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于非洲西南部，从安哥拉南部延伸至纳米比亚中部。","other":"2013年的一项分子系统发育分析显示，卡氏山雀原本分类在Parus属中，后因分析结果表明其构成独立的支系而被移至Melaniparus属。"},{"name":"白胸山雀","english_name":"White-bellied Tit","scientific_name":"Melaniparus albiventris","overview":"白胸山雀（英文名：White-bellied Tit，学名：Melaniparus albiventris），是雀形目山雀科黑山雀属的鸟类。显著特征为身体大部分呈黑色，腹部为白色，翼部带有白色标记。分布于非洲中西部至东部，包括尼日利亚东南部、喀麦隆、南苏丹南部、乌干达东部、肯尼亚和坦桑尼亚。","appearance":"白胸山雀体长14-15厘米，雄鸟头部、背部及尾部全黑，新鲜羽毛略带蓝光；尾羽尖端及外侧羽毛边缘为白色，翼部有大量白色。雌鸟较雄鸟暗淡，呈灰黑色或褐色，光泽较弱，下体颜色更灰或更暗。幼鸟上部呈烟灰色，翅膀和尾巴为烟黑色，翼覆羽的白色部分为黄褐色或泛黄，喉部可能略微苍白。","call":"鸣叫声包括粗糙的鼻音‘si-chah-chah-chah’，通常在警告时强调发出，还有类似但更清脆或悦耳的‘tss-tss-tss, cher-cher-cher-cher’；接触叫声包括‘twach-twach-twach’或‘chrip-twsich-twach’，也会发出尖锐的‘tss, tsee’短语，常以较长系列出现。歌曲罕见，‘chee-er-weeoo, chee-er-wheeo’，以及柔和而重复的颤音‘pee-pee-purr’。","habits":"栖息于较为湿润的稀树草原、林地及森林边缘，多见于中高海拔地区。通常成对或小群活动，常加入多种鸟类混群。生活习性的具体细节有待进一步研究。","breeding":"关于生长繁殖的详细信息尚未充分记载，需进一步观察研究。","identification":"与黑山雀属的其他物种相比，白胸山雀因腹部的白色而容易区分。","protection":"IUCN状态未知，需查阅最新资料确认。","distribution":"繁殖区域主要集中在非洲中西部至东部，包括尼日利亚东南部、喀麦隆、南苏丹南部、乌干达东部、肯尼亚和坦桑尼亚。","other":"曾被归入Parus属，2013年基于分子系统发育分析，被移至Melaniparus属。"},{"name":"白背黑山雀","english_name":"White-backed Black Tit","scientific_name":"Melaniparus leuconotus","overview":"白背黑山雀（英文名：White-backed Black Tit，学名：Melaniparus leuconotus），是雀形目山雀科黑山雀属的鸟类。体型中至大型的山雀科鸟类，主要分布在非洲的厄立特里亚和埃塞俄比亚山区。以其大部分黑色体羽与独特的亮白色背部为显著特征。","appearance":"白背黑山雀体长约13.5-14厘米，体重约16-17克。全身主要为黑色，翅膀和尾巴呈煤烟色，但雄鸟的上背部有明显的奶油白色斑块，而雌鸟和未成年个体的相应部位则是淡褐色。雄鸟在新鲜羽毛状态下，头部至颈背有深蓝色光泽，其余上体部分包括翅膀微带光泽，尾羽边缘泛蓝黑色，最外侧三对尾羽有细窄的白色尖端。雌鸟的下体比雄鸟更暗或偏褐色。幼鸟比成鸟略显暗淡和褐色，缺乏光泽，背部斑块更暗或偏黄褐色，可能显示出较暗的羽毛基部。","call":"其叫声包括典型的山雀鸣声，但音调更柔和，包含高音的'sit'音符和刮擦音。歌声高度变化，常含有重复的旋律哨音。","habits":"栖息于海拔1800-3200米的高山哈格尼亚森林和混合松果柏-杜松-橄榄树森林，偶尔在更高海拔的高山竹林和巨型石楠丛中出现，最高可达3500米。饮食以小型无脊椎动物、幼虫和种子为主。通常单独或成对活动，也会形成小群。活跃于树木的中上层。","identification":"与白肩黑山雀相似，但可通过亮白色的背部和黑色的翅膀轻易区分。","protection":"IUCN状态未知。","distribution":"主要分布于非洲的厄立特里亚和埃塞俄比亚山区，具体为蒙坦地区的哈格尼亚森林、混合松果柏-杜松-橄榄树森林，海拔高度在1800-3200米之间。在某些地区，如埃塞俄比亚南部吉马附近的记录显示，它们的分布低至1370米。"},{"name":"暗色山雀","english_name":"Dusky Tit","scientific_name":"Melaniparus funereus","overview":"暗色山雀（英文名：Dusky Tit，学名：Melaniparus funereus），是雀形目山雀科黑山雀属的鸟类。原属Parus，后因分子系统学研究被归入Melaniparus。非洲热带雨林的特有种，其体色以黑色为主，雌雄差异在于雄鸟整体更黑，而雌鸟上身呈黑灰至棕色，体型中等到偏大，长度介于13至15厘米之间，以红眼和‘dree di-di-di’的鸣声为特征。","appearance":"暗色山雀体型中等至偏大，全长约13至14.5厘米，体重22至29克。雄鸟通体黑色，雌鸟则为深灰至棕色，两者均具红色眼睛。幼鸟与成年雄鸟相似，但上体呈黑褐色，缺乏光泽。雄鸟新鲜羽毛带有蓝绿色光泽，雌鸟上部较暗淡，尾羽边缘带灰褐色，面部及下体颜色比雄鸟更淡。","call":"鸣叫多样，包括慢速而清脆的‘see-er, see-er, see-er’，金属质感的‘chut-chut-tzi-tzi-tzi’，以及一系列缓慢、粗犷的颤音‘tirrru, tirrru, tirrru, turee, tirrru’。歌曲为叫声的延长版本，包含金属质感的‘tsi-piu, tsi-piu, tsi-piu’和其他杂乱的颤音。","habits":"常栖息于湿润森林，偏好森林边缘或开阔地带，成对或小群活动，常加入混合物种群落。主要以小型无脊椎动物为食，如甲虫、正翅目昆虫及微鳞翅目昆虫的幼虫，也吃种子和果实。","breeding":"尚未提供具体繁殖细节。","identification":"与其它深色森林鸟类相比，暗色山雀具有活跃的山雀行为、较小的体型和喙。幼鸟可通过上体的黑褐色和缺乏光泽的羽毛来辨别。","protection":"IUCN状态未明确给出。","distribution":"分布于非洲中部，包括安哥拉、刚果民主共和国、苏丹、乌干达、利比里亚、加纳和肯尼亚等地。常见于旧种植园、耕作边缘和森林。","other":"暗色山雀的种群规模目前未知，但已知正在减少，其再生周期约为4.2年。"},{"name":"棕胸山雀","english_name":"Rufous-bellied Tit","scientific_name":"Melaniparus rufiventris","overview":"棕胸山雀（英文名：Rufous-bellied Tit，学名：Melaniparus rufiventris），是雀形目山雀科黑山雀属的鸟类。体型较大的山雀，体长14–15厘米，重约20克。其显著特征为黑色头部延伸至胸部，腹部呈棕红色或肉桂色，眼色浅淡。该鸟分布于非洲中南部，包括安哥拉北部至刚果民主共和国西部、赞比亚中部、纳米比亚东北部、马拉维及坦桑尼亚西南部等地，主要栖息于海拔600–2000米的米翁博林地、刺灌丛稀树草原及干燥常绿林缘。棕胸山雀为留鸟，以小型无脊椎动物及其幼虫为食，繁殖期为9月至12月，营巢于树洞或旧啄木鸟洞中。目前IUCN未评估其全球威胁状态，但在部分地区较为常见。","appearance":"成鸟头部至胸部为黑色，背部深灰色，尾羽黑色，外侧两枚尾羽具白色窄端。翼上覆羽黑色，具宽阔的白色羽缘，飞羽黑色，三级飞羽具白色羽缘。腹侧至下胸深灰色，其余下体呈暗红橙色。雌鸟与雄鸟相似，但下体红橙色略浅。幼鸟较成鸟暗淡，头部至上胸为暗煤灰色，冠部略带灰色，上体泛棕色，翼羽边缘呈黄褐色，下体淡栗色，虹膜较深或灰色。亚种差异较小：diligens亚种头部较暗，背部更偏蓝灰色；masukuensis亚种上体灰色较浅，喉部黑色较淡，下体更淡或呈粉红肉桂色。Cinnamon-breasted亚种（M. r. pallidiventris）下体为淡粉红色，背部灰色较浅，翼覆羽白色羽缘更宽，外侧初级飞羽基部白色更多，喉部黑色与胸部灰色界限更清晰。","call":"棕胸山雀的叫声包括细薄的“sit, sit”和“szit”，可扩展为“si-ch”或“tsitsi-chaa-chaa-chaa-chaa”等连续音节，或更滚动的“whit-cherr, whit-cherr, whit-cherr”。报警声为刺耳的“churrr-churrr-churrr”。鸣唱类似延长版的叫声，包括快速清脆的“weetlu-chu”、“chick-wee”、“peetada”等重复音节。Cinnamon-breasted亚种的叫声与指名亚种无异。","habits":"棕胸山雀为留鸟，主要栖息于海拔600–2000米的成熟米翁博（Brachystegia）林地、刺灌丛稀树草原及干燥常绿林缘，亦见于苔藓过渡林地。常与Parus griseiventris同域分布，但占据不同生态位；在纳米比亚东北部亦与南黑山雀共存。通常单独或成对活动，偶见于3–4只的小群，亦加入混合种群觅食群。主要在树冠中上层觅食，偏好大型树木及地衣茂密的枝条，通过悬停于细枝上从叶片外缘啄取昆虫。","breeding":"繁殖期为9月至12月，可能为合作繁殖者。巢由草、植物纤维、树皮条及动物毛发构成的杯状或垫状结构，置于树洞或旧树桩中，高度通常不超过3米（偶达8米），常利用旧啄木鸟（Picidae）或拟啄木鸟（Capitonidae）的洞穴。每窝产卵3–4枚（Cinnamon-breasted亚种为4枚），其余繁殖细节尚不清楚。","identification":"与近缘种Parus griseiventris的区别在于棕胸山雀具有黑色头部及棕红色腹部，而后者腹部灰色。与南黑山雀的区别在于后者全身黑色，无棕红色下体。亚种间差异较小，主要通过下体颜色及翼部白色羽缘的宽度区分。","protection":"IUCN: NE（未评估）","distribution":"繁殖区域：指名亚种（M. r. rufiventris）分布于安哥拉北部至刚果民主共和国西部、纳米比亚东北部及赞比亚中部；masukuensis亚种分布于刚果民主共和国东南部、赞比亚东部、马拉维及坦桑尼亚西南部。非繁殖区域：Cinnamon-breasted亚种（M. r. pallidiventris）分布于坦桑尼亚、莫桑比克北部、津巴布韦及赞比亚极东部。","other":"棕胸山雀曾被认为与玫红胸山雀为同种又分拆，区别在于腹部颜色，杂交证据尚未证实。亚种间存在广泛的渐变现象，需进一步遗传学研究。现归为棕胸山雀的亚种。"},{"name":"玫红胸山雀","english_name":"Cinnamon-breasted Tit","scientific_name":"Melaniparus pallidiventris","overview":"玫红胸山雀（英文名：Cinnamon-breasted Tit，学名：Melaniparus pallidiventris），是雀形目山雀科黑山雀属的小型鸟类。曾在分类上与棕胸山雀视为同一物种，但现已确认为独立种类。","appearance":"玫红胸山雀具有独特的外观，胸部呈温暖的肉桂色，腹部较淡。其眼睛颜色曾被用来区分它与棕胸山雀，但现在认为这一特征并不稳定，两物种可能在同一群中混居。","habits":"这种山雀偏好居住在米奥博树林地带，活动范围广泛，通常在树冠层活动，以昆虫为主食。","identification":"与棕胸山雀相比，玫红胸山雀的胸部色彩更加鲜明，但两者间的辨识并非绝对，特别是在眼睛颜色方面存在重叠。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东南部，包括坦桑尼亚、马拉维、莫桑比克和津巴布韦。","other":"现为棕胸山雀亚种。"},{"name":"红喉山雀","english_name":"Red-throated Tit","scientific_name":"Melaniparus fringillinus","overview":"红喉山雀（英文名：Red-throated Tit，学名：Melaniparus fringillinus），是雀形目山雀科黑山雀属的小型鸟类。其显著特征为红褐色的面部、颈圈和胸部，以及灰色的顶冠和背部。分布于非洲的肯尼亚南部和坦桑尼亚北部的干燥金合欢灌木丛地带。","appearance":"体长约11.5至12厘米，体型介于小到中等大小。雄鸟的前额至眼上方狭窄区域、面颊、颈背、颈侧和下颏至胸部呈明亮的红褐色（有时带淡黄色调），顶冠至颈背深灰至黑色，上体为中至深灰色。尾巴黑色，所有尾羽尖端有窄白边，最外两根尾羽外缘白色。上翼覆羽暗灰至黑色，中覆羽宽白尖，大覆羽边缘和尖端白色，飞羽灰黑色，三级飞羽和次级飞羽宽白边，一级飞羽窄白边。腹部和臀部淡灰黄色，两胁和尾下覆羽稍显灰暗，后者宽白尖。雌鸟与雄鸟相似，但红褐色前额和面颊至胸部颜色略淡。幼鸟似雌鸟，但顶冠更灰，界限不明显，尾羽白边较窄，虹膜棕色至深棕色，喙蓝灰色至黑色，腿蓝色至黑色。","call":"叫声包括多变的‘chick’或‘plick’声，音质或哀婉或尖锐或爆发，还有柔和而连续的‘chick-chick, chick-chick-chick, chick-chick-chick...’系列音符，‘chachawi-chachawi-chachawi’和典型的雀科‘prtt-tchay-tchay-tchay’声，类似褐头山雀的叫声。此外，还有拉长的‘see-er’音符系列，更嗡嗡的‘bzee-zee-zee’声，以及尖锐的责骂声‘ch-ch-ch-ch’或更长的‘chrrrr’声。","habits":"通常在干燥的金合欢灌木丛地带以小群体活动，容易加入混合群与其他物种一起。栖息地为干热的金合欢灌木丛。","breeding":"繁殖季节不明，记录显示可能在1月、2月、4月和8月至9月繁殖，可能全年均可繁殖，主要频率由雨季决定。已知的巢穴主要由柔软的植物绒毛和纤维构成，置于树皮下的空洞中。一对红喉山雀在肯尼亚中部裂谷的公园巢箱中成功繁殖，至少每年两次，从2009年至2013年在湿润的4月至7月和10月至12月期间，共抚育了40多只幼鸟。","identification":"红喉山雀以其独特的红褐色胸部轻松区分于所有其他山雀。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲的肯尼亚南部和坦桑尼亚北部。"},{"name":"纹胸山雀","english_name":"Stripe-breasted Tit","scientific_name":"Melaniparus fasciiventer","overview":"纹胸山雀（英文名：Stripe-breasted Tit，学名：Melaniparus fasciiventer），是雀形目山雀科黑山雀属的鸟类。原置于Parus属，后因分子系统发育分析被归入Melaniparus属。该鸟种主要分布于非洲中东部，包括布隆迪、刚果民主共和国、卢旺达和乌干达。其生境为亚热带或热带湿润的山地森林。","appearance":"纹胸山雀体长约14厘米，重14-15克。头部黑色，腹部中央有一条黑色条纹，翼部边缘白色，尾羽外侧广泛白色。雄鸟的头、颈侧、喉及胸部为黑色，逐渐变淡至腹部上部。雌鸟头部至胸部颜色略偏褐色。幼鸟头部至胸部呈烟灰色或较暗的褐色，腹中部有狭窄的黑色条纹，其余下体部分泛黄或淡黄色。亚种差异主要体现在颜色深浅和斑纹的明显程度。","call":"纹胸山雀的叫声包括柔和的“whit”或“whip”接触音和尖锐的“chit”声，以及较低沉的“dzerr”声和一系列颤音“tititirrrrrrrr”。在警戒时会发出短促的“chrit”声，有时延长为连续的“chrit-it-it-it-it-it...”。鸣唱为重复的“tea-cher”短语，类似欧亚大山雀的歌声。","habits":"纹胸山雀栖息于山地森林，包括Hagenia林地，竹林和茂密的灌木丛。它们也会出现在树丛和森林画廊中。在乌干达海拔1800-3400米，卢旺达西南部高于2300米的Nyungwe森林中广泛分布。以小昆虫和幼虫为主食，通常在小到中等规模的家庭群体中活动，偶尔加入混合物种觅食群，与和白眼鸟(Zosterops)一同觅食。它们在树冠层活动，也会沿森林边缘的小树和空地觅食，偶尔下降至树木较低层，但在森林底层较为罕见。","breeding":"在乌干达Bwindi不可穿透森林的一项为期15年的巢箱研究显示，纹胸山雀平均每年孵化1.62只雏鸟，一年可产四窝，平均每年繁殖成功率提高至每雌3.09只。平均孵化期为15.1天，雏鸟期为23.5天。雏鸟成长速度较慢，留巢时间比欧洲欧亚大山雀长4.6天，但离巢时翅膀相对较长。幼鸟在离巢后平均81天仍接受父母照顾，最长可达三年。61%的巢中有帮手，76%的成年繁殖者在至少一次繁殖尝试中有帮手。","identification":"纹胸山雀与同属的其他物种相比，具有独特的黑色头罩和腹部中央的黑色条纹。亚种间存在颜色和斑纹上的细微差异，可通过观察这些特征进行区分。","protection":"IUCN：LC（无危）","distribution":"纹胸山雀主要分布在非洲中东部的布隆迪、刚果民主共和国、卢旺达和乌干达的山地森林中。","other":"纹胸山雀的生活史特征与北温带的欧亚大山雀有显著差异，显示出其适应赤道地区独特环境的策略。"},{"name":"索马里山雀","english_name":"Acacia Tit","scientific_name":"Melaniparus thruppi","overview":"索马里山雀（英文名：Acacia Tit，学名：Melaniparus thruppi），是雀形目山雀科黑山雀属的鸟类。以蓝黑色的头部、颈部、喉咙和胸部与大面积的淡黄色白色面颊形成鲜明对比而著称，其体长11.5-12厘米，体重约12克。栖息于非洲东北部干燥的金合欢树生境。","appearance":"索马里山雀体型小巧，头戴蓝黑色帽，颈背至喉部同样呈现蓝黑色，与脸部延伸至颈侧的大片淡黄色白色斑块形成强烈对比。背部灰色，翼部有白色斑点，颈后有一小白点。腹部灰白色，被一条宽阔的黑色带状条纹分割。腿与喙均为石板灰色。雌鸟山雀的黑色带状条纹较窄，幼鸟颜色较暗淡。成年个体体长4.5-4.7英寸，体重约0.42盎司。","call":"鸣叫声包括刺耳的‘chya chya’声，柔和而嘶哑的‘chet’或‘chut’声，常连续发出‘chet-chet-chet’系列，还有‘tsi-tsa-char’和爆发性的‘tsi-tsi-chay-chay-chay’或‘tsi-tsi-de-de-de-de-de’声。歌曲则为悦耳的‘see-uu’或‘tuwee’，强调第二个音节，重复多达六次，或更典型的‘twee-tew-tew-tew’或‘tsi-tsi-tchuerr-tchuerr-tchuerr’。","habits":"索马里山雀通常成对或小群体出现，偶尔加入混合物种觅食群。它们主要栖息在干燥和半干旱的木林与灌木草原，尤其是金合欢树丛或沿河流的树林中，避免极端干旱地带。海拔可达2,000米。食物以小型无脊椎动物为主，如黄蜂、甲虫和毛虫。","breeding":"繁殖习性了解甚少，已知它们在树洞中筑巢，曾有记录显示蛇类会掠食其巢穴。","identification":"与相似的北灰山雀区别在于颈部两侧有宽广的黑色，包围着脸部的白色部分，以及稍宽的黑色胸带。","protection":"IUCN：LC（无危）","distribution":"分布在非洲东北部，从埃塞俄比亚和索马里南至坦桑尼亚东北部。","other":"曾属于Parus属，分子系统发育分析后移至Melaniparus属，与红喉山雀形成超种群，可能还包括北灰山雀和阿卡山雀。"},{"name":"北灰山雀","english_name":"Miombo Tit","scientific_name":"Melaniparus griseiventris","overview":"北灰山雀（英文名：Miombo Tit，学名：Melaniparus griseiventris），是雀形目山雀科黑山雀属的鸟类。主要分布在非洲的安哥拉至坦桑尼亚西部、马拉维和津巴布韦等地，偏好居住在开放且成熟的miombo（Brachystegia）林地，其自然生境为亚热带或热带干燥森林。","appearance":"北灰山雀体长约14至15厘米，体重约20克，特征鲜明，具有黑色、白色和灰色的典型组合。雄鸟头部前额、冠部和侧冠（至眼下方）以及颈背为黑色，新羽时略带蓝色光泽，有时可见下颈背的灰白小斑块；上体呈灰色，最长的尾上覆羽尖端为黑色；尾巴黑色，除中央一对尾羽外，其余尾羽边缘有浅灰色。翅膀上的覆羽黑色，中覆羽和大覆羽边缘及尖端宽幅白色，初级飞羽覆羽黑色，细边白色；飞行羽黑色，次级飞羽和初级飞羽细边白色；颊部、耳羽和颈部侧面为暗淡的白色至黄褐色；下巴和喉部为烟黑色，沿腹部中心有一条窄线延续；下胸和腹部为淡白色，两胁灰色，尾下覆羽灰色带白色边缘。雌鸟与雄鸟相似，但头部光泽稍暗，黑色面积较小，围兜不那么显著。幼鸟类似雌鸟，但尾羽仅边缘狭窄，无白色尖端，翅膀深棕色，飞行羽边缘泛黄。","call":"北灰山雀的鸣叫包括频繁的'chitji'声，有时伴有响亮的'chip'声，还有刺耳或低沉的'chrrr-chrrr-chrrr-chrrr'声，通常以薄薄的'si'、'sisi'、'tit'或'plit'声为前奏，偶尔会发出更尖锐的'tit-tieu'声。此外，它还会发出滚动的'swip-ji-ji-ji-ji'声和叽叽喳喳的'tjou-tjou-tjou-tjou'声，以及更为延长和下滑的'tsirrrrrrr'声。其歌曲是一系列典型的百灵鸟式的吹哨短语，如'toowee-toowee, toowee-teeyoo, toowee-teeyoo'、'tsi-trreeeoo-tweetoo'或'twee-too-you, twee-too-you'，重复多次，常以'rit'声作为开场。","habits":"北灰山雀通常成对或小群（可能为家庭群）活动，常见于混种觅食群中，尤其在与阿卡山雀重叠的范围内。它主要在树冠层觅食，活动于活树和死树的树皮和枝干间，包括最大的枝干。它与棕胸山雀在成熟的miombo林地中共同生存，尽管两个物种似乎占据不同的生态位。","breeding":"北灰山雀的繁殖季节为8月至12月。它们在树洞中筑巢，包括啄木鸟或拟啄木鸟留下的旧洞，或在墙、篱笆柱、白蚁丘、地面或斜坡上的洞，甚至排水管中。每窝产3至5枚卵，关于孵化期和育雏期的信息尚不清楚。有时会被北非响蜜䴕寄生。在津巴布韦的miombo林地，75%的巢穴都能成功孵化两只雏鸟。","identification":"北灰山雀与非常相似的索马里山雀的区别在于体型较大，颈部侧面无黑色（脸部的白色与颈部侧面相连）；与阿卡山雀的区别在于喙较小，顶冠较暗淡，羽毛颜色较灰，下体更白。雌鸟与雄鸟相似，但光泽略暗，黑色面积较小，围兜不那么显著。幼鸟与雌鸟相似，但尾羽仅边缘狭窄，无白色尖端。","protection":"IUCN：LC（无危）。北灰山雀在其大部分分布区内常见或局部常见。在坦桑尼亚分布零散，仅在鲁翁戈山附近较为常见。在赞比亚的miombo林地中，密度约为14只/100公顷。由于其特定的生境需求，被认为有潜在的脆弱性；在生境被破坏并被次生灌木和荆棘取代的区域，似乎被阿卡山雀所取代。","distribution":"北灰山雀的分布区域覆盖了安哥拉、刚果民主共和国南部和东南部、坦桑尼亚西部、马拉维、赞比亚、津巴布韦和莫桑比克西北部。","other":"2013年发表的一项分子系统发育分析显示，北灰山雀原本是Parus属的众多物种之一，但后来因分析结果将其移至Melaniparus属，形成一个独特的支系。"},{"name":"阿卡山雀","english_name":"Ashy Tit","scientific_name":"Melaniparus cinerascens","overview":"阿卡山雀（英文名：Ashy Tit，学名：Melaniparus cinerascens），是雀形目山雀科黑山雀属的鸟类。这灰褐色的大型山雀，具有醒目的黑白头部图案和黑色胸带。主要分布于非洲南部，包括安哥拉、博茨瓦纳、纳米比亚、南非和津巴布韦。栖息于干旱的灌木丛和荆棘树，偶尔出现在河流附近的林地和阔叶林。","appearance":"体长14.5至15厘米，体重18.5至21.7克。雄鸟具黑色额部至头顶，侧冠至眼下方，颈背黑色，新鲜羽衣略泛蓝光，下颈背中央有一白色斑点。上体灰色，最长的上尾覆羽尖端黑色；尾羽黑色，多数尾羽（除中间一对外）尖端白色，最外侧边缘白色；翼上覆羽灰黑色，较小的覆羽尖端同上体色，中覆羽和大覆羽边缘和更宽的尖端淡黄色至白色，翼小覆羽和初级覆羽黑色，细边和尖端微白；飞行羽灰黑色，三级飞羽边缘灰白色，次级飞羽如同三级飞羽但稍暗淡，初级飞羽细边微白；颊、耳羽和颈部侧面白色；颏和喉至耳羽下方和胸部中心黑色，喉咙和胸部略泛蓝色光泽，一条狭窄的黑色线从下胸延伸到腹部，边缘狭窄的白色至浅灰色或黄褐色；其余下体灰色，除较暗的尾下覆羽尖端白色；腋下和翼下覆羽灰色，尖端偏白色。虹膜深棕色至棕黑色；喙黑色；腿蓝灰色或深灰色至黑色。雌鸟与雄鸟相似，但上体及翅膀和尾巴略微呈棕色，胸带通常更暗淡、光泽较少。幼鸟类似成鸟，但头至颈背为烟灰色，上体略呈暗棕色，尾羽深棕色，尖端非常窄的偏白色，翅膀深烟灰色，中覆羽和大覆羽有宽阔的淡灰色或黄褐色尖端，大覆羽边缘比成鸟窄，胸带棕色，略带暗灰色，仅限于喉咙和胸部，腹线通常不存在。","call":"鸣唱是一系列圆润的颤音，\"tlu-tlu-tlu-tlu-tlu-tlu, chi-chi-chi-chi-chi, tri-tri-tri-tri-tri\"，偶尔带有较慢的变化，例如\"trewet-treet-treet-treet-tretretretretretretre\"。叫声包括细长而相当嘶哑的\"si-si-si\"或较长且更复杂的\"psi-psi\"或\"sisisisi-cha-cha-cha\"音符，还有更粗糙的\"psi-psi-chrrrr\"；警报声为一系列鼻音的颤音，干燥的\"jejejejejejejeje\"和延长的\"chrrrrrr\"或\"tschrr tschrr tschrr\"。声音与灰山雀非常相似。","habits":"主要以小型无脊椎动物为食，包括甲虫、蛾类、蜘蛛、蚂蚁、苍蝇和幼虫，偶尔也会吃些果实和种子；巢中的幼鸟主要以鳞翅目幼虫和蛹为食。单独、成对或小群体活动；非繁殖季节常与其他物种混群，偶尔包括P. griseiventris。在树木的中层和高大的灌木丛中觅食，偶尔会降至地面；猛烈地敲打骆驼刺的种子荚以提取内部的无脊椎动物幼虫。","breeding":"繁殖季为9月至翌年4月。一夫一妻制；可能是合作繁殖者，多个成年个体参与照料繁殖雌鸟和幼鸟。领域性强；雄鸟在整个孵卵和雏鸟阶段都会从高处灌木中强烈鸣唱以保卫领地。巢由柔软的植物材料构成，包括绒毛、动物毛发和羽毛，放置于离地面2至4米的树干洞穴、旧树桩或地面洞穴中。每窝产4至6枚蛋；孵化由雌鸟负责，雄鸟喂养巢中的幼鸟，孵化期为11至13天；雏鸟期长达22天。繁殖成功率高度依赖于当地降雨量；在纳米比亚的24个巢中，由于天气炎热干燥，有12个巢在孵化前失败，其余的每个巢至少成功孵化了一只幼鸟。","identification":"与北灰山雀（颜色更淡，嘴更小，偏好miombo林地）和灰山雀（颜色更深，下体更黄，尾巴更短，栖息于较干燥的沿海灌木丛和Karoo）相似。可以通过灰褐色的上体、白色的颈背斑点、白色的翼缘和灰褐色而非黄褐色的下体来与它们区分开。","protection":"IUCN：LC（无危）","distribution":"非洲南部，包括安哥拉、博茨瓦纳、纳米比亚、南非和津巴布韦。"},{"name":"灰山雀","english_name":"Grey Tit","scientific_name":"Melaniparus afer","overview":"灰山雀（英文名：Grey Tit，学名：Melaniparus afer），是雀形目山雀科黑山雀属的鸟类。中到大型的暗灰色山雀，头部至胸部呈黑色，面部下方为白色，背部灰或淡棕色，尾巴烟黑色。该物种主要分布于非洲南部，包括Lesotho和南非，偏好干燥的灌木丛生环境，如半沙漠地带的Karoo区域，尤其是岩石露头附近的栖息地。灰山雀以昆虫为食，常成对或小群体活动。","appearance":"灰山雀体长约14至15厘米，体重约17.3至22.4克。头部至胸部为黑色，面部下方白色，上体灰或淡棕色，最长的尾羽覆羽尖端黑色；尾巴烟黑色，所有羽毛尖端带淡白色；翼上覆羽深灰棕色，较小的覆羽尖端与上体相似，中等和较大的覆羽边缘及更宽的尖端为灰白色或淡黄色；颊部、耳羽和颈侧为淡黄色；下巴和喉咙至耳羽下方及上胸中央黑色，逐渐变细为一条黑色线条直至肛门；胸部两侧和腹部白色，带有粉红色调，两胁淡黄色或粉黄色，尾下覆羽较暗，尖端较亮；腋窝和翼下覆羽黑色，尖端为淡黄色至灰白色。在磨损的羽毛状态下，冠部和颈背颜色更深，光泽减弱，上体颜色更深，略带棕色（灰色减少），尾羽的白色尖端磨损或消失，翼羽边缘磨损或消失（但大覆羽的尖端可能漂白得更白），黑色领巾颜色更暗，其余下体颜色更黄褐色。","call":"灰山雀的鸣唱通常是一系列哨音'piet-tjou-tjou, tudi-tudi-tudi'，其间穿插责备声、嗡嗡声和叽叽喳喳的声音。","habits":"灰山雀栖息于干燥的荆棘灌木丛，包括半沙漠的Karoo地区，偏好植被较低的开放岩石地带，如干涸的河床和农业区边缘。它们通常是居民或局部游荡者，以小型无脊椎动物为食，如胡蜂、蚂蚁、甲虫、蜘蛛和幼虫，尤其是长达4厘米的飞蛾幼虫，偶尔也会食用蜜刺果实。它们成对或小家族群活动，有时会加入混合物种觅食群，与Crombecs、黑胸鹪莺、棕耳鹪莺和南攀雀一起。它们在灌木丛、低矮的灌木树的叶片中觅食，也会从较高的树干和树枝的树皮中寻找猎物。","breeding":"繁殖季节从8月至3月。可能是合作性繁殖者。巢由两性共同建造，由草、植物纤维、动物毛发、羊毛和羽毛构成厚垫或杯状结构，置于岩石、涵洞或堤岸中的洞穴，或排水管、栅栏柱、旧建筑中，偶尔在树上（如果栖息地中存在）。每窝产卵2至5枚；孵化期可达14天；雏鸟由多达四只成鸟喂养，关于巢中雏鸟的持续时间没有具体信息。","identification":"灰山雀与阿卡山雀类似，但后者颜色更冷灰，翅膀边缘白色，尾巴更长，偏好Acacia荆棘灌木丛栖息地。","protection":"IUCN：LC（无危）","distribution":"灰山雀主要分布在非洲南部，包括Lesotho和南非，偏好干燥的灌木丛生环境，如半沙漠地带的Karoo区域。"},{"name":"欧亚攀雀","english_name":"Eurasian Penduline Tit","scientific_name":"Remiz pendulinus","overview":"欧亚攀雀（英文名：Eurasian Penduline Tit，学名：Remiz pendulinus），是雀形目攀雀科攀雀属的小型鸟类。其特征包括锐利尖喙、锈褐色背部和黑色眼罩，雄鸟眼罩较宽，雌鸟则较窄。分布广泛，从西部、北部至中南部的欧洲及亚洲部分地区。以湖泊、河流湿地为栖息地，善于建造独特的袋状巢穴。","appearance":"体长10-11.5厘米，尾较长，喙尖细，头部呈淡灰色，具黑色眼罩。背部锈褐色，雄鸟眼罩更宽，背部更红褐色。雌雄相似，但雄鸟眼罩更宽，背部颜色更深。幼鸟整体呈均匀棕色，无眼罩特征。","call":"发出尖锐、高音的哨声叫声，类似未上油的门铰链声，与欧亚鸲的警报叫声相似。歌曲由一系列啾啾声组成，穿插着叫声，包含模仿其他鸟类歌声的片段。","habits":"偏好湖泊边和河流湿地的植被，如芦苇、香蒲、柳树和杨树。栖息于低地，偶尔在山坡上的树林和果园筑巢。迁徙模式随地理位置而异，北方种群高度迁徙，南方种群迁移距离较短。春季迁徙最早可在2月开始，高峰出现在4月初。","breeding":"繁殖季节从5月至6月，巢穴为精致的悬挂式袋状结构，由植物纤维、蛛网和羽毛构成，入口朝下。孵化期约为13-14天，通常由雌鸟单独孵化。幼鸟喂养期为18-26天，主要由雌鸟负责。部分情况下，雄鸟会独自孵化和抚养后代。","identification":"与同属其他物种相比，欧亚攀雀具有更尖锐的喙和更长的尾巴。通过黑色眼罩、锈褐色背部和灰头可以轻易辨认。幼鸟缺乏明显的特征，与成鸟有明显区别。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖了欧洲西部、北部和中南部，冬季迁徙至南欧和北非部分地区。在中国大陆的分布较为零散。","other":"自1950年代起，其分布范围向西显著扩张，尤其是在欧洲中部和北部。适应了人类活动创造的新栖息地，如鱼塘、砂坑和因采矿形成的湖泊。"},{"name":"黑头攀雀","english_name":"Black-headed Penduline Tit","scientific_name":"Remiz macronyx","overview":"黑头攀雀（英文名：Black-headed Penduline Tit，学名：Remiz macronyx），是雀形目攀雀科攀雀属的鸟类。独特的小型鸟类，主要分布于亚洲中部，包括河流或湖泊附近的植被，如芦苇丛，但通常避开最密集的生长区。","appearance":"整体呈现淡褐色，头部颜色较深。相较于伊朗的同类，中央亚洲的个体平均颜色更浅一些。雌雄外观相似，但雌鸟的色彩更为柔和，对比度较低。其特征之一是整个头部为暗色，与‘caspia’形式的欧亚攀雀有所不同，后者仅具有一张暗色的面具。","habits":"栖息于河流或湖泊周边的植被中，偏好芦苇丛生的环境，但会避开过于密集的区域。它们展现出特定的栖息地选择和活动模式。","breeding":"如同其他攀雀，黑头攀雀构建悬垂式的袋状巢穴，通常在芦苇间编织，以提供安全的繁殖场所。","identification":"与‘caspia’形式的欧亚攀雀相比，黑头攀雀的头部全部为暗色，而非仅限于面具部分，这是辨识两者的重要特征。","protection":"IUCN：NE（未评估）","distribution":"主要分布在亚洲中部，具体包括中央亚洲的繁殖区域。","other":"系统学历史与分类学上，曾被认为是欧亚攀雀的同物异名，但现在被确认为独立物种。"},{"name":"白冠攀雀","english_name":"White-crowned Penduline Tit","scientific_name":"Remiz coronatus","overview":"白冠攀雀（英文名：White-crowned Penduline Tit，学名：Remiz coronatus），是雀形目攀雀科攀雀属的小型鸟类。其显著特征是雄鸟拥有明显的黑色面罩和几乎白色的冠羽，分布于中亚至中国西北及俄罗斯东南部，常见于近水的苇丛和柳、桦、杨等阔叶树间。","appearance":"成年白冠攀雀长约10-11厘米，体重约9.3-10.5克。雄鸟具有一块宽大的黑色面罩，覆盖眼周和耳羽，延伸至喙基和后颈上部，冠羽非常淡灰，接近白色，尤其是在野外显得几乎是白色。雌鸟较为朴素，冠羽和颈背呈灰色，面罩棕色且范围较小。幼鸟头部、胸部侧面和背部呈灰褐色，逐渐变为肉桂色，翼部较成鸟暗淡，下体为均匀浅黄色。","call":"白冠攀雀的叫声是一声拉长的、哀怨的哨音，歌声短促，以果断的‘chip’音结束。","habits":"栖息于河流附近的杨树和柳树林，湿地和河漫滩草地，偶尔也在灌木山坡、花园、果园和胡桃林中繁殖。在非繁殖季节，它们会出现在开放的森林、柽柳、沿岸树木、水库和有时是芦苇地（虽然繁殖季节避免，但在巴基斯坦的冬季很受欢迎）。在巴基斯坦，冬季的白冠攀雀最早可能在9月末到达，多数在12月到达，直到3月底离开。","breeding":"繁殖期从5月下旬至6月中旬开始，巢由两性共同建造，呈长圆形袋状，侧向入口，通常悬挂在树水平枝尖端6-8米高的位置。每窝产3-9枚卵，孵化由雌鸟负责，雄鸟喂食。孵化期和雏鸟离巢时间未知。","identification":"与相似的欧亚攀雀相比，白冠攀雀的羽毛图案更加鲜明，没有冠部的栗色，黑色面罩更宽，横跨后颈，突出几乎白色的颈环，喙更小更细，腿和脚趾更纤细。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要在中亚，包括哈萨克斯坦、蒙古、乌兹别克斯坦等地，冬季迁徙至伊朗、阿富汗、巴基斯坦部分地区，以及中国新疆的少数记录。","other":"白冠攀雀过去曾被认为是欧亚攀雀的一个亚种。"},{"name":"中华攀雀","english_name":"Chinese Penduline Tit","scientific_name":"Remiz consobrinus","overview":"中华攀雀（英文名：Chinese Penduline Tit，学名：Remiz consobrinus），是雀形目攀雀科攀雀属的鸟类。俗名: 洋红儿，精致小鸟。以其独特的巢穴建筑技能闻名。雄鸟头部灰顶，面部黑色眼罩，背部棕色，尾部呈凹形。广泛分布于中国北部，俄罗斯远东地区及中国东北部。迁徙季节，可见于日本、朝鲜与中国东部。","appearance":"体长约9-12厘米，体重约7.5-11.9克。雄性中华攀雀头部具黑色眼罩，边缘白色，灰色顶冠，颈侧及肩部有红褐色色调，背部呈淡棕色，翼羽基部暗色，尾羽宽边淡色。雌鸟颜色较暗淡，头部、颈侧及背部呈浅棕褐色，眼罩深棕色或红棕色，喉部及腹部暖棕色。幼鸟特征不明显，全身呈暗淡的棕黄色。","call":"发出高亢、尖锐的‘tseee’或‘pseee’叫声，类似‘siu, siu, siu, siu’系列，以及‘piu’音调，歌声为‘si, si, tiu, si, si, tiu’的重复。","habits":"偏好栖息于开阔的田地和湿地中的芦苇丛，冬季常集成小到大的群体，活跃于芦苇地带，觅食小型昆虫、幼虫、蜘蛛及冬季的种子。飞行轻盈跳跃，常群飞。","breeding":"繁殖季节自4月初至6月中旬，雄鸟积极筑巢，巢似梨形袋，具管状延伸，侧面入口。雌鸟产卵5-10枚，独自行孵卵12-15天。雏鸟由双亲共同抚养，离巢后仍返回巢内睡眠15-20天。","identification":"与相似种白冠攀雀区别在于较小的黑色眼罩，周围有白色边框，灰色顶冠和颈侧，无黑色上颈环，下部呈浅色至喉部，突出白色眼下区。","protection":"IUCN：LC（无危）","distribution":"繁殖于俄罗斯远东地区和中国东北（从宁夏南部、内蒙古东部至黑龙江）。非繁殖季节分布于中国东部和南部（长江中下游、云南、广西、广东、香港）、韩国南部和日本南部（主要是九州和本州）。","other":"中华攀雀曾被视为欧亚攀雀欧亚攀雀的一个亚种。"},{"name":"斑额攀雀","english_name":"Sennar Penduline Tit","scientific_name":"Anthoscopus punctifrons","overview":"斑额攀雀（英文名：Sennar Penduline Tit，学名：Anthoscopus punctifrons），是雀形目攀雀科非洲攀雀属的小型鸟类。其最显著的外部特征是尖锐的喙、淡橄榄灰的背部、淡黄色的腹部和布满黑色斑点的前额。广泛分布于非洲的干草原和荆棘灌木丛地带，从毛里塔尼亚南部和塞内加尔延伸至苏丹东部，厄立特里亚和南苏丹北部。","appearance":"斑额攀雀是一种体型微小的鸟类，拥有尖锐的喙，背部呈淡橄榄灰色，腹部颜色较浅，为淡黄色。最引人注目的特征是其前额上布满了黑色的斑点。雌雄鸟在外观上相似，通常以成对或小群体的形式出现，显得温顺但不显眼。","call":"斑额攀雀的鸣叫声包括高音的‘sit’音符和长长的干燥颤音，这些声音有助于在野外识别它们的存在。","habits":"斑额攀雀栖息于干燥的草原和荆棘灌木丛中，常见于非洲的萨赫勒地带。它们通常成对或以小群体活动，表现出一定的温顺性，尽管不容易被察觉。鸣叫声包括高音的‘sit’音符和长长的干燥颤音。","breeding":"关于斑额攀雀的繁殖习性的具体信息尚不详尽，但此类小型鸟类通常会在特定季节内筑巢、交配和育雏。","identification":"斑额攀雀与黄攀雀相似，但色彩较为暗淡，腹部颜色为淡黄色而非鲜艳的黄色，且翼羽边缘没有白色。通过这些特征，可以在野外区分这两种鸟类。","protection":"IUCN：LC（无危）","distribution":"斑额攀雀的分布范围覆盖了非洲的广阔区域，从毛里塔尼亚南部和塞内加尔向东延伸至苏丹东部，厄立特里亚和南苏丹北部。具体而言，它们在极南部的毛里塔尼亚、塞内加尔东部、马里的南部、布基纳法索北部、尼日尔南部、尼日利亚东北部、乍得中部、喀麦隆北部、苏丹中部和东南部、埃塞俄比亚北部以及南苏丹西部都有分布。"},{"name":"黄攀雀","english_name":"Yellow Penduline Tit","scientific_name":"Anthoscopus parvulus","overview":"黄攀雀（英文名：Yellow Penduline Tit，学名：Anthoscopus parvulus），是雀形目攀雀科非洲攀雀属的鸟类。这小巧、色彩鲜艳的鸟类，拥有橄榄绿色的背部，翼羽边缘呈白色，下体黄色。分布于西非的半干旱草原地带，从毛里塔尼亚南部至几内亚比绍，东至南苏丹和刚果民主共和国东北部。","appearance":"体长约8厘米，体重约6至8克。全身橄榄黄色，头顶至前额亮黄色，眼纹灰暗，冠羽及上体为橄榄绿中带灰色调，臀部和尾上覆羽更显黄色。翅膀深褐色，羽缘黄绿色，初级飞羽边缘淡黄白色，形成窄白翼板。尾巴深褐色，下体至尾下覆羽鲜黄色，随羽毛磨损，翼和尾色渐变为浅棕色，下体转为暗黄色。喙尖锐锥形，腿脚蓝灰或铅灰色。雌雄相似，幼鸟色泽较淡，头顶和下体黄色较淡。亚种间差异主要在于羽色黄色强度：senegalensis亚种比指名亚种更亮，几乎全黄，缺乏上体的灰色调；aureus亚种色泽较暗，但新羽期具有明显的白翼板。","call":"鸣声为一系列上下起伏的哨音，以及快速连续的嗡鸣音符。接触叫声为细薄的“si, sli-sli-sli”，类似北长尾山雀的叫声。","habits":"栖息于干燥或半干旱的沙质或短草草原，偏爱水边的大树荫凉处或大金合欢树群。常在三到六只的小群体或偶见三十只左右的大群中活动，也与白眼鸟和石燕鸟等小型鸟类混合觅食。以小昆虫及其幼虫为主食，主要在树冠层觅食，跳跃于树枝之间。","breeding":"繁殖状况了解较少。已知在3月的冈比亚、2月至3月的马里（巴马科）、1月的加纳和6月的尼日利亚（阿贡古）发现处于繁殖状态的个体。巢穴为精致编织的吊篮状，材质坚固，入口为短管状，能自动关闭，位于离地面约5.5米的软叶树顶。一窝产卵2枚，更多繁殖信息未知。","identification":"与同类相比，黄攀雀颜色更为鲜亮，下体黄色而非淡黄色，翼羽边缘白色明显。幼鸟和亚种间存在颜色深浅差异。","protection":"IUCN：LC（无危）","distribution":"分布于毛里塔尼亚南部至几内亚比绍，东部至南苏丹和刚果民主共和国东北部。常见于西非的半干旱草原地带。","other":"黄攀雀能在一定程度上容忍因砍伐木材和家畜过度放牧造成的栖息地退化，其未来似乎较为安全。"},{"name":"灰攀雀","english_name":"Mouse-colored Penduline Tit","scientific_name":"Anthoscopus musculus","overview":"灰攀雀（英文名：Mouse-colored Penduline Tit，学名：Anthoscopus musculus），是雀形目攀雀科非洲攀雀属的鸟类。身长仅约8厘米，是非洲最短小的鸟类之一。全身呈现灰褐色，腹部白色，分布于东非的干旱草原和灌木丛中。","appearance":"这种小鸟体型极小，全长约8厘米，体重约6至8克。整体呈灰褐色，背部较为灰暗，腹部洁白，尾巴非常短，喙尖而圆锥形，腿脚强健。头部和上体颜色较淡，额头和耳羽处略带浅黄褐色斑点，翅膀和尾巴颜色更深，边缘略显灰色。眼睛棕色，喙黑色渐变至基部较淡，腿部呈深蓝灰或黑色。","call":"其典型叫声为高音的“tit, tit, tit...”，还发出突然的鼻音“tzeee”或“bzeeu”。歌曲由几个重复的乐句组成，包括快速的“di-di-di-di-di-di...”颤音，清脆的“we-cha-we-cha-we-cha-we-cha...”，以及细长的“tsee-tsi, tsee-tsi, tsee-tsi...”。","habits":"灰攀雀主要以小型昆虫及其幼虫为食。它们通常成对或家庭群觅食，有时与其他小型鸟类松散地混群。它们活跃于低矮的灌木丛和大树冠层，动作敏捷，常倒挂取食，有时会像踮脚般伸展去获取食物。觅食时对人类的存在似乎不太在意。","identification":"与非洲攀雀的主要区别在于其腹部完全为白色。与斑额攀雀和非洲攀雀相比，背部更灰，下方更淡。与黄腹孤莺或黄臀孤莺的区别在于喙更短更细，腹部无黄色。","protection":"IUCN：LC（无危）","distribution":"分布在非洲东部，从中埃塞俄比亚至南苏丹，向东南至索马里、肯尼亚、北坦桑尼亚和东北乌干达。"},{"name":"林攀雀","english_name":"Forest Penduline Tit","scientific_name":"Anthoscopus flavifrons","overview":"林攀雀（英文名：Forest Penduline Tit，学名：Anthoscopus flavifrons），是雀形目攀雀科非洲攀雀属的鸟类。小型、颜色暗淡的鸟类，拥有尖锐的喙，背部呈暗橄榄绿色，腹部和前额为淡黄色。林攀雀主要分布于非洲西部和中部的低地雨林、次生森林以及偶尔出现在种植园的树冠层。尽管数量不多且不显眼，通常以成对或小群的形式出现。","appearance":"林攀雀体型小巧，羽毛色彩较为单调，背部长有暗橄榄绿色的羽毛，而其腹部和前额则是淡黄色调。头部和胸部无明显的条纹，整体外观较黄攀雀更为暗淡。喙部较短，基部较宽且尖锐，区别于一些颜色较鲜艳的太阳鸟。","call":"林攀雀的叫声为非常尖细的‘sit’音符，音调极高，容易被忽视。","habits":"林攀雀偏好生活在低地雨林、次生森林和某些种植园的树冠层，主要活动于树梢。它们的生活习性较为隐秘，常见于成对或小群体中。","identification":"与黄攀雀相比，林攀雀颜色更加暗淡，且栖息环境不同。与拟雀莺相比，林攀雀整体更暗淡，头部和胸部无条纹。与一些太阳鸟相比较，林攀雀的喙部更短、更宽、更尖。","protection":"IUCN：LC（无危）","distribution":"林攀雀广泛分布于非洲西部和中部，包括喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、加蓬、加纳、利比里亚和尼日利亚。其自然栖息地为亚热带或热带湿润的低地森林。"},{"name":"非洲攀雀","english_name":"Grey Penduline Tit","scientific_name":"Anthoscopus caroli","overview":"非洲攀雀（英文名：Grey Penduline Tit，学名：Anthoscopus caroli），是雀形目攀雀科非洲攀雀属的鸟类。体形极小、羽色朴素的攀雀科鸟类，整体呈灰色，腹部颜色因地域差异从近白至浓栗色不等，嘴细小而尖锐，尾短。它广泛分布于非洲东部与南部，自乌干达、肯尼亚直至纳米比亚东北部与南非东部，活动于稀树草原及阔叶林等多种林地，通常结小群活动，以昆虫为主食，以精巧的悬袋状巢著称。","appearance":"成鸟体长8–9厘米，体重5.5–10克；嘴小而尖，呈圆锥形，暗灰色；腿、趾强健，呈石板灰至黑色。两性同色：额与短眉纹淡黄褐或浅肉桂色，杂有暗色斑点；头顶至上体淡灰色，新鲜羽衣略带橄榄色；飞羽及尾羽暗褐，羽缘灰褐或橄榄灰；翼上覆羽具淡色端斑，形成狭窄翼带；颏、喉近白，胸染浅黄，转为胁部暖黄，腹部及尾下覆羽深橙褐色。幼鸟较成鸟暗淡，上体偏褐，下体浅黄。各亚种差异体现在上体橄榄或灰色深浅、下体黄或栗色浓淡及前额颜色。","call":"最常见叫声为高频“tsu-tsu-tsii”三连音。鸣唱多变，为重复2–7次的高节奏短句，由一两个带沙哑的短音接一长而尖的“see”或“tseeuw”音，如“chi-chi-seee…”。另有粗糙的低哑斥责声与短促“ti-ti-ti”联络声。部分亚种（如sylviella）发出2–3秒的高音略降金属颤音。鸣唱多见于清晨，自树梢快速移动时发出。","habits":"主要留鸟，局部具雨季下降或游荡记录。栖息于海拔100–2200米的各类林地：湿润的阔叶林、米翁布（Brachystegia）林、Baikiaea林、金合欢稀树草原，偶见于红树林、花园及山地灌丛。常在树冠至中层敏捷跳跃觅食，倒悬于叶簇或花序上啄食昆虫，也下至灌木甚至地面；多单只或家族小群活动，常与白眼、柳莺、鹎等混群。食物以小昆虫及其幼虫为主，亦食少量果实与花蜜，曾见被黑背蓬背鹟盗食。","breeding":"繁殖期与雨季同步：南部非洲8–4月（高峰9–11月），赞比亚8–11月，马拉维9–11月，刚果2月，东非2、4–6、9–12月。雌雄共同编织悬袋巢，悬于1–10米高细枝分叉处，巢呈梨形，由蛛丝、植物茸毛织成，壁厚可达50毫米，入口为25–40毫米自闭管状，需用足开启；其下具假室以迷惑天敌。巢高120–130毫米，直径65–75毫米。卵椭圆形，白垩色带奶油光泽，12.6–16.6×8.5–10.0毫米；窝卵3–6枚（平均4.4）。孵化期约15天，双亲轮流孵卵并共同育雏，雏鸟22–28天离巢，曾见三鸟共建一巢，示合作繁殖可能。","identification":"与同属灰攀雀相比，本种腹色较浅且上体更偏褐；与南攀雀相比，后者具黑色面纹及短白眉。与莺类区分：黄腹孤莺腹黄、嘴较长；欧柳莺具明显眉纹及白黄腹。亚种间差异：ansorgei 上体亮橄榄绿，下体近白；roccatii 下体淡黄；rankinei 上体石板灰，下体近白；sylviella及 sharpei 下体栗褐色。","protection":"IUCN: LC（无危）。分布广泛但不常见，局部稀少；已记录于多国国家公园及保护区，种群总体稳定。东南肯尼亚沿海低地种群近年已消失，需关注。","distribution":"繁殖区：非洲东部与南部，自乌干达、肯尼亚经卢旺达、布隆迪、坦桑尼亚、刚果东南部、赞比亚、安哥拉、马拉维、莫桑比克、津巴布韦至纳米比亚东北部与南非东北部夸祖鲁-纳塔尔及林波波省。非繁殖区：基本留鸟，局部雨季下移。分布呈斑块状，东非高原、阿尔伯丁裂谷、赞比西河流域及南非北部为主要集中区。","other":"分类变动：曾被置于 Remiz 属，亦有学者建议将亚种 sylviella（含 sharpei）独立为种。分子研究表明非洲攀雀与欧亚攀雀早在中新世即已分化。亚种数量及有效性仍在研究，目前认可11个亚种并归入5个亚种组。"},{"name":"南攀雀","english_name":"Cape Penduline Tit","scientific_name":"Anthoscopus minutus","overview":"南攀雀（英文名：Cape Penduline Tit，学名：Anthoscopus minutus），是雀形目攀雀科非洲攀雀属的鸟类。分布于非洲西南部，包括安哥拉、博茨瓦纳、纳米比亚、南非和津巴布韦。以其黄色腹部、绿色背部和灰色头部的精细外观著称，额头呈现独特的黑白色鳞状图案。","appearance":"体长约8至9厘米，体重约6至7.5克。特征为灰黄相间的羽毛，拥有尖锐的小锥形喙和强健的短腿。成年鸟额头呈黑白色鳞片状，下额和喉咙为白色，全身下部为淡黄色，翅膀和尾巴为较暗的灰棕色。雄雌相似，幼鸟颜色较为暗淡，比成鸟更偏褐色。","call":"鸣唱为一系列高音的‘chiueew’声，重复5到7次，声音清脆哀婉。还发出简单而尖锐的金属声和刺耳声。","habits":"栖息于沙漠和半沙漠灌木丛，偏好较高的荆棘树。以昆虫、蜘蛛、小果实和种子为食，常倒挂搜索食物。成对或小群活动，有时与混合鸟群一起。","breeding":"筑球形巢，利用蜘蛛网和植物纤维，入口侧向，构造复杂，有假入口以防蛇和其他捕食者。","identification":"与非洲攀雀相比，体型略大，具有黑白色的额头鳞纹，腹部颜色为黄色而非土黄色。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲西南部，包括安哥拉、博茨瓦纳、纳米比亚、南非和津巴布韦。在博茨瓦纳，出现在卡拉哈里沙漠的孤立荆棘丛中。","other":"在一些保护区如南非的Koeberg自然保护区和津巴布韦的Hwange国家公园可见其踪迹，未来生存状况稳定。"},{"name":"黄头金雀","english_name":"Verdin","scientific_name":"Auriparus flaviceps","overview":"黄头金雀（英文名：Verdin，学名：Auriparus flaviceps），是雀形目攀雀科黄头金雀属的鸟类。属于攀雀科，体长约10厘米，以明亮的黄色头部和颈部为显著特征。栖息于美国西南部至墨西哥北部的干燥灌木丛生地带，如索若拉沙漠，偏好在带刺植被中营巢。","appearance":"黄头金雀体型小巧，全身大致呈灰白色调，头部和喉部为鲜明的黄色，肩部可见一小块红棕色斑点。喙尖锐，黑色眼先，胸部和腹部为灰白色，翅膀上的栗色斑纹明显。雌雄外观相似，但在色彩饱和度上雌鸟略显灰暗。","call":"黄头金雀发出一系列响亮的‘tschep’声，快速而连贯，对于它们的体型而言音量较大。此外，还有‘gee-gee-gee-gee’的警报声以及‘tweedle’的颤音，可能用于加强配偶间的联系。","habits":"黄头金雀居住在干燥的灌木丛中，如索若拉沙漠的带刺植被内，以昆虫为主食，偶尔也会访问蜂鸟喂食器获取花蜜。它们几乎全年无休地觅食，尤其在较凉爽的天气里，频繁地在树叶和花朵间寻找蜘蛛和小型昆虫。","breeding":"春季繁殖期间，黄头金雀形成一夫一妻制，雄鸟和雌鸟共同参与筑巢、孵化及育雏。巢通常位于灌木或小树的外侧枝叶中，呈封闭式，直径约15-25厘米，有一个侧面底部的入口。每窝产卵3-6枚，卵壳呈浅绿色，带有不规则的深红棕色斑点。","identification":"黄头金雀最易通过其独特的黄色头部和肩部的红棕色斑点与其它鸟类区分开来。与赤腰虫森莺或Bushtit相比，其喙更为粗壮，且有明显的黄色头部。","protection":"IUCN：LC（无危）","distribution":"黄头金雀分布于北美西南部，包括美国的西南部和中南部，以及墨西哥北部。具体而言，它们在加利福尼亚南部、亚利桑那南部、新墨西哥和墨西哥北部的干旱地区最为常见。","other":"黄头金雀是北美唯一的新世界Remizidae家族成员，这一家族在旧世界包括了penduline tits。"},{"name":"黄翼斑斗鹎","english_name":"Western Nicator","scientific_name":"Nicator chloris","overview":"黄翼斑斗鹎（英文名：Western Nicator，学名：Nicator chloris），是雀形目斗鹎科斗鹎属的鸟类。具有橄榄绿色的上部羽毛和带白点的翅膀，黄色尾羽尖端在飞行中显眼。常见于非洲热带雨林中的雨林、画廊森林、灌木丛和茂密的次生植被中。与黄喉斗鹎极为相似，但分布范围不重叠。","appearance":"体长20-23厘米，体重雄鸟48-67克，雌鸟32-51克。具有厚重钩状喙，翅膀上有显眼的黄色斑点。头部羽毛坚硬短小，向上指。上部羽毛深橄榄绿，臀部和尾上覆羽更偏黄绿色。尾羽暗绿色，边缘泛黄，末端黄色扩大。喉部灰色，侧边黄色，胸部灰色，侧面更绿，腹部灰白色，中心略呈米色，大腿绿黄色，下尾覆羽鲜黄，腋下和翼下覆羽黄色。虹膜棕色、灰棕色或栗棕色，眼环和嘴裂淡黄色；喙黑色；腿蓝灰色。与非常相似的东非斗鹎区别在于更橄榄绿（而非灰）的冠羽。雌雄相似，雌鸟平均比雄鸟小。幼鸟上方稍浅，下胸和腹部纯白。","call":"非常活跃的鸣唱，包括快速杂乱的木音符和穿透性的‘chaak’叫声。其歌声强而悦耳，变化多样，包含清晰的哨音和喉音等，有时模仿其他物种的声音。","habits":"栖息于常绿和半落叶的原始森林、沼泽森林、画廊森林和稀树草原地带的密集灌木丛中。在次生环境中，如伐木森林、阴影下的可可种植园、伐木道路旁和水道边也能找到它们。主要生活在低地，但也出现在高达1400-1500米的森林中，偶尔至1800米。以节肢动物、大型昆虫、甲虫、毛虫和小型蛙类为食，偶尔吃一些浆果和种子。通常成对出现，但在觅食时伴侣间可能相隔较远；有时加入混种鸟群。在浓密的灌木丛和开阔的植被中缓慢而有条不紊地觅食，主要在5-25米高的下层和中间层。","breeding":"筑巢记录显示在4月的塞拉利昂，2月和11月的利比里亚，12月的科特迪瓦，6月的尼日利亚，4-6月和8月的喀麦隆，全年在加蓬，5-11月的刚果民主共和国，7-8月的苏丹，4月和6-7月的乌干达，6月的中非共和国，2-3月的安哥拉。一夫一妻制，领域性强。巢小而简陋，由几根棍子支撑藤蔓和腐朽的枝条构成，选择处于分解状态的树枝，让生长在上面的真菌遍布整个巢穴，使其结合并稳固。每窝产一枚蛋，仅由雌鸟孵化，孵化期17-18天。雏鸟在离开巢穴前16-18天由双亲喂养，此时尚不能飞行，移动到邻近的树枝上。","identification":"与黄喉斗鹎的区别主要在于分布范围和部分鸣叫特征。与东非斗鹎相比，体型更大，没有明亮的黄色喉咙和眼上的条纹。","protection":"IUCN：LC（无危）","distribution":"分布于塞内加尔、冈比亚至苏丹南部南部、乌干达、坦桑尼亚西部、赞比亚和安哥拉北部。"},{"name":"东非斗鹎","english_name":"Eastern Nicator","scientific_name":"Nicator gularis","overview":"东非斗鹎（英文名：Eastern Nicator，学名：Nicator gularis），是雀形目斗鹎科斗鹎属的鸟类。具有显著的钩状喙。上身橄榄绿色带白色斑点，下身淡色，黄色尾角在飞行中尤为醒目。广泛分布于非洲东部，自索马里南部至南非东部，包括内陆沿赞比西河地区。","appearance":"体长20-23厘米，雄鸟体重40-63克，雌鸟29-41克。头部橄榄灰色，背部暗橄榄绿，尾羽绿褐色，边缘泛黄，翼部有明显黄色斑点。喉部灰白，胸侧偏绿，腹部灰白，大腿呈淡绿黄色，下覆羽和腋羽黄色。喙角质色，腿脚蓝灰色或浅蓝灰色，雌雄相似，幼鸟初级飞羽尖端黄色。","call":"声音丰富，从隐蔽高处开始低音“tik-chopweeoo-tok”，随后是有力的“trrr”声，接着是响亮流畅的哨音，如“hip-to-wee-to-chip to-weet”。模仿能力出色，能模仿Moustached Green Tinkerbird和Eastern Black-headed Oriole的叫声。","habits":"栖息于森林、灌木丛和密集的林地，偏好隐蔽的生活方式，常见于树冠下的纠缠植被中。主要以昆虫为食，活动范围广泛，迁徙模式不明。","identification":"其独特的大而钩状的喙和翼上的黄色斑点使其易于与其他鸟类区分开来，尤其是与同属物种的区别明显。","protection":"IUCN：LC（无危）。在某些地区数量稀少，但在其他地区常见，估计在莫桑比克南部的数量至少为1万只。在马拉维最适宜的栖息地中，密度可达每10公顷3-5对。在多个保护区中得到良好保护。","distribution":"分布于索马里南部、肯尼亚东南部、坦桑尼亚东北部和东部（含桑给巴尔）、赞比亚南部、纳米比亚极东北部（赞比西地区）、津巴布韦北部、东部和东南部、马拉维大部分地区、莫桑比克南部至南非东北部（夸祖鲁-纳塔尔省）和斯威士兰东部；刚果民主共和国极东南部和邻近赞比亚西北部也有离散的种群。","other":"曾被称为‘黄斑斗鹎’，但现在这一名称仅用于中非的西部斗鹎。"},{"name":"黄喉斗鹎","english_name":"Yellow-throated Nicator","scientific_name":"Nicator vireo","overview":"黄喉斗鹎（英文名：Yellow-throated Nicator，学名：Nicator vireo），是雀形目斗鹎科斗鹎属的鸟类。生活在非洲中南部的稀有小鸟。以昆虫和植物果实为食，被《世界自然保护联盟》列为2009年鸟类红色名录物种。在国际上，黄喉斗鹎被列为一级保护鸟类。","appearance":"体长约16-18厘米，体重约21-26克。外形似绿鹎，但喙部更厚实，呈钩状。头部前额和顶冠为灰橄榄色，后顶冠和背部为橄榄绿色；尾部较淡，呈黄绿色，尾羽末端除最内侧两对外均为黄色，从第三对外展至最外侧的第六对尾羽，黄色逐渐扩大。翼羽暗褐色，边缘泛亮橄榄绿，次级飞羽和三级飞羽有显著的黄色端斑；较大的上覆羽暗褐色，初级覆羽边缘黄色，中覆羽和大覆羽有大的浅黄色端斑，小覆羽深绿色，形成两排对比鲜明的黄色斑点。下巴灰色，喉部和颈部侧面为黄色或黄绿色；胸部和胁部灰色，侧身泛绿色，腹部灰白色，大腿部绿色，尾下覆羽黄色或黄绿色；翅膀下覆羽和腋羽黄色；虹膜棕色或灰棕色；喙上部黑色或黑角质色，下部蓝灰色或淡灰色；腿蓝灰色或灰色。雄雌外观相似，雌鸟平均体型小于雄鸟。幼鸟额头绿色，喉部黄色较少。","call":"藏匿于密林中的鸣唱是一系列响亮、远传的8-11个回响爆炸音，如“ko-kwee-ko-ko-ko-kwee-kuk-kuk”或“po-tyoo-ho-ho-ho-whee, tyoo-ho-ho”，伴随一些变化。叫声包括愤怒的“gwrrrrrr”。","habits":"生活在亚热带或热带湿润低地森林，偏好森林和森林边缘地带，通常隐匿于树荫之中。","identification":"与黄翼斑斗鹎相比，黄喉斗鹎体型较小，喉部黄色，具有更广泛、更显眼的黄色眉纹。","protection":"IUCN：LC（无危）","distribution":"分布于喀麦隆至刚果民主共和国东北部和南部至安哥拉北部，具体包括喀麦隆、中非共和国、刚果共和国、刚果民主共和国、赤道几内亚、加蓬和乌干达。"},{"name":"文须雀","english_name":"Bearded Reedling","scientific_name":"Panurus biarmicus","overview":"文须雀（英文名：Bearded Reedling，学名：Panurus biarmicus），是雀形目文须雀科文须雀属的鸟类。属于文须雀科，广泛分布于欧亚大陆的温带地区。在夏季主要以昆虫为食，冬季则转向种子，是繁殖能力极强的物种。雄鸟具有独特的蓝色头部和黑色“胡须”，而雌鸟则颜色较淡，缺乏明显的黑须。","appearance":"文须雀体长14.5-17厘米，尾长显著，羽毛主要为橙棕色，喉部和胸部为白色，翼部有黑白对比的斑纹，尾羽边缘白色。雄鸟头部灰蓝，有黑色“胡须”和黑色尾下覆羽；雌鸟头部偏棕色，无黑须或尾下覆羽，但有时可见黑色条纹或斑点。幼鸟色彩更淡，背部有黑色斑块，尾羽基部黑色。","call":"文须雀的鸣叫声独特，包括清脆的“ping ping”或“tschin tschin”声，用于同伴间的联系，以及金属质感的‘tschin-schik-schra’鸣唱。","habits":"文须雀栖息于广阔的芦苇床及附近密集的非木本植被，如Phragmites芦苇，偏好新鲜或微咸水域旁的沼泽和湖泊。它们在夏季以昆虫为食，冬季转而摄取种子。飞行快速，行动敏捷，常在芦苇丛间跳跃或攀爬。","breeding":"繁殖期为4月至7月，巢建于芦苇或灌木底部，呈深杯状，由干芦苇茎和叶片构成。每窝产卵5-6枚，孵化期12-13天，雌雄共同育雏，每年繁殖2-3窝。","identification":"文须雀最显著的辨识特征是雄鸟的蓝色头部和黑色“胡须”。与之类似物种的区别在于其独特的色彩和鸣叫声。","protection":"IUCN：LC（无危）","distribution":"文须雀分布于欧洲和亚洲的温带区域，从西班牙、法国和英国延伸至远东的Manchuria地区，近年来在北欧的分布有所扩展。","other":"文须雀的种群数量受冬季严寒影响较大，但在适宜条件下繁殖力强，能够迅速恢复。"},{"name":"拟戴胜百灵","english_name":"Greater Hoopoe-Lark","scientific_name":"Alaemon alaudipes","overview":"拟戴胜百灵（英文名：Greater Hoopoe-Lark，学名：Alaemon alaudipes），是雀形目百灵科拟戴胜百灵属的鸟类。独特的大型沙漠鸣禽。其特征为长而向下弯曲的喙，沙色的羽毛上带有斑点，飞行时露出醒目的黑白翼纹。分布于从摩洛哥到巴基斯坦的广大沙漠和半沙漠地区。","appearance":"拟戴胜百灵体长19至23厘米，喙长3至3.5厘米，雄鸟体重39至51克，雌鸟体重30至39克。身体修长，腿长，喙细长而向下弯曲，端部尖锐。上体沙色或灰褐色，头部有明显的图案，眼上有一条奶油色眉纹，眼睛下方有长长的黑色眼纹，颊部有黑色须纹。上背沙色或淡褐色，前额、头顶中央、颈后及头侧灰色。初级飞羽黑色，基部白色，末端白色（除最外侧），次级飞羽白色，有宽大的黑色中央带，形成黑白相间的翼纹。尾巴黑色，中央尾羽棕色，边缘淡色，外侧尾羽主要白色。胸部奶油色，有黑色小斑点，其余下体奶油白色。眼睛深棕色，喙暗灰色，腿和脚浅灰色。存在较为罕见的灰色变型，上体均匀灰色。幼鸟类似成鸟，但头部图案不那么明显，上体羽毛边缘和顶端呈淡黄色，外侧初级飞羽更长。不同亚种在体型和羽毛颜色上有所差异。","call":"拟戴胜百灵的鸣唱是一系列均匀、悠扬而略带忧郁的哨音，起初缓慢，随着鸟儿攀升加速，达到顶点时有一短促的颤音，随后是一连串的笛音，速度和音调逐渐下降。鸣唱持续约12秒，间隔5秒后可能重复。","habits":"拟戴胜百灵栖息于沙漠或半沙漠地带，偏好开放平原或起伏地形，沙质土壤和稀疏植被覆盖的环境。以昆虫为主食，偶尔吃小型脊椎动物、种子和绿色植物。单独或成对出现，有时会组成小群体。挖掘沙土或软土寻找食物，深度可达5厘米。不需要饮用水。","breeding":"繁殖季节随地理位置和降雨模式变化，通常在雨季之后。一季中可能会有1至2窝。雄鸟的求偶飞行极具特技性，通常从灌木顶部起飞，翅膀拍打，尾巴展开，陡峭上升至2至5米高度，然后翻转，经常做空翻，再俯冲回原处。雌鸟筑巢，由小枝构成，内部铺垫柔软材料，直径7至8厘米，通常位于低矮灌木或草丛顶部，较少见于地面。每窝产卵2至4枚，孵化期14天，由雌鸟或双亲共同承担。雏鸟期12至13天，幼鸟至少一个月内与父母同住。","identification":"拟戴胜百灵与其他鸟类的区别在于其长而弯曲的喙，沙色斑点的羽毛，以及飞行时显现的黑白翼纹。雌雄之间可通过标记的细微差别来区分。","protection":"IUCN：LC（无危）","distribution":"广泛分布于北非至中东，包括摩洛哥至巴基斯坦，以及阿拉伯半岛、叙利亚、阿富汗、巴基斯坦和印度的部分地区。"},{"name":"小拟戴胜百灵","english_name":"Lesser Hoopoe-Lark","scientific_name":"Alaemon hamertoni","overview":"小拟戴胜百灵（英文名：Lesser Hoopoe-Lark，学名：Alaemon hamertoni），是雀形目百灵科拟戴胜百灵属的小型鸣禽。该鸟种为索马里的特有种，主要栖息于干旱的低地草原，上体呈麻褐色，带有暗色斑纹，双翼红棕色，尾巴长且颜色为黑棕相间。其独特的外形和分布区域使其成为研究者关注的对象。","appearance":"小拟戴胜百灵体长约17至21厘米，外形纤长，全身羽毛均匀一致，上体麻褐色，有暗色斑点。脸部除了一条淡色的眉纹外，其余部分几乎无斑纹。双翼红棕色，带黑色翎羽，尾巴长，颜色为黑棕相间。眼睛深棕色，嘴巴细长且略弯，鼻孔上方有羽毛覆盖。翅膀尖长，尾部较短，跗跖后缘钝，有盾状鳞，后爪长而直。雌雄羽毛相似，雌鸟体型平均较小。幼鸟特征未知，不同亚种在上体颜色上有所差异。","call":"鸣叫声未详细描述。","habits":"小拟戴胜百灵居住在干燥的干旱台地及高原草地，半沙漠或有稀疏植被的沙漠区域，偏好岩石地形。它们擅长地面行走，飞行时会作柔和的波状运动，鸣唱时或在空中振翅缓慢垂直下降。它们在地上寻找昆虫和种子作为食物，主要食物包括草籽、嫩芽以及昆虫如蚱蜢和蝗虫。","breeding":"雄鸟在求偶时会在空中鸣唱或在高空拍打翅膀。巢穴建在地面凹陷处或草丛中，形似杯状，通常位于沙质地形上。巢的外缘用小卵石或沙子加固，内部铺有杂草草叶和细蒿秆。每窝产卵4-5枚，卵呈近黄白色，表面光滑并带有褐色细斑，大小约23毫米×18毫米。孵化期为11至12天，由双亲轮流孵化。雏鸟出生时赤身裸体，仅某些部位有绒羽，7天后睁开眼睛。幼鸟在8天后离巢，14或15天后能飞行，期间双亲共同喂食昆虫幼虫。","identification":"与拟戴胜百灵相比，小拟戴胜百灵体型更小，脸部和翅膀无明显斑纹，缺乏黑白相间的翼部图案。与Mirafra somalica相比，其羽毛颜色更单一，整体色调更淡。不同亚种在上体颜色上有所不同，tertius亚种更偏红棕，而alter亚种色调更暖，为浅沙棕色。","protection":"IUCN状态未提供。","distribution":"小拟戴胜百灵分布于非洲的索马里北部和东部，特别是在繁殖区域内。"},{"name":"比氏直爪百灵","english_name":"Beesley's Lark","scientific_name":"Chersomanes beesleyi","overview":"比氏直爪百灵（英文名：Beesley's Lark，学名：Chersomanes beesleyi），是雀形目百灵科钉踝百灵属的小型鸟类，体长约11厘米，雄鸟重约27克，雌鸟约22克。以其独特的纤细弯曲喙、直立姿态、长而直的后爪以及白色尾尖为显著特征。雄鸟头部具白色眉纹和眼圈，耳羽淡红褐色，上体深棕色，边缘色浅，类似当地土壤颜色，与Pseudalaemon fremantlii和Calandrella somalica地方种群相似。雌鸟腹部更富红褐色，胸斑更大胆。幼鸟上体边缘色更窄，胸斑更大且更散。分布于坦桑尼亚东北部，栖息于无树或灌木的短草平原。","appearance":"雄性比氏直爪百灵具有白色眉纹和眼圈，淡红褐色耳羽，上体深棕色，边缘色浅，与当地土壤颜色匹配，下体浅红褐色，胸部有深棕色条纹。雌鸟腹部红褐色较浓，胸斑较大，数量较少。幼鸟上体边缘色较窄，胸斑较大且更散。其喙纤细弯曲，尾短带白色尖端，后爪长且直，站立时呈直立姿态。","call":"发出略带鼻音的高音叽喳声，与直爪百灵类似，喂食雏鸟时成鸟会发出弹性的啾啾声。","habits":"比氏直爪百灵居住在坦桑尼亚东北部，栖息于海拔1400至1550米的短草平原，偏好无树木或灌木覆盖、草丛间有足够的空间、地面覆盖率约50%的环境，避开石质区域。全年以成对或小群体出现，偶尔形成多达十只的小群。食物以鞘翅目的象鼻虫、暗黑甲虫和叶甲为主，还包括毛虫、大型蜈蚣和种子。雏鸟被喂以毛虫。","breeding":"繁殖期在雨季期间，主要在10月至12月和3月至4月。至少由两位成鸟喂养雏鸟，巢为地面的浅杯状，内部铺有干草和牛粪，一窝产两枚蛋，关于孵化和离巢期的信息未知。","identification":"与直爪百灵相比，比氏直爪百灵的胸部条纹更重，体型较小，翼长平均短10%，雌鸟腹部红褐色更浓，胸斑更大胆。幼鸟上体边缘色较窄，胸斑更大且更散。","protection":"IUCN：CR（极危）。全球受威胁物种，整个世界种群仅限于两个小于10平方公里的小区域，位于阿鲁沙以北30至50公里处，这两个区域均未受保护。由于栖息地面积小且土地使用变化可能带来灾难性影响，其具体状况目前未被BirdLife International认可。","distribution":"分布于非洲坦桑尼亚东北部，集中在阿鲁沙以北的两个小区域。","other":"比氏直爪百灵曾被认为是直爪百灵的一个亚种，但现在被确认为独立物种。"},{"name":"直爪百灵","english_name":"Spike-heeled Lark","scientific_name":"Chersomanes albofasciata","overview":"直爪百灵（英文名：Spike-heeled Lark，学名：Chersomanes albofasciata），是雀形目百灵科钉踝百灵属的鸟类。小型鸣禽，广泛分布于非洲南部和西南部的干燥地带。其特征为头部具羽冠，棕色与黑色相间的鳞纹，白色喉咙和眼圈，下体白色，嘴尖细而呈圆锥状，略带弯曲，后爪异常长且直。","appearance":"直爪百灵体型约13至14厘米，体重在23至34克之间，雌雄羽毛相似，但雌鸟平均较小。其特征包括站立时的直立姿态，纤细的下弯喙，以及带有显著白色尖端的短尾巴。成鸟头顶有淡色眉纹和眼圈，耳覆羽红棕色，上体红棕色有黑纹，颈背颜色较深或偏灰。翅膀深棕色，边缘泛黄；尾部深棕色，除中央尾羽外普遍有宽白尖。下体自喉部至腹部白色，与浅红棕色至肉桂色的胸腹形成对比。幼鸟的羽冠和背部有白色尖端，翼覆羽有白色边缘，胸部暗斑不明显。不同亚种在羽毛色泽上差异显著。","call":"直爪百灵的典型叫声为干涩的颤音，'trrri-trrri-trrri-trrr'，类似矶鹬的叫声，用于群体成员间的联系和领地宣告。群体对这种叫声的播放反应强烈，有时会发出近乎歇斯底里的合唱。","habits":"栖息于多种开阔生境，包括山地草原、干旱的卡鲁灌木丛和半沙漠及沙漠平原。常见于哺乳动物洞穴附近，也可见于纳米比亚的Etosha盐沼和博茨瓦纳的Makgadikgadi盐沼边缘。主要食物为昆虫，包括白蚁、甲虫、蚂蚁、蛾子和蛛形纲动物，也会摄食部分种子。通常以3至10个个体组成的群体活动，其中一只常站在小灌木或白蚁丘上担任哨兵，其余成员觅食。遇威胁时，会躲入哺乳动物的洞穴中避难。","breeding":"繁殖期主要在7月至12月，但在干旱区雨后会刺激繁殖，几乎全年均可发生。在纳米比亚，繁殖期通常为2月至4月。巢建于地面凹处，通常位于灌木基部或草丛中，内衬干草、茎和根须。巢边有时装饰有砂岩蜘蛛网。每窝产卵2至3枚，孵化期12至13天，雏鸟由双亲喂养，约在孵化后8至12天离巢，但不能飞行，仍需父母照料一段时间。","identification":"与其他百灵科鸟类相比，直爪百灵的后爪特别长且直，是重要的辨识特征。不同亚种在羽毛色彩和条纹上存在差异，例如alticola亚种上体颜色更深，macdonaldi亚种上体偏灰，而kalahariae亚种整体颜色更浅。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲南部和西南部，包括纳米比亚、博茨瓦纳、南非等地的干旱和半干旱地区。","other":"直爪百灵的巢有时受到小型哺乳动物，尤其是獴的捕食，导致繁殖成功率较低。"},{"name":"格氏漠百灵","english_name":"Gray's Lark","scientific_name":"Ammomanopsis grayi","overview":"格氏漠百灵（英文名：Gray's Lark，学名：Ammomanopsis grayi），是雀形目百灵科格氏漠百灵属的鸟类。小型鸣禽，以其沙漠拟态著称，主要分布在非洲西南部的热沙漠地带。身体颜色与环境融合，呈现沙黄色，带有深棕色斑纹。","appearance":"格氏漠百灵具有紧凑的体型，长度约14厘米，体重介于17至27克之间。上体和翅膀呈淡沙黄色，带有深棕色斑点，下体为浅灰白色。嘴部为铁灰色，较为粗壮且呈圆锥状。其特征性的短喙和暗色尾羽边缘带白色，使其在飞行中易于识别。幼鸟的羽毛边缘更显淡色，胸部轻微斑驳。","call":"格氏漠百灵的鸣唱在黎明前或黄昏后最为频繁，声音为一系列奇怪而高亢的短叫声和上升的哨音，如“tink tink tink wheeeeeer tink tink”，还伴有各种上升调的短哨音。","habits":"格氏漠百灵栖息于干燥的草原、半沙漠或仅有零星植被的沙漠区域。它们通常在地面上寻找食物，包括草籽、嫩芽、昆虫如蚱蜢和蝗虫。在极端天气下，它们会躲入鼠洞避暑或站在岩石上散热。","breeding":"格氏漠百灵的繁殖行为包括雄鸟在空中鸣唱求偶，雌鸟选择雄鸟搭建的杯形巢穴。巢穴通常建在柔软的沙质地形上，由小石头加固，内部铺垫草叶和细蒿秆。每窝产卵2-3枚，孵化期大约11-12天，雏鸟出生后7天睁开眼睛，由双亲共同喂养，主要喂食昆虫幼虫。","identification":"格氏漠百灵与斯氏沙百灵和雌性灰背雀百灵相比，羽毛更为单一，与特拉岩䳭的沙漠亚种的区别在于喙部更厚重，腿更短，姿态和步态完全不同。","protection":"IUCN：LC（无危）","distribution":"格氏漠百灵主要分布在非洲西南部，包括纳米比亚、南非、博茨瓦纳和安哥拉的部分地区。","other":"格氏漠百灵属于雀形目百灵科，曾被归类于Ammomanes属，2009年被重新分类至Ammomanopsis属，该属目前仅包含这一物种。"},{"name":"短爪歌百灵","english_name":"Short-clawed Lark","scientific_name":"Certhilauda chuana","overview":"短爪歌百灵（英文名：Short-clawed Lark，学名：Certhilauda chuana），是雀形目百灵科长嘴百灵属的鸟类。体型中等、修长，特征为细长的喙、醒目的白色眉纹和暖色调与深色斑点交织的背部。常见于非洲南部的博茨瓦纳和南非，偏好干燥的荆棘稀树草原，尤其是草丛短小、开放的牧场。","appearance":"短爪歌百灵长约17至19厘米，体重约44克，雄鸟体型明显大于雌鸟。拥有鲜明的浅色眉纹，上体羽毛为深黑褐色，边缘宽阔的淡黄色，颈后颜色较淡；喉咙白色，其余下体部分为淡奶油色，胸部颜色较深，有时带有暗褐色条纹；眼睛呈棕色，喙为暗角褐色，腿色为暗粉色。","call":"雄鸟在飞行表演中发出单个上升的哨音‘poooeeee’，还有一系列1至3个响亮的简单哨音，通常音调逐渐下降，‘wheoo wheooo’。此外，它还会发出一系列粗糙和较为刺耳的联系叫声。","habits":"栖息于干旱的金合欢（Acacia）稀树草原，偏好有较短、稀疏草被和散生矮小金合欢的地方，尤其是近期休耕土地和过度放牧区。食物主要包括多种昆虫，如蚱蜢、甲虫、毛虫、白蚁和蚂蚁，以及种子；雏鸟以昆虫和其他无脊椎动物喂养。在地面上觅食，偶尔也会在低矮植被中寻找昆虫。","breeding":"繁殖季节，雄鸟会在空中鸣唱或拍打翅膀求偶。巢穴建在地面凹陷处或草丛中，由杂草和细枝构成，表面多有杂草遮盖。每次产卵2至3枚，孵化期约为15天，这是非洲所有百灵物种中最长的。雏鸟出生后，与父母共同生活6至8周。","identification":"与同属其他种类相比，短爪歌百灵上体斑点更加醒目。它比Mirafra afranica更为修长，没有锈色翼斑和冠羽。与较小的萨博塔歌百灵相比，它更紧凑，面部标记更为大胆。","protection":"IUCN：LC（无危）。在博茨瓦纳常见，但在南非数量较少，被列入该国‘近危’红色名录。总数量估计超过10,000只，仅在博茨瓦纳东南部可能就有如此之多。然而，只有130至300只生活在保护区。农业实践的变化可能对其造成威胁。","distribution":"分布于博茨瓦纳东南部和南非北部及东北部，包括相邻的西北省和林波波省。在Polokwane高原有孤立群体。在半干旱Tarchonanthus稀树草原也有分布，但密度较低。","other":"短爪歌百灵的分类曾多次调整，最初归类于Alauda，后移至Mirafra，最终被重新分类到Calendulauda。"},{"name":"卡鲁歌百灵","english_name":"Karoo Long-billed Lark","scientific_name":"Certhilauda subcoronata","overview":"卡鲁歌百灵（英文名：Karoo Long-billed Lark，学名：Certhilauda subcoronata），是雀形目百灵科长嘴百灵属的小型鸣禽。长嘴百灵复合体中分布最广的一种，常见于南非西部和南部、纳米比亚大部及安哥拉西南部干旱的石质灌丛与矮灌草原。其羽色较浅、暗纹稀疏，上体沙红褐色、下体以白为主，胸具褐斑。全年雄鸟持续鸣唱，通常被视为留鸟，但南部卡鲁地区会出现数量波动。","appearance":"中等体型，体长18–22厘米，体重31–55克。雄鸟比雌鸟大12–14%，喙长28%。上体整体暗红褐色，羽轴纹深褐；颈背浅灰、几无纵纹，与头顶及背部形成明显对比。眉纹及眼圈白色，耳羽白而具细红褐斑。下体白色，胸具细密褐色纵斑，并略延至胁部。翼及尾深褐色，外侧尾羽具淡色边缘。幼鸟上体羽端浅黄褐，胸部斑点更弥散。","call":"雄鸟全年鸣唱，繁殖前期尤甚。鸣声为响亮而传远的单音下降哨音“peeooo”或“peeeuuuuu”，长0.8–1.2秒，起始频率3.5–4 kHz下降1.5–2.5 kHz，近处可闻吸气前奏“whi-peeoooo”。另有断续滚音“rreeeuw”，可单独或成串发出。求偶展示时，雄鸟自地面或低栖起飞，垂直爬升至10–15 m后悬停鸣唱，再垂直俯冲降落。","habits":"栖息于海拔数百米的干旱及半干旱环境：石质平原、岩质山脊、矮灌草原与灌丛，偏好碎石或黏土，避开沙地。主要在地面活动，以行走方式觅食，常于植株基部、石块下或松土中用略向下弯的强壮喙部挖掘。食物以昆虫、蜘蛛等无脊椎动物为主，兼食多种植物种子、果实及小块球茎。不主动饮水，可能从食物中获取水分。","breeding":"繁殖期随雨季变化：西南部8–10月，中部卡鲁10–12月，北部纳米比亚1–4月。单配制，领域性。巢筑于灌丛、草丛或岩石基部浅凹处，由雄鸟以细枝、根须编织成开口杯状，内衬柔絮种子，偶见植被拱顶。每窝2–3枚卵，卵乳白具红褐和紫褐色粗斑，23×16 毫米。孵化期未知，双亲轮流觅食喂雏，离巢后幼鸟仍随亲鸟数周。","identification":"与同属长嘴百灵复合体成员重叠分布：比长嘴歌百灵稍小，上体更红褐，颈背灰对比明显，下体斑纹稀疏；较阿古歌百灵体型大、尾长、喙长；与半颈环歌百灵相比，体型更大、喙更长、上体斑纹更重，颈背呈灰与上体形成对比。各亚种间差异在于体型、色度及斑纹深浅。","protection":"IUCN: LC（无危）。","distribution":"繁殖区：西南安哥拉沿海、纳米比亚大部（北起Kaokoveld南至Richtersveld）、南非西北部及西部（北至Kenhardt，南至南部卡鲁）。非繁殖区：全年留居，未见迁徙，但南部卡鲁有局部数量波动。","other":"曾被归入“长嘴百灵”单一物种，现依据遗传、形态及鸣声差异拆分为多个独立种。本种分benguelensis与subcoronata两大亚种组，二者形态相似但遗传差异显著，有研究主张再次分种。"},{"name":"本格拉歌百灵","english_name":"Benguela Long-billed Lark","scientific_name":"Certhilauda benguelensis","overview":"本格拉歌百灵（英文名：Benguela Long-billed Lark，学名：Certhilauda benguelensis），是雀形目百灵科长嘴百灵属的鸟类。这种中型鸣禽体长18-20厘米，头部棕色，喉部白色，拥有黑色的喙，背部呈褐色，腿部为桃红色，眼睛棕色。其自然生境为南部非洲的干旱台地及高原草地。","appearance":"本格拉歌百灵体长18至20厘米，雄鸟体型比雌鸟平均大12-14%，喙长28%。羽毛颜色偏灰棕色，背部有深色条纹，腹部白色，胸部长有暗棕色斑点和条纹。头部有羽冠，喙尖细而圆锥状，鼻孔有悬羽遮盖，翅膀尖长，尾短于翅，跗跖后缘钝，有盾状鳞，后爪长且直。两性羽毛相似，幼鸟胸部斑点更扩散，上体羽端淡色。","call":"雄鸟的歌声为略带颤音的下降哨声'peeooo'，类似同属其他物种，但音调变化可能较小。此外，还会发出模糊的接触叫声。","habits":"生活在南部非洲干旱的石质山坡和平原，偏好稍密的灌木区。饮食包括甲虫和其他昆虫，以及种子。单独或小群活动，善于地面行走，或振翼作波状飞行。在地面、飞行中或空中振翅同时缓慢垂直下降时鸣唱。在高地上鸣叫频繁，声音尖细优美，集群寻找昆虫和种子。","breeding":"雄鸟在空中鸣唱或在高空拍打翅膀求偶。巢建在地面凹处或草丛中，由杂草、草叶和细蒿杆构成，表面有杂草遮蔽。每年5-6月间产卵，每窝通常产2-5枚卵，卵呈白色或近黄色，表面有褐色细斑，大小约23毫米×18毫米。孵化期约15天，雏鸟出壳时赤身裸体，仅部分部位有绒羽，7天后睁开双眼。","identification":"本格拉歌百灵与Karoo长嘴百灵相比，体型较小，上体颜色可能更浅。Kaokoensis亚种体型更小，上体颜色可能更浅。辨识主要依据大小、颜色以及地理分布。","protection":"IUCN：LC（无危）。在当地适宜的生境中常见，是西南安哥拉干旱沿海平原上最普遍的陆地鸟类之一。正式保护区中有大量种群。","distribution":"分布于非洲的西南部，具体为安哥拉的西南部和纳米比亚的西北部。","other":"现为卡鲁歌百灵亚种。"},{"name":"半颈环歌百灵","english_name":"Eastern Long-billed Lark","scientific_name":"Certhilauda semitorquata","overview":"半颈环歌百灵（英文名：Eastern Long-billed Lark，学名：Certhilauda semitorquata），是雀形目百灵科长嘴百灵属的鸟类。中等体型、修长的鸣禽，拥有细长的喙和长腿，上体呈红棕色，带有黑褐色条纹，下体淡色且轻微条纹。主要分布在非洲东南部的亚热带或热带干燥低地草原。","appearance":"体长16-20厘米，体重30-48克。上体红棕色，有黑褐色条纹；眼眉宽且乳白色，脸颊带斑点，耳羽白色；尾巴和飞羽有略浅的黑褐色；喉咙白色，胸部光泽浅黄色，淡红褐色斑纹；眼睛浅灰褐色，嘴尖细而长，稍弯曲，鼻孔有悬羽遮盖；翅膀尖长，尾较翅短，跗跖后缘钝，盾状鳞，后爪长直。","call":"雄鸟全年歌唱，从喜爱的岩石或在空中展示时发出简单的下降音调‘peeoooo’，缺乏开唱前的吸气声，还会发出模糊的接触叫声。","habits":"栖息于干燥的南部非洲的干旱台地及高原草地，通常在岩石地形附近。单独或分散群居，常于地面行走或振翼作柔弱的波状飞行，于地面或空中缓慢垂直下降时鸣唱。集群在地面上寻找昆虫和种子。","breeding":"雄鸟在空中鸣唱或高空拍动翅膀求偶。巢建于地面凹处或草丛中，由杂草和细蒿秆构成，表面多有杂草掩蔽。每窝产卵2-5枚，卵白色或近黄色，具褐色细斑，大小约23毫米×18毫米，孵化期约15天。","identification":"与相似的长嘴百灵相比，本种较小，背部和胸部条纹更轻，喙最短。与其他同域的百灵相比，本种更大；可能与鹬类混淆，但其红棕色上体和缺乏白色外侧尾羽排除了这一可能性。","protection":"IUCN状态未知","distribution":"主要分布于非洲东南部，包括南非的部分地区。","other":"曾被认为是长嘴歌百灵的一个亚种，但现被视为独立物种。"},{"name":"长嘴歌百灵","english_name":"Cape Long-billed Lark","scientific_name":"Certhilauda curvirostris","overview":"长嘴歌百灵（英文名：Cape Long-billed Lark，学名：Certhilauda curvirostris），是雀形目百灵科长嘴百灵属的鸣禽。南非西开普省沿海及其邻近地区几乎特有的百灵，仅稍向西南纳米比亚延伸。其最显著的特征是极长而明显下弯的喙，羽色平淡，上体灰褐并具深色纵纹，下体白而胸密布褐色纵纹。现代分类将其分为两个亚种群（falcirostris/curvirostris 与 brevirostris），后者在部分文献中被视为独立种“阿古拉斯长嘴歌百灵”。该鸟对短灌丛、稀疏沙丘及休耕地等生境适应良好，整体数量尚稳定。","appearance":"成鸟全长约20–24厘米（brevirostris 亚种18–21厘米），为南非体型最大的百灵。具极长而下弯的喙（雄鸟平均30.7 毫米，雌鸟25.7 毫米；在 brevirostris 亚种则更短），长尾、长脚。上体灰褐至淡褐，各羽具暗褐色中央轴纹；翼及尾羽褐色。眉纹及眼圈淡色，颊及耳羽微具斑点；喉白，胸具大型泪滴状深褐纵纹，下腹及两胁具较窄纵纹。两性同色，唯雄鸟体型明显较大。幼鸟上体羽缘淡黄褐，胸斑纹较模糊。","call":"雄鸟鸣唱为双音节哨音：首音短而弱，次音长而响亮，如“tsweee peeuuu”或“whi-peeeooo”。brevirostris 亚种鸣唱持续约1.2 s，间隔8–15 s重复；falcirostris 亚种北部种群则单音下降哨音“peeeoooo”。展示时雄鸟先贴地飞行，再垂直上升10–15 m后停翅俯冲，在顶点鸣唱。另有低沉滚动的联络叫声“irrr-errr”等。全年可闻唱，但繁殖前冬末春初最盛。","habits":"留鸟，不迁徙。栖息于海岸矮灌丛（strandveld、renosterveld）、沙丘稀疏植被、休耕地及新近耕作地；在作物高密区仅见于田边。主要步行觅食，翻动石块、挖掘沙土或拉拽植被，以甲虫、毛虫等昆虫为主，偶尔食少量种子。领域性强，常年成对活动，偶见家族群。","breeding":"繁殖资料匮乏。产卵期：curvirostris 亚种8–10月，brevirostris 亚种9–10月；雏鸟10–11月离巢。巢置于地面草丛、石块或矮灌木旁，为干草构成的杯状或半穹顶状结构，内衬细草根。每窝2–3枚卵，卵色乳白或粉白，具黄褐至灰褐色斑点。孵化期及育雏细节未知。","identification":"与卡鲁歌百灵相比，上体冷灰褐而非红褐，下体更白且纵纹延至两胁；brevirostris 亚种体型更小，喙更短，羽色更淡，纵纹更均匀。亚种间：brevirostris 最小且羽色偏淡褐，falcirostris 与 curvirostris 较大，后者上体更褐、尾更长。","protection":"IUCN: LC（无危）。brevirostris 亚种曾被评估为近危，但因重新归入本种而暂无单独评估。整体分布虽受农业与采矿影响，但种群仍常见且局部适应农田环境，估算 brevirostris 亚种有20–37万只。","distribution":"繁殖区：南非西开普省沿海平原，自西南纳米比亚极南端向南延伸至好望角附近；breirostris 亚种分布于阿古拉斯平原（Bot River 至 Mossel Bay 并沿 Breede 河谷向北至 Worcester 一带）。无明确非繁殖区分化。","other":"分子研究显示本种与半颈环歌百灵亲缘关系密切，二者在 Breede 河谷有接触。系统分类上，长嘴百灵复合群曾被视作单种，现依遗传与形态差异拆分为多个种。"},{"name":"阿古歌百灵","english_name":"Agulhas Long-billed Lark","scientific_name":"Certhilauda brevirostris","overview":"阿古歌百灵（英文名：Agulhas Long-billed Lark，学名：Certhilauda brevirostris），是雀形目百灵科长嘴百灵属的鸟类。小型鸣禽，主要分布在南非西部开普省的阿古拉斯平原和布雷德山谷，栖息于被改造为小麦田和牧场的土地上，仅30%的原始栖息地保留了沿海灌木和卡鲁灌木丛。该物种适应了人类改造的环境，如农田。","appearance":"阿古歌百灵体长18至20厘米，长尾，拥有略带弯曲的长嘴。头部和背部呈条纹状的淡黄灰色，闭合的翅膀呈灰色，下体为奶油色，胸部和侧翼带有深色条纹。其特征还包括尖细的圆锥状嘴，翅膀尖长，尾巴比翅膀短，后爪长且直。","call":"雄鸟的展示歌唱是一连串的双音节哨声，通常从黎明到上午晚些时候演唱，全年皆可听到。此外，还发出模糊的接触叫声。","habits":"栖息于广阔草原，善于地面行走和振翼做柔弱的波状飞行。在地面或空中振翼时鸣唱。常在干旱的台地及高原草地活动，单个或形成分散的小群。以种子和昆虫为食，尤其在繁殖季节会大量捕食昆虫。","breeding":"雄鸟在空中鸣唱或在高空拍动翅膀求偶。巢建于地面凹处或草丛中，由杂草和细蒿秆构成，表面多有杂草遮掩。每窝产卵2至5枚，卵白色或浅黄色，表面光滑具褐色细斑，孵化期约15天。","identification":"与长嘴歌百灵的区别在于体型更小，嘴和尾巴更短，颜色更偏向淡黄色。","protection":"IUCN：LC（无危）","distribution":"阿古歌百灵主要分布在南非南部，具体为阿古拉斯平原和布雷德山谷，从霍顿特-荷兰山脉以东到莫斯塞尔湾。","other":"曾被视为长嘴歌百灵的亚种，但在1990年和1993年被提升为独立物种。然而，2017年《世界鸟类手册》将其重新归类于长嘴歌百灵之下，Clements分类系统也采取了同样的做法。但 Avilist 为长嘴歌百灵亚种。"},{"name":"黑歌百灵","english_name":"Dusky Lark","scientific_name":"Pinarocorys nigricans","overview":"黑歌百灵（英文名：Dusky Lark，学名：Pinarocorys nigricans），是雀形目百灵科黑歌百灵属的小型鸣禽。其特征为上体、前胸及双翼深褐色，腹部灰黄色，拥有一圈灰白色围脖和白色眼眉。黑歌百灵分布于非洲中部和南部，是季节性迁徙物种。","appearance":"黑歌百灵长约19至20厘米，雄鸟体重30至46克，雌鸟31至41克。体态修长，似鸫的百灵，拥有显著的面部图案，上体非常暗，胸部有大胆条纹。雄鸟有白色眉线、眼周、脸颊、颈侧、髭纹，深色眼纹、耳羽、颊线和颊部条纹；头顶和上体黑褐色，新羽期翼羽边缘明显；下体白色，胸部有深褐色大胆条纹；眼睛深棕色；喙暗角质色，下颚基部淡黄色角质色；腿白色。雌鸟与雄鸟的区别在于面部图案不那么鲜明，上体颜色较浅，下体偏棕（而非白色），胸部条纹颜色较浅。幼鸟上体更偏棕色，背部和翼羽边缘为棕黄色，下体带有较淡的条纹。occidentis亚种与指名亚种的区别在于胸部条纹较淡，下方显得更苍白。","habits":"黑歌百灵在干燥的草地和灌木覆盖的平原及矮山中生活，常于地面行走或进行柔和的波状飞行。它在地面、飞行中或空中振翼同时缓慢垂直下降时鸣唱。高飞时直冲云霄，在地面也善于奔跑，受到惊扰时常隐藏不动。常站在高地或沙丘上连续鸣唱，声音尖细而悦耳。集群在地上寻找昆虫和种子，主要食物为草籽、嫩芽，偶尔捕食昆虫，如蚱蜢和蝗虫。","breeding":"雄鸟求偶时会在空中鸣唱或在高空拍打翅膀。巢建在地面凹陷处或草丛中，由杂草、草叶和细蒿秆构成，表面通常被杂草遮掩。巢呈杯状。5月至6月间产卵，每窝产卵数量大多为2至5枚。卵近黄白色，表面光滑，带有褐色细斑，大小约23毫米×18毫米。孵化期约为15天，雏鸟破壳而出后，全身赤裸，仅部分部位长有绒毛，7天后才能睁开双眼。","identification":"与非洲地鸫最为相似，但体型较小，翼羽有斑点，飞行时没有明显的淡色翼带。雌雄个体间面部图案的鲜明程度有所不同。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于非洲中部，包括赞比西河以北的中非地区。非繁殖季节，分布南至安哥拉南部，东至坦桑尼亚南部，以及纳米比亚中部、南非北部和东北部，以及莫桑比克南部。两个亚种在非繁殖地上共同存在。"},{"name":"棕腰歌百灵","english_name":"Rufous-rumped Lark","scientific_name":"Pinarocorys erythropygia","overview":"棕腰歌百灵（英文名：Rufous-rumped Lark，学名：Pinarocorys erythropygia），是雀形目百灵科黑歌百灵属的鸟类。显著特征为腰部一片红棕色，上体布满深褐色斑点，下体浅灰白色。分布于非洲西部和中部，从马里、几内亚和塞拉利昂至苏丹东部、苏丹南部和乌干达西北部。","appearance":"体型中等偏大，长约18厘米，重约30克，外观类似鸫鸟的百灵，拥有醒目的红棕色臀部和外侧尾羽。上体暗褐色，轻微鳞纹，下体苍白，胸部有浓重条纹，面部标记鲜明。雌鸟翼部更显红棕色，幼鸟上体颜色较淡，红棕色边缘更为柔和，下体泛黄色，条纹不明显。喙尖细呈圆锥状，翅膀略长，尾短于翅，腿粉白色。","call":"在空中展示时发出一系列笛音般的哨声，如‘tseoo tseoo’或‘tsit-tseoo tsit-tseoo’，偶尔伴有嗡嗡颤音，飞行时叫声为干涩的‘wree’。","habits":"栖息于开阔的落叶林地和稀树草原，非繁殖季节偏好更干旱的草原，如烧过的区域，吸引数百只聚集。成对或松散群落地面觅食昆虫和种子，迁徙期间会出现在萨赫勒和干旱草原地带，包括田野和开放耕作地。","breeding":"繁殖期为10月至翌年4月，雄鸟会在空中鸣唱求偶。巢建于地面凹陷处或草丛中，由草叶和细枝构成，掩藏良好。每窝产卵2-5枚，卵近黄白色，具褐色细斑，孵化期约15天。","identification":"与黑歌百灵相比，体型略小，红棕色臀部和尾羽突出，下体泛红棕色。雌鸟与雄鸟相似，但翼部红棕色更明显。幼鸟颜色较淡，红棕色边缘柔和。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括西几内亚和东塞拉利昂，东至南苏丹和乌干达西北部；迁徙至萨赫勒和干旱草原，从南马里向东至尼日尔北部、乍得北部和苏丹中部。","other":"最初分类在Alauda属，后被考虑归入Certhilauda和Mirafra属，现属Pinarocorys属。"},{"name":"厚嘴百灵","english_name":"Thick-billed Lark","scientific_name":"Ramphocoris clotbey","overview":"厚嘴百灵（英文名：Thick-billed Lark，学名：Ramphocoris clotbey），是雀形目百灵科厚嘴百灵属的鸟类。拥有显著的圆锥状厚喙，上体色彩与环境相融，胸带放射状黑斑，头顶带黑色斑点，喉部白色，眼部有白色边缘。体型小巧，长度约17厘米。分布于北非，自毛里塔尼亚和摩洛哥至利比亚，以及阿拉伯半岛中部。","appearance":"厚嘴百灵的体型短小，仅约17厘米。头部圆锥状的喙厚实粗壮，上体颜色为桃红色或灰棕色，与环境色调一致。胸部有显著的放射状大黑点，头顶略带黑色斑点，喉部呈现白色，眼睛周围有白色环边。雌鸟的羽毛颜色较为单一，斑纹不如雄鸟深邃。鼻孔上方有悬羽覆盖，翅膀尖长，尾部较短于翅，跗跖后缘较为钝厚，后爪长而直。雄鸟的外观比雌鸟更鲜明，头部黑色区域更为明显，下颌有白色斑块，冠部和背部粉红至浅黄褐色，翅膀上的黑色中心和粉棕色边缘形成对比，尾巴有黑色亚端带，下体淡黄色，强烈地斑点黑色，翅膀下白色宽边。","call":"厚嘴百灵的鸣叫包括一系列清脆的颤音和颤动的音符，有时描述为柔和而安静的金属声和颤音组合，或快速的推特音节。其叫声包括尖锐的“prit”，在飞行中常见，还有“coo-ee”，“co-ep”，“wick-wick”，“wheet-wheet-wheet”，“sree”，以及类似的叫声；报警时发出长而哀怨的哨声“tsu-ee”。","habits":"厚嘴百灵栖息于干燥的干旱台地及高原草地，半沙漠或有稀疏植被的沙漠区域，开阔的矮草地。它们偏好平坦或起伏的地形，尤其是石质或紧密土壤的地区，如哈马达地区。它们也会出现在瓦迪床地带。它们的生活区域从开放的斯蒂帕或莱杰姆草原到各种干旱地带，包括艾草灌木或肉质植物。厚嘴百灵通常单独或以小群活动，偶尔会组成多达50只的群体。它们在地面觅食，有时跳跃，拉下枝条寻找种子，甚至挖掘。主要以草籽、嫩芽、昆虫和绿色植物为食，可能不需要水，但在某些情况下会在水源附近发现群集。","breeding":"繁殖季节从2月至5月。雄鸟求偶时在空中鸣唱或在高空拍动翅膀。巢筑于地面的凹陷处或草丛中，巢的形状如同杯状，一般建在沙质地形上，巢的外缘由小卵石或沙子等围拢加固，内部由杂草、草叶和细蒿秆等构成。每次产卵3至5枚（平均4枚），雌鸟负责孵卵，双方共同喂养雏鸟。关于孵化期、雏鸟期和雏鸟离巢时间的具体信息尚不清楚。","identification":"厚嘴百灵与其他种类的百灵相比，最明显的特征是其巨大的喙，黑色面颊上的白色斑块，以及飞行时翅膀上的显著白色区域。雄鸟的羽毛比雌鸟更加鲜明，具有对比明显的黑斑和白色边缘。在鉴别时，可以观察其独特的喙形、面部标记、以及飞行中的翼白。","protection":"IUCN：LC（无危）","distribution":"厚嘴百灵分布于北非，从西撒哈拉、毛里塔尼亚南部、摩洛哥南部和东南部、阿尔及利亚西部和北部内陆、突尼斯中部和南部、利比亚西北部，到约旦中部和沙特阿拉伯北部；偶尔出现在以色列南部（1995年起有记录）、科威特（2002年首次记录繁殖），可能也在叙利亚南部有分布。在埃及、沙特阿拉伯中部和南部、科威特西部和邻近地区有罕见的冬季访客记录。在以色列南部、也门南部、阿曼和伊拉克有零星记录。"},{"name":"漠百灵","english_name":"Desert Lark","scientific_name":"Ammomanes deserti","overview":"漠百灵（英文名：Desert Lark，学名：Ammomanes deserti），是雀形目百灵科漠百灵属的鸟类。中型鸣禽，分布广泛，从摩洛哥至印度西部。其显著特征包括大头、长喙和适应沙漠环境的淡沙色体羽。","appearance":"漠百灵体型中等，长度约16至17厘米，头部相对较大，喙部厚实且略长，翼展宽广，尾部较短。上体呈淡粉色，下体为灰色，有明显的地理变异性。喙部颜色为浅棕色至黄色，腿脚为肉色至灰褐色或黄褐色。","call":"鸣唱时发出悠扬的颤音，如“trreooee”，声音清脆，可在地面或飞行中发出。叫声多样，包括觅食时的“chu”声和飞行中的“chee-lu”或“chee-wu”声。","habits":"居住在干旱的草原、半沙漠或岩石斜坡地带，避免平坦的沙地，偏好起伏地形。在地面或石头间觅食，饮食包括小种子和昆虫，雏鸟主要以昆虫喂养。能够通过岩石或硬面破碎硬食。","breeding":"繁殖期在北部分布区为3月至5月，南部分布区为2月至4月，索马里为4月至6月。每年繁殖1至2窝。雄鸟进行短暂的水平或垂直的求偶飞行。巢由双方共建，通常位于岩石旁或草丛中，用植物材料筑成，孵化期10至11天，雏鸟在9至11天后离巢。","identification":"与巴尾百灵相似，但喙部更大，尾部黑色带纹更模糊。上体颜色随亚种和生境变化，从淡色到深色，下体为淡粉色灰色，具有更多条纹。","protection":"IUCN：LC（无危）","distribution":"分布于非洲、欧亚大陆，从摩洛哥至印度西部，包括北部非洲、中南部非洲、西南亚洲、印度次大陆。","other":"已知有22个亚种，各亚种在色彩和大小上存在差异。"},{"name":"斑尾漠百灵","english_name":"Bar-tailed Lark","scientific_name":"Ammomanes cinctura","overview":"斑尾漠百灵（英文名：Bar-tailed Lark，学名：Ammomanes cinctura），是雀形目百灵科漠百灵属的小型鸣禽。主要分布在摩洛哥至巴基斯坦的广阔区域，常见于热沙漠地带。该鸟以其独特的肉桂色砂质地羽色和淡色的超眉线著称。","appearance":"斑尾漠百灵体长约14厘米，体重介于14至23克之间，体态小巧精致。头部相对较小且圆润，喙短，初级飞羽长，约等于次级飞羽的一半长度，外侧初级飞羽略长于覆羽，腿脚短且细。背部多呈红褐色，具有淡色的眉纹；翅膀和尾巴为橙红色，翅膀末端有黑色尖端，尾巴有明显的黑色终端带；腹部呈淡色，胸部带有橙色色调；喙呈沙粉色；腿脚颜色从沙色角质到浅棕色不等。幼鸟与成鸟相似，但尾巴和翅膀上的黑色标记较为模糊，外侧初级飞羽更宽且较长。","call":"斑尾漠百灵的鸣唱为一系列高音调的‘see-oo-lee’或‘cher-ho-hee’，起始音节音调较低，往往只有近距离才能听到，最后一音节高亢纯净且略带吱吱声，节奏规律，间隔约1.5秒。叫声包括干涩的‘prrit’或‘cherr’以及细长的下降音‘peeyu’或‘see-oo’。","habits":"斑尾漠百灵栖息于年降水量少于100毫米的沙漠地带，包括石质或沙质土壤的平坦或微起伏地形，植被覆盖稀疏或几乎无植被。在北非西部的撒哈拉沙漠，偏好石质黏土平原（砾石平原伴杂沙地）和草地，以及地形中的小洼地；在半干旱草原也很常见。通常生活在低地，但在巴基斯坦的繁殖季节后可能达到海拔1700米。它是留鸟，但在冬季会分散到较为湿润的地区，特别是在干旱时期；中东和阿拉伯半岛的短距离迁徙记录表明其有一定的游荡习性。偶尔会长距离分散，春季时在加那利群岛、西班牙地中海沿岸、意大利、马耳他和塞浦路斯等地有迷鸟记录。","breeding":"繁殖季节受降雨影响，北非地区为1月至4月，开普维尔德群岛为9月至6月，中东地区主要在3月中旬至4月中旬，有时会有二次繁殖。雄鸟的求偶飞行呈陡峭的波动状，飞行路径蜿蜒但大致圆形，以快速俯冲结束。巢由雌鸟建造，位于岩石下或石头旁的地面上，直径7至8厘米，朝向北方，内部铺垫有少量植被和小石子。每窝产卵2至4枚，孵化期12至14天，由双亲共同承担孵化任务；雏鸟由双方照料并喂食，大约11天后离巢，13至15天后羽翼丰满。","identification":"斑尾漠百灵与沙漠百灵非常相似，但其喙较小且更为精致。与沙漠百灵相比，斑尾漠百灵的体型略小，头部更圆，腿脚更细，尾巴末端有明显的黑色带纹。此外，斑尾漠百灵的叫声和鸣唱也有独特之处。","protection":"IUCN：LC（无危）","distribution":"斑尾漠百灵广泛分布于北非至西亚地区，包括摩洛哥至巴基斯坦的广大区域。在开普维尔德群岛、毛里塔尼亚、摩洛哥南部、突尼斯南部、西撒哈拉沿海地带、利比亚、埃及、以色列、约旦、沙特阿拉伯、巴勒斯坦、阿曼、苏丹、叙利亚、阿联酋、科威特、卡塔尔、巴林、伊拉克、伊朗、阿富汗、土耳其南部、也门北部均有记录。在部分区域如开普维尔德群岛的萨尔岛、博阿维斯塔岛和马约岛数量较多，而在其他地方如摩洛哥、突尼斯、沙特阿拉伯、巴勒斯坦、阿曼、苏丹、叙利亚、阿联酋、科威特、卡塔尔、巴林、伊拉克、伊朗、阿富汗、土耳其南部、也门北部则较为罕见或局部分布。","other":"斑尾漠百灵的种群数量正在逐渐减少，尽管其分布广泛且目前未面临明显威胁，但全球数量呈现下降趋势。"},{"name":"棕尾漠百灵","english_name":"Rufous-tailed Lark","scientific_name":"Ammomanes phoenicura","overview":"棕尾漠百灵（英文名：Rufous-tailed Lark，学名：Ammomanes phoenicura），是雀形目百灵科漠百灵属的鸟类。小型鸣禽，广泛分布在印度及巴基斯坦的部分地区。其最显著的特征是棕灰色的上体和前胸上的褐色斑纹，腹部沙黄色且无斑纹。鸟嘴粗壮呈圆锥状，翅膀尖长，尾部比翅短。生活在干燥的草原、半沙漠或植被稀疏的沙漠地带。","appearance":"棕尾漠百灵体型较小，上体呈棕灰色，布满褐色斑纹。前胸和翅膀同样带有这些斑点，而腹部以下为沙黄色，无斑纹。嘴部粗壮且圆锥状，鼻孔被悬羽覆盖。翅膀尖长，尾部相对较短，跗跖后缘钝，有盾状鳞片，后爪长且直。雌雄相似，但雌鸟平均比雄鸟小。幼鸟与成鸟相比，上体边缘略显淡色。","call":"鸣唱时发出悦耳的短哨音和清脆的颤音，通常在地面、低矮的栖木上或是低空飞行中鸣唱。叫声包括一系列简单的音符，如“juu, juuh, tchérrrwe”，有时混合短促的颤音乐节。最常见的是柔和的‘djup’叫声。","habits":"偏好干燥的开阔地带，常与其它物种如灰顶雀百灵一同出现。通常单独或成对活动，忙碌地在地面上觅食，也会栖息在高地或电线上。食物主要包括草籽、谷物和昆虫，如甲虫等。飞行时有起伏的特征。","breeding":"繁殖季节主要在2月至5月，雄鸟会在低空进行短暂的求偶飞行，伴有起伏的飞行路径和叫声。巢由两性共建，位于地面凹陷处，通常由泥土块、草丛或植物遮蔽，内衬细草，周围可能有鹅卵石或小树枝。一窝产2至4枚卵，孵化和育雏由双方参与，但具体孵化和离巢时间未有确切记录。","identification":"与同属其他物种的区别在于其特有的棕红色尾羽和尾部的暗色横带，以及明亮的喉部条纹。雄鸟在求偶展示中的飞行模式和叫声也助于辨识。","protection":"IUCN：LC（无危）；在南亚部分地区较为常见，但巴基斯坦境内的状况不确定，可能是季风雨季的不规则访客。尼泊尔南部的记录显示其非常罕见且局部分布，繁殖状态待确认。","distribution":"主要分布于印度南部，自恒河以南延伸至古吉拉特邦和拉贾斯坦邦的阿腊瓦利山脉。夏季访问巴基斯坦北部旁遮普省和尼泊尔南部。在斯里兰卡未见分布，仅有的报道未得到证实。印度西部喀拉拉邦的西部高止山脉地区几乎不存在。","other":"历史上，曾将斑尾漠百灵视为其亚种，但现在普遍认为两者是独立物种。存在两个公认的亚种，其中一个（testaceus）在印度半岛南部，色彩更为鲜艳。"},{"name":"黑耳雀百灵","english_name":"Black-eared Sparrow-Lark","scientific_name":"Eremopterix australis","overview":"黑耳雀百灵（英文名：Black-eared Sparrow-Lark，学名：Eremopterix australis），是雀形目百灵科雀百灵属的鸟类。小型鸣禽，雄鸟特征鲜明，全身大部分为黑色，雌鸟则呈红褐色并带有深色条纹。该物种分布于非洲南部，包括纳米比亚、博茨瓦纳南部至南非，偏好干燥的大草原、半沙漠或有稀疏植被的沙漠区域。","appearance":"雄鸟头、颈、下体、腹部和翼下均为黑色，双翼和翼下的羽毛为红褐色，羽缘略带黑色。雌鸟上体为红褐色，带有更深的条纹，羽缘泛白，稍带黑棕色斑纹。嘴较粗壮，呈圆锥状，鼻孔上有悬羽掩盖，翅膀稍尖长，尾较翅短，跗跖后缘较钝，具有盾状鳞，后爪长而直。","call":"雄鸟的鸣唱主要是在地面发出短暂的啾啾声，而在空中展示飞行时则发出一系列简单的嗡嗡音。群鸟被惊飞时的合唱比的叫声更深沉、不那么尖锐。","habits":"黑耳雀百灵常于地面行走或振翼作波状飞行，偏好在干燥的大草原、半沙漠或有稀疏植被的沙漠区域活动。它们在地面或飞行时鸣唱，高飞时直冲入云，善于奔走，受惊时常藏匿不动，利用保护色躲避天敌。主要以草籽、嫩芽为食，也会捕食昆虫。","breeding":"巢由雌鸟在凹陷的地面上建造，通常安置在松软的沙质地形上，巢外缘用小卵石或沙子加固，内部由杂草草叶和细蒿秆构成。每窝产4枚卵，孵化期为8至12天。雏鸟出生后赤身裸体，仅部分部位有绒羽，7天后睁开双眼。幼鸟在8天后离巢，15至20天后能飞行。","identification":"雌鸟通过其全黑的翼下和缺乏黑色腹部斑块与其它雌鸟雀百灵区分开来。与栗背雀百灵的区别在于其背部颜色均匀，与灰背雀百灵的区别在于其上体颜色更深，以及翼下黑色覆盖更广。","protection":"IUCN：LC（无危）","distribution":"分布在非洲南部，包括纳米比亚和博茨瓦纳南部至南非。在纳米比亚，从北Namaqualand向南延伸；在博茨瓦纳，主要出现在Kalahari-Gemsbok国家公园；在南非，广泛分布于Great Karoo地区。","other":"该物种在历史上的繁殖记录显示可能的分布范围收缩，特别是在前Transvaal地区，自1870年后未再有记录。核心分布区在正式的保护区中代表不足。"},{"name":"马岛雀百灵","english_name":"Madagascar Lark","scientific_name":"Eremopterix hova","overview":"马岛雀百灵（英文名：Madagascar Lark，学名：Eremopterix hova），是雀形目百灵科雀百灵属的鸟类。小型的、带有斑纹的棕色鸟类，常见于马达加斯加的各种开阔生境，唯独不见于密林之中。","appearance":"马岛雀百灵长约13厘米，体型紧凑，喙短而粗壮。其上体为淡棕色，饰以深棕色条纹，新鲜羽毛的轮廓边缘呈浅黄色（但这些边缘常被磨损）。头部有显著的冠纹，与宽阔的灰棕色至浅黄色眉线形成鲜明对比；窄的眼纹和更宽的颊纹在眼下形成独特的‘泪滴’状标记；飞羽棕色，边缘较淡；下体白色至浅黄色，胸部有明显的暗色条纹，两胁和尾下覆羽染以较深的黄褐色；眼睛深棕色；喙色从粉红色到橙色肉色不等，有时上喙上半部颜色较暗；腿色淡，从粉红色肉色到棕肉色。雄雌外观相似。幼鸟未详述，可能图案更为鲜明，上体有浅色羽毛边缘，胸部斑点而非条纹。","call":"雄鸟的歌声多变且悦耳，通常在展示飞行中发出，也会从栖木甚至地面演唱。","habits":"马岛雀百灵主要生活在干燥的草原和亚热带或热带的干燥灌木丛中，偏好开阔地带，大部分时间在地面行走。其具体食性和捕食者信息未详细描述。","breeding":"关于马岛雀百灵的繁殖行为和生长周期的具体细节未提供。","identification":"与较小的马达加斯加Cisticola相似，但马岛雀百灵有较短的尾巴和喙，胸部有条纹，且通常在地面上行走。所有其他相似物种喙形不同。","protection":"IUCN：LC（无危）","distribution":"马岛雀百灵的分布局限于非洲的马达加斯加岛，遍布全岛，估计全球分布面积超过100,000平方千米。"},{"name":"黑顶雀百灵","english_name":"Black-crowned Sparrow-Lark","scientific_name":"Eremopterix nigriceps","overview":"黑顶雀百灵（英文名：Black-crowned Sparrow-Lark，学名：Eremopterix nigriceps），是雀形目百灵科雀百灵属的鸟类。雄鸟具有显著的黑白头部特征，雌鸟整体呈淡沙褐色，广泛分布于北非至印度西北部的干旱及半干旱平原地带。","appearance":"雄鸟具黑冠和黑色下体，脸颊白色，上体灰褐带红晕；雌鸟上体沙褐，下体白色，胸带淡肉桂色，下翼覆羽黑色。成鸟长10-11厘米，体重12-16克，嘴较粗圆锥状，翅尖长，尾短，腿后缘钝，后爪长直。幼鸟似雌鸟，但羽缘微具淡色边。","call":"雄鸟的鸣唱为一系列清脆、高音的哨音，重复短语，有时在低处如灌木或岩石上展示或飞行中发出。","habits":"栖息于干燥大草原、半沙漠及有稀疏植被的沙漠区域，偏好沙地而非岩石地面。群居觅食，以种子为主食，也食昆虫和其他无脊椎动物。活动高峰在早晚，日间高温时会寻找阴凉处或蜥蜴洞穴避暑。","breeding":"繁殖季节多与雨季关联，夏季为主要繁殖期，巢为浅凹坑，铺垫植物材料，位于草丛或灌木下。每窝产卵2-3枚，双亲共孵约11-12天，雏鸟早熟，8天左右离巢，21-22天羽毛丰满。","identification":"雄鸟的黑白头纹和雌鸟的沙褐色外观是辨识关键，与栗头雀百灵相比，其头部标记更黑，额头白，无白色冠纹，两侧胸部白色窄条更细；与灰顶雀百灵区别在于头部图案和较浅的上体颜色。","protection":"IUCN：LC（无危）","distribution":"非洲北部至印度西北部，包括毛里塔尼亚至巴基斯坦和印度，也见于阿拉伯半岛。","other":"适应性强，能容忍适度放牧压力，随着西非荒漠化加剧，分布范围向南扩展。"},{"name":"栗背雀百灵","english_name":"Chestnut-backed Sparrow-Lark","scientific_name":"Eremopterix leucotis","overview":"栗背雀百灵（英文名：Chestnut-backed Sparrow-Lark，学名：Eremopterix leucotis），是雀形目百灵科雀百灵属的鸟类。小型鸣禽，广泛分布于非洲南部至撒哈拉沙漠以南地区。雄鸟以其黑色头部与胸腹及醒目的白色耳斑、栗色背部和翅膀著称，雌鸟则较为朴素，上体栗色带斑点，下体淡色且有深色条纹。","appearance":"雄鸟体长约12-14厘米，体重约12-21克，具有黑色头部、胸部和腹部，背部和翅膀为鲜明的栗色，头部两侧有显著的白色斑块。雌鸟颜色较为暗淡，上体为栗色并带有深褐色条纹，下体为淡色并有深褐色条纹，喉咙至腹部有黑色斑块。喙部厚实，呈灰色，脚为淡肉灰色。幼鸟外观类似雌鸟，但冠羽和背部羽毛边缘为白色。","call":"该物种的鸣叫声尚未详细描述。","habits":"栗背雀百灵偏好短草丛生的开阔草地和半干旱的稀树草原，尤其喜欢烧过的地方、空旷的田野和新耕的土地。它们以种子和昆虫为食，常在地面或低矮的灌木丛中寻找食物。这种鸟既有定居习性也有游荡习性，具体迁徙模式尚不清楚。在非洲西部，繁殖季节结束后会向南迁移。","breeding":"繁殖期主要在10月至翌年3月，但在某些地区可能全年都有繁殖行为。筑巢于地面，通常一次产卵1-2枚，孵化期为10-11天。幼鸟孵化后不久就能跟随父母，大约在8-10天后离巢。","identification":"雄鸟通过其独特的黑色头部、白色的耳斑和丰富的栗色背部易于识别。雌鸟与其他同属物种的区别在于其栗色的上体与较淡的臀部形成对比，以及黑色的中央腹部斑块。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲，从南苏丹到埃塞俄比亚、厄立特里亚、索马里西北部，以及非洲南部地区。在非洲东部与栗头雀百灵的分布区有重叠。"},{"name":"灰顶雀百灵","english_name":"Ashy-crowned Sparrow-Lark","scientific_name":"Eremopterix griseus","overview":"灰顶雀百灵（英文名：Ashy-crowned Sparrow-Lark，学名：Eremopterix griseus），是雀形目百灵科雀百灵属的鸟类。小型鸣禽，分布于印度、巴基斯坦，南至斯里兰卡，以及印度半岛。雄鸟具独特黑白脸部图案，雌鸟外观似麻雀，但腿更短，体态更丰满。常见于干燥地带，如大草原、半沙漠和有稀疏植被的沙漠。","appearance":"灰顶雀百灵体型小，长约11-12厘米，具有厚重的喙，类似雀鸟。雄鸟头部和腹部为棕黑色，颈部有白斑，冠部灰色，上体和翅膀呈苍白灰色。雌鸟上体为白灰棕色，胸部淡黄色，腹部白色。幼鸟羽毛颜色与雌鸟相似。喙为白灰色，厚实且圆锥形。","call":"鸣唱主要在高空飞行时进行，由快速重复的短音节组成，间或插入略带忧郁的拉长哨音，有时从地面或低矮栖木发出。","habits":"栖息于海拔1000米以下的干燥开阔地带，如草原、半沙漠或有散落植被的沙漠区域。主要以草籽、嫩芽及昆虫为食，如蚱蜢和小甲虫。常在地面觅食，也会在空中振翅飞行时鸣唱。","breeding":"繁殖季节不固定，大致从2月持续到9月，可能有两次繁殖。雄鸟会在高空进行展示飞行，伴有鸣叫。巢建于地面，通常位于石头、土块或灌木下方，由细草、根须、毛发或羽毛铺垫。每窝产卵2-3枚，由双亲孵化约13-14天。雏鸟孵化后由双方共同抚育。","identification":"雄鸟与黑顶雀百灵可通过头部灰黑色的区别识别，雌鸟较难区分。幼鸟与雌鸟羽色相似，但肩羽和翼覆羽边缘有白色。在分布范围内，与黑顶雀百灵的区分主要在于生境差异。","protection":"IUCN：LC（无危）","distribution":"分布于南亚平原，自喜马拉雅山脉南部至斯里兰卡，向西延伸至印度河流域，向东至阿萨姆邦。在中国大陆，见于西藏南部和云南西部。","other":"曾被称为灰顶雀百灵的亚种ceylonensis和siccata，但因变异连续，现被视为单一物种。"},{"name":"栗头雀百灵","english_name":"Chestnut-headed Sparrow-Lark","scientific_name":"Eremopterix signatus","overview":"栗头雀百灵（英文名：Chestnut-headed Sparrow-Lark，学名：Eremopterix signatus），是雀形目百灵科雀百灵属的鸟类。分布于非洲东部和东北部的干燥大草原、半沙漠或有稀疏植被的沙漠区域。成年雄鸟头部和胸部有显著的黑色和白色标记，雌鸟则较为暗淡，两者均具有一些独特的辨识特征。","appearance":"成年雄鸟拥有鲜明的黑白胸腹部图案，头顶有纯白色的斑点，周围环绕着深栗色边缘，雌鸟则呈现较为单调的褐色，但有红棕色眉纹和腹部的黑色斑点。雄鸟的上体和翅膀布满褐色斑纹，嘴较粗壮呈圆锥状。雌鸟和雄鸟在外表上有明显的差异，雌鸟上体更偏暗褐色，下体污白色，有变异性斑点。幼鸟与雌鸟相似，但颜色更为柔和，有鳞片状的上体羽毛。","call":"这种鸟在飞行中会发出简单的鸣叫声，通常在低空飞行时或站立于裸露地面上鸣唱。","habits":"栗头雀百灵栖息在干旱和开阔的生境，包括沙漠、草地和灌木丛，常见于成群活动，数量可达40只，尤其在非繁殖季节。它们主要在地面上觅食，食物以草籽为主，雏鸟则会被喂养昆虫。这种鸟倾向于在水源附近活动。","breeding":"繁殖期在4月至7月，可能实行一夫一妻制。雄鸟在领地上方6至10米处进行空中展示。巢为开放式的杯子形状，由干燥的纤维草搭建，位于地面浅坑中，通常靠近草丛基部。每窝产卵3至5枚，孵化和育雏细节未知。","identification":"雄鸟通过其独特的黑白和栗色标记与白颊雀百灵相区别，后者缺乏白色斑点。雌鸟与黑顶雀百灵和白颊雀百灵的雌鸟相似，但可通过更暗的上体、更亮的背部和较重的喙来识别。","protection":"IUCN：LC（无危）","distribution":"非洲东部和东北部，包括索马里等地，分布于从海平面到海拔1500米的高度，年降雨量在75至500毫米之间。"},{"name":"灰背雀百灵","english_name":"Grey-backed Sparrow-Lark","scientific_name":"Eremopterix verticalis","overview":"灰背雀百灵（英文名：Grey-backed Sparrow-Lark，学名：Eremopterix verticalis），是雀形目百灵科雀百灵属的鸟类。别称有时与黑耳雀百灵混淆。该鸟以灰黑色为主色调，双翼带有灰白色斑纹，脸部和后颈有显著的灰白色块。主要分布于非洲南部和中南部的半干旱地区，栖息于干燥的草地、灌木覆盖的平原和矮山。","appearance":"灰背雀百灵体长约12至13厘米，体重约13至21克。雄鸟具有灰褐色背部和翅膀，带有鳞片状图案，头部黑色，配有大胆的白色耳斑延伸至颈背。雌鸟外观较单调，根据地理分布变化，但总有一块深色腹部斑块，整体比其他雌鸟雀百灵更淡。幼鸟上部颜色比雌鸟更深，面部呈淡红栗色，喉部和胸部淡黄色，斑点更深，腹部斑块较小且颜色更深。成年雄鸟在幼鸟换羽后1至2个月获得斑驳的幼年羽毛，一年左右完成第一次换羽获得成年羽毛。","call":"雄鸟的鸣唱通常在空中展示，由一系列简单的音符组成：“shreep shreep shrup-up shreep-eep”。飞行叫声柔和，为“pink”，比黑耳雀百灵的声音更干净、更高。被惊扰时从巢中发出“prink”的声音，喂食雏鸟时发出轻柔的“tsee-ree”叫声。","habits":"灰背雀百灵栖息于半干旱地区的草地，也见于稀疏的灌木林、休耕田和南非西部开普省的小麦田。偏好卡拉哈里沙漠中的淡色钙质平地和河床而非红色沙地。在核心分布区外，偶尔会出现在各种较湿润的草原。它们在开阔的低地平原上生活，山区较少见。以种子为主要食物，也会食用少量绿色植被和昆虫，如白蚁、蚱蜢、蚂蚁和甲虫。雨后，它们的胃中会发现大量的Hodotermes收获白蚁，这可能与白蚁有翅型的大量出现有关。雏鸟主要以昆虫喂养，尤其是收获白蚁。","breeding":"雄鸟求偶时会在空中鸣唱或在高空拍打翅膀。巢建在地面凹陷处或草丛中，由杂草叶片和细蒿秆构成，表面多有杂草遮掩，呈杯状。繁殖季节在5至6月间，每窝产卵2至5枚。卵近黄白色，表面光滑带有褐色细斑，大小约为23毫米×18毫米。孵化期大约15天，雏鸟破壳而出时全身裸露，仅部分长有绒羽，7天后睁开双眼。","identification":"雄鸟与雌鸟在羽毛上有明显差异，雌鸟颜色更淡，腹部有深色斑块，这有助于与其他雌鸟雀百灵区分开。幼鸟颜色比雌鸟更深，特征更为明显。不同亚种在上部颜色和翼覆羽边缘宽度上有所不同。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲南部和中南部，具体包括AF: s, sc地区。","other":"灰背雀百灵在系统学历史上有四个亚种被认可。"}];
